 6→/// Lifecycle status of an incoming watch-to-iPhone transfer.
 7→/// Tracks from first progress signal through chunk assembly and handoff to RecordingMetadata.
 8→enum WatchTransferStatus: Int16, CaseIterable {
 9→    /// Transfer announced via applicationContext but no file received yet
10→    case pending = 0
11→    /// One or more chunk files received (or single-file in progress)
12→    case receiving = 1
13→    /// All chunks received, audio merge in progress
14→    case assembling = 2
15→    /// Merge complete, ready to hand off to RecordingMetadata pipeline
16→    case assembled = 3
17→    /// Fully processed and handed off (terminal)
18→    case completed = 4
19→    /// Transfer or merge failed
20→    case failed = 5
21→    /// No progress for an extended period (terminal)
22→    case timedOut = 6
23→
24→    var isTerminal: Bool {
25→        return self == .completed || self == .timedOut
26→    }
27→
28→    var isActive: Bool {
29→        return !isTerminal && self != .failed
30→    }
31→
32→    var displayName: String {
33→        switch self {
34→        case .pending:    return "Pending"
35→        case .receiving:  return "Receiving"
36→        case .assembling: return "Merging"
37→        case .assembled:  return "Ready"
38→        case .completed:  return "Completed"
39→        case .failed:     return "Failed"
40→        case .timedOut:   return "Timed Out"
41→        }
42→    }
43→}
