    // MARK: - Initialization

    init(
        recordingEngine: RecordingEngineProtocol? = nil,
        chunkPolicy: ChunkPolicyProtocol? = nil,
        metadataFactory: ChunkMetadataFactoryProtocol? = nil,
        chunkFileStore: ChunkFileStoreProtocol? = nil,
        clock: RecordingClockProtocol? = nil,
        logger: Logger = LoggerFactory.makeLogger(),
        recordingSettings: [String: Any] = defaultRecordingSettings
    ) {
        self.recordingEngine = recordingEngine ?? AVAudioRecordingEngine()
        self.chunkPolicy = chunkPolicy ?? DefaultChunkPolicy()
        self.metadataFactory = metadataFactory ?? DefaultChunkMetadataFactory()
        self.chunkFileStore = chunkFileStore ?? DefaultChunkFileStore()
        self.clock = clock ?? TimerRecordingClock()
        self.logger = logger
        self.recordingSettings = recordingSettings

        logger.info(
            "[ChunkedRecordingManager] Initialized (initial allocation: \(self.chunkPolicy.initialAllocationSeconds)s, extend amount: \(self.chunkPolicy.extendAmountSeconds)s)"
        )
    }

    deinit {
        elapsedTickCancellable?.cancel()
    }

    // MARK: - Public Methods

    func startRecording(
        onChunkCompleted: @escaping ChunkCompletedHandler,
        onRecordingFinished: RecordingFinishedHandler? = nil
    ) -> UUID? {
        guard !isRecording else {
            logger.warning("[ChunkedRecordingManager] Already recording")
            return parentRecordingId
        }

        let recordingId = UUID()
        parentRecordingId = recordingId
        recordingStartTime = clock.now
        currentChunkIndex = 0
        accumulatedDuration = 0
        totalElapsedTime = 0
        allocatedTime = chunkPolicy.initialAllocationSeconds
        remainingTime = chunkPolicy.initialAllocationSeconds
        isExtendEnabled = false
        autoStopFired = false
        chunkFileStore.reset()

        self.onChunkCompleted = onChunkCompleted
        self.onRecordingFinished = onRecordingFinished

        logger.info("[ChunkedRecordingManager] Starting recording: \(recordingId), allocation: \(allocatedTime)s")

        guard startNewChunk() else {
            logger.error("[ChunkedRecordingManager] Failed to start first chunk", error: nil)
            resetSessionStateAfterFailure()
            return nil
        }

        isRecording = true
        startElapsedTimer()
        return recordingId
    }

    @discardableResult
    func stopRecording() -> TimeInterval {
        guard isRecording else {
            logger.warning("[ChunkedRecordingManager] Not recording")
            return 0
        }

        logger.info("[ChunkedRecordingManager] Stopping recording")
        stopElapsedTimer()
        finalizeCurrentChunk(isLastChunk: true)

        isRecording = false
        isExtendEnabled = false

        let totalDuration = totalElapsedTime
        logger.info(
            "[ChunkedRecordingManager] Recording stopped. Total duration: \(String(format: "%.1f", totalDuration))s, Chunks: \(currentChunkIndex + 1)"
        )

        onRecordingFinished?()
        return totalDuration
    }

    func extendRecording() -> Bool {
        guard isRecording else {
            logger.warning("[ChunkedRecordingManager] Cannot extend - not recording")
            return false
        }

        guard isExtendEnabled else {
            logger.warning("[ChunkedRecordingManager] Cannot extend - EXTEND not yet enabled")
            return false
        }

        guard chunkPolicy.canApplyExtend(currentAllocation: allocatedTime) else {
            logger.warning("[ChunkedRecordingManager] Cannot extend - would exceed max allocation (\(chunkPolicy.maxAllocatedSeconds)s)")
            return false
        }

        logger.info("[ChunkedRecordingManager] === EXTEND RECORDING ===")
        logger.info("[ChunkedRecordingManager] Creating chunk boundary at index \(currentChunkIndex)")

        let completedChunkIndex = currentChunkIndex
        recordingEngine.stop()

        currentChunkIndex += 1
        accumulatedDuration = totalElapsedTime

        let newChunkStarted = startNewChunk()
        sendChunkForTransfer(chunkIndex: completedChunkIndex, isLastChunk: false)

        if !newChunkStarted {
            logger.error("[ChunkedRecordingManager] Failed to start new chunk after EXTEND", error: nil)
            isRecording = false
            stopElapsedTimer()
            onRecordingFinished?()
            return false
        }

        allocatedTime = chunkPolicy.extendedAllocation(from: allocatedTime)
        remainingTime = chunkPolicy.remainingTime(allocatedTime: allocatedTime, totalElapsed: totalElapsedTime)
        isExtendEnabled = false
        autoStopFired = false

        logger.info(
            "[ChunkedRecordingManager] EXTEND successful. New allocation: \(allocatedTime)s, remaining: \(remainingTime)s, chunk: \(currentChunkIndex)"
        )
        return true
    }

    func pauseRecording() {
        recordingEngine.pause()
        stopElapsedTimer()
        logger.info("[ChunkedRecordingManager] Recording paused")
    }

    func resumeRecording() {
        _ = recordingEngine.resume()
        startElapsedTimer()
        logger.info("[ChunkedRecordingManager] Recording resumed")
    }

    func deleteLocalChunks(for recordingId: UUID) {
        guard recordingId == parentRecordingId else {
            logger.warning("[ChunkedRecordingManager] Recording ID mismatch for chunk deletion")
            return
        }

        let report = chunkFileStore.deleteAllTrackedChunks()

        for (index, url) in report.deleted.sorted(by: { $0.key < $1.key }) {
            logger.info("[ChunkedRecordingManager] Deleted chunk \(index): \(url.lastPathComponent)")
        }

        for (index, error) in report.failures.sorted(by: { $0.key < $1.key }) {
            logger.error("[ChunkedRecordingManager] Failed to delete chunk \(index)", error: error)
        }

        logger.info("[ChunkedRecordingManager] All local chunks deleted for recording: \(recordingId)")
    }

    func getLocalChunkFiles() -> [Int: URL] {
        chunkFileStore.allChunkFiles()
    }

    // MARK: - Private Methods

    private func resetSessionStateAfterFailure() {
        parentRecordingId = nil
        recordingStartTime = nil
        chunkFileStore.reset()
    }

    private func startNewChunk() -> Bool {
        guard let recordingId = parentRecordingId else { return false }

        let chunkURL = chunkFileStore.makeChunkURL(recordingId: recordingId, chunkIndex: currentChunkIndex)

        do {
            try recordingEngine.startRecording(at: chunkURL, settings: recordingSettings)
            chunkFileStore.trackChunk(index: currentChunkIndex, url: chunkURL)

            logger.info("[ChunkedRecordingManager] Started chunk \(currentChunkIndex): \(chunkURL.lastPathComponent)")
            return true
        } catch {
            logger.error("[ChunkedRecordingManager] Failed to start recorder for chunk \(currentChunkIndex)", error: error)
            return false
        }
    }

    private func finalizeCurrentChunk(isLastChunk: Bool) {
        let chunkIndex = currentChunkIndex
        recordingEngine.stop()
        sendChunkForTransfer(chunkIndex: chunkIndex, isLastChunk: isLastChunk)
    }

    private func sendChunkForTransfer(chunkIndex: Int, isLastChunk: Bool) {
        guard
            let parentId = parentRecordingId,
            let startTime = recordingStartTime,
            let chunkURL = chunkFileStore.chunkURL(for: chunkIndex)
        else {
            logger.error("[ChunkedRecordingManager] Missing data for chunk transfer at index \(chunkIndex)", error: nil)
            return
        }

        let chunkDuration = metadataFactory.chunkDuration(for: chunkURL)

        if !isLastChunk || chunkIndex > 0 {
            accumulatedDuration = totalElapsedTime
        }
        let totalDuration = accumulatedDuration + chunkDuration

        let transferMetadata = metadataFactory.makeTransferMetadata(
            parentRecordingId: parentId,
            recordingStartTime: startTime,
            chunkURL: chunkURL,
            chunkIndex: chunkIndex,
            isLastChunk: isLastChunk,
            totalDurationSoFar: totalDuration,
            createdAt: clock.now
        )

        logger.info(
            "[ChunkedRecordingManager] Chunk \(chunkIndex) ready for transfer: \(chunkURL.lastPathComponent) (\(String(format: "%.1f", chunkDuration))s)"
        )
        if isLastChunk {
            logger.info(
                "[ChunkedRecordingManager] This is the LAST chunk (total: \(chunkIndex + 1)). Total duration: \(String(format: "%.1f", totalDuration))s"
            )
        }

        onChunkCompleted?(chunkURL, transferMetadata)
    }

    // MARK: - Timer Management

    private func startElapsedTimer() {
        stopElapsedTimer()
        elapsedTickCancellable = clock.startRepeating(interval: 0.5) { [weak self] in
            Task { @MainActor in
                guard let self = self, self.isRecording else { return }

                let currentChunkElapsed = self.recordingEngine.currentTime
                self.totalElapsedTime = self.accumulatedDuration + currentChunkElapsed
                self.remainingTime = self.chunkPolicy.remainingTime(
                    allocatedTime: self.allocatedTime,
                    totalElapsed: self.totalElapsedTime
                )

                self.updateExtendEnabled()

                if self.remainingTime <= 0 && !self.autoStopFired {
                    self.autoStopFired = true
                    self.logger.info("[ChunkedRecordingManager] Countdown reached zero - triggering auto-stop")
                    self.onAutoStop?()
                }
            }
        }
    }

    private func stopElapsedTimer() {
        elapsedTickCancellable?.cancel()
        elapsedTickCancellable = nil
    }

    private func updateExtendEnabled() {
        isExtendEnabled = chunkPolicy.canEnableExtend(
            totalElapsed: totalElapsedTime,
            allocatedTime: allocatedTime
        )
    }
}

