import Foundation
import AVFoundation

enum RecordingEngineError: Error {
    case failedToPrepare
    case failedToStart
}

@MainActor
protocol RecordingEngineProtocol: AnyObject {
    var currentTime: TimeInterval { get }
    var isRecording: Bool { get }

    func startRecording(at url: URL, settings: [String: Any]) throws
    func stop()
    func pause()
    func resume() -> Bool
}

@MainActor
final class AVAudioRecordingEngine: RecordingEngineProtocol {
    private var recorder: AVAudioRecorder?

    var currentTime: TimeInterval {
        recorder?.currentTime ?? 0
    }

    var isRecording: Bool {
        recorder?.isRecording ?? false
    }

    func startRecording(at url: URL, settings: [String: Any]) throws {
        let recorder = try AVAudioRecorder(url: url, settings: settings)
        recorder.isMeteringEnabled = true

        guard recorder.prepareToRecord() else {
            throw RecordingEngineError.failedToPrepare
        }

        guard recorder.record() else {
            throw RecordingEngineError.failedToStart
        }

        self.recorder = recorder
    }

    func stop() {
        recorder?.stop()
        recorder = nil
    }

    func pause() {
        recorder?.pause()
    }

    func resume() -> Bool {
        recorder?.record() ?? false
    }
}

