import Foundation

struct ChunkPolicyConfiguration {
    let initialAllocationSeconds: TimeInterval
    let extendAmountSeconds: TimeInterval
    let extendEnabledAfterSeconds: TimeInterval
    let maxTotalExtensionSeconds: TimeInterval

    var maxAllocatedSeconds: TimeInterval {
        initialAllocationSeconds + maxTotalExtensionSeconds
    }

    #if DEBUG
    static let useTestTimings = false
    #endif

    static let `default`: ChunkPolicyConfiguration = {
        #if DEBUG
        if useTestTimings {
            return ChunkPolicyConfiguration(
                initialAllocationSeconds: 5 * 60,
                extendAmountSeconds: 5 * 60,
                extendEnabledAfterSeconds: 4 * 60,
                maxTotalExtensionSeconds: 5 * 60
            )
        }
        #endif

        return ChunkPolicyConfiguration(
            initialAllocationSeconds: 45 * 60,
            extendAmountSeconds: 45 * 60,
            // Enable EXTEND during the final 15 minutes of the initial 45-minute window.
            extendEnabledAfterSeconds: 30 * 60,
            maxTotalExtensionSeconds: 45 * 60
        )
    }()
}

protocol ChunkPolicyProtocol {
    var initialAllocationSeconds: TimeInterval { get }
    var extendAmountSeconds: TimeInterval { get }
    var maxAllocatedSeconds: TimeInterval { get }

    func remainingTime(allocatedTime: TimeInterval, totalElapsed: TimeInterval) -> TimeInterval
    func canEnableExtend(totalElapsed: TimeInterval, allocatedTime: TimeInterval) -> Bool
    func canApplyExtend(currentAllocation: TimeInterval) -> Bool
    func extendedAllocation(from currentAllocation: TimeInterval) -> TimeInterval
}

struct DefaultChunkPolicy: ChunkPolicyProtocol {
    private let configuration: ChunkPolicyConfiguration

    init(configuration: ChunkPolicyConfiguration = .default) {
        self.configuration = configuration
    }

    var initialAllocationSeconds: TimeInterval {
        configuration.initialAllocationSeconds
    }

    var extendAmountSeconds: TimeInterval {
        configuration.extendAmountSeconds
    }

    var maxAllocatedSeconds: TimeInterval {
        configuration.maxAllocatedSeconds
    }

    func remainingTime(allocatedTime: TimeInterval, totalElapsed: TimeInterval) -> TimeInterval {
        max(0, allocatedTime - totalElapsed)
    }

    func canEnableExtend(totalElapsed: TimeInterval, allocatedTime: TimeInterval) -> Bool {
        let usedExtensionSeconds = max(0, allocatedTime - configuration.initialAllocationSeconds)
        let meetsElapsedThreshold = totalElapsed >= configuration.extendEnabledAfterSeconds
        let canAddMoreExtension = usedExtensionSeconds < configuration.maxTotalExtensionSeconds
        return meetsElapsedThreshold && canAddMoreExtension
    }

    func canApplyExtend(currentAllocation: TimeInterval) -> Bool {
        currentAllocation + configuration.extendAmountSeconds <= configuration.maxAllocatedSeconds
    }

    func extendedAllocation(from currentAllocation: TimeInterval) -> TimeInterval {
        min(configuration.maxAllocatedSeconds, currentAllocation + configuration.extendAmountSeconds)
    }
}

