import Foundation

struct ChunkDeletionReport {
    let deleted: [Int: URL]
    let failures: [Int: Error]
}

protocol ChunkFileStoreProtocol: AnyObject {
    func reset()
    func makeChunkURL(recordingId: UUID, chunkIndex: Int) -> URL
    func trackChunk(index: Int, url: URL)
    func chunkURL(for index: Int) -> URL?
    func allChunkFiles() -> [Int: URL]
    func deleteAllTrackedChunks() -> ChunkDeletionReport
}

final class DefaultChunkFileStore: ChunkFileStoreProtocol {
    private let fileManager: FileManager
    private let baseDirectory: URL
    private var trackedChunkFiles: [Int: URL] = [:]

    init(
        fileManager: FileManager = .default,
        baseDirectory: URL = FileManager.default.temporaryDirectory
    ) {
        self.fileManager = fileManager
        self.baseDirectory = baseDirectory
    }

    func reset() {
        trackedChunkFiles.removeAll()
    }

    func makeChunkURL(recordingId: UUID, chunkIndex: Int) -> URL {
        let chunkFilename = "\(recordingId.uuidString)_chunk\(chunkIndex).m4a"
        return baseDirectory.appendingPathComponent(chunkFilename)
    }

    func trackChunk(index: Int, url: URL) {
        trackedChunkFiles[index] = url
    }

    func chunkURL(for index: Int) -> URL? {
        trackedChunkFiles[index]
    }

    func allChunkFiles() -> [Int: URL] {
        trackedChunkFiles
    }

    func deleteAllTrackedChunks() -> ChunkDeletionReport {
        var deleted: [Int: URL] = [:]
        var failures: [Int: Error] = [:]

        for (index, url) in trackedChunkFiles {
            do {
                try fileManager.removeItem(at: url)
                deleted[index] = url
            } catch {
                failures[index] = error
            }
        }

        trackedChunkFiles.removeAll()
        return ChunkDeletionReport(deleted: deleted, failures: failures)
    }
}

import Foundation
import AVFoundation

protocol ChunkMetadataFactoryProtocol {
    func chunkDuration(for chunkURL: URL) -> TimeInterval
    func makeTransferMetadata(
        parentRecordingId: UUID,
        recordingStartTime: Date,
        chunkURL: URL,
        chunkIndex: Int,
        isLastChunk: Bool,
        totalDurationSoFar: TimeInterval,
        createdAt: Date
    ) -> RecordingTransferMetadata
}

struct DefaultChunkMetadataFactory: ChunkMetadataFactoryProtocol {
    func chunkDuration(for chunkURL: URL) -> TimeInterval {
        let asset = AVURLAsset(url: chunkURL)
        return CMTimeGetSeconds(asset.duration)
    }

    func makeTransferMetadata(
        parentRecordingId: UUID,
        recordingStartTime: Date,
        chunkURL: URL,
        chunkIndex: Int,
        isLastChunk: Bool,
        totalDurationSoFar: TimeInterval,
        createdAt: Date
    ) -> RecordingTransferMetadata {
        let duration = chunkDuration(for: chunkURL)

        let chunkInfo = ChunkTransferMetadata(
            parentRecordingId: parentRecordingId,
            chunkId: UUID(),
            chunkIndex: chunkIndex,
            isLastChunk: isLastChunk,
            chunkDuration: duration,
            totalDurationSoFar: totalDurationSoFar,
            recordingStartTime: recordingStartTime
        )

        return RecordingTransferMetadata(
            id: parentRecordingId,
            filename: chunkURL.lastPathComponent,
            duration: duration,
            createdAt: createdAt,
            startTime: recordingStartTime,
            chunkInfo: chunkInfo
        )
    }
}

