import Foundation
import Combine

protocol RecordingClockProtocol {
    var now: Date { get }
    func startRepeating(interval: TimeInterval, onTick: @escaping () -> Void) -> AnyCancellable
}

struct TimerRecordingClock: RecordingClockProtocol {
    var now: Date {
        Date()
    }

    func startRepeating(interval: TimeInterval, onTick: @escaping () -> Void) -> AnyCancellable {
        Timer.publish(every: interval, on: .main, in: .common)
            .autoconnect()
            .sink { _ in
                onTick()
            }
    }
}

import Foundation
import AVFoundation

// MARK: - AudioChunkMerger

/// Merges multiple M4A audio chunk files into a single continuous M4A file.
///
/// Uses AVMutableComposition to concatenate audio tracks from each chunk
/// in order, then exports the result via AVAssetExportSession.
///
/// This is used on the iPhone to reassemble recordings that were split into
/// 45-minute segments on the Apple Watch for reliable transfer.
///
/// - Note: The merger preserves the original audio format (AAC M4A) and does
///   not re-encode, keeping the process fast and lossless.
enum AudioChunkMerger {

    // MARK: - Errors

    /// Errors that can occur during chunk merging
    enum MergeError: LocalizedError {
        case noChunksProvided
        case noAudioTrack(URL)
        case exportSessionCreationFailed
        case exportFailed(String)
        case exportCancelled

        var errorDescription: String? {
            switch self {
            case .noChunksProvided:
                return AppText.AudioMerge.noChunksProvided

            case .noAudioTrack(let url):
                return AppText.AudioMerge.noAudioTrack(
                    fileName: url.lastPathComponent
                )

            case .exportSessionCreationFailed:
                return AppText.AudioMerge.exportSessionCreationFailed

            case .exportFailed(let message):
                return AppText.AudioMerge.exportFailed(message)

            case .exportCancelled:
                return AppText.AudioMerge.exportCancelled
            }
        }
    }

    // MARK: - Public Methods

    /// Merges an ordered array of audio chunk files into a single M4A file.
    ///
    /// - Parameters:
    ///   - chunks: Array of chunk file URLs, in playback order (index 0 = first chunk)
    ///   - outputFilename: Name for the output file (e.g., "recording_UUID.m4a")
    /// - Returns: URL of the merged audio file
    /// - Throws: MergeError if merging fails
    static func merge(chunks: [URL], outputFilename: String) async throws -> URL {
        let logger = LoggerFactory.makeLogger()

        guard !chunks.isEmpty else {
            throw MergeError.noChunksProvided
        }

        // If there's only one chunk, no merging needed -- just return/copy it
        if chunks.count == 1 {
            logger.info("[AudioChunkMerger] Single chunk -- no merge needed")
            let outputURL = mergedFileDirectory().appendingPathComponent(outputFilename)

            // Remove existing file if present
            if FileManager.default.fileExists(atPath: outputURL.path) {
                try FileManager.default.removeItem(at: outputURL)
            }

            try FileManager.default.copyItem(at: chunks[0], to: outputURL)
            return outputURL
        }

        logger.info("[AudioChunkMerger] Merging \(chunks.count) chunks into \(outputFilename)")

        // Create composition
        let composition = AVMutableComposition()

        // Create an audio track in the composition
        guard let compositionTrack = composition.addMutableTrack(
            withMediaType: .audio,
            preferredTrackID: kCMPersistentTrackID_Invalid
        ) else {
            throw MergeError.exportSessionCreationFailed
        }

        // Running insertion time (where the next chunk starts in the composition)
        var insertionTime = CMTime.zero

        // Append each chunk's audio track to the composition
        for (index, chunkURL) in chunks.enumerated() {
            logger.debug("[AudioChunkMerger] Processing chunk \(index): \(chunkURL.lastPathComponent)")

            let asset = AVURLAsset(url: chunkURL)

            // Load the audio tracks from the asset
            let audioTracks = try await asset.loadTracks(withMediaType: .audio)

            guard let sourceTrack = audioTracks.first else {
                throw MergeError.noAudioTrack(chunkURL)
            }

            // Get the duration of this chunk
            let duration = try await asset.load(.duration)
            let timeRange = CMTimeRange(start: .zero, duration: duration)

            // Insert the chunk's audio at the current insertion point
            try compositionTrack.insertTimeRange(
                timeRange,
                of: sourceTrack,
                at: insertionTime
            )

            // Advance insertion point
            insertionTime = CMTimeAdd(insertionTime, duration)

            let durationSeconds = CMTimeGetSeconds(duration)
            logger.debug("[AudioChunkMerger] Chunk \(index) duration: \(String(format: "%.1f", durationSeconds))s, total: \(String(format: "%.1f", CMTimeGetSeconds(insertionTime)))s")
        }

        // Export the merged composition
        let outputURL = mergedFileDirectory().appendingPathComponent(outputFilename)

        // Remove existing file if present
        if FileManager.default.fileExists(atPath: outputURL.path) {
            try FileManager.default.removeItem(at: outputURL)
        }

        guard let exportSession = AVAssetExportSession(
            asset: composition,
            presetName: AVAssetExportPresetAppleM4A
        ) else {
            throw MergeError.exportSessionCreationFailed
        }

        exportSession.outputURL = outputURL
        exportSession.outputFileType = .m4a

        logger.info("[AudioChunkMerger] Starting export to: \(outputURL.path)")

        // Perform export
        await exportSession.export()

        // Check result
        switch exportSession.status {
        case .completed:
            let totalDuration = CMTimeGetSeconds(insertionTime)

            // Verify output file
            let attrs = try FileManager.default.attributesOfItem(atPath: outputURL.path)
            let fileSize = attrs[.size] as? Int64 ?? 0

            logger.info("[AudioChunkMerger] Merge complete!")
            logger.info("[AudioChunkMerger] Total duration: \(String(format: "%.1f", totalDuration))s")
            logger.info("[AudioChunkMerger] File size: \(fileSize / 1024) KB")

            return outputURL

        case .failed:
            let errorMessage = exportSession.error?.localizedDescription ?? "Unknown error"
            logger.error("[AudioChunkMerger] Export failed: \(errorMessage)", error: exportSession.error)
            throw MergeError.exportFailed(errorMessage)

        case .cancelled:
            logger.warning("[AudioChunkMerger] Export was cancelled")
            throw MergeError.exportCancelled

        default:
            let statusMsg = "Unexpected export status: \(exportSession.status.rawValue)"
            logger.error("[AudioChunkMerger] \(statusMsg)", error: nil)
            throw MergeError.exportFailed(statusMsg)
        }
    }

    // MARK: - Private Helpers

    /// Returns (and creates if needed) the directory for merged output files.
    private static func mergedFileDirectory() -> URL {
        let dir = FileManager.default.temporaryDirectory
            .appendingPathComponent("WatchRecordings", isDirectory: true)
            .appendingPathComponent("merged", isDirectory: true)
        try? FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true)
        return dir
    }
}

import Foundation
import Combine

// MARK: - ChunkAssemblyManager

/// Manages the collection and assembly of recording chunks received from Apple Watch.
///
/// When the Watch sends a chunked recording (45-minute segments), this manager:
/// 1. Tracks received chunks per parent recording ID
/// 2. Stores chunk file URLs and metadata
/// 3. Detects when all chunks have been received
/// 4. Triggers merge via AudioChunkMerger
/// 5. Persists chunk inventory to disk (survives app kill)
///
/// For single-file (non-chunked) transfers, this manager is bypassed and the
/// existing WatchRecordingService flow handles reception directly.
///
/// - Important: Chunk files are retained locally until the entire recording
///   is assembled, uploaded, and confirmed to the Watch.
@MainActor
final class ChunkAssemblyManager: ObservableObject {

    // MARK: - Singleton

    static let shared = ChunkAssemblyManager()

    // MARK: - Types

    /// State of a recording being assembled from chunks
    enum AssemblyState: Equatable {
        /// Receiving chunks (not all arrived yet)
        case receiving(chunksReceived: Int, totalExpected: Int?)
        /// All chunks received, merging in progress
        case merging
        /// Merge complete, ready for upload
        case ready(mergedFileURL: URL)
        /// Assembly failed
        case failed(String)

        static func == (lhs: AssemblyState, rhs: AssemblyState) -> Bool {
            switch (lhs, rhs) {
            case (.receiving(let lc, let lt), .receiving(let rc, let rt)):
                return lc == rc && lt == rt
            case (.merging, .merging):
                return true
            case (.ready(let lURL), .ready(let rURL)):
                return lURL == rURL
            case (.failed(let lMsg), .failed(let rMsg)):
                return lMsg == rMsg
            default:
                return false
            }
        }
    }

    /// Information about a recording being assembled
    struct AssemblyInfo: Identifiable {
        let id: UUID  // parentRecordingId
        var chunks: [Int: URL]  // chunkIndex -> fileURL
        var totalExpectedChunks: Int?  // Set when isLastChunk arrives
        var totalDuration: TimeInterval  // Accumulated duration
        var recordingStartTime: Date?
        var state: AssemblyState

        /// True when all expected chunks have been received
        var isComplete: Bool {
            guard let expected = totalExpectedChunks else { return false }
            return chunks.count == expected
        }

        /// Returns chunk URLs sorted by index
        var sortedChunkURLs: [URL] {
            return (0..<(totalExpectedChunks ?? chunks.count))
                .compactMap { chunks[$0] }
        }
    }

    // MARK: - Published Properties

    /// Active assemblies keyed by parent recording ID
    @Published private(set) var activeAssemblies: [UUID: AssemblyInfo] = [:]

    // MARK: - Callbacks

    /// Called when a recording is fully assembled and ready for upload.
    /// Parameters: parentRecordingId, mergedFileURL, totalDuration, recordingStartTime
    var onRecordingAssembled: ((UUID, URL, TimeInterval, Date?) -> Void)?

    // MARK: - Private Properties

    private let logger = LoggerFactory.makeLogger()

    /// Core Data repository for persisting transfer lifecycle state.
    /// Injected via `setWatchTransferRepository(_:)` after DI container is ready.
    private var watchTransferRepository: WatchTransferRepository?

    /// Directory for storing received chunk files
    private let chunksBaseDirectory: URL = {
        let dir = FileManager.default.temporaryDirectory
            .appendingPathComponent("WatchRecordings", isDirectory: true)
            .appendingPathComponent("chunks", isDirectory: true)
        try? FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true)
        return dir
    }()

    /// Persistent inventory file for surviving app kills
    private var inventoryFileURL: URL {
        return chunksBaseDirectory.appendingPathComponent("chunk_inventory.json")
    }

    // MARK: - Initialization

    private init() {
        logger.info("[ChunkAssemblyManager] Initialized")
        // Restore any persisted chunk inventory from disk
        restoreInventoryFromDisk()
    }

    // MARK: - Configuration

    /// Sets the Core Data repository for persisting transfer state.
    /// Called by WatchRecordingService.configure() after DI is ready.
    func setWatchTransferRepository(_ repository: WatchTransferRepository) {
        self.watchTransferRepository = repository
    }

    /// Triggers merge for any assemblies that were complete before the app was killed.
    /// MUST be called after `onRecordingAssembled` callback is set, otherwise the
    /// merged file would be produced but never handed off to the upload pipeline.
    func processRestoredAssemblies() {
        let completeAssemblies = activeAssemblies.filter { $0.value.isComplete }
        guard !completeAssemblies.isEmpty else { return }

        logger.info("[ChunkAssemblyManager] Processing \(completeAssemblies.count) restored complete assembly(ies)")
        for (parentId, _) in completeAssemblies {
            triggerMerge(parentId: parentId)
        }
    }

    // MARK: - Public Methods

    /// Handles a received chunk file from the Watch.
    ///
    /// Stores the chunk, updates assembly tracking, and triggers merge
    /// if all chunks for the recording have been received.
    ///
    /// - Parameters:
    ///   - fileURL: The local URL of the received chunk file (already copied to safe location)
    ///   - metadata: The transfer metadata containing chunk information
    func chunkReceived(fileURL: URL, metadata: RecordingTransferMetadata) {
        guard let chunkInfo = metadata.chunkInfo else {
            logger.error("[ChunkAssemblyManager] Received non-chunked file -- should not be routed here", error: nil)
            return
        }

        let parentId = chunkInfo.parentRecordingId
        let chunkIndex = chunkInfo.chunkIndex

        logger.info("[ChunkAssemblyManager] Received chunk \(chunkIndex) for recording \(parentId)")
        logger.debug("[ChunkAssemblyManager] isLastChunk: \(chunkInfo.isLastChunk), duration: \(chunkInfo.chunkDuration)s")

        // Move chunk file to organized directory
        let recordingDir = chunksBaseDirectory.appendingPathComponent(parentId.uuidString, isDirectory: true)
        try? FileManager.default.createDirectory(at: recordingDir, withIntermediateDirectories: true)

        let destinationURL = recordingDir.appendingPathComponent("chunk_\(chunkIndex).m4a")

        do {
            let sourcePath = fileURL.standardizedFileURL.path
            let destPath = destinationURL.standardizedFileURL.path

            if sourcePath == destPath {
                // WatchConnectivityManager already placed the file at our destination path.
                // The file is already where we need it -- no move required.
                logger.debug("[ChunkAssemblyManager] File already at destination (placed by WCM) -- skipping move")
            } else {
                // Remove existing file if present (retry scenario)
                if FileManager.default.fileExists(atPath: destinationURL.path) {
                    try FileManager.default.removeItem(at: destinationURL)
                }
                try FileManager.default.moveItem(at: fileURL, to: destinationURL)
            }

            logger.debug("[ChunkAssemblyManager] Chunk stored at: \(destinationURL.path)")
        } catch {
            logger.error("[ChunkAssemblyManager] Failed to store chunk file", error: error)
            updateAssemblyState(parentId: parentId, state: .failed("Failed to store chunk: \(error.localizedDescription)"))
            return
        }

        // Update or create assembly info
        var assembly = activeAssemblies[parentId] ?? AssemblyInfo(
            id: parentId,
            chunks: [:],
            totalExpectedChunks: nil,
            totalDuration: 0,
            recordingStartTime: chunkInfo.recordingStartTime,
            state: .receiving(chunksReceived: 0, totalExpected: nil)
        )

        // Store chunk reference
        assembly.chunks[chunkIndex] = destinationURL
        assembly.totalDuration = chunkInfo.totalDurationSoFar
        assembly.recordingStartTime = chunkInfo.recordingStartTime

        // If this is the last chunk, we now know the total count
        if chunkInfo.isLastChunk {
            assembly.totalExpectedChunks = chunkIndex + 1
            logger.info("[ChunkAssemblyManager] Last chunk received. Total expected: \(chunkIndex + 1)")
        }

        // Update state
        assembly.state = .receiving(
            chunksReceived: assembly.chunks.count,
            totalExpected: assembly.totalExpectedChunks
        )

        activeAssemblies[parentId] = assembly

        // Persist inventory to disk
        persistInventoryToDisk()

        // Check if all chunks are present
        if assembly.isComplete {
            logger.info("[ChunkAssemblyManager] All \(assembly.chunks.count) chunks received for recording \(parentId)")
            triggerMerge(parentId: parentId)
        } else {
            let received = assembly.chunks.count
            let expected = assembly.totalExpectedChunks.map { String($0) } ?? "?"
            logger.info("[ChunkAssemblyManager] Chunk \(chunkIndex) stored. Progress: \(received)/\(expected)")
        }
    }

    /// Returns assembly state for a given recording, or nil if not being assembled
    func getAssemblyState(for parentRecordingId: UUID) -> AssemblyState? {
        return activeAssemblies[parentRecordingId]?.state
    }

    /// Cleans up assembly data for a recording after successful upload.
    /// - Parameter parentRecordingId: The parent recording ID to clean up
    func cleanupAssembly(for parentRecordingId: UUID) {
        guard let assembly = activeAssemblies[parentRecordingId] else { return }

        // Delete chunk files
        for (_, url) in assembly.chunks {
            try? FileManager.default.removeItem(at: url)
        }

        // Delete recording directory
        let recordingDir = chunksBaseDirectory.appendingPathComponent(parentRecordingId.uuidString, isDirectory: true)
        try? FileManager.default.removeItem(at: recordingDir)

        // Remove from tracking
        activeAssemblies.removeValue(forKey: parentRecordingId)
        persistInventoryToDisk()

        logger.info("[ChunkAssemblyManager] Cleaned up assembly for recording: \(parentRecordingId)")
    }

    // MARK: - Private Methods

    /// Triggers the merge process for a complete recording.
    /// After successful merge, individual chunk files are deleted (only the merged file is kept).
    private func triggerMerge(parentId: UUID) {
        guard var assembly = activeAssemblies[parentId], assembly.isComplete else { return }

        assembly.state = .merging
        activeAssemblies[parentId] = assembly

        // Persist assembling status in Core Data
        if let repo = watchTransferRepository {
            try? repo.markAssembling(parentId)
        }

        let sortedURLs = assembly.sortedChunkURLs
        let totalDuration = assembly.totalDuration
        let startTime = assembly.recordingStartTime

        logger.info("[ChunkAssemblyManager] Starting merge for recording \(parentId) (\(sortedURLs.count) chunks)")

        Task {
            do {
                let mergedURL = try await AudioChunkMerger.merge(
                    chunks: sortedURLs,
                    outputFilename: "recording_\(parentId.uuidString).m4a"
                )

                logger.info("[ChunkAssemblyManager] Merge complete: \(mergedURL.path)")

                // Delete individual chunk files now that we have the merged output
                deleteChunkFiles(for: parentId)

                // Update state
                var updatedAssembly = activeAssemblies[parentId]
                updatedAssembly?.state = .ready(mergedFileURL: mergedURL)
                if let updated = updatedAssembly {
                    activeAssemblies[parentId] = updated
                }
                persistInventoryToDisk()

                // Persist assembled status in Core Data
                if let repo = watchTransferRepository {
                    try? repo.markAssembled(parentId)
                }

                // Notify that recording is ready for upload
                onRecordingAssembled?(parentId, mergedURL, totalDuration, startTime)

            } catch {
                logger.error("[ChunkAssemblyManager] Merge failed for recording \(parentId)", error: error)
                updateAssemblyState(parentId: parentId, state: .failed("Merge failed: \(error.localizedDescription)"))

                // Persist failure in Core Data and increment retry counter
                if let repo = watchTransferRepository {
                    try? repo.markFailed(parentId, error: "Merge failed: \(error.localizedDescription)")
                    try? repo.incrementMergeRetryCount(parentId)
                }
            }
        }
    }

    /// Deletes individual chunk files for a recording while keeping the merged output file.
    /// Called after a successful merge to free disk space.
    private func deleteChunkFiles(for parentId: UUID) {
        guard let assembly = activeAssemblies[parentId] else { return }

        var deletedCount = 0
        for (index, url) in assembly.chunks {
            do {
                try FileManager.default.removeItem(at: url)
                deletedCount += 1
            } catch {
                logger.warning("[ChunkAssemblyManager] Could not delete chunk \(index): \(error.localizedDescription)")
            }
        }

        // Delete the recording's chunk directory (will succeed if all files were removed)
        let recordingDir = chunksBaseDirectory.appendingPathComponent(parentId.uuidString, isDirectory: true)
        try? FileManager.default.removeItem(at: recordingDir)

        logger.info("[ChunkAssemblyManager] Deleted \(deletedCount)/\(assembly.chunks.count) chunk files for recording \(parentId)")
    }

    /// Updates the assembly state for a recording
    private func updateAssemblyState(parentId: UUID, state: AssemblyState) {
        if var assembly = activeAssemblies[parentId] {
            assembly.state = state
            activeAssemblies[parentId] = assembly
        }
    }

    // MARK: - Merge Retry

    /// Retries merge for transfers that previously failed, up to `maxRetries` attempts.
    /// Called on app launch to recover from transient merge errors.
    func retryFailedMerges(maxRetries: Int = 3) {
        guard let repo = watchTransferRepository else { return }

        guard let retryable = try? repo.fetchRetryableMerges(maxRetries: maxRetries), !retryable.isEmpty else { return }

        logger.info("[ChunkAssemblyManager] Found \(retryable.count) failed merge(s) eligible for retry")

        for transfer in retryable {
            guard let recordingId = transfer.id else { continue }

            // The assembly must exist in-memory (restored from disk) for merge to work
            guard let assembly = activeAssemblies[recordingId], assembly.isComplete else {
                logger.warning("[ChunkAssemblyManager] Skipping retry for \(recordingId) — assembly not in memory or incomplete")
                continue
            }

            logger.info("[ChunkAssemblyManager] Retrying merge for \(recordingId) (attempt \(transfer.mergeRetryCount + 1))")
            triggerMerge(parentId: recordingId)
        }
    }

    // MARK: - Persistence

    /// Persists chunk inventory to disk so it survives app kills.
    /// Only stores minimal data (file paths and chunk indices), not file contents.
    private func persistInventoryToDisk() {
        let inventory = activeAssemblies.mapValues { assembly -> [String: Any] in
            var dict: [String: Any] = [
                "chunks": Dictionary(uniqueKeysWithValues: assembly.chunks.map { (String($0.key), $0.value.path) }),
                "totalDuration": assembly.totalDuration
            ]
            if let expected = assembly.totalExpectedChunks {
                dict["totalExpectedChunks"] = expected
            }
            if let startTime = assembly.recordingStartTime {
                dict["recordingStartTime"] = startTime.timeIntervalSince1970
            }
            return dict
        }

        let keyed = inventory.reduce(into: [String: Any]()) { result, pair in
            result[pair.key.uuidString] = pair.value
        }

        do {
            let data = try JSONSerialization.data(withJSONObject: keyed, options: .prettyPrinted)
            try data.write(to: inventoryFileURL, options: .atomic)
            logger.debug("[ChunkAssemblyManager] Inventory persisted to disk")
        } catch {
            logger.error("[ChunkAssemblyManager] Failed to persist inventory", error: error)
        }
    }

    /// Restores chunk inventory from disk after app relaunch.
    private func restoreInventoryFromDisk() {
        guard FileManager.default.fileExists(atPath: inventoryFileURL.path) else { return }

        do {
            let data = try Data(contentsOf: inventoryFileURL)
            guard let keyed = try JSONSerialization.jsonObject(with: data) as? [String: [String: Any]] else { return }

            var restored: [UUID: AssemblyInfo] = [:]

            for (idString, dict) in keyed {
                guard let parentId = UUID(uuidString: idString),
                      let chunksDict = dict["chunks"] as? [String: String] else { continue }

                let totalDuration = dict["totalDuration"] as? TimeInterval ?? 0
                let expectedChunks = dict["totalExpectedChunks"] as? Int
                let startTimestamp = dict["recordingStartTime"] as? TimeInterval
                let startTime = startTimestamp.map { Date(timeIntervalSince1970: $0) }

                // Reconstruct chunks dictionary, verifying files still exist
                var validChunks: [Int: URL] = [:]
                for (indexStr, pathStr) in chunksDict {
                    if let index = Int(indexStr) {
                        let url = URL(fileURLWithPath: pathStr)
                        if FileManager.default.fileExists(atPath: url.path) {
                            validChunks[index] = url
                        }
                    }
                }

                guard !validChunks.isEmpty else { continue }

                let assembly = AssemblyInfo(
                    id: parentId,
                    chunks: validChunks,
                    totalExpectedChunks: expectedChunks,
                    totalDuration: totalDuration,
                    recordingStartTime: startTime,
                    state: .receiving(chunksReceived: validChunks.count, totalExpected: expectedChunks)
                )

                restored[parentId] = assembly

                // If assembly was already complete before app kill, trigger merge
                if assembly.isComplete {
                    logger.info("[ChunkAssemblyManager] Restored complete assembly for \(parentId) -- triggering merge")
                }
            }

            activeAssemblies = restored

            if !restored.isEmpty {
                logger.info("[ChunkAssemblyManager] Restored \(restored.count) assembly(ies) from disk")
                // NOTE: Do NOT trigger merge here. The onRecordingAssembled callback
                // hasn't been set yet (set by WatchRecordingService.configure).
                // Call processRestoredAssemblies() after the callback is wired up.
            }

        } catch {
            logger.error("[ChunkAssemblyManager] Failed to restore inventory from disk", error: error)
        }
    }
}

