import Foundation
import WatchConnectivity
import Combine

final class WatchConnectivityManager: NSObject, ObservableObject {

    static let shared = WatchConnectivityManager()

    /// Logger instance for connectivity-related logging
    private let logger = LoggerFactory.makeLogger()

    @Published private(set) var isSupported: Bool = WCSession.isSupported()
    @Published private(set) var activationState: WCSessionActivationState = .notActivated
    @Published public private(set) var isReachable: Bool = false
    @Published private(set) var receivedMessage: [String: Any]? = nil
    @Published private(set) var lastContext: [String: Any]? = nil
    @Published private(set) var lastError: Error? = nil

    /// Clears the last error. Call this when operations succeed to prevent stale error state.
    func clearLastError() {
        DispatchQueue.main.async {
            self.lastError = nil
        }
    }
    @Published public private(set) var isWatchConnected: Bool = false
    @Published public private(set) var isPaired: Bool = false
    @Published public private(set) var isWatchAppInstalled: Bool = false

    // Recording transfer state tracking - per-recording (no global state to support concurrent transfers)
    @Published public private(set) var lastTransferredRecordingId: UUID? = nil

    // MARK: - Constants

    /// Maximum progress increment per KVO update (5%) to smooth out progress jumps
    /// Prevents jarring UI updates when progress jumps forward rapidly
    private static let maxProgressIncrement: Double = 0.05

    /// Delay in seconds before auto-removing completed transfers from UI
    /// Gives users time to see the completion state before it disappears
    private static let completedTransferAutoRemoveDelay: TimeInterval = 3.0

    #if os(watchOS)
    // Transfer progress per recording ID (0.0 to 1.0)
    // CRITICAL: @Published properties must be accessed on main thread
    // All mutations happen on main thread via DispatchQueue.main.async
    @Published private(set) var recordingTransferProgress: [UUID: Double] = [:]

    /// Cached aggregate transfer state (updated when progress changes)
    /// Avoids deadlock risk from DispatchQueue.main.sync
    @Published public private(set) var cachedAggregateTransferState: RecordingTransferState = .idle

    /// Internal helper to compute aggregate state (must be called on main thread)
    private func computeAggregateState() -> RecordingTransferState {
        assert(Thread.isMainThread, "computeAggregateState must be called on main thread")

        if recordingTransferProgress.isEmpty {
            return .idle
        }

        // Find max progress and any failures
        let progressValues = recordingTransferProgress.values
        if let maxProgress = progressValues.max() {
            if maxProgress >= 1.0 && progressValues.allSatisfy({ $0 >= 1.0 }) {
                return .completed
            }
            return .transferring(progress: maxProgress)
        }

        return .idle
    }
    #endif

    #if os(iOS)
    /// Whether the Watch has granted microphone permission (synced via application context)
    /// `nil` means we haven't received the status from the Watch yet
    @Published public private(set) var watchMicrophonePermissionGranted: Bool? = nil

    /// True when the Watch has started recording and has not yet stopped (iPhone shows Live Activity / banner).
    @Published public private(set) var isRecordingOnWatch: Bool = false

    /// When recording started on Watch (for elapsed time in Live Activity). Nil when not recording.
    @Published public private(set) var recordingStartedAt: Date? = nil

    /// True when `isRecordingOnWatch` was set from cached activation context (potentially stale).
    /// Observers should treat this as unconfirmed and avoid side-effects like notifications
    /// until fresh context arrives (at which point this becomes `false`).
    @Published public private(set) var isRecordingStateFromActivation: Bool = false

    /// Sentinel UUID for placeholder pending transfers (never maps to real recordings)
    /// Public so WatchRecordingService can filter it out from UI
    public static let pendingPlaceholderID = UUID(uuidString: "00000000-0000-0000-0000-000000000001")!

    /// State tracking for incoming transfers from watch (per-recording)
    /// Tracks state transitions and progress for real-time updates
    public enum IncomingTransferState: Equatable {
        case pending          // Transfer announced but not started (hasContentPending = true)
        case receiving(progress: Double?)  // File is being received (with optional progress 0.0-1.0)
        case completed        // Transfer complete and saved
        case failed(String)   // Transfer failed with error message

        public static func == (lhs: IncomingTransferState, rhs: IncomingTransferState) -> Bool {
            switch (lhs, rhs) {
            case (.pending, .pending), (.completed, .completed):
                return true
            case (.receiving(let lhsProgress), .receiving(let rhsProgress)):
                // Compare progress values (with small tolerance for floating point)
                if let lhs = lhsProgress, let rhs = rhsProgress {
                    return abs(lhs - rhs) < 0.001
                }
                return lhsProgress == nil && rhsProgress == nil
            case (.failed(let lhsError), .failed(let rhsError)):
                return lhsError == rhsError
            default:
                return false
            }
        }
    }

    // Track incoming transfers from watch (per-recording progress state)
    // CRITICAL: @Published properties must be accessed on main thread
    @Published public private(set) var incomingTransferProgress: [UUID: IncomingTransferState] = [:]

    /// Last timestamp when incoming progress changed for a recording.
    /// Used to detect stale "stuck at X%" progress entries coming from cached context.
    private var incomingProgressLastChangeAt: [UUID: Date] = [:]

    /// Last known incoming progress value per recording.
    private var incomingProgressLastValue: [UUID: Double] = [:]

    /// Recordings whose stale progress has been timed out and should not be re-added
    /// from repeated cached context updates unless progress meaningfully changes.
    private var suppressedStaleIncomingProgressIds: Set<UUID> = []

    /// Shared timeout policy (3 minutes per 30 minutes of recording duration).
    private let transferTimeoutPolicy = TransferTimeoutPolicy.default

    /// Cached aggregate state of all incoming transfers (updated when state changes)
    /// Avoids deadlock risk from DispatchQueue.main.sync
    @Published public private(set) var cachedAggregateIncomingTransferState: RecordingTransferState = .idle

    /// Internal helper to compute aggregate incoming transfer state (must be called on main thread)
    private func computeAggregateIncomingState() -> RecordingTransferState {
        assert(Thread.isMainThread, "computeAggregateIncomingState must be called on main thread")

        // Filter out placeholder UUID (sentinel value)
        let realTransfers = incomingTransferProgress.filter { $0.key != Self.pendingPlaceholderID }

        if realTransfers.isEmpty {
            return .idle
        }

        // Check for any failures
        for state in realTransfers.values {
            if case .failed(let error) = state {
                return .failed(error)
            }
        }

        // Check if all are completed
        let allCompleted = realTransfers.values.allSatisfy { state in
            if case .completed = state {
                return true
            }
            return false
        }

        if allCompleted {
            return .completed
        }

        // Find max progress from receiving transfers
        var maxProgress: Double = 0.0
        var hasActive = false

        for state in realTransfers.values {
            if case .pending = state {
                hasActive = true
            } else if case .receiving(let progress) = state {
                hasActive = true
                if let progress = progress {
                    maxProgress = max(maxProgress, progress)
                }
            }
        }

        if hasActive {
            // Use actual progress if available, otherwise use 0.5 as placeholder
            let displayProgress = maxProgress > 0 ? maxProgress : 0.5
            return .transferring(progress: displayProgress)
        }

        return .idle
    }

