/// Service responsible for handling recordings received from Apple Watch.
/// Automatically submits received recordings to the transcription service.
/// Should be initialized early in the app lifecycle to ensure recordings are captured.
///
/// Flow:
/// 1. Watch records audio → transfers to iOS
/// 2. WatchRecordingService receives file via WatchConnectivityManager
/// 3. File is saved to local storage
/// 4. Recording is automatically submitted for transcription
/// 5. Confirmation sent back to watch to delete local copy
@MainActor
final class WatchRecordingService: ObservableObject {

    // MARK: - Singleton

    static let shared = WatchRecordingService()

    // MARK: - Published Properties

    /// Number of recordings received from watch in current session
    @Published private(set) var recordingsReceivedCount: Int = 0

    /// Last received recording (if any)
    @Published private(set) var lastReceivedRecording: Recording? = nil

    /// Indicates if the service is currently processing a received file
    @Published private(set) var isProcessingTransfer: Bool = false

    /// Indicates if there are pending files from when app was terminated
    @Published private(set) var hasPendingFiles: Bool = false

    /// Information about incoming transfers from watch (per-recording)
    @Published private(set) var incomingTransfers: [UUID: IncomingTransferInfo] = [:]

    // MARK: - Incoming Transfer Info

    /// Information about an incoming transfer from watch
    struct IncomingTransferInfo: Identifiable {
        let id: UUID
        let metadata: RecordingTransferMetadata?
        var state: WatchConnectivityManager.IncomingTransferState
        var progress: Double?  // Optional - can be nil for indeterminate progress
        var uploadId: UUID?  // Track associated upload
        var uploadProgress: Double?  // Upload progress (0.0 to 1.0)

        // MARK: - Chunk-Aware Fields

        /// Number of chunks received so far (nil for single-file transfers)
        var chunksReceived: Int?

        /// Total expected chunks (nil if last chunk not yet received, or single-file)
        var totalExpectedChunks: Int?

        /// True if the recording is currently being merged from chunks
        var isMerging: Bool = false

        /// Last time progress was updated (for stalled transfer detection)
        var lastProgressUpdateTime: Date?

        // MARK: - Computed Properties

        var isUploading: Bool {
            return uploadId != nil && uploadProgress != nil && uploadProgress! < 1.0
        }

        /// True if this transfer appears stalled (no progress update in 2+ minutes).
        /// Shown as a visual warning in the UI before the 5-minute hard timeout kicks in.
        var isStalled: Bool {
            guard let lastUpdate = lastProgressUpdateTime else { return false }
            return Date().timeIntervalSince(lastUpdate) > 120
        }

        /// Human-readable chunk progress (e.g., "2 of 3 parts received")
        var chunkProgressText: String? {
            guard let received = chunksReceived else { return nil }
            if let total = totalExpectedChunks {
                return "\(received) of \(total) parts received"
            } else {
                return "\(received) part(s) received"
            }
        }

        /// Total recording duration from chunk metadata (shows accumulated duration, not per-chunk)
        var totalRecordingDuration: TimeInterval? {
            return metadata?.chunkInfo?.totalDurationSoFar ?? metadata?.duration
        }

        init(id: UUID, metadata: RecordingTransferMetadata? = nil, state: WatchConnectivityManager.IncomingTransferState, uploadId: UUID? = nil, uploadProgress: Double? = nil, lastProgressUpdateTime: Date = Date()) {
            self.id = id
            self.metadata = metadata
            self.state = state
            self.uploadId = uploadId
            self.uploadProgress = uploadProgress
            self.lastProgressUpdateTime = lastProgressUpdateTime
            // Extract progress from state
            switch state {
            case .pending:
                self.progress = nil // Indeterminate
            case .receiving(let progress):
                self.progress = progress // Use progress from watch if available
            case .completed:
                self.progress = 1.0 // 100%
            case .failed:
                self.progress = nil // No progress on failure
            }
        }
    }

    // MARK: - Private Properties

    private let connectivityManager = WatchConnectivityManager.shared
    private var repository: LocalRecordingRepository?
    private var locationManager: LocationManager?
    private var createMeetingFromAudioUseCase: CreateMeetingFromAudioUseCase?
    private var metadataRepository: RecordingMetadataRepository?
    private let notificationService = NotificationService.shared
    private let liveActivityManager = TransferLiveActivityManager.shared
    private let recordingLiveActivityManager = RecordingLiveActivityManager.shared
    private var cancellables = Set<AnyCancellable>()

    /// True when we already showed "recording started" for the current session (avoid duplicate notifications).
    private var didNotifyRecordingStartedThisSession = false

    /// Queue of recording IDs that have been successfully saved (pending confirmation to watch)
    private var pendingConfirmations: [UUID] = []

    /// Flag to track if we've already checked for pending files on this launch
    private var hasCheckedPendingFiles: Bool = false

    /// Whether automatic upload and meeting creation is enabled
    private var autoUploadEnabled: Bool = true

    /// Tracks which recordings already triggered a completion notification to avoid duplicates
    private var notifiedRecordingIds: Set<UUID> = []

    /// Mapping from upload ID to recording ID for tracking upload progress
    private var uploadIdToRecordingId: [UUID: UUID] = [:]

    /// Cancellable for observing upload progress
    private var uploadProgressCancellable: AnyCancellable?

    /// Dispatch queue for thread-safe notification idempotency checks
    private let notificationQueue = DispatchQueue(label: "com.memorable.watchRecordingService.notificationIds")

    /// Core Data repository tracking the full incoming-transfer lifecycle.
    /// Replaces the old in-memory `processedChunkKeys` set with persisted dedup
    /// and gives `ChunkAssemblyManager` a durable chunk inventory.
    private var watchTransferRepository: WatchTransferRepository?

    /// Lightweight in-memory dedup for the window between init and configure(),
    /// when watchTransferRepository is still nil. WCM fires both a callback and a
    /// notification for each file, so without this the same file could be processed
    /// twice before Core Data dedup is available.
    private var preConfigureDeliveryKeys: Set<String> = []

    /// Tracks last sent upload progress percentage per recording to avoid missing intermediate values
    private var lastSentUploadProgress: [UUID: Int] = [:]

    /// Timer that periodically checks for transfers stuck without progress updates
    private var stallCheckTimer: Timer?

    /// Shared timeout policy (3 minutes per 30 minutes of recording duration).
    private let transferTimeoutPolicy = TransferTimeoutPolicy.default

    /// Local notification sender for timeout failures.
    private let transferFailureNotificationService = TransferFailureNotificationService.shared

    // NOTE: UIBackgroundTask management was removed in favor of BackgroundUploadManager
    // which uses a background URLSession that survives app termination.
    // If an upload is interrupted, RecordingRetryService picks it up on next launch.

    // MARK: - Logging

    private let logPrefix = "📱🎙️ [WatchRecordingService]"
    private let logger = LoggerFactory.makeLogger()

    // MARK: - Initialization

    private init() {
        setupRepository()
        setupRecordingReceptionCallback()
        setupActivationStateObserver()
        setupIncomingTransferObserver()

}
#endif

/// Updates cached aggregate states on main thread (called when progress/state changes)
/// Available on both watchOS and iOS - updates platform-specific cached state
private func updateCachedAggregateStates() {
    DispatchQueue.main.async { [weak self] in
        guard let self = self else { return }
        #if os(watchOS)
        self.cachedAggregateTransferState = self.computeAggregateState()
        #else
        self.cachedAggregateIncomingTransferState = self.computeAggregateIncomingState()
        #endif
    }
}

// Callback for when a recording transfer completes (used by watchOS to delete local copy)
public var onTransferComplete: ((UUID, Bool) -> Void)?

// Callback for when iOS receives a recording file
// Uses Result type to propagate errors (e.g., file copy failures)
public var onRecordingReceived: ((Result<(URL, RecordingTransferMetadata), Error>) -> Void)?

// Cached application context (thread-safe, updated on main thread)
// Used instead of reading session.receivedApplicationContext directly from background threads
@Published private var cachedApplicationContext: [String: Any] = [:]

/// Thread-safe access to cached application context
/// CRITICAL: Must be accessed from main thread only to avoid deadlocks
/// @Published properties are main-thread only, so this getter enforces that requirement
var applicationContext: [String: Any] {
    dispatchPrecondition(condition: .onQueue(.main))
    return cachedApplicationContext
}

/// Safely retrieves cached application context, ensuring main thread access
/// This method should only be called from contexts where you can guarantee main thread execution
/// or where async dispatch is acceptable. For synchronous access from main thread, use applicationContext property directly.
/// - Returns: The cached application context, or lastContext if cached is empty
private func getCachedApplicationContextSafely() -> [String: Any] {
    dispatchPrecondition(condition: .onQueue(.main))
    let context = cachedApplicationContext
    return context.isEmpty ? (lastContext ?? [:]) : context
}

private let session: WCSession?
private let watchConnectivityQueue = DispatchQueue(label: "com.memorable.watchconnectivity")

// Thread-safe queue for transfer state management
// All access to pendingTransfers, progressObservers, and recordingTransferProgress must go through this queue
private let transferStateQueue = DispatchQueue(
    label: "com.memorable.watchconnectivity.transferstate",
    qos: .userInitiated
)

// Pending file transfers keyed by recording ID (watchOS only, single-file transfers)
// All access must be through transferStateQueue
private var pendingTransfers: [UUID: WCSessionFileTransfer] = [:]

#if os(watchOS)
// KVO observers for progress tracking keyed by recording ID (single-file transfers)
// All access must be through transferStateQueue
private var progressObservers: [UUID: NSKeyValueObservation] = [:]

// MARK: - Multi-Chunk Transfer Tracking
// Parallel tracking system for chunked recordings. Each chunk has its own
// WCSessionFileTransfer, keyed by ObjectIdentifier for precise matching.

/// Maps each chunk's WCSessionFileTransfer to its parent recording + chunk index
private var chunkTransfers: [ObjectIdentifier: (recordingId: UUID, chunkIndex: Int)] = [:]

/// Total expected chunk count per recording (set when isLastChunk is seen)
private var recordingChunkCounts: [UUID: Int] = [:]

/// Chunk indices that have been successfully delivered per recording
private var recordingCompletedChunks: [UUID: Set<Int>] = [:]

/// Current progress (0.0–1.0) for each chunk, used to compute aggregate progress
private var chunkProgressValues: [UUID: [Int: Double]] = [:]

/// Per-chunk KVO observers (keyed by ObjectIdentifier of the transfer)
private var chunkProgressObservers: [ObjectIdentifier: NSKeyValueObservation] = [:]

// Reference to repository for Core Data updates (watchOS)
private var repository: LocalRecordingRepository?

/// Set of processed confirmation keys (`recordingId|phase`) for idempotency.
/// This lets us process both `received` and `processed` confirmations exactly once.
private var processedConfirmationKeys = Set<String>()

/// Sets the repository for Core Data status updates (watchOS only)
/// Call this during watch app initialization
func setRepository(_ repo: LocalRecordingRepository) {
    self.repository = repo
}

/// Clears the processed confirmations set (call on logout or when starting fresh)
/// This allows re-processing of confirmations after a fresh start
func clearProcessedConfirmations() {
    processedConfirmationKeys.removeAll()
    logger.info("[WatchConnectivity] Cleared processed confirmations set")
}
#endif

#if os(iOS)
// Reference to metadata repository for duplicate detection (iOS)
private var metadataRepository: RecordingMetadataRepository?

/// Sets the metadata repository for duplicate detection (iOS only)
/// Call this during iOS app initialization
func setMetadataRepository(_ repo: RecordingMetadataRepository) {
    self.metadataRepository = repo
}
