private override init() {
    guard WCSession.isSupported() else {
        session = nil
        super.init()
        return
    }

    session = WCSession.default
    super.init()

    session?.delegate = self
    session?.activate()

    // Initialize cached context if session is already activated
    if let session = session, session.activationState == .activated {
        DispatchQueue.main.async { [weak self] in
            self?.cachedApplicationContext = session.receivedApplicationContext
            self?.lastContext = session.receivedApplicationContext
        }
    }
}

deinit {
    #if os(watchOS)
    // Clean up all KVO observers
    transferStateQueue.sync {
        for observer in progressObservers.values {
            observer.invalidate()
        }
        progressObservers.removeAll()

        for observer in chunkProgressObservers.values {
            observer.invalidate()
        }
        chunkProgressObservers.removeAll()
        chunkTransfers.removeAll()
        recordingChunkCounts.removeAll()
        recordingCompletedChunks.removeAll()
        chunkProgressValues.removeAll()
    }
    #endif
}

/// Flag to track if we've done initial status logging (to avoid duplicate logs)
private var hasLoggedInitialStatus: Bool = false

/// Updates connection status from session properties.
/// NOTE: Must be called from main thread (already dispatched in call sites).
/// WCSession properties are accessed on main thread as per Apple's documentation.
private func updateConnectionStatus() {
    dispatchPrecondition(condition: .onQueue(.main))

    guard let session = self.session else { return }

        // Read all session properties on main queue (they're UI-related)
        #if os(iOS)
        self.isPaired = session.isPaired
        self.isWatchAppInstalled = session.isWatchAppInstalled
        self.isWatchConnected = session.isPaired && session.isWatchAppInstalled

    // Check for pending content - files being transferred from watch
    // Note: We can't get specific metadata until files arrive, so we show generic "pending" state
    // Store placeholder UUID in a property to track it
    let placeholderId = Self.pendingPlaceholderID
    let hasRealTransfers = incomingTransferProgress.keys.contains { $0 != placeholderId }

    if session.hasContentPending {
        // There are pending files but we don't know which recordings yet
        // We'll update to specific states when files arrive in session(_:didReceive:)
        // Check if we already have a pending placeholder
        let hasPendingPlaceholder = incomingTransferProgress[placeholderId] != nil

        // Only add placeholder if:
        // 1. We don't already have one
        // 2. We have no real transfers (only add if truly empty)
        if !hasPendingPlaceholder && !hasRealTransfers {
            incomingTransferProgress[placeholderId] = .pending
            updateCachedAggregateStates()
            logger.debug("[WatchConnectivity] Added placeholder for pending content")
        } else if hasPendingPlaceholder && hasRealTransfers {
            // We have real transfers now, remove placeholder
            incomingTransferProgress.removeValue(forKey: placeholderId)
            updateCachedAggregateStates()
            logger.debug("[WatchConnectivity] Removed placeholder - real transfers exist")
        }

    setupIncomingTransferObserver()
    setupUploadProgressObserver()
    setupRecordingOnWatchObserver()
    setupTransferCoordinationObservers()
    setupStallDetectionTimer()
    // Log Live Activities diagnostics
    liveActivityManager.printDiagnostics()

}

/// Sets up observer for upload progress updates.
/// Throttled to avoid flooding ActivityKit with updates (it rate-limits at ~1/sec).
private func setupUploadProgressObserver() {
    uploadProgressCancellable = UploadManager.shared.$activeUploads
        .throttle(for: .seconds(1.0), scheduler: DispatchQueue.main, latest: true)
        .receive(on: DispatchQueue.main)
        .sink { [weak self] uploads in
            guard let self = self else { return }


            for (uploadId, uploadProgress) in uploads {
                log("   Upload \(uploadId): \(Int(uploadProgress.progress * 100))% - \(uploadProgress.status)")

                guard let recordingId = self.uploadIdToRecordingId[uploadId] else {
                    log("   ⚠️ No recording mapped to upload ID: \(uploadId)")
                    continue
                }

                log("   ✅ Linked to recording: \(recordingId)")

                if var transfer = self.incomingTransfers[recordingId] {
                    transfer.uploadId = uploadId
                    transfer.uploadProgress = uploadProgress.progress
                    self.incomingTransfers[recordingId] = transfer
                    log("   ✅ Updated transfer info with progress: \(Int(uploadProgress.progress * 100))%")

                    self.updateLiveActivityForTransfer(
                        recordingId: recordingId,
                        transferInfo: transfer
                    )
                } else {
                    // Transfer was dropped (e.g., incoming transfer observer rebuilt the dict
                    // before upload progress was set). Re-create so cloud upload stays visible.
                    log("   ⚠️ Re-creating transfer for recording: \(recordingId)")
                    let metadata = self.connectivityManager.getTransferMetadata(for: recordingId)
                    let recreated = IncomingTransferInfo(
                        id: recordingId,
                        metadata: metadata,
                        state: .completed,
                        uploadId: uploadId,
                        uploadProgress: uploadProgress.progress
                    )
                    self.incomingTransfers[recordingId] = recreated

                    self.updateLiveActivityForTransfer(
                        recordingId: recordingId,
                        transferInfo: recreated
                    )
                    log("   ✅ Re-created transfer with upload progress: \(Int(uploadProgress.progress * 100))%")
                }

                // Sync upload progress to watch (throttle to every 10%)
                let progress = uploadProgress.progress
                let progressPercent = Int(progress * 100)
                let lastSent = self.lastSentUploadProgress[recordingId] ?? -1

                if progressPercent >= lastSent + 10 || progress >= 1.0 {
                    WatchStatusSync().sendStatusToWatch(
                        recordingId: recordingId,
                        status: .uploading,
                        uploadProgress: progress
                    )
                    self.lastSentUploadProgress[recordingId] = progressPercent
                    log("   📤 Sent progress update to watch: \(progressPercent)%")

                    if progress >= 1.0 {
                        log("   ✅ Upload reached 100% for recording: \(recordingId)")
                    }
                }
            }
        }
}

// MARK: - Configuration

/// Configures dependencies for automatic upload and meeting creation.
/// Call this after AppContainer is set up.
/// - Parameters:
///   - locationManager: The LocationManager for getting location data
///   - createMeetingFromAudioUseCase: The use case for creating meetings from audio files
///   - metadataRepository: The repository for recording metadata persistence
func configure(
    locationManager: LocationManager,
    createMeetingFromAudioUseCase: CreateMeetingFromAudioUseCase,
    metadataRepository: RecordingMetadataRepository,
    watchTransferRepository: WatchTransferRepository
) {

    self.locationManager = locationManager
    self.createMeetingFromAudioUseCase = createMeetingFromAudioUseCase
    self.metadataRepository = metadataRepository
    self.watchTransferRepository = watchTransferRepository

    // Clear pre-configure fallback dedup cache once durable Core Data dedup is ready.
    // Keeping these keys beyond startup can incorrectly block legitimate retries.
    preConfigureDeliveryKeys.removeAll()

    // Share the repository with the chunk assembly manager
    ChunkAssemblyManager.shared.setWatchTransferRepository(watchTransferRepository)

    // Configure chunk assembly manager to route merged recordings into the upload pipeline.
    // IMPORTANT: callback must be set BEFORE processRestoredAssemblies() to avoid
    // merged files being produced but never handed off to the upload pipeline.
    setupChunkAssemblyCallback()

    // Now that the callback is wired, process any assemblies that were complete before app kill
    ChunkAssemblyManager.shared.processRestoredAssemblies()

    // Clean up completed transfers older than 24 hours
    try? watchTransferRepository.deleteCompleted(olderThan: Date().addingTimeInterval(-86400))
}

// MARK: - Chunk Assembly Integration

/// Sets up the callback for when ChunkAssemblyManager finishes merging a recording.
/// The merged file is treated like a single-file recording from this point forward:
/// saved to permanent storage, metadata updated, and uploaded.
private func setupChunkAssemblyCallback() {
    ChunkAssemblyManager.shared.onRecordingAssembled = { [weak self] parentRecordingId, mergedFileURL, totalDuration, recordingStartTime in
        guard let self = self else { return }

        self.logger.info("[WatchRecordingService] Assembled recording ready: \(parentRecordingId)")
        self.logger.info("[WatchRecordingService] Merged file: \(mergedFileURL.path), duration: \(totalDuration)s")

        // Build metadata for the assembled recording
        let assembledMetadata = RecordingTransferMetadata(
            id: parentRecordingId,
            filename: mergedFileURL.lastPathComponent,
            duration: totalDuration,
            createdAt: Date(),
            startTime: recordingStartTime ?? Date()
        )

        // Process like a single-file recording (save, upload, confirm)
        self.handleAssembledRecording(fileURL: mergedFileURL, metadata: assembledMetadata)
    }

    logger.info("[WatchRecordingService] ChunkAssemblyManager callback configured")
}

/// Handles a fully assembled (merged) recording from the chunk pipeline.
/// This mirrors the single-file flow: save to permanent storage, upload, confirm.
/// - Parameters:
///   - fileURL: The merged file URL
///   - metadata: Metadata for the assembled recording
private func handleAssembledRecording(fileURL: URL, metadata: RecordingTransferMetadata) {
    log("═══════════════════════════════════════════════════")
    log("📥 ASSEMBLED RECORDING READY FOR UPLOAD")
    log("═══════════════════════════════════════════════════")
    log("Recording ID: \(metadata.id)")
    log("Duration: \(String(format: "%.2f", metadata.duration))s")

    guard let repository = repository else {
        logError("❌ Repository not initialized for assembled recording!", error: nil)
        return
    }

    do {
        // Save to permanent storage (same as single-file flow)
        let savedRecording = try repository.saveRecordingFromWatch(
            sourceURL: fileURL,
            id: metadata.id,
            filename: metadata.filename,
            duration: metadata.duration,
            createdAt: metadata.createdAt,
            startTime: metadata.startTime
        )

        // Create/update metadata
        if let metadataRepo = metadataRepository {
            do {
                if try metadataRepo.fetchById(metadata.id) == nil {
                    _ = try metadataRepo.create(recordingId: metadata.id, filePath: savedRecording.fileURL.path)
                }
                try metadataRepo.updateFilePath(metadata.id, filePath: savedRecording.fileURL.path)
                try metadataRepo.updateStatus(metadata.id, status: .received, error: nil)
                try? repository.updateStatus(metadata.id, status: .received, error: nil)
            } catch {
                logError("⚠️ Failed to update metadata for assembled recording", error: error)
            }
        }

        recordingsReceivedCount += 1
        lastReceivedRecording = savedRecording

        // Mark the chunked transfer as completed in the connectivity manager.
        // Without this, the observer in setupIncomingTransferObserver() would overwrite
        // our local .completed state back to .receiving (since WCM never transitions
        // chunked transfers to .completed on its own).
        connectivityManager.markIncomingTransferCompleted(recordingId: metadata.id)


        // Update transfer info to completed.
        // Set uploadProgress to 0.0 so the incoming-transfer observer's merge logic
        // keeps this entry alive while the cloud upload is pending.
        let completedTransfer = IncomingTransferInfo(
            id: metadata.id,
            metadata: metadata,
            state: .completed,
            uploadId: nil,
            uploadProgress: 0.0
        )
        incomingTransfers[metadata.id] = completedTransfer

        // Mark WatchTransfer as completed in Core Data
        if let repo = watchTransferRepository {
            try? repo.markCompleted(metadata.id)
        }

        // Send confirmation to watch (for the ENTIRE recording, not per-chunk)
        // The Watch will only delete its local chunks after this full-recording confirmation
        pendingConfirmations.append(metadata.id)
        sendConfirmationToWatch()

        // Upload and create meeting
        uploadAndCreateMeeting(recording: savedRecording)

        log("✅ ASSEMBLED RECORDING PROCESSED SUCCESSFULLY")

        // Clean up chunk assembly data (chunks files on disk)
        ChunkAssemblyManager.shared.cleanupAssembly(for: metadata.id)

        // Auto-remove the transfer card from UI after a brief display period.
        // The transfer itself is complete (confirmed to Watch). The ongoing upload
        // status is tracked via RecordingMetadata in the recordings list.
        let assembledId = metadata.id
        DispatchQueue.main.asyncAfter(deadline: .now() + 3.0) { [weak self] in
            guard let self = self else { return }
            if let transfer = self.incomingTransfers[assembledId],
               case .completed = transfer.state {
                self.incomingTransfers.removeValue(forKey: assembledId)
                self.connectivityManager.removeIncomingTransfer(recordingId: assembledId)
                self.log("🧹 Auto-removed assembled transfer from UI: \(assembledId)")
            }
        }

    } catch {
        logError("❌ Failed to save assembled recording", error: error)
    }
}

/// Enables or disables automatic upload and meeting creation of received recordings
/// - Parameter enabled: Whether to automatically upload recordings
func setAutoUpload(enabled: Bool) {
    autoUploadEnabled = enabled
    log("Auto-upload \(enabled ? "enabled" : "disabled")")
}

