/// Sets up observer for incoming transfer progress from WatchConnectivityManager
private func setupIncomingTransferObserver() {
    log("Setting up incoming transfer progress observer...")

    // Observe incoming transfer progress changes
    connectivityManager.$incomingTransferProgress
        .receive(on: DispatchQueue.main)
        .sink { [weak self] progressDict in
            guard let self = self else { return }

            // Update our incoming transfers based on connectivity manager state
            var updatedTransfers: [UUID: IncomingTransferInfo] = [:]

            // Filter out placeholder ID (should never appear in UI)
            let placeholderId = WatchConnectivityManager.pendingPlaceholderID

            for (recordingId, state) in progressDict {
                // Skip placeholder - it should be filtered out
                if recordingId == placeholderId {
                    continue
                }

                // Get existing transfer info if available
                var transferInfo = self.incomingTransfers[recordingId]

                // If we don't have metadata yet, try to get it from context
                var metadata = transferInfo?.metadata
                if metadata == nil {
                    // Try to get metadata from context (sent by watch when transfer starts)
                    metadata = self.connectivityManager.getTransferMetadata(for: recordingId)
                }

                if transferInfo == nil {
                    // NEW TRANSFER DETECTED - Track in-memory only (no DB entry yet)
                    // RecordingMetadata will be created when the actual file is received
                    transferInfo = IncomingTransferInfo(id: recordingId, metadata: metadata, state: state)

                    // Start Live Activity for new transfer
                    if self.liveActivityManager.startActivity(for: recordingId, metadata: metadata) {
                        self.log("✅ Started Live Activity for recording: \(recordingId)")
                    }
                } else {
                    // Only reset lastProgressUpdateTime if the state actually changed.
                    // This is critical for accurate stall detection — if the publisher
                    // re-emits the same state, we must keep the original timestamp.
                    let stateChanged = transferInfo!.state != state
                    let preservedTimestamp = stateChanged
                        ? Date()
                        : (transferInfo!.lastProgressUpdateTime ?? Date())

                    transferInfo = IncomingTransferInfo(
                        id: recordingId,
                        metadata: metadata ?? transferInfo!.metadata,
                        state: state,
                        uploadId: transferInfo!.uploadId,
                        uploadProgress: transferInfo!.uploadProgress,
                        lastProgressUpdateTime: preservedTimestamp
                    )
                }

                updatedTransfers[recordingId] = transferInfo

                // Update Live Activity with current transfer progress
                // transferInfo is guaranteed to be non-nil after the if-else block above
                if let transferInfo = transferInfo {
                    self.updateLiveActivityForTransfer(
                        recordingId: recordingId,
                        transferInfo: transferInfo
                    )
                }
            }

            // Always update to match the connectivity manager state (removes deleted transfers)
            // But preserve any upload tracking info for transfers not in the update
            let previousCount = self.incomingTransfers.count

            // Preserve transfers that are no longer in the connectivity manager's progress dict
            // but are still relevant (uploading to cloud or waiting for upload to start).
            for (recordingId, existingTransfer) in self.incomingTransfers {
                guard updatedTransfers[recordingId] == nil else { continue }

                let shouldPreserve: Bool
                if case .completed = existingTransfer.state {
                    // Keep completed transfers unless upload is fully done (progress >= 1.0).
                    // This covers: upload pending (nil), upload starting (0.0), upload in-flight (0.x).
                    if let progress = existingTransfer.uploadProgress, progress >= 1.0 {
                        shouldPreserve = false
                    } else {
                        shouldPreserve = true
                    }
                } else if let uploadProgress = existingTransfer.uploadProgress, uploadProgress < 1.0 {
                    shouldPreserve = true
                } else {
                    shouldPreserve = false
                }

                if shouldPreserve {
                    updatedTransfers[recordingId] = existingTransfer
                }
            }

            self.incomingTransfers = updatedTransfers
            let newCount = updatedTransfers.count

            if previousCount != newCount {
                log("📊 Transfer count changed: \(previousCount) -> \(newCount)")
            }

            // Log state changes
            if !updatedTransfers.isEmpty {
                let transfers = Array(updatedTransfers.values)
                let pendingCount = transfers.filter { if case .pending = $0.state { return true }; return false }.count
                let receivingCount = transfers.filter { if case .receiving = $0.state { return true }; return false }.count
                let completedCount = transfers.filter { if case .completed = $0.state { return true }; return false }.count
                let failedCount = transfers.filter { if case .failed = $0.state { return true }; return false }.count

                if pendingCount > 0 || receivingCount > 0 {
                    log("📊 Incoming transfers - Pending: \(pendingCount), Receiving: \(receivingCount), Completed: \(completedCount), Failed: \(failedCount)")
                }
            } else if previousCount > 0 {
                log("📊 All transfers cleared from UI")
            }
        }
        .store(in: &cancellables)

    log("✅ Incoming transfer progress observer configured")
}

/// Sets up observer for recording-on-Watch indicator (Guideline 2.5.14).
/// Starts Recording Live Activity and sends local notification when Watch starts recording;
/// ends Live Activity when Watch stops recording.
///
/// Includes `isRecordingStateFromActivation` in the combine pipeline so that notifications
/// are only sent when the recording state has been confirmed by fresh context from the Watch
/// (not from potentially stale cached context read during session activation).
private func setupRecordingOnWatchObserver() {
    connectivityManager.$isRecordingOnWatch
        .combineLatest(
            connectivityManager.$recordingStartedAt,
            connectivityManager.$isRecordingStateFromActivation
        )
        .receive(on: DispatchQueue.main)
        .sink { [weak self] isRecording, startedAt, isFromActivation in
            guard let self = self else { return }
            log("📡 isRecordingOnWatch=\(isRecording), startedAt=\(String(describing: startedAt)), fromActivation=\(isFromActivation)")
            if isRecording {
                let started = startedAt ?? Date()
                if recordingLiveActivityManager.startRecordingActivity(startedAt: started) {
                    log("✅ Started Recording Live Activity (recording on Watch)")
                } else {
                    log("⚠️ Recording Live Activity did not start — check Settings > Memorable > Live Activities is ON, and iOS 18+")
                }
                // Only send notification when the state is confirmed by fresh context.
                // Activation context may be stale (Watch sent isRecording=false while iPhone was not running),
                // so we wait for the Watch to re-confirm via a fresh application context update.
                if isFromActivation {
                    log("⏳ Recording state from activation context — deferring notification until confirmed by Watch")
                } else if !didNotifyRecordingStartedThisSession {
                    didNotifyRecordingStartedThisSession = true
                    Task {
                        let sent = await self.notificationService.notifyRecordingStartedOnWatch()
                        if !sent {
                            await MainActor.run { self.didNotifyRecordingStartedThisSession = false }
                        }
                    }
                }
            } else {
                recordingLiveActivityManager.endRecordingActivity()
                didNotifyRecordingStartedThisSession = false
                log("✅ Ended Recording Live Activity (recording stopped on Watch)")
            }
        }
        .store(in: &cancellables)
    log("✅ Recording-on-Watch observer configured")
}

// MARK: - Transfer Coordination

/// Sets up observers for Watch transfer coordination messages:
/// - Metadata readiness check (Watch sends metadata, iPhone acknowledges)
/// - Cleanup request (Watch hit complete-fail, iPhone deletes partial data)
private func setupTransferCoordinationObservers() {
    log("Setting up transfer coordination observers...")

    // Watch is preparing to send chunks — acknowledge readiness
    NotificationCenter.default.publisher(for: .watchPreparingTransfer)
        .receive(on: DispatchQueue.main)
        .sink { [weak self] notification in

            guard let self = self else { return }
            self.handleTransferPreparation(notification: notification)
        }
        .store(in: &cancellables)

    // Watch hit complete-fail — clean up partial chunk data
    NotificationCenter.default.publisher(for: .watchRequestedCleanup)
        .receive(on: DispatchQueue.main)
        .sink { [weak self] notification in
            guard let self = self else { return }
            self.handleCleanupRequest(notification: notification)
        }
        .store(in: &cancellables)

    log("Transfer coordination observers configured")
}

/// Handles the Watch's "prepare for transfer" message.
/// Sends an acknowledgment back so the Watch knows it can start sending chunks.
/// - Parameter notification: Contains recording metadata (recordingId, totalChunks, etc.)
private func handleTransferPreparation(notification: Notification) {
    guard let userInfo = notification.userInfo,
          let recordingIdString = userInfo[WatchMessageKey.recordingId] as? String else {
        log("Received prepareForTransfer without recordingId")
        return
    }

    log("Received transfer preparation request for recording: \(recordingIdString)")

    // Send acknowledgment to Watch that we're ready to receive
    let ackMessage: [String: Any] = [
        WatchMessageKey.action: WatchMessageKey.actionTransferAcknowledged,
        WatchMessageKey.recordingId: recordingIdString
    ]

    connectivityManager.sendMessage(ackMessage) { [weak self] error in
        if let error = error {
            self?.logError("Failed to send transfer acknowledgment", error: error)
        } else {
            self?.log("Transfer acknowledgment sent to Watch")
        }
    }
}

/// Handles the Watch's "cleanup partials" request.
/// Deletes all partial chunk data and metadata for a recording that hit complete-fail.
/// - Parameter notification: Contains the recordingId to clean up
private func handleCleanupRequest(notification: Notification) {
    guard let userInfo = notification.userInfo,
          let recordingIdString = userInfo[WatchMessageKey.recordingId] as? String,
          let recordingId = UUID(uuidString: recordingIdString) else {
        log("Received cleanup request without valid recordingId")
        return
    }

    log("Cleaning up partial data for recording: \(recordingId)")

    // Clean up chunk assembly data
    ChunkAssemblyManager.shared.cleanupAssembly(for: recordingId)

    // Clean up metadata if it exists
    if let metadataRepo = metadataRepository {
        do {
            if let metadata = try metadataRepo.fetchById(recordingId) {
                try metadataRepo.delete(recordingId)
                log("Deleted metadata for recording: \(recordingId)")
            }
        } catch {
            logError("Failed to cleanup metadata for recording: \(recordingId)", error: error)
        }
    }

    // Remove from incoming transfers UI
    incomingTransfers.removeValue(forKey: recordingId)

    log("Cleanup complete for recording: \(recordingId) — Watch will resend all chunks")
}

// MARK: - Stall Detection (iPhone-Side)

/// Starts a repeating timer that checks for transfers stuck without progress updates.
/// Fires every 60 seconds. Timeout budget is duration-aware via `TransferTimeoutPolicy`
/// (3 min per 30 min bucket). The Watch has its own parallel stall detection;
/// this acts as a safety net on the iPhone side.
private func setupStallDetectionTimer() {
    stallCheckTimer?.invalidate()
    stallCheckTimer = Timer.scheduledTimer(withTimeInterval: 60, repeats: true) { [weak self] _ in
        Task { @MainActor in
            self?.checkForStalledIncomingTransfers()
        }
    }
    log("✅ Stall detection timer started (60s interval, duration-aware timeout)")
}

/// Iterates all incoming transfers and fails any that have been stuck for too long.
/// Also checks Core Data for:
/// - Orphaned transfers (progress 100% in DB but file never arrived — no RecordingMetadata)
/// - Chunk assemblies stuck in `.receiving` for > 1 hour.
private func checkForStalledIncomingTransfers() {
    let now = Date()

    for (recordingId, transfer) in incomingTransfers {
        // Only check active transfers (pending / receiving); skip completed or already-failed
        switch transfer.state {
        case .pending, .receiving:
            break
        case .completed, .failed:
            continue
        }

        guard let lastUpdate = transfer.lastProgressUpdateTime else { continue }

        let elapsed = now.timeIntervalSince(lastUpdate)
        let timeout = transferTimeoutPolicy.timeout(forRecordingDuration: transfer.totalRecordingDuration)
        guard elapsed >= timeout else { continue }

        let elapsedMinutes = Int(elapsed / 60)
        log("⏰ Transfer \(recordingId) stalled — no progress for \(elapsedMinutes) min. Marking as failed.")
        handleStalledIncomingTransfer(recordingId: recordingId)
    }

    // Orphaned transfer check: DB shows receiving with old updatedAt but no RecordingMetadata.
    // File was never saved (e.g. progress reached 100% via context but didReceive file never fired).
    if let repo = watchTransferRepository, let metadataRepo = metadataRepository {
        if let active = try? repo.fetchActive() {
            for transfer in active {
                guard let recordingId = transfer.id else { continue }
                guard transfer.statusEnum == .receiving else { continue }
                let timeout = transferTimeoutPolicy.timeout(forRecordingDuration: transfer.duration)
                let staleCutoff = now.addingTimeInterval(-timeout)
                guard (transfer.updatedAt ?? transfer.createdAt ?? now) < staleCutoff else { continue }
                // No RecordingMetadata means file was never received and saved.
                guard (try? metadataRepo.fetchById(recordingId)) == nil else { continue }
                let orphanError = "Transfer stalled at 100% — file never arrived. Tap Retry to resend."
                log("⏰ Orphaned transfer detected: \(recordingId) — \(orphanError)")
                handleStalledIncomingTransfer(recordingId: recordingId, customError: orphanError)
            }
        }
    }

    // Stale assembly timeout: chunk assemblies stuck in `.receiving` for > 1 hour.
    if let repo = watchTransferRepository {
        let oneHourAgo = now.addingTimeInterval(-3600)
        if let staleAssemblies = try? repo.fetchStaleAssemblies(olderThan: oneHourAgo) {
            for transfer in staleAssemblies {
                guard let recordingId = transfer.id else { continue }
                log("⏰ Stale chunk assembly detected: \(recordingId) — no chunk for > 1 hour. Timing out.")
                try? repo.markTimedOut(recordingId)
                handleStalledIncomingTransfer(recordingId: recordingId)
            }
        }
    }
}

/// Handles a single stalled incoming transfer:
/// 1. Marks it as failed in both WatchRecordingService and WatchConnectivityManager
/// 2. Cleans up partial chunk assembly data
/// 3. Ends the associated Live Activity
/// 4. Keeps failed row visible for manual retry/dismiss
/// - Parameters:
///   - recordingId: The UUID of the stalled recording
///   - customError: Optional custom error message (e.g. for orphaned "100% but file never arrived" case)
private func handleStalledIncomingTransfer(recordingId: UUID, customError: String? = nil) {
    let timeoutSeconds = transferTimeoutSeconds(for: recordingId)
    let timeoutMinutes = Int(timeoutSeconds / 60)
    let errorMessage = customError ?? "Transfer timed out — no progress for \(timeoutMinutes) minutes. Retry will start from scratch."

    // 0. Persist failure in Core Data
    if let repo = watchTransferRepository {
        try? repo.markFailed(recordingId, error: errorMessage)
    }

    // 1. Mark as failed in WatchConnectivityManager so the observer doesn't overwrite us
    connectivityManager.markIncomingTransferTimedOut(
        recordingId: recordingId,
        error: errorMessage
    )

    // 2. Update our local transfer info
    let existing = incomingTransfers[recordingId]
    let failedTransfer = IncomingTransferInfo(
        id: recordingId,
        metadata: existing?.metadata,
        state: .failed(errorMessage),
        uploadId: existing?.uploadId,
        uploadProgress: existing?.uploadProgress
    )
    incomingTransfers[recordingId] = failedTransfer

    // 3. Timeouts must retry from scratch, so remove all partial assembly state.
    ChunkAssemblyManager.shared.cleanupAssembly(for: recordingId)

    // 4. End Live Activity with failure
    liveActivityManager.endActivity(
        recordingId: recordingId,
        success: false,
        errorMessage: errorMessage
    )

    Task { @MainActor [weak self] in
        await self?.transferFailureNotificationService.notifyTransferFailed(recordingId: recordingId)
    }

    logError("❌ Transfer timed out for recording: \(recordingId)", error: nil)

    // 5. Keep failed row visible so user can inspect details and retry.
}

private func transferTimeoutSeconds(for recordingId: UUID) -> TimeInterval {
    if let transfer = incomingTransfers[recordingId] {
        return transferTimeoutPolicy.timeout(forRecordingDuration: transfer.totalRecordingDuration)
    }
    if let repo = watchTransferRepository,
       let transfer = try? repo.fetchById(recordingId) {
        return transferTimeoutPolicy.timeout(forRecordingDuration: transfer.duration)
    }
    return transferTimeoutPolicy.timeout(forRecordingDuration: nil)
}

/// Prepares local iPhone state so manual retry from Watch starts from scratch.
/// Clears partial chunk assembly and resets incoming transfer progress guards.
func prepareManualRetryFromScratch(recordingId: UUID) {
    ChunkAssemblyManager.shared.cleanupAssembly(for: recordingId)
    connectivityManager.prepareIncomingTransferRetry(recordingId: recordingId)
    log("Prepared manual retry from scratch for recording: \(recordingId)")
}

// MARK: - Recording Reception

/// Handles a recording file received from the Apple Watch.
///
/// If the transfer contains chunk info, the file is routed to `ChunkAssemblyManager`
/// for progressive assembly. Otherwise, it follows the existing single-file flow.
///
/// Flow (single-file): Receive → Save → Upload → Confirm
/// Flow (chunked):     Receive → AssemblyManager → (all chunks) → Merge → Upload → Confirm
///
/// - Parameters:
///   - fileURL: The temporary URL where the transferred file is located
///   - metadata: The recording metadata from the watch
private func handleReceivedRecording(fileURL: URL, metadata: RecordingTransferMetadata) {
    logger.info("[WatchRecordingService] Receiving recording from Watch — id: \(metadata.id), filename: \(metadata.filename), duration: \(String(format: "%.2f", metadata.duration))s, isChunked: \(metadata.isChunked)")

    // ========================================
    // DUPLICATE DELIVERY GUARD
    // WatchConnectivityManager fires both `onRecordingReceived` callback AND
    // `.recordingDidReceiveFromWatch` notification for the same incoming file.
    // Primary: Core Data-based dedup (survives app restarts).
    // Fallback: in-memory Set for the window before configure() is called.
    // ========================================

        guard let dict = dict,
              let parentIdString = dict["parentRecordingId"] as? String,
              let parentId = UUID(uuidString: parentIdString),
              let chunkIdString = dict["chunkId"] as? String,
              let chunkId = UUID(uuidString: chunkIdString),
              let chunkIndex = dict["chunkIndex"] as? Int,
              let isLastChunk = dict["isLastChunk"] as? Bool,
              let chunkDuration = dict["chunkDuration"] as? TimeInterval,
              let totalDurationSoFar = dict["totalDurationSoFar"] as? TimeInterval,
              let startTimestamp = dict["recordingStartTime"] as? TimeInterval else {
            return nil
        }

        return ChunkTransferMetadata(
            parentRecordingId: parentId,
            chunkId: chunkId,
            chunkIndex: chunkIndex,
            isLastChunk: isLastChunk,
            chunkDuration: chunkDuration,
            totalDurationSoFar: totalDurationSoFar,
            recordingStartTime: Date(timeIntervalSince1970: startTimestamp)
        )
    }
}

