// MARK: - Authentication Token Sync

extension WatchConnectivityManager {

    #if os(iOS)
    /// Syncs the access token and user identity to the paired Apple Watch via application context.
    /// The context will be delivered to the watch even if it's not immediately reachable.
    /// IMPORTANT: Preserves recording confirmations when updating auth context.
    /// - Parameters:
    ///   - token: The access token to send to the watch. Pass nil to clear the token on the watch.
    ///   - userId: The authenticated user's ID (from fetchMe). Included so watch can tag Sentry events.
    ///   - userEmail: The authenticated user's email (from fetchMe). Included so watch can tag Sentry events.
    ///   - completion: Optional completion handler called on main queue with success/failure result.
    func syncAccessToken(
        _ token: String?,
        userId: String? = nil,
        userEmail: String? = nil,
        completion: ((Result<Void, Error>) -> Void)? = nil
    ) {
        if Thread.isMainThread {
            performSyncAccessToken(token: token, userId: userId, userEmail: userEmail, completion: completion)
        } else {
            DispatchQueue.main.async { [weak self] in
                self?.performSyncAccessToken(token: token, userId: userId, userEmail: userEmail, completion: completion)
            }
        }
    }

    /// Internal method to perform access token sync (must be called on main thread)
    private func performSyncAccessToken(
        token: String?,
        userId: String?,
        userEmail: String?,
        completion: ((Result<Void, Error>) -> Void)?
    ) {
        dispatchPrecondition(condition: .onQueue(.main))

        // Get authoritative context from cached copy
        var context = getCachedApplicationContextSafely()

        // Update auth-related keys
        context[WatchContextKey.isAuthenticated] = token != nil

        if let token = token {
            context[WatchContextKey.accessToken] = token
        } else {
            context.removeValue(forKey: WatchContextKey.accessToken)
        }

        // Sync user identity for Sentry tagging on the watch
        if let userId = userId {
            context[WatchContextKey.userId] = userId
        } else {
            context.removeValue(forKey: WatchContextKey.userId)
        }
        if let userEmail = userEmail {
            context[WatchContextKey.userEmail] = userEmail
        } else {
            context.removeValue(forKey: WatchContextKey.userEmail)
        }

        // Preserve transferredRecordingIds from existing context
        // This prevents overwriting recording confirmations when auth state changes

        // Use application context for reliable delivery even when watch is not reachable
        updateApplicationContext(context) { [weak self] error in
            guard let self = self else { return }
            if let error = error {
                self.logger.error("[WatchConnectivity] Failed to sync access token: \(error.localizedDescription)", error: error)
                completion?(.failure(error))
            } else {
                self.logger.info("[WatchConnectivity] Access token synced to watch (confirmations preserved)")
                completion?(.success(()))
            }
        }
    }

    /// Clears the authentication token on the paired Apple Watch.
    /// Call this when the user signs out.
    func clearWatchAuthToken(completion: ((Result<Void, Error>) -> Void)? = nil) {
        syncAccessToken(nil, completion: completion)
    }
    #endif

    #if os(watchOS)
    /// Handles received authentication context from the iOS app.
    /// Stores or clears the access token in the watch's Keychain.
    /// - Parameter context: The application context dictionary received from iOS
    func handleReceivedAuthContext(_ context: [String: Any]) {
        let isAuthenticated = context[WatchContextKey.isAuthenticated] as? Bool ?? false

        if isAuthenticated, let token = context[WatchContextKey.accessToken] as? String {
            // Store the token securely in Keychain
            let success = WatchKeychainHelper.shared.setAccessToken(token)
            if success {
                logger.info("[WatchConnectivity] Access token received and stored successfully")
            } else {
                logger.error("[WatchConnectivity] Failed to store received access token", error: nil)
            }

            // Tag Sentry with user identity synced from iOS (from fetchMe response)
            let userId = context[WatchContextKey.userId] as? String
            let userEmail = context[WatchContextKey.userEmail] as? String
            setSentryUser(id: userId, email: userEmail)
        } else {
            // Clear the stored token (user signed out or token cleared)
            WatchKeychainHelper.shared.clearAccessToken()
            logger.info("[WatchConnectivity] Access token cleared on watch")

            // Clear Sentry user on sign-out
            logger.setUser(id: nil, email: nil)
        }

        // Post notification for any observers that need to react to auth state changes
        NotificationCenter.default.post(
            name: .watchAuthStateDidChange,
            object: nil,
            userInfo: [WatchContextKey.isAuthenticated: isAuthenticated]
        )
    }

    /// Sets the Sentry user identity on the watch side.
    /// Called when auth context is received from iOS and on app launch from cached context.
    func setSentryUser(id: String?, email: String?) {
        guard id != nil else {
            logger.warning("[WatchConnectivity] No userId available for Sentry tagging")
            return
        }

        logger.setUser(id: id, email: email)
        logger.info("[WatchConnectivity] Sentry user set: id=\(id ?? "nil")")
    }

    /// Retrieves the currently stored access token on the watch
    /// - Returns: The stored access token, or nil if not available
    func getStoredAccessToken() -> String? {
        return WatchKeychainHelper.shared.getAccessToken()
    }

    /// Checks if the watch has a valid access token
    var hasAccessToken: Bool {
        return WatchKeychainHelper.shared.hasAccessToken
    }

    /// Handles iOS processing status updates
    /// Called when iOS sends recording processing status via application context
    func handleiOSProcessingStatusUpdates(_ context: [String: Any]) {
        guard let statuses = context["recordingProcessingStatuses"] as? [String: [String: Any]] else {
            return
        }

        for (idString, statusPayload) in statuses {
            guard let recordingId = UUID(uuidString: idString),
                  let statusName = statusPayload["status"] as? String else {
                continue
            }

            let meetingId = statusPayload["meetingId"] as? String
            let uploadProgress = statusPayload["uploadProgress"] as? Double

            let progressStr = uploadProgress.map { " (\(Int($0 * 100))%)" } ?? ""
            logger.info("[WatchConnectivity] Received iOS status update: \(recordingId) -> \(statusName)\(progressStr)")

            // Update local Core Data via notification
            NotificationCenter.default.post(
                name: .iosProcessingStatusUpdated,
                object: nil,
                userInfo: [
                    "recordingId": recordingId,
                    "status": statusName,
                    "uploadProgress": uploadProgress as Any,
                    "meetingId": meetingId as Any
                ]
            )
        }
    }
    #endif
}

