    /// Watch → iPhone: Sends recording metadata before chunk transfer begins.
    /// iPhone should respond with acknowledgment when ready to receive.
    static let actionPrepareForTransfer = "prepareForTransfer"

    /// Watch → iPhone: Tells iPhone to delete all partial chunks and metadata
    /// for a recording that hit the complete-fail state.
    static let actionCleanupPartials = "cleanupPartials"

    /// iPhone → Watch: Tells the Watch user to open the iPhone app
    /// (e.g., when background upload cannot proceed)
    static let actionOpenIPhoneApp = "openIPhoneApp"

