import Foundation

/// Shared policy for transfer timeout decisions across Watch and iPhone.
/// Rule: 3 minutes for every 30 minutes of recording, rounded up by bucket.
struct TransferTimeoutPolicy {
    static let `default` = TransferTimeoutPolicy()

    /// Timeout budget per 30-minute recording bucket.
    let timeoutPerThirtyMinuteBucket: TimeInterval

    /// Recording-duration bucket size.
    let durationBucket: TimeInterval

    init(
        timeoutPerThirtyMinuteBucket: TimeInterval = 3 * 60,
        durationBucket: TimeInterval = 30 * 60
    ) {
        self.timeoutPerThirtyMinuteBucket = timeoutPerThirtyMinuteBucket
        self.durationBucket = durationBucket
    }

    /// Calculates timeout for a recording duration using bucketed rounding:
    /// 0...30m -> 3m, 30...60m -> 6m, 60...90m -> 9m, etc.
    /// Unknown/invalid durations still get the minimum 3-minute timeout.
    func timeout(forRecordingDuration duration: TimeInterval?) -> TimeInterval {
        let safeDuration = max(0, duration ?? 0)
        let bucketCount = max(1, Int(ceil(safeDuration / durationBucket)))
        return TimeInterval(bucketCount) * timeoutPerThirtyMinuteBucket
    }
}

