import Foundation
import CoreData

// MARK: - Protocol

/// Manages persistence for incoming watch-to-iPhone transfers.
/// Replaces the scattered in-memory stores (`processedChunkKeys`,
/// `ChunkAssemblyManager` JSON inventory) with a single Core Data table.
protocol WatchTransferRepository {
    /// Creates a new transfer or updates an existing one (upsert by recording id).
    @discardableResult
    func createOrUpdate(
        recordingId: UUID,
        isChunked: Bool,
        filename: String?,
        duration: TimeInterval,
        startTime: Date?,
        status: WatchTransferStatus
    ) throws -> WatchTransfer

    /// Fetches a single transfer by recording id.
    func fetchById(_ id: UUID) throws -> WatchTransfer?

    /// Returns all transfers that are not in a terminal state (completed / timedOut).
    func fetchActive() throws -> [WatchTransfer]

    /// Finds chunk assemblies stuck in `.receiving` longer than `threshold`.
    func fetchStaleAssemblies(olderThan threshold: Date) throws -> [WatchTransfer]

    /// Finds transfers in `.failed` state eligible for merge retry.
    func fetchRetryableMerges(maxRetries: Int) throws -> [WatchTransfer]

    // MARK: - Status Mutations

    func updateProgress(_ id: UUID, progress: Double) throws
    func markReceiving(_ id: UUID) throws
    func markAssembling(_ id: UUID) throws
    func markAssembled(_ id: UUID) throws
    func markCompleted(_ id: UUID) throws
    func markFailed(_ id: UUID, error: String) throws
    func markTimedOut(_ id: UUID) throws
    func incrementMergeRetryCount(_ id: UUID) throws

    // MARK: - Chunk Tracking

    /// Records that a chunk at `chunkIndex` has arrived for `recordingId`.
    /// Also sets `totalExpectedChunks` when `isLastChunk` is true.
    func addChunkIndex(
        recordingId: UUID,
        chunkIndex: Int,
        isLastChunk: Bool,
        totalExpectedChunks: Int?
    ) throws

    /// Whether a specific chunk was already received (persisted dedup guard).
    func hasReceivedChunk(recordingId: UUID, chunkIndex: Int) throws -> Bool

    // MARK: - Cleanup

    /// Deletes completed transfers older than `date`.
    func deleteCompleted(olderThan date: Date) throws
}

// MARK: - Implementation

final class WatchTransferRepositoryImpl: WatchTransferRepository {

    private let context: NSManagedObjectContext
    private let logger = LoggerFactory.makeLogger()

    init(context: NSManagedObjectContext) {
        self.context = context
    }

    // MARK: - Upsert

    @discardableResult
    func createOrUpdate(
        recordingId: UUID,
        isChunked: Bool,
        filename: String?,
        duration: TimeInterval,
        startTime: Date?,
        status: WatchTransferStatus
    ) throws -> WatchTransfer {
        if let existing = try fetchById(recordingId) {
            // Never regress from a terminal or advanced state (e.g. Watch retry
            // after confirmation was lost should not overwrite .completed → .receiving)
            let currentStatus = existing.statusEnum
            if currentStatus.isTerminal ||
               (currentStatus == .assembled && status.rawValue < WatchTransferStatus.assembled.rawValue) ||
               (currentStatus == .assembling && status == .receiving) {
                logger.info("[WatchTransferRepo] Skipping status downgrade for \(recordingId): \(currentStatus) → \(status)")
                existing.touch()
                try context.save()
                return existing
            }

            existing.isChunked = isChunked
            if let f = filename { existing.filename = f }
            existing.duration = duration
            existing.startTime = startTime
            existing.statusEnum = status
            existing.touch()
            try context.save()
            return existing
        }

        let transfer = WatchTransfer(context: context)
        transfer.id = recordingId
        transfer.isChunked = isChunked
        transfer.filename = filename
        transfer.duration = duration
        transfer.startTime = startTime
        transfer.statusEnum = status
        transfer.createdAt = Date()
        transfer.updatedAt = Date()
        transfer.progress = 0
        transfer.chunksReceived = 0
        transfer.totalExpectedChunks = 0
        transfer.mergeRetryCount = 0

        try context.save()
        logger.info("[WatchTransferRepo] Created transfer: \(recordingId)")
        return transfer
    }

    // MARK: - Fetch

    func fetchById(_ id: UUID) throws -> WatchTransfer? {
        let request: NSFetchRequest<WatchTransfer> = WatchTransfer.fetchRequest()
        request.predicate = NSPredicate(format: "id == %@", id as CVarArg)
        request.fetchLimit = 1
        return try context.fetch(request).first
    }

    func fetchActive() throws -> [WatchTransfer] {
        let request: NSFetchRequest<WatchTransfer> = WatchTransfer.fetchRequest()
        let terminalStatuses: [Int16] = [
            WatchTransferStatus.completed.rawValue,
            WatchTransferStatus.timedOut.rawValue
        ]
        request.predicate = NSPredicate(format: "NOT (status IN %@)", terminalStatuses)
        request.sortDescriptors = [NSSortDescriptor(key: "createdAt", ascending: false)]
        return try context.fetch(request)
    }

    func fetchStaleAssemblies(olderThan threshold: Date) throws -> [WatchTransfer] {
        let request: NSFetchRequest<WatchTransfer> = WatchTransfer.fetchRequest()
        request.predicate = NSPredicate(
            format: "status == %d AND isChunked == YES AND updatedAt < %@",
            WatchTransferStatus.receiving.rawValue,
            threshold as NSDate
        )
        return try context.fetch(request)
    }

    func fetchRetryableMerges(maxRetries: Int) throws -> [WatchTransfer] {
        let request: NSFetchRequest<WatchTransfer> = WatchTransfer.fetchRequest()
        request.predicate = NSPredicate(
            format: "status == %d AND mergeRetryCount < %d",
            WatchTransferStatus.failed.rawValue,
            maxRetries
        )
        return try context.fetch(request)
    }

    // MARK: - Status Mutations

    func updateProgress(_ id: UUID, progress: Double) throws {
        guard let t = try fetchById(id) else { return }
        t.progress = progress
        t.touch()
        try context.save()
    }

    func markReceiving(_ id: UUID) throws {
        try setStatus(id, status: .receiving)
    }

    func markAssembling(_ id: UUID) throws {
        try setStatus(id, status: .assembling)
    }

    func markAssembled(_ id: UUID) throws {
        try setStatus(id, status: .assembled)
    }

    func markCompleted(_ id: UUID) throws {
        try setStatus(id, status: .completed)
    }

    func markFailed(_ id: UUID, error: String) throws {
        guard let t = try fetchById(id) else { return }
        t.statusEnum = .failed
        t.errorMessage = error
        t.touch()
        try context.save()
    }

    func markTimedOut(_ id: UUID) throws {
        try setStatus(id, status: .timedOut)
    }

    func incrementMergeRetryCount(_ id: UUID) throws {
        guard let t = try fetchById(id) else { return }
        t.mergeRetryCount += 1
        t.touch()
        try context.save()
    }

    // MARK: - Chunk Tracking

    func addChunkIndex(
        recordingId: UUID,
        chunkIndex: Int,
        isLastChunk: Bool,
        totalExpectedChunks: Int?
    ) throws {
        guard let t = try fetchById(recordingId) else {
            logger.warning("[WatchTransferRepo] Cannot add chunk — transfer not found: \(recordingId)")
            return
        }
        t.addReceivedChunkIndex(chunkIndex)
        if isLastChunk, let total = totalExpectedChunks {
            t.totalExpectedChunks = Int16(total)
        }
        try context.save()
    }

    func hasReceivedChunk(recordingId: UUID, chunkIndex: Int) throws -> Bool {
        guard let t = try fetchById(recordingId) else { return false }
        return t.hasChunkIndex(chunkIndex)
    }

    // MARK: - Cleanup

    func deleteCompleted(olderThan date: Date) throws {
        let request: NSFetchRequest<WatchTransfer> = WatchTransfer.fetchRequest()
        request.predicate = NSPredicate(
            format: "status == %d AND updatedAt < %@",
            WatchTransferStatus.completed.rawValue,
            date as NSDate
        )
        let results = try context.fetch(request)
        for item in results {
            context.delete(item)
        }
        try context.save()
        if !results.isEmpty {
            logger.info("[WatchTransferRepo] Cleaned up \(results.count) completed transfer(s)")
        }
    }

    // MARK: - Private

    private func setStatus(_ id: UUID, status: WatchTransferStatus) throws {
        guard let t = try fetchById(id) else { return }
        t.statusEnum = status
        t.touch()
        try context.save()
    }
}

