import Foundation

/// Helper for syncing recording status from iOS to Watch
final class WatchStatusSync {
    private let connectivity = WatchConnectivityManager.shared
    private let logger = LoggerFactory.makeLogger()

    /// Sends processing status update to watch with optional upload progress
    /// - Parameters:
    ///   - recordingId: Recording identifier
    ///   - status: Current RecordingStatus
    ///   - uploadProgress: Upload progress (0.0 to 1.0) - only for .uploading status
    ///   - meetingId: Meeting ID when meeting is created
    /// - Note: This method must be called from the main thread as it accesses @Published properties
    func sendStatusToWatch(recordingId: UUID, status: RecordingStatus, uploadProgress: Double? = nil, meetingId: UUID? = nil) {
        // applicationContext requires main thread access (enforced by dispatchPrecondition)
        var context = connectivity.applicationContext

        // Get existing status dictionary or create new
        var processingStatuses = context["recordingProcessingStatuses"] as? [String: [String: Any]] ?? [:]

        // Create status payload
        var statusPayload: [String: Any] = [
            "status": status.displayName,
            "statusRaw": status.rawValue,
            "timestamp": Date().timeIntervalSince1970
        ]

        // Include upload progress for uploading status
        if let progress = uploadProgress, status == .uploading {
            statusPayload["uploadProgress"] = progress
        }

        if let meetingId = meetingId {
            statusPayload["meetingId"] = meetingId.uuidString
        }

        processingStatuses[recordingId.uuidString] = statusPayload
        context["recordingProcessingStatuses"] = processingStatuses

        connectivity.updateApplicationContext(context) { [weak self] error in
            if let error = error {
                self?.logger.error("Failed to sync status to watch: \(error)")
            } else {
                let progressStr = uploadProgress.map { " (\(Int($0 * 100))%)" } ?? ""
                self?.logger.info("Synced status to watch: \(recordingId) -> \(status.displayName)\(progressStr)")
            }
        }
    }

    /// Clears status for a completed recording
    /// - Note: This method must be called from the main thread as it accesses @Published properties
    func clearStatusFromWatch(recordingId: UUID) {
        // applicationContext requires main thread access (enforced by dispatchPrecondition)
        var context = connectivity.applicationContext

        guard var processingStatuses = context["recordingProcessingStatuses"] as? [String: [String: Any]] else {
            return
        }

        processingStatuses.removeValue(forKey: recordingId.uuidString)

        if processingStatuses.isEmpty {
            context.removeValue(forKey: "recordingProcessingStatuses")
        } else {
            context["recordingProcessingStatuses"] = processingStatuses
        }

        connectivity.updateApplicationContext(context, completion: nil)
    }
}

import Foundation
import Combine
import SwiftUI
