/// Sends transfer progress update to iOS via application context
/// Throttles updates to avoid flooding (sends every ~1% progress or on completion)
/// - Parameters:
///   - recordingId: The UUID of the recording being transferred
///   - progress: The current progress (0.0 to 1.0)
///   - metadata: Optional metadata to send (typically on first update)
private func sendProgressUpdateToiOS(recordingId: UUID, progress: Double, metadata: RecordingTransferMetadata? = nil) {
    dispatchPrecondition(condition: .onQueue(.main))
    guard let session = session else { return }

    // Get current context from cached copy (must be on main thread)
    var context = getCachedApplicationContextSafely()

    // Get existing progress updates or create new dictionary
    var progressUpdates: [String: Double]
    if let existing = context[WatchContextKey.transferProgressUpdates] as? [String: Double] {
        progressUpdates = existing
    } else {
        progressUpdates = [:]
    }

    // Only include transfers that are still active (not completed)
    // Check both single-file (pendingTransfers) and multi-chunk (chunkTransfers) tracking
    let isStillActive = transferStateQueue.sync {
        if pendingTransfers[recordingId] != nil { return true }
        if chunkTransfers.values.contains(where: { $0.recordingId == recordingId }) { return true }
        if let total = recordingChunkCounts[recordingId],
           let completed = recordingCompletedChunks[recordingId],
           completed.count < total { return true }
        return false
    }

    if isStillActive {
        // Update progress for this recording
        progressUpdates[recordingId.uuidString] = progress
        context[WatchContextKey.transferProgressUpdates] = progressUpdates

        // Send metadata if provided (typically on transfer start)
        if let metadata = metadata {
            var metadataDict: [String: [String: Any]]
            if let existing = context[WatchContextKey.transferMetadata] as? [String: [String: Any]] {
                metadataDict = existing
            } else {
                metadataDict = [:]
            }

            // Store metadata for this recording
            metadataDict[recordingId.uuidString] = metadata.toDictionary()
            context[WatchContextKey.transferMetadata] = metadataDict
        }
    } else {
        // Transfer is no longer active, clean it up from context
        progressUpdates.removeValue(forKey: recordingId.uuidString)
        if progressUpdates.isEmpty {
            context.removeValue(forKey: WatchContextKey.transferProgressUpdates)
        } else {
            context[WatchContextKey.transferProgressUpdates] = progressUpdates
        }

        // Remove metadata for completed transfers
        if var metadataDict = context[WatchContextKey.transferMetadata] as? [String: [String: Any]] {
            metadataDict.removeValue(forKey: recordingId.uuidString)
            if metadataDict.isEmpty {
                context.removeValue(forKey: WatchContextKey.transferMetadata)
            } else {
                context[WatchContextKey.transferMetadata] = metadataDict
            }
        }

        // Don't send update if no changes needed
        return
    }

    // Send via application context (reliable, even if iOS is in background)
    updateApplicationContext(context) { [weak self] error in
        guard let self = self else { return }
        if let error = error {
            self.logger.error("[WatchConnectivity] Failed to send progress update: \(error.localizedDescription)", error: error)
        } else {
            self.logger.debug("[WatchConnectivity] Sent progress update: \(recordingId) = \(Int(progress * 100))%")
        }
    }
}

/// Clears progress update and metadata for a completed transfer
/// - Parameter recordingId: The UUID of the recording to clear progress for
private func clearProgressUpdateForiOS(recordingId: UUID) {
    dispatchPrecondition(condition: .onQueue(.main))
    guard let session = session else { return }

    // Get current context from cached copy (must be on main thread)
    var context = getCachedApplicationContextSafely()

    // Aggressively prune completed transfer from context immediately
    if var progressUpdates = context[WatchContextKey.transferProgressUpdates] as? [String: Double] {
        progressUpdates.removeValue(forKey: recordingId.uuidString)
        // Also clean up any other completed transfers (defensive cleanup)
        // Keep only transfers that are still in pendingTransfers
        let activeIds = transferStateQueue.sync { Set(pendingTransfers.keys.map { $0.uuidString }) }
        progressUpdates = progressUpdates.filter { activeIds.contains($0.key) }

        if progressUpdates.isEmpty {
            context.removeValue(forKey: WatchContextKey.transferProgressUpdates)
        } else {
            context[WatchContextKey.transferProgressUpdates] = progressUpdates
        }
    }

    // Remove metadata immediately for completed transfer
    if var metadataDict = context[WatchContextKey.transferMetadata] as? [String: [String: Any]] {
        metadataDict.removeValue(forKey: recordingId.uuidString)
        // Clean up metadata for other completed transfers too
        let activeIds = transferStateQueue.sync { Set(pendingTransfers.keys.map { $0.uuidString }) }
        metadataDict = metadataDict.filter { activeIds.contains($0.key) }

        if metadataDict.isEmpty {
            context.removeValue(forKey: WatchContextKey.transferMetadata)
        } else {
            context[WatchContextKey.transferMetadata] = metadataDict
        }
    }

    // Update context (only if we actually changed something)
    updateApplicationContext(context) { [weak self] error in
        guard let self = self else { return }
        if let error = error {
            self.logger.error("[WatchConnectivity] Failed to clear progress update: \(error.localizedDescription)", error: error)
        }
    }
}

/// Notifies iPhone that recording has started or stopped on Watch. Call from main thread.
/// Merges into current application context so auth and transfer keys are preserved.
/// - Parameters:
///   - isRecording: True when recording (or paused), false when stopped
///   - startedAt: When recording started (for elapsed time on iPhone). Pass nil when isRecording is false.
func sendRecordingOnWatchIndicator(isRecording: Bool, startedAt: Date?) {
    dispatchPrecondition(condition: .onQueue(.main))
    var context = getCachedApplicationContextSafely()
    context[WatchContextKey.isRecordingOnWatch] = isRecording
    if let started = startedAt {
        context[WatchContextKey.recordingStartedAt] = started.timeIntervalSince1970
    } else {
        context.removeValue(forKey: WatchContextKey.recordingStartedAt)
    }
    updateApplicationContext(context) { [weak self] error in
        guard let self = self else { return }
        if let error = error {
            self.logger.error("[WatchConnectivity] Failed to send recording indicator: \(error.localizedDescription)", error: error)
        } else {
            self.logger.debug("[WatchConnectivity] Sent recording on Watch: \(isRecording)")
        }
    }
}

/// Restores pending file transfers after app restart
/// Checks session.outstandingFileTransfers and restores any transfers that aren't already confirmed
private func restorePendingTransfers() {
    guard let session = session else { return }

    let outstanding = session.outstandingFileTransfers

    guard !outstanding.isEmpty else {
        logger.debug("[WatchConnectivity] No outstanding transfers to restore")
        return
    }

    logger.info("[WatchConnectivity] Restoring \(outstanding.count) pending transfer(s)")

    // Collect transfers to restore (thread-safe)
    var transfersToRestore: [(UUID, WCSessionFileTransfer, RecordingTransferMetadata)] = []

    for transfer in outstanding {
        guard let metadataDict = transfer.file.metadata,
              let metadata = RecordingTransferMetadata.fromDictionary(metadataDict) else {
            continue
        }

        let recordingId = metadata.id

        // Check Core Data status before restoring — skip recordings already
        // confirmed/sent by iOS. Without this guard, already-completed transfers
        // are re-queued on every app restart, causing phantom progress in iPhone UI
        // and unnecessary duplicate resends.
        if let repo = repository {
            let (canSend, reason) = repo.canSendRecording(recordingId)
            if !canSend {
                logger.info("[WatchConnectivity] ⏭️ Skipping restore for \(recordingId): \(reason ?? "not sendable")")
                transfer.cancel()
                continue
            }
        }

        transfersToRestore.append((recordingId, transfer, metadata))
    }

    // Restore all transfers in thread-safe manner
    transferStateQueue.async { [weak self] in
        guard let self = self else { return }

        for (recordingId, transfer, metadata) in transfersToRestore {
            let transferObjId = ObjectIdentifier(transfer)

            if let chunkInfo = metadata.chunkInfo {
                // Restore as a chunk transfer
                self.chunkTransfers[transferObjId] = (recordingId: recordingId, chunkIndex: chunkInfo.chunkIndex)

                if chunkInfo.isLastChunk {
                    self.recordingChunkCounts[recordingId] = chunkInfo.chunkIndex + 1
                } else if self.recordingChunkCounts[recordingId] == nil {
                    self.recordingChunkCounts[recordingId] = chunkInfo.chunkIndex + 1
                }
                if self.recordingCompletedChunks[recordingId] == nil {
                    self.recordingCompletedChunks[recordingId] = Set()
                }
                if self.chunkProgressValues[recordingId] == nil {
                    self.chunkProgressValues[recordingId] = [:]
                }

                let initialProgress = transfer.progress.fractionCompleted
                self.chunkProgressValues[recordingId]?[chunkInfo.chunkIndex] = initialProgress

                self.logger.info("[WatchConnectivity] ✅ Restored chunk \(chunkInfo.chunkIndex): \(metadata.filename)")

                DispatchQueue.main.async {
                    // Compute aggregate for restored chunks
                    let totalChunks = self.recordingChunkCounts[recordingId] ?? 1
                    let allProgress = self.chunkProgressValues[recordingId]?.values.reduce(0.0, +) ?? 0.0
                    let aggregate = min(allProgress / Double(totalChunks), 1.0)
                    self.recordingTransferProgress[recordingId] = aggregate
                    self.updateCachedAggregateStates()

                    // Send restored progress to iOS so the phone reflects current state
                    self.sendProgressUpdateToiOS(recordingId: recordingId, progress: aggregate, metadata: metadata)

                    self.observeChunkTransferProgress(transfer, transferObjId: transferObjId, recordingId: recordingId, chunkIndex: chunkInfo.chunkIndex)
                }
            } else {
                // Restore as single-file transfer
                self.pendingTransfers[recordingId] = transfer
                self.logger.info("[WatchConnectivity] ✅ Restored: \(metadata.filename)")

                let initialProgress = transfer.progress.fractionCompleted
                DispatchQueue.main.async {
                    self.recordingTransferProgress[recordingId] = initialProgress
                    self.updateCachedAggregateStates()
                    self.sendProgressUpdateToiOS(recordingId: recordingId, progress: initialProgress, metadata: metadata)
                    self.observeTransferProgress(transfer, recordingId: recordingId)
                }
            }
        }
    }
}

/// Handles confirmation that iOS received a recording (called when app context is received)
func handleTransferConfirmation(_ context: [String: Any]) {
    // Check for transferred recording IDs that iOS has confirmed receiving
    // Use explicit type checking to ensure safety
    guard let transferredIdsValue = context[WatchContextKey.transferredRecordingIds] else {
        return
    }

    // Defensive parsing: handle both [String] and other array types
    var transferredIds: [String] = []

    if let stringArray = transferredIdsValue as? [String] {
        // Expected format: array of UUID strings
        transferredIds = stringArray
    } else if let uuidArray = transferredIdsValue as? [UUID] {
        // Fallback: array of UUID objects - convert to strings
        transferredIds = uuidArray.map { $0.uuidString }

        _ = setupAudioSession()
    }
}

// MARK: - Keep-Alive Session Management

/// Starts an ExtendedRuntimeSession to keep the app alive during recording.
/// Provides ~1 hour of background execution. User interaction (EXTEND/alerts)
/// keeps the app in the foreground, extending effective recording duration.
private func startExtendedRuntimeSessionFallback() {
    let sessionStarted = extendedRuntimeSessionManager.startSession(
        onStateChange: { sessionState in
            RecordingLogger.log("Extended runtime session state changed: \(sessionState)")
        },
        onExpiration: { [weak self] in
            Task { @MainActor [weak self] in
                self?.handleExtendedRuntimeSessionExpiration()
            }
        },
        onInvalidation: { [weak self] reason, error in
            Task { @MainActor [weak self] in
                self?.handleExtendedRuntimeSessionInvalidation(reason: reason, error: error)
            }
        }
    )

    if sessionStarted {
        RecordingLogger.success("ExtendedRuntimeSession fallback started (~1 hour limit)")
    } else {
        RecordingLogger.log("⚠️ ExtendedRuntimeSession fallback could not start")
    }
}

/// Stops the keep-alive extended runtime session.
private func stopKeepAliveSession() {
    extendedRuntimeSessionManager.stopSession()
    RecordingLogger.log("Extended runtime session stopped")
}

// MARK: - Extended Runtime Session Handling

/// Sets up callbacks for extended runtime session state changes and expiration
private func setupExtendedRuntimeSessionCallbacks() {
    RecordingLogger.log("Setting up extended runtime session callbacks...")

    // Note: Callbacks are set when starting the session in startRecording()
    // This method is here for future extensibility if needed
    RecordingLogger.success("Extended runtime session callback setup ready")
}

// MARK: - Graceful Recording Shutdown

/// Performs a graceful shutdown of an active recording: saves chunks, initiates transfer,
/// logs the reason to Sentry (with user context), and shows a user-friendly message.
///
/// Every error path that interrupts a recording must funnel through this method so that
/// no recorded audio is lost.
///
/// - Parameters:
///   - reason: Human-readable reason shown in the UI (e.g. "Session time limit was reached.")
///   - sentryMessage: Technical message sent to Sentry for debugging / alerting
///   - error: Optional underlying error object attached to the Sentry event
private func gracefulRecordingShutdown(
    reason: String,
    sentryMessage: String,
    error: Error? = nil
) {
    guard state == .recording || state == .paused else { return }

    DispatchQueue.main.async { [weak self] in
        guard let self = self, self.state == .recording || self.state == .paused else { return }

        let recordedDuration = self.elapsed

        // Save the recording and initiate transfer to iPhone
        self.stopRecording()

        // Log to Sentry so we can track which users hit this and why
        RecordingLogger.error(
            "\(sentryMessage) — recording gracefully stopped after \(Int(recordedDuration))s",
            error: error
        )

        self.state = .error("Meeting saved. \(reason)")
        WKInterfaceDevice.current().play(.notification)
    }
}

/// Handles extended runtime session expiration
/// Called when the session is about to expire (typically after ~4 hours).
private func handleExtendedRuntimeSessionExpiration() {
    RecordingLogger.log("⚠️ Extended runtime session is expiring")

    gracefulRecordingShutdown(
        reason: "Session time limit was reached.",
        sentryMessage: "Session time limit reached (expiration callback)"
    )
}

/// Handles extended runtime session invalidation
/// Called when the session is invalidated for various reasons
/// - Parameters:
///   - reason: The reason for invalidation
///   - error: Optional error if invalidation was due to an error
private func handleExtendedRuntimeSessionInvalidation(
    reason: WKExtendedRuntimeSessionInvalidationReason,
    error: Error?
) {
    RecordingLogger.log("Extended runtime session invalidated - Reason: \(reason)")

    switch reason {
    case .none:
        // Manual invalidation (expected when stopping recording) — no action needed
        RecordingLogger.log("Session invalidated manually (expected)")

    case .sessionInProgress:
        RecordingLogger.log("Session invalidated - another session already in progress")
        gracefulRecordingShutdown(
            reason: "A session conflict occurred.",
            sentryMessage: "Session invalidated — sessionInProgress"
        )

    case .expired:
        RecordingLogger.log("Session expired - time limit reached (invalidation handler)")
        gracefulRecordingShutdown(
            reason: "Session time limit was reached.",
            sentryMessage: "Session invalidated — expired"
        )

    case .resignedFrontmost:
        RecordingLogger.log("Session invalidated - app resigned frontmost status (will not pause during ringing)")
        // Do not pause on frontmost resignation (e.g., incoming call UI). Keep state as-is and attempt to keep the recorder running.
        if state == .recording {
            // Best-effort to keep/resume the engine in case the OS briefly halted it.
            chunkedRecordingManager.resumeRecording()
        }

    case .suppressedBySystem:
        RecordingLogger.log("Session invalidated - suppressed by system")
        gracefulRecordingShutdown(
            reason: "A system limitation occurred.",
            sentryMessage: "Session invalidated — suppressedBySystem"
        )

    case .error:
        RecordingLogger.log("Session invalidated due to error")
        gracefulRecordingShutdown(
            reason: "An unexpected error occurred.",
            sentryMessage: "Session invalidated — error",
            error: error
        )

    @unknown default:
        RecordingLogger.log("Session invalidated for unknown reason: \(reason.rawValue)")
        gracefulRecordingShutdown(
            reason: "The session ended unexpectedly.",
            sentryMessage: "Session invalidated — unknown reason (\(reason.rawValue))"
        )
    }
}

// MARK: - Recording State Resync

/// Observes iPhone's request to re-send our current recording state.
/// When the iPhone app launches, it reads cached `session.receivedApplicationContext` which may
/// contain a stale `isRecordingOnWatch = true`. The iPhone sends a message asking us to confirm,
/// and we respond with our actual current state via application context.
private func setupRecordingStateResyncObserver() {
    NotificationCenter.default.addObserver(
        self,
        selector: #selector(handleRecordingStateResyncRequest),
        name: .watchShouldResyncRecordingState,
        object: nil
    )
    RecordingLogger.log("Recording state resync observer configured")
}

/// Observes iPhone's request to retry/resend a specific recording transfer.
private func setupTransferRetryRequestObserver() {
    NotificationCenter.default.addObserver(
        self,
        selector: #selector(handleTransferRetryRequestFromiPhone(_:)),
        name: .iPhoneRequestedTransferRetry,
        object: nil
    )
    RecordingLogger.log("iPhone transfer retry observer configured")
}

@objc private func handleRecordingStateResyncRequest() {
    RecordingLogger.log("Received recording state resync request from iPhone")
    DispatchQueue.main.async { [weak self] in
        guard let self = self else { return }
        let isCurrentlyRecording = (self.state == .recording || self.state == .paused)
        let currentStartDate = isCurrentlyRecording ? self.startDate : nil

        RecordingLogger.log("Re-sending recording state: isRecording=\(isCurrentlyRecording), startedAt=\(String(describing: currentStartDate))")
        WatchConnectivityManager.shared.sendRecordingOnWatchIndicator(
            isRecording: isCurrentlyRecording,
            startedAt: currentStartDate
        )
    }
}

@objc private func handleTransferRetryRequestFromiPhone(_ notification: Notification) {
    guard let userInfo = notification.userInfo,
          let recordingIdString = userInfo[WatchMessageKey.recordingId] as? String,
          let recordingId = UUID(uuidString: recordingIdString) else {
        RecordingLogger.log("Received invalid retry request payload from iPhone")
        return
    }

    RecordingLogger.log("Received retry request from iPhone for recording: \(recordingId)")
    DispatchQueue.main.async { [weak self] in
        self?.handleRetryRequestFromiPhone(recordingId: recordingId)
    }
}

/// Handles iPhone-initiated retry while respecting one-recording-at-a-time queueing.
private func handleRetryRequestFromiPhone(recordingId: UUID) {
    guard let localRepo = repository as? LocalRecordingRepository else {
        RecordingLogger.error("Cannot handle iPhone retry request - repository is not LocalRecordingRepository")
        return
    }

    guard let recording = try? repository.fetchAllRecordings().first(where: { $0.id == recordingId }) else {
        RecordingLogger.log("Retry request ignored - recording not found locally: \(recordingId)")
        return
    }

    if currentTransferRecordingId == recordingId || activeTransfers.contains(recordingId) ||
        connectivityManager.isRecordingTransferring(recordingId) {
        RecordingLogger.log("Retry request ignored because recording is already transferring: \(recordingId)")
        return
    }

    // If currently busy with a different recording, queue this one as pending.
    if let activeId = currentTransferRecordingId, activeId != recordingId {
        do {
            try localRepo.updateStatus(recordingId, status: .pending, error: "Queued from iPhone retry request")
            RecordingLogger.log("Queued retry request while transfer slot busy (\(activeId)) for recording: \(recordingId)")
        } catch {
            RecordingLogger.error("Failed to mark recording as queued from iPhone retry request", error: error)
        }
        return
    }

    if activeTransfers.contains(where: { $0 != recordingId }) {
        do {
            try localRepo.updateStatus(recordingId, status: .pending, error: "Queued from iPhone retry request")
            RecordingLogger.log("Queued retry request while another active transfer exists for recording: \(recordingId)")
        } catch {
            RecordingLogger.error("Failed to mark recording as queued from iPhone retry request", error: error)
        }
        return
    }

    // Ensure request retries are sendable through normal pipeline.
    do {
        try localRepo.updateStatus(recordingId, status: .pending, error: "Retry requested by iPhone")
    } catch {
        RecordingLogger.error("Failed to reset status before iPhone-requested retry", error: error)
    }

    transferToiOS(recording: recording)
}

