/// Handles audio session interruption notifications (phone calls, etc.)

        logger.warning("[WatchConnectivity] ⚠️ Received UUID objects instead of strings, converting...")
    } else if let anyArray = transferredIdsValue as? [Any] {
        // Fallback: array of mixed types - attempt to extract UUID strings
        transferredIds = anyArray.compactMap { value in
            if let uuidString = value as? String {
                // Validate it's a valid UUID string
                return UUID(uuidString: uuidString) != nil ? uuidString : nil
            } else if let uuid = value as? UUID {
                return uuid.uuidString
            }
            // Try to parse as UUID string from description
            let description = String(describing: value)
            if UUID(uuidString: description) != nil {
                return description
            }
            return nil
        }
        if transferredIds.isEmpty {
            logger.warning("[WatchConnectivity] ⚠️ Could not parse transferredRecordingIds from: \(type(of: transferredIdsValue))")
            return
        } else {
            logger.debug("[WatchConnectivity] ⚠️ Parsed \(transferredIds.count) UUIDs from mixed array type")
        }
    } else {
        logger.warning("[WatchConnectivity] ⚠️ Unexpected type for transferredRecordingIds: \(type(of: transferredIdsValue))")
        return
    }

    let phaseRaw = context[WatchContextKey.transferredRecordingAckPhase] as? String
    let confirmationPhase = RecordingTransferConfirmationPhase(rawValue: phaseRaw ?? "") ?? .received

    // Collect confirmations for thread-safe processing
    var confirmationsToProcess: [UUID] = []

    for idString in transferredIds {
        guard let recordingId = UUID(uuidString: idString) else {
            logger.warning("[WatchConnectivity] ⚠️ Invalid UUID string in transferredRecordingIds: \(idString)")
            continue
        }

        let confirmationKey = "\(recordingId.uuidString)|\(confirmationPhase.rawValue)"

        // Skip already processed confirmations (idempotency check)
        guard !processedConfirmationKeys.contains(confirmationKey) else {
            logger.debug("[WatchConnectivity] ⏭️ Ignoring duplicate \(confirmationPhase.rawValue) confirmation for: \(recordingId)")
            continue
        }

        // Mark as processed BEFORE doing any work (prevents race conditions)
        processedConfirmationKeys.insert(confirmationKey)

        // Add to confirmed IDs for processing
        logger.info("[WatchConnectivity] ✅ iOS sent \(confirmationPhase.rawValue) confirmation for recording: \(recordingId)")
        confirmationsToProcess.append(recordingId)
    }

    // Process confirmations in thread-safe manner
    transferStateQueue.async { [weak self] in
        guard let self = self else { return }

        for recordingId in confirmationsToProcess {
            logger.debug("[WatchConnectivity] Processing \(confirmationPhase.rawValue) confirmation for: \(recordingId)")

            do {
                guard let repo = repository else {
                    logger.error("[WatchConnectivity] ❌ Repository not available - cannot update status", error: nil)
                    logger.warning("[WatchConnectivity] Continuing with in-memory cleanup and callbacks")
                    continue
                }

                switch confirmationPhase {
                case .received:
                    // Mark transfer delivery confirmed on watch.
                    try repo.updateStatus(
                        recordingId,
                        status: .sent,
                        error: nil
                    )
                    logger.info("[WatchConnectivity] ✅ Core Data status updated to .sent")
                case .processed:
                    // Mark full iPhone pipeline completion on watch.
                    try repo.updateStatus(
                        recordingId,
                        status: .confirmed,
                        error: nil
                    )
                    logger.info("[WatchConnectivity] ✅ Core Data status updated to .confirmed")
                }
            } catch {
                logger.error("[WatchConnectivity] ❌ Failed to update Core Data status for \(confirmationPhase.rawValue) confirmation", error: error)
            }

            // ========================================
            // Now safe to remove from pending transfers
            // ========================================

            // Remove from single-file pending transfers
            self.pendingTransfers.removeValue(forKey: recordingId)
            self.progressObservers[recordingId]?.invalidate()
            self.progressObservers.removeValue(forKey: recordingId)

            // Also clean up multi-chunk tracking (no-op if not a chunked transfer)
            self.cleanupAllChunkTracking(for: recordingId)

            // Update UI on main thread
            DispatchQueue.main.async {
                // Remove from progress tracking
                self.recordingTransferProgress.removeValue(forKey: recordingId)
                self.updateCachedAggregateStates()
                self.lastTransferredRecordingId = recordingId

                // Notify completion callback only for transfer-received phase.
                if confirmationPhase == .received {
                    self.onTransferComplete?(recordingId, true)
                }

                #if os(watchOS)
                if confirmationPhase == .processed {
                    // For chunked recordings: full lifecycle is complete on iPhone.
                    // Post this only on processed confirmation to match semantics.
                    NotificationCenter.default.post(
                        name: .fullRecordingConfirmed,
                        object: nil,
                        userInfo: ["parentRecordingId": recordingId]
                    )
                }
                #endif

                // Post transfer completion notification
                NotificationCenter.default.post(
                    name: .recordingTransferDidComplete,
                    object: nil,
                    userInfo: ["recordingId": recordingId, "success": true]
                )

                // Post confirmation notification for Core Data status update
                NotificationCenter.default.post(
                    name: .watchRecordingTransferConfirmed,
                    object: nil,
                    userInfo: ["recordingId": recordingId]
                )

                self.logger.info("[WatchConnectivity] 🎉 Transfer \(confirmationPhase.rawValue) confirmation handled: \(recordingId)")

                // Scrub confirmed recording from applicationContext so stale
                // progress entries are not re-delivered to iPhone on future
                // context updates (applicationContext is persisted across restarts).
                self.removeConfirmedRecordingFromContext(recordingId: recordingId)
            }
        }
    }
}

/// Removes a confirmed recording's progress and metadata entries from
/// the application context. Without this cleanup, `transferProgressUpdates`
/// persists across app restarts and every future context update re-injects
/// stale progress into iPhone's `incomingTransferProgress`, causing phantom
/// transfer entries in the UI.
private func removeConfirmedRecordingFromContext(recordingId: UUID) {
    dispatchPrecondition(condition: .onQueue(.main))
    guard let session = session else { return }

    var context = getCachedApplicationContextSafely()
    var didChange = false

    if var progressUpdates = context[WatchContextKey.transferProgressUpdates] as? [String: Double] {
        if progressUpdates.removeValue(forKey: recordingId.uuidString) != nil {
            if progressUpdates.isEmpty {
                context.removeValue(forKey: WatchContextKey.transferProgressUpdates)
            } else {
                context[WatchContextKey.transferProgressUpdates] = progressUpdates
            }
            didChange = true
        }
    }

    if var metadataDict = context[WatchContextKey.transferMetadata] as? [String: [String: Any]] {
        if metadataDict.removeValue(forKey: recordingId.uuidString) != nil {
            if metadataDict.isEmpty {
                context.removeValue(forKey: WatchContextKey.transferMetadata)
            } else {
                context[WatchContextKey.transferMetadata] = metadataDict
            }
            didChange = true
        }
    }

    guard didChange else { return }

    updateApplicationContext(context) { [weak self] error in
        if let error = error {
            self?.logger.error("[WatchConnectivity] Failed to clean context for confirmed recording: \(error.localizedDescription)", error: error)
        } else {
            self?.logger.debug("[WatchConnectivity] 🧹 Cleaned context for confirmed recording: \(recordingId)")
        }
    }
}

