// metadataRepository uses viewContext (main-queue NSManagedObjectContext) but
// session(_:didReceive file:) runs on WCSession's background queue.
// Use a background-safe Core Data context to avoid deadlocking with DispatchQueue.main.sync.
enum DuplicateCheckResult {
    case alreadyProcessed
    case currentlyProcessing
    case allowRetry
    case noExistingRecord
}

// Perform the duplicate check on a background-safe context to avoid deadlock.
// Previously this used DispatchQueue.main.sync which could deadlock if the main
// thread was blocked on transferStateQueue or another lock touched by this code path.
let checkResult: DuplicateCheckResult = {
    var result: DuplicateCheckResult = .noExistingRecord
    let semaphore = DispatchSemaphore(value: 0)
    DispatchQueue.main.async { [weak self] in
        guard let self = self else {
            semaphore.signal()
            return
        }
        do {
            guard let existing = try self.metadataRepository?.fetchById(recordingId) else {
                semaphore.signal()
                return
            }
            let status = existing.statusEnum
            if status == .created || existing.meetingId != nil {
                result = .alreadyProcessed
            } else if status == .uploading || status == .creatingMeeting {
                result = .currentlyProcessing
            } else if status.isFailed {
                result = .allowRetry
            }
        } catch {
            self.logger.error("[WatchConnectivity] Error checking for duplicate: \(error)")
        }
        semaphore.signal()
    }
    // Wait with timeout to prevent indefinite blocking if main thread is busy.
    // On timeout, treat as new record and proceed (safe: worst case is a duplicate
    // that the downstream pipeline will dedup anyway).
    let waitResult = semaphore.wait(timeout: .now() + 3.0)
    if waitResult == .timedOut {
        logger.warning("[WatchConnectivity] Duplicate check timed out — proceeding as new record to avoid data loss")
        return .noExistingRecord
    }
    return result
}()

switch checkResult {
case .alreadyProcessed:
    logger.info("[WatchConnectivity] Recording already processed: \(recordingId)")
    DispatchQueue.main.async {
        self.incomingTransferProgress[recordingId] = .completed
        self.updateCachedAggregateStates()
        self.confirmRecordingsReceived([recordingId])
    }
    return

case .currentlyProcessing:
    logger.info("[WatchConnectivity] Recording currently processing: \(recordingId)")
    DispatchQueue.main.async {
        self.incomingTransferProgress[recordingId] = .receiving(progress: 1.0)
        self.updateCachedAggregateStates()
        _ = self.confirmRecordingsReceived([recordingId])
    }
    return

case .allowRetry:
    logger.info("[WatchConnectivity] Retrying failed recording: \(recordingId)")

case .noExistingRecord:
    logger.debug("🔵 [WatchConnectivity] ✅ New or retryable recording - proceeding")
}

// ========================================
// DUPLICATE DETECTION - END
// ========================================
} // end if !isChunkedTransfer

