//
//  WatchConnectivityManager.swift
//  Memorable
//
//  Created by Anshuman Sharma on 23/12/25.
//

import Foundation
import WatchConnectivity
import Combine

final class WatchConnectivityManager: NSObject, ObservableObject {

    static let shared = WatchConnectivityManager()

    /// Logger instance for connectivity-related logging
    private let logger = LoggerFactory.makeLogger()

    @Published private(set) var isSupported: Bool = WCSession.isSupported()
    @Published private(set) var activationState: WCSessionActivationState = .notActivated
    @Published public private(set) var isReachable: Bool = false
    @Published private(set) var receivedMessage: [String: Any]? = nil
    @Published private(set) var lastContext: [String: Any]? = nil
    @Published private(set) var lastError: Error? = nil

    /// Clears the last error. Call this when operations succeed to prevent stale error state.
    func clearLastError() {
        DispatchQueue.main.async {
            self.lastError = nil
        }
    }
    @Published public private(set) var isWatchConnected: Bool = false
    @Published public private(set) var isPaired: Bool = false
    @Published public private(set) var isWatchAppInstalled: Bool = false

    // Recording transfer state tracking - per-recording (no global state to support concurrent transfers)
    @Published public private(set) var lastTransferredRecordingId: UUID? = nil

    // MARK: - Constants

    /// Maximum progress increment per KVO update (5%) to smooth out progress jumps
    /// Prevents jarring UI updates when progress jumps forward rapidly
    private static let maxProgressIncrement: Double = 0.05

    /// Delay in seconds before auto-removing completed transfers from UI
    /// Gives users time to see the completion state before it disappears
    private static let completedTransferAutoRemoveDelay: TimeInterval = 3.0

    #if os(watchOS)
    // Transfer progress per recording ID (0.0 to 1.0)
    // CRITICAL: @Published properties must be accessed on main thread
    // All mutations happen on main thread via DispatchQueue.main.async
    @Published private(set) var recordingTransferProgress: [UUID: Double] = [:]

    /// Cached aggregate transfer state (updated when progress changes)
    /// Avoids deadlock risk from DispatchQueue.main.sync
    @Published public private(set) var cachedAggregateTransferState: RecordingTransferState = .idle

    /// Internal helper to compute aggregate state (must be called on main thread)
    private func computeAggregateState() -> RecordingTransferState {
        assert(Thread.isMainThread, "computeAggregateState must be called on main thread")

        if recordingTransferProgress.isEmpty {
            return .idle
        }

        // Find max progress and any failures
        let progressValues = recordingTransferProgress.values
        if let maxProgress = progressValues.max() {
            if maxProgress >= 1.0 && progressValues.allSatisfy({ $0 >= 1.0 }) {
                return .completed
            }
            return .transferring(progress: maxProgress)
        }

        return .idle
    }
    #endif

    #if os(iOS)
    /// Whether the Watch has granted microphone permission (synced via application context)
    /// `nil` means we haven't received the status from the Watch yet
    @Published public private(set) var watchMicrophonePermissionGranted: Bool? = nil

    /// True when the Watch has started recording and has not yet stopped (iPhone shows Live Activity / banner).
    @Published public private(set) var isRecordingOnWatch: Bool = false

    /// When recording started on Watch (for elapsed time in Live Activity). Nil when not recording.
    @Published public private(set) var recordingStartedAt: Date? = nil

    /// True when `isRecordingOnWatch` was set from cached activation context (potentially stale).
    /// Observers should treat this as unconfirmed and avoid side-effects like notifications
    /// until fresh context arrives (at which point this becomes `false`).
    @Published public private(set) var isRecordingStateFromActivation: Bool = false

    /// Sentinel UUID for placeholder pending transfers (never maps to real recordings)
    /// Public so WatchRecordingService can filter it out from UI
    public static let pendingPlaceholderID = UUID(uuidString: "00000000-0000-0000-0000-000000000001")!

    /// State tracking for incoming transfers from watch (per-recording)
    /// Tracks state transitions and progress for real-time updates
    public enum IncomingTransferState: Equatable {
        case pending          // Transfer announced but not started (hasContentPending = true)
        case receiving(progress: Double?)  // File is being received (with optional progress 0.0-1.0)
        case completed        // Transfer complete and saved
        case failed(String)   // Transfer failed with error message

        public static func == (lhs: IncomingTransferState, rhs: IncomingTransferState) -> Bool {
            switch (lhs, rhs) {
            case (.pending, .pending), (.completed, .completed):
                return true
            case (.receiving(let lhsProgress), .receiving(let rhsProgress)):
                // Compare progress values (with small tolerance for floating point)
                if let lhs = lhsProgress, let rhs = rhsProgress {
                    return abs(lhs - rhs) < 0.001
                }
                return lhsProgress == nil && rhsProgress == nil
            case (.failed(let lhsError), .failed(let rhsError)):
                return lhsError == rhsError
            default:
                return false
            }
        }
    }

    // Track incoming transfers from watch (per-recording progress state)
    // CRITICAL: @Published properties must be accessed on main thread
    @Published public private(set) var incomingTransferProgress: [UUID: IncomingTransferState] = [:]

    /// Last timestamp when incoming progress changed for a recording.
    /// Used to detect stale "stuck at X%" progress entries coming from cached context.
    private var incomingProgressLastChangeAt: [UUID: Date] = [:]

    /// Last known incoming progress value per recording.
    private var incomingProgressLastValue: [UUID: Double] = [:]

    /// Recordings whose stale progress has been timed out and should not be re-added
    /// from repeated cached context updates unless progress meaningfully changes.
    private var suppressedStaleIncomingProgressIds: Set<UUID> = []

    /// Shared timeout policy (3 minutes per 30 minutes of recording duration).
    private let transferTimeoutPolicy = TransferTimeoutPolicy.default

    /// Cached aggregate state of all incoming transfers (updated when state changes)
    /// Avoids deadlock risk from DispatchQueue.main.sync
    @Published public private(set) var cachedAggregateIncomingTransferState: RecordingTransferState = .idle

    /// Internal helper to compute aggregate incoming transfer state (must be called on main thread)
    private func computeAggregateIncomingState() -> RecordingTransferState {
        assert(Thread.isMainThread, "computeAggregateIncomingState must be called on main thread")

        // Filter out placeholder UUID (sentinel value)
        let realTransfers = incomingTransferProgress.filter { $0.key != Self.pendingPlaceholderID }

        if realTransfers.isEmpty {
            return .idle
        }

        // Check for any failures
        for state in realTransfers.values {
            if case .failed(let error) = state {
                return .failed(error)
            }
        }

        // Check if all are completed
        let allCompleted = realTransfers.values.allSatisfy { state in
            if case .completed = state {
                return true
            }
            return false
        }

        if allCompleted {
            return .completed
        }

        // Find max progress from receiving transfers
        var maxProgress: Double = 0.0
        var hasActive = false

        for state in realTransfers.values {
            if case .pending = state {
                hasActive = true
            } else if case .receiving(let progress) = state {
                hasActive = true
                if let progress = progress {
                    maxProgress = max(maxProgress, progress)
                }
            }
        }

        if hasActive {
            // Use actual progress if available, otherwise use 0.5 as placeholder
            let displayProgress = maxProgress > 0 ? maxProgress : 0.5
            return .transferring(progress: displayProgress)
        }

        return .idle
    }
    #endif

    /// Updates cached aggregate states on main thread (called when progress/state changes)
    /// Available on both watchOS and iOS - updates platform-specific cached state
    private func updateCachedAggregateStates() {
        DispatchQueue.main.async { [weak self] in
            guard let self = self else { return }
            #if os(watchOS)
            self.cachedAggregateTransferState = self.computeAggregateState()
            #else
            self.cachedAggregateIncomingTransferState = self.computeAggregateIncomingState()
            #endif
        }
    }

    // Callback for when a recording transfer completes (used by watchOS to delete local copy)
    public var onTransferComplete: ((UUID, Bool) -> Void)?

    // Callback for when iOS receives a recording file
    // Uses Result type to propagate errors (e.g., file copy failures)
    public var onRecordingReceived: ((Result<(URL, RecordingTransferMetadata), Error>) -> Void)?

    // Cached application context (thread-safe, updated on main thread)
    // Used instead of reading session.receivedApplicationContext directly from background threads
    @Published private var cachedApplicationContext: [String: Any] = [:]

    /// Thread-safe access to cached application context
    /// CRITICAL: Must be accessed from main thread only to avoid deadlocks
    /// @Published properties are main-thread only, so this getter enforces that requirement
    var applicationContext: [String: Any] {
        dispatchPrecondition(condition: .onQueue(.main))
        return cachedApplicationContext
    }

    /// Safely retrieves cached application context, ensuring main thread access
    /// This method should only be called from contexts where you can guarantee main thread execution
    /// or where async dispatch is acceptable. For synchronous access from main thread, use applicationContext property directly.
    /// - Returns: The cached application context, or lastContext if cached is empty
    private func getCachedApplicationContextSafely() -> [String: Any] {
        dispatchPrecondition(condition: .onQueue(.main))
        let context = cachedApplicationContext
        return context.isEmpty ? (lastContext ?? [:]) : context
    }

    private let session: WCSession?
    private let watchConnectivityQueue = DispatchQueue(label: "com.memorable.watchconnectivity")

    // Thread-safe queue for transfer state management
    // All access to pendingTransfers, progressObservers, and recordingTransferProgress must go through this queue
    private let transferStateQueue = DispatchQueue(
        label: "com.memorable.watchconnectivity.transferstate",
        qos: .userInitiated
    )

    // Pending file transfers keyed by recording ID (watchOS only, single-file transfers)
    // All access must be through transferStateQueue
    private var pendingTransfers: [UUID: WCSessionFileTransfer] = [:]

    #if os(watchOS)
    // KVO observers for progress tracking keyed by recording ID (single-file transfers)
    // All access must be through transferStateQueue
    private var progressObservers: [UUID: NSKeyValueObservation] = [:]

    // MARK: - Multi-Chunk Transfer Tracking
    // Parallel tracking system for chunked recordings. Each chunk has its own
    // WCSessionFileTransfer, keyed by ObjectIdentifier for precise matching.

    /// Maps each chunk's WCSessionFileTransfer to its parent recording + chunk index
    private var chunkTransfers: [ObjectIdentifier: (recordingId: UUID, chunkIndex: Int)] = [:]

    /// Total expected chunk count per recording (set when isLastChunk is seen)
    private var recordingChunkCounts: [UUID: Int] = [:]

    /// Chunk indices that have been successfully delivered per recording
    private var recordingCompletedChunks: [UUID: Set<Int>] = [:]

    /// Current progress (0.0–1.0) for each chunk, used to compute aggregate progress
    private var chunkProgressValues: [UUID: [Int: Double]] = [:]

    /// Per-chunk KVO observers (keyed by ObjectIdentifier of the transfer)
    private var chunkProgressObservers: [ObjectIdentifier: NSKeyValueObservation] = [:]

    // Reference to repository for Core Data updates (watchOS)
    private var repository: LocalRecordingRepository?

    /// Set of processed confirmation keys (`recordingId|phase`) for idempotency.
    /// This lets us process both `received` and `processed` confirmations exactly once.
    private var processedConfirmationKeys = Set<String>()

    /// Sets the repository for Core Data status updates (watchOS only)
    /// Call this during watch app initialization
    func setRepository(_ repo: LocalRecordingRepository) {
        self.repository = repo
    }

    /// Clears the processed confirmations set (call on logout or when starting fresh)
    /// This allows re-processing of confirmations after a fresh start
    func clearProcessedConfirmations() {
        processedConfirmationKeys.removeAll()
        logger.info("[WatchConnectivity] Cleared processed confirmations set")
    }
    #endif

    #if os(iOS)
    // Reference to metadata repository for duplicate detection (iOS)
    private var metadataRepository: RecordingMetadataRepository?

    /// Sets the metadata repository for duplicate detection (iOS only)
    /// Call this during iOS app initialization
    func setMetadataRepository(_ repo: RecordingMetadataRepository) {
        self.metadataRepository = repo
    }
    #endif

    private override init() {
        guard WCSession.isSupported() else {
            session = nil
            super.init()
            return
        }

        session = WCSession.default
        super.init()

        session?.delegate = self
        session?.activate()

        // Initialize cached context if session is already activated
        if let session = session, session.activationState == .activated {
            DispatchQueue.main.async { [weak self] in
                self?.cachedApplicationContext = session.receivedApplicationContext
                self?.lastContext = session.receivedApplicationContext
            }
        }
    }

    deinit {
        #if os(watchOS)
        // Clean up all KVO observers
        transferStateQueue.sync {
            for observer in progressObservers.values {
                observer.invalidate()
            }
            progressObservers.removeAll()

            for observer in chunkProgressObservers.values {
                observer.invalidate()
            }
            chunkProgressObservers.removeAll()
            chunkTransfers.removeAll()
            recordingChunkCounts.removeAll()
            recordingCompletedChunks.removeAll()
            chunkProgressValues.removeAll()
        }
        #endif
    }

    /// Flag to track if we've done initial status logging (to avoid duplicate logs)
    private var hasLoggedInitialStatus: Bool = false

    /// Updates connection status from session properties.
    /// NOTE: Must be called from main thread (already dispatched in call sites).
    /// WCSession properties are accessed on main thread as per Apple's documentation.
    private func updateConnectionStatus() {
        dispatchPrecondition(condition: .onQueue(.main))

        guard let session = self.session else { return }

            // Read all session properties on main queue (they're UI-related)
            #if os(iOS)
            self.isPaired = session.isPaired
            self.isWatchAppInstalled = session.isWatchAppInstalled
            self.isWatchConnected = session.isPaired && session.isWatchAppInstalled

        // Check for pending content - files being transferred from watch
        // Note: We can't get specific metadata until files arrive, so we show generic "pending" state
        // Store placeholder UUID in a property to track it
        let placeholderId = Self.pendingPlaceholderID
        let hasRealTransfers = incomingTransferProgress.keys.contains { $0 != placeholderId }

        if session.hasContentPending {
            // There are pending files but we don't know which recordings yet
            // We'll update to specific states when files arrive in session(_:didReceive:)
            // Check if we already have a pending placeholder
            let hasPendingPlaceholder = incomingTransferProgress[placeholderId] != nil

            // Only add placeholder if:
            // 1. We don't already have one
            // 2. We have no real transfers (only add if truly empty)
            if !hasPendingPlaceholder && !hasRealTransfers {
                incomingTransferProgress[placeholderId] = .pending
                updateCachedAggregateStates()
                logger.debug("[WatchConnectivity] Added placeholder for pending content")
            } else if hasPendingPlaceholder && hasRealTransfers {
                // We have real transfers now, remove placeholder
                incomingTransferProgress.removeValue(forKey: placeholderId)
                updateCachedAggregateStates()
                logger.debug("[WatchConnectivity] Removed placeholder - real transfers exist")
            }
        } else {
            // No pending content - always remove placeholder if it exists
            if incomingTransferProgress[placeholderId] != nil {
                incomingTransferProgress.removeValue(forKey: placeholderId)
                updateCachedAggregateStates()
                logger.debug("[WatchConnectivity] Removed placeholder - no pending content")
            }
        }

        // Periodic cleanup: Remove old completed transfers to prevent accumulation.
        // Keep `.receiving(100%)` entries so they remain actionable if they stall.
        let transfersToCleanup = incomingTransferProgress.keys.filter { id in
            if id == placeholderId { return false } // Don't remove placeholder here

            // Remove completed transfers
            if case .completed = incomingTransferProgress[id] { return true }

            return false
        }

        // Aggressively clean up completed transfers.
        if !transfersToCleanup.isEmpty {
            for id in transfersToCleanup {
                incomingTransferProgress.removeValue(forKey: id)
                logger.debug("[WatchConnectivity] Periodic cleanup: Removed completed transfer: \(id)")
            }
            updateCachedAggregateStates()
        }
            #else
            // On watchOS
            self.isWatchConnected = session.isCompanionAppInstalled
            #endif

            self.isReachable = session.isReachable
    }

    // MARK: - Send Message (SAFE)

    func sendMessage(
        _ message: [String: Any],
        replyHandler: (([String: Any]) -> Void)? = nil,
        completion: ((Error?) -> Void)? = nil
    ) {
        guard let session else {
            completion?(WatchConnectivityError.notSupported)
            return
        }

        guard activationState == .activated else {
            completion?(WatchConnectivityError.notActivated)
            return
        }

        guard session.isReachable else {
            completion?(WatchConnectivityError.notReachable)
            return
        }

        watchConnectivityQueue.async {
            session.sendMessage(
                message,
                replyHandler: { reply in
                    DispatchQueue.main.async {
                        replyHandler?(reply)
                        completion?(nil)
                    }
                },
                errorHandler: { error in
                    DispatchQueue.main.async {
                        self.lastError = error
                        completion?(error)
                    }
                }
            )
        }
    }

    // MARK: - Application Context

    func updateApplicationContext(
        _ context: [String: Any],
        completion: ((Error?) -> Void)? = nil
    ) {
        guard let session else {
            completion?(WatchConnectivityError.notSupported)
            return
        }

        watchConnectivityQueue.async {
            do {
                try session.updateApplicationContext(context)
                DispatchQueue.main.async {
                    // Update cached context on main thread
                    self.cachedApplicationContext = context
                    self.lastContext = context
                    completion?(nil)
                }
            } catch {
                DispatchQueue.main.async {
                    self.lastError = error
                    completion?(error)
                }
            }
        }
    }
}

// MARK: - WCSessionDelegate

extension WatchConnectivityManager: WCSessionDelegate {

    func session(
        _ session: WCSession,
        activationDidCompleteWith activationState: WCSessionActivationState,
        error: Error?
    ) {
        DispatchQueue.main.async {
            self.activationState = activationState
            self.isReachable = session.isReachable
            self.lastError = error
            self.isSupported = true

            #if os(iOS)
            let platform = "📱 [iOS]"
            #else
            let platform = "⌚ [watchOS]"
            #endif

            self.logger.info("\(platform) WatchConnectivity session activated (state: \(activationState.rawValue))")

            // Initialize cached context on main thread (thread-safe)
            self.cachedApplicationContext = session.receivedApplicationContext
            self.lastContext = session.receivedApplicationContext

            if let error = error {
                self.logger.error("\(platform) ❌ Activation error: \(error.localizedDescription)", error: error)
            }

            // NEW: Update status and start monitoring
            self.updateConnectionStatus()
            if activationState == .activated {
                #if os(watchOS)
                self.restorePendingTransfers()
                #endif
                #if os(iOS)
                // Parse recording-on-Watch from initial context (e.g. Watch already recording at launch).
                // Marked as activation context so downstream observers defer notifications until
                // fresh context from the Watch confirms the recording state.
                self.handleRecordingOnWatchContext(session.receivedApplicationContext, isFromActivation: true)
                // Parse microphone permission from initial context
                self.handleWatchMicrophonePermissionContext(session.receivedApplicationContext)

                // Process any transfer progress already in the cached context.
                // Without this, the UI stays blank until the Watch sends its next
                // applicationContext update (at the next 5% threshold), causing a
                // visible delay between "Uploading to iPhone" on Watch and the
                // transfer card appearing on iPhone.
                self.handleReceivedProgressUpdates(session.receivedApplicationContext)

                // If cached context says recording is active, ask the Watch to re-send
                // its current state so we can confirm (or correct) the potentially stale value.
                if self.isRecordingOnWatch {
                    self.requestWatchRecordingStateCheck()
                }
                #endif
            }
        }
    }

    func sessionReachabilityDidChange(_ session: WCSession) {
        DispatchQueue.main.async {
            self.isReachable = session.isReachable
            self.updateConnectionStatus()
        }
    }

    func session(_ session: WCSession, didReceiveMessage message: [String : Any]) {
        DispatchQueue.main.async {
            self.receivedMessage = message

            #if os(watchOS)
            // Handle microphone permission re-check request from iPhone
            if message[WatchMessageKey.requestMicrophonePermissionCheck] as? Bool == true {
                self.logger.info("[WatchConnectivity] Received mic permission re-check request from iPhone")
                NotificationCenter.default.post(name: .watchShouldRecheckMicrophonePermission, object: nil)
            }

            // Handle recording state re-sync request from iPhone
            // iPhone sends this on session activation to verify that cached isRecordingOnWatch is still accurate.
            if message[WatchMessageKey.requestRecordingStateCheck] as? Bool == true {
                self.logger.info("[WatchConnectivity] Received recording state check request from iPhone")
                NotificationCenter.default.post(name: .watchShouldResyncRecordingState, object: nil)
            }

            // Handle transfer acknowledgment from iPhone
            if let action = message[WatchMessageKey.action] as? String {
                if action == WatchMessageKey.actionTransferAcknowledged {
                    self.logger.info("[WatchConnectivity] iPhone acknowledged transfer readiness")
                    NotificationCenter.default.post(name: .iPhoneTransferAcknowledged, object: nil, userInfo: message)
                }

                // Handle request to open iPhone app
                if action == WatchMessageKey.actionOpenIPhoneApp {
                    self.logger.info("[WatchConnectivity] iPhone requests user to open iPhone app")
                    NotificationCenter.default.post(name: .iPhoneRequestsOpenApp, object: nil, userInfo: message)
                }

                if action == WatchMessageKey.actionRetryTransferRequest {
                    self.logger.info("[WatchConnectivity] iPhone requested transfer retry")
                    NotificationCenter.default.post(name: .iPhoneRequestedTransferRetry, object: nil, userInfo: message)
                }
            }
            #endif

            #if os(iOS)
            // Handle Watch transfer coordination messages
            if let action = message[WatchMessageKey.action] as? String {
                switch action {
                case WatchMessageKey.actionPrepareForTransfer:
                    // Watch is about to send chunks -- acknowledge readiness
                    self.logger.info("[WatchConnectivity] Watch preparing to transfer, sending acknowledgment")
                    NotificationCenter.default.post(name: .watchPreparingTransfer, object: nil, userInfo: message)

                case WatchMessageKey.actionCleanupPartials:
                    // Watch hit complete-fail -- clean up partial data
                    if let recordingIdString = message[WatchMessageKey.recordingId] as? String {
                        self.logger.info("[WatchConnectivity] Watch requested cleanup of partials for: \(recordingIdString)")
                        NotificationCenter.default.post(name: .watchRequestedCleanup, object: nil, userInfo: message)
                    }

                default:
                    self.logger.debug("[WatchConnectivity] Unknown action from Watch: \(action)")
                }
            }
            #endif
        }
    }

    func session(_ session: WCSession, didReceiveApplicationContext applicationContext: [String : Any]) {
        DispatchQueue.main.async {
            // Update cached context on main thread (thread-safe access)
            self.cachedApplicationContext = applicationContext
            self.lastContext = applicationContext

            #if os(watchOS)
            // Handle authentication token sync on watchOS
            self.handleReceivedAuthContext(applicationContext)

            // Handle recording transfer confirmations (legacy -- kept for backward compatibility)
            self.handleTransferConfirmation(applicationContext)

            // Handle iOS processing status updates
            self.handleiOSProcessingStatusUpdates(applicationContext)
            #endif

            #if os(iOS)
            // Handle transfer progress updates from watch
            self.handleReceivedProgressUpdates(applicationContext)
            // Handle recording-on-Watch indicator (for Live Activity and Profile banner)
            self.handleRecordingOnWatchContext(applicationContext)
            // Handle microphone permission status from watch
            self.handleWatchMicrophonePermissionContext(applicationContext)
            #endif
        }
    }

    /// Called when user info is received via transferUserInfo (queued delivery).
    /// Confirmations are now sent via transferUserInfo instead of applicationContext
    /// to ensure guaranteed delivery without being overwritten by other context updates.
    func session(_ session: WCSession, didReceiveUserInfo userInfo: [String: Any] = [:]) {
        DispatchQueue.main.async {
            #if os(watchOS)
            // Handle recording transfer confirmations delivered via transferUserInfo.
            // This is the preferred path -- applicationContext confirmations are kept
            // only for backward compatibility with older iOS app versions.
            self.handleTransferConfirmation(userInfo)
            #endif

            #if os(iOS)
            // Currently no iOS-side handling needed for transferUserInfo from Watch.
            // Watch uses applicationContext for progress updates (last-value-wins is fine for progress).
            self.logger.debug("[WatchConnectivity] Received transferUserInfo on iOS: \(userInfo.keys)")
            #endif
        }
    }

    #if os(iOS)
    func sessionDidBecomeInactive(_ session: WCSession) {
        DispatchQueue.main.async {
            self.updateConnectionStatus()
        }
    }

    func sessionDidDeactivate(_ session: WCSession) {
        session.activate()
    }

    // NEW: Track watch state changes
    func sessionWatchStateDidChange(_ session: WCSession) {
        DispatchQueue.main.async {
            self.updateConnectionStatus()
        }
    }
    #endif
}

// MARK: - Errors

enum WatchConnectivityError: LocalizedError {
    case notSupported
    case notReachable
    case notActivated

    var errorDescription: String? {
        switch self {
        case .notSupported:
            return AppSharedText.notSupported
        case .notReachable:
            return AppSharedText.notReachable
        case .notActivated:
            return AppSharedText.notActivated
        }
    }
}

public enum WatchConnectionVisualState {
    case notPaired
    case pairedNotReachable
    case reachable
}

// MARK: - Context Keys for Watch Communication
/// Keys used for application context communication between iOS and watchOS
enum WatchContextKey {
    static let accessToken = "accessToken"
    static let isAuthenticated = "isAuthenticated"

    // User identity keys (synced from iOS after fetchMe)
    static let userId = "userId"
    static let userEmail = "userEmail"

    // Recording transfer keys
    static let transferredRecordingIds = "transferredRecordingIds"
    static let transferredRecordingAckPhase = "transferredRecordingAckPhase"
    static let pendingDeletions = "pendingDeletions"

    // Transfer progress keys (watch -> iOS)
    static let transferProgressUpdates = "transferProgressUpdates" // Dictionary: [recordingId: progress]
    static let transferMetadata = "transferMetadata" // Dictionary: [recordingId: metadataDict]

    // Recording-on-Watch indicator (watch -> iOS)
    static let isRecordingOnWatch = "isRecordingOnWatch"
    static let recordingStartedAt = "recordingStartedAt"

    // Microphone permission status (watch -> iOS)
    // Synced so the iPhone can gate the user until mic permission is granted on the Watch
    static let microphonePermissionGranted = "microphonePermissionGranted"
}

/// Phase of iPhone -> Watch transfer confirmation.
/// - `received`: iPhone durably received/saved transfer payload.
/// - `processed`: iPhone finished downstream processing (upload + meeting creation).
enum RecordingTransferConfirmationPhase: String {
    case received
    case processed
}

// MARK: - Recording Transfer Metadata

/// Metadata sent alongside recording file transfers from watch to iOS
/// This struct is Codable to allow serialization in the file transfer metadata dictionary
public struct RecordingTransferMetadata: Codable {
    public let id: UUID
    public let filename: String
    public let duration: TimeInterval
    public let createdAt: Date
    /// When the recording actually started (for sending to backend)
    public let startTime: Date

    /// Optional chunk information. When nil, this is a legacy single-file transfer.
    /// When present, this file is one chunk of a larger recording that will be
    /// assembled on the iPhone before upload.
    public let chunkInfo: ChunkTransferMetadata?

    /// True if this transfer is part of a chunked recording
    public var isChunked: Bool {
        return chunkInfo != nil
    }

    public init(id: UUID, filename: String, duration: TimeInterval, createdAt: Date, startTime: Date, chunkInfo: ChunkTransferMetadata? = nil) {
        self.id = id
        self.filename = filename
        self.duration = duration
        self.createdAt = createdAt
        self.startTime = startTime
        self.chunkInfo = chunkInfo
    }

    /// Converts the metadata to a dictionary for WCSession file transfer
    func toDictionary() -> [String: Any] {
        var dict: [String: Any] = [
            "id": id.uuidString,
            "filename": filename,
            "duration": duration,
            "createdAt": createdAt.timeIntervalSince1970,
            "startTime": startTime.timeIntervalSince1970
        ]

        // Include chunk info if this is a chunked transfer
        if let chunkInfo = chunkInfo {
            dict["chunkInfo"] = chunkInfo.toDictionary()
        }

        return dict
    }

    /// Creates metadata from a dictionary received via WCSession file transfer
    static func fromDictionary(_ dict: [String: Any]) -> RecordingTransferMetadata? {
        guard let idString = dict["id"] as? String,
              let id = UUID(uuidString: idString),
              let filename = dict["filename"] as? String,
              let duration = dict["duration"] as? TimeInterval,
              let createdAtTimestamp = dict["createdAt"] as? TimeInterval else {
            return nil
        }

        // Use startTime if available, otherwise fallback to createdAt for backwards compatibility
        let startTimeTimestamp = dict["startTime"] as? TimeInterval ?? createdAtTimestamp

        return RecordingTransferMetadata(
            id: id,
            filename: filename,
            duration: duration,
            createdAt: Date(timeIntervalSince1970: createdAtTimestamp),
            startTime: Date(timeIntervalSince1970: startTimeTimestamp),
            chunkInfo: ChunkTransferMetadata.fromDictionary(dict["chunkInfo"] as? [String: Any])
        )
    }
}

// MARK: - Chunk Transfer Metadata

/// Metadata for a single chunk of a longer recording that has been split
/// for reliable transfer. When `chunkInfo` is nil on `RecordingTransferMetadata`,
/// the transfer is a legacy single-file recording (backward compatible).
public struct ChunkTransferMetadata: Codable {
    /// The logical recording ID that all chunks belong to
    public let parentRecordingId: UUID

    /// Unique ID for this specific chunk
    public let chunkId: UUID

    /// 0-based index indicating the order of this chunk in the recording
    public let chunkIndex: Int

    /// True if this is the final chunk (recording has stopped)
    public let isLastChunk: Bool

    /// Duration of audio in this specific chunk (seconds)
    public let chunkDuration: TimeInterval

    /// Total accumulated recording duration including this chunk (seconds)
    public let totalDurationSoFar: TimeInterval

    /// When the overall recording started (not when this chunk started)
    public let recordingStartTime: Date

    public init(
        parentRecordingId: UUID,
        chunkId: UUID,
        chunkIndex: Int,
        isLastChunk: Bool,
        chunkDuration: TimeInterval,
        totalDurationSoFar: TimeInterval,
        recordingStartTime: Date
    ) {
        self.parentRecordingId = parentRecordingId
        self.chunkId = chunkId
        self.chunkIndex = chunkIndex
        self.isLastChunk = isLastChunk
        self.chunkDuration = chunkDuration
        self.totalDurationSoFar = totalDurationSoFar
        self.recordingStartTime = recordingStartTime
    }

    /// Converts to dictionary for WCSession file transfer metadata
    func toDictionary() -> [String: Any] {
        return [
            "parentRecordingId": parentRecordingId.uuidString,
            "chunkId": chunkId.uuidString,
            "chunkIndex": chunkIndex,
            "isLastChunk": isLastChunk,
            "chunkDuration": chunkDuration,
            "totalDurationSoFar": totalDurationSoFar,
            "recordingStartTime": recordingStartTime.timeIntervalSince1970
        ]
    }

    /// Creates from dictionary received via WCSession file transfer
    static func fromDictionary(_ dict: [String: Any]?) -> ChunkTransferMetadata? {
        guard let dict = dict,
              let parentIdString = dict["parentRecordingId"] as? String,
              let parentId = UUID(uuidString: parentIdString),
              let chunkIdString = dict["chunkId"] as? String,
              let chunkId = UUID(uuidString: chunkIdString),
              let chunkIndex = dict["chunkIndex"] as? Int,
              let isLastChunk = dict["isLastChunk"] as? Bool,
              let chunkDuration = dict["chunkDuration"] as? TimeInterval,
              let totalDurationSoFar = dict["totalDurationSoFar"] as? TimeInterval,
              let startTimestamp = dict["recordingStartTime"] as? TimeInterval else {
            return nil
        }

        return ChunkTransferMetadata(
            parentRecordingId: parentId,
            chunkId: chunkId,
            chunkIndex: chunkIndex,
            isLastChunk: isLastChunk,
            chunkDuration: chunkDuration,
            totalDurationSoFar: totalDurationSoFar,
            recordingStartTime: Date(timeIntervalSince1970: startTimestamp)
        )
    }
}

// MARK: - Recording Transfer State

/// Represents the current state of a recording transfer
public enum RecordingTransferState: Equatable {
    case idle
    case transferring(progress: Double)
    case completed
    case failed(String)
}


extension WatchConnectivityManager {
    var visualState: WatchConnectionVisualState {
        if !isPaired {
            return .notPaired
        } else if isReachable {
            return .reachable
        } else {
            return .pairedNotReachable
        }
    }
}

// MARK: - Authentication Token Sync

extension WatchConnectivityManager {

    #if os(iOS)
    /// Syncs the access token and user identity to the paired Apple Watch via application context.
    /// The context will be delivered to the watch even if it's not immediately reachable.
    /// IMPORTANT: Preserves recording confirmations when updating auth context.
    /// - Parameters:
    ///   - token: The access token to send to the watch. Pass nil to clear the token on the watch.
    ///   - userId: The authenticated user's ID (from fetchMe). Included so watch can tag Sentry events.
    ///   - userEmail: The authenticated user's email (from fetchMe). Included so watch can tag Sentry events.
    ///   - completion: Optional completion handler called on main queue with success/failure result.
    func syncAccessToken(
        _ token: String?,
        userId: String? = nil,
        userEmail: String? = nil,
        completion: ((Result<Void, Error>) -> Void)? = nil
    ) {
        if Thread.isMainThread {
            performSyncAccessToken(token: token, userId: userId, userEmail: userEmail, completion: completion)
        } else {
            DispatchQueue.main.async { [weak self] in
                self?.performSyncAccessToken(token: token, userId: userId, userEmail: userEmail, completion: completion)
            }
        }
    }

    /// Internal method to perform access token sync (must be called on main thread)
    private func performSyncAccessToken(
        token: String?,
        userId: String?,
        userEmail: String?,
        completion: ((Result<Void, Error>) -> Void)?
    ) {
        dispatchPrecondition(condition: .onQueue(.main))

        // Get authoritative context from cached copy
        var context = getCachedApplicationContextSafely()

        // Update auth-related keys
        context[WatchContextKey.isAuthenticated] = token != nil

        if let token = token {
            context[WatchContextKey.accessToken] = token
        } else {
            context.removeValue(forKey: WatchContextKey.accessToken)
        }

        // Sync user identity for Sentry tagging on the watch
        if let userId = userId {
            context[WatchContextKey.userId] = userId
        } else {
            context.removeValue(forKey: WatchContextKey.userId)
        }
        if let userEmail = userEmail {
            context[WatchContextKey.userEmail] = userEmail
        } else {
            context.removeValue(forKey: WatchContextKey.userEmail)
        }

        // Preserve transferredRecordingIds from existing context
        // This prevents overwriting recording confirmations when auth state changes

        // Use application context for reliable delivery even when watch is not reachable
        updateApplicationContext(context) { [weak self] error in
            guard let self = self else { return }
            if let error = error {
                self.logger.error("[WatchConnectivity] Failed to sync access token: \(error.localizedDescription)", error: error)
                completion?(.failure(error))
            } else {
                self.logger.info("[WatchConnectivity] Access token synced to watch (confirmations preserved)")
                completion?(.success(()))
            }
        }
    }

    /// Clears the authentication token on the paired Apple Watch.
    /// Call this when the user signs out.
    func clearWatchAuthToken(completion: ((Result<Void, Error>) -> Void)? = nil) {
        syncAccessToken(nil, completion: completion)
    }
    #endif

    #if os(watchOS)
    /// Handles received authentication context from the iOS app.
    /// Stores or clears the access token in the watch's Keychain.
    /// - Parameter context: The application context dictionary received from iOS
    func handleReceivedAuthContext(_ context: [String: Any]) {
        let isAuthenticated = context[WatchContextKey.isAuthenticated] as? Bool ?? false

        if isAuthenticated, let token = context[WatchContextKey.accessToken] as? String {
            // Store the token securely in Keychain
            let success = WatchKeychainHelper.shared.setAccessToken(token)
            if success {
                logger.info("[WatchConnectivity] Access token received and stored successfully")
            } else {
                logger.error("[WatchConnectivity] Failed to store received access token", error: nil)
            }

            // Tag Sentry with user identity synced from iOS (from fetchMe response)
            let userId = context[WatchContextKey.userId] as? String
            let userEmail = context[WatchContextKey.userEmail] as? String
            setSentryUser(id: userId, email: userEmail)
        } else {
            // Clear the stored token (user signed out or token cleared)
            WatchKeychainHelper.shared.clearAccessToken()
            logger.info("[WatchConnectivity] Access token cleared on watch")

            // Clear Sentry user on sign-out
            logger.setUser(id: nil, email: nil)
        }

        // Post notification for any observers that need to react to auth state changes
        NotificationCenter.default.post(
            name: .watchAuthStateDidChange,
            object: nil,
            userInfo: [WatchContextKey.isAuthenticated: isAuthenticated]
        )
    }

    /// Sets the Sentry user identity on the watch side.
    /// Called when auth context is received from iOS and on app launch from cached context.
    func setSentryUser(id: String?, email: String?) {
        guard id != nil else {
            logger.warning("[WatchConnectivity] No userId available for Sentry tagging")
            return
        }

        logger.setUser(id: id, email: email)
        logger.info("[WatchConnectivity] Sentry user set: id=\(id ?? "nil")")
    }

    /// Retrieves the currently stored access token on the watch
    /// - Returns: The stored access token, or nil if not available
    func getStoredAccessToken() -> String? {
        return WatchKeychainHelper.shared.getAccessToken()
    }

    /// Checks if the watch has a valid access token
    var hasAccessToken: Bool {
        return WatchKeychainHelper.shared.hasAccessToken
    }

    /// Handles iOS processing status updates
    /// Called when iOS sends recording processing status via application context
    func handleiOSProcessingStatusUpdates(_ context: [String: Any]) {
        guard let statuses = context["recordingProcessingStatuses"] as? [String: [String: Any]] else {
            return
        }

        for (idString, statusPayload) in statuses {
            guard let recordingId = UUID(uuidString: idString),
                  let statusName = statusPayload["status"] as? String else {
                continue
            }

            let meetingId = statusPayload["meetingId"] as? String
            let uploadProgress = statusPayload["uploadProgress"] as? Double

            let progressStr = uploadProgress.map { " (\(Int($0 * 100))%)" } ?? ""
            logger.info("[WatchConnectivity] Received iOS status update: \(recordingId) -> \(statusName)\(progressStr)")

            // Update local Core Data via notification
            NotificationCenter.default.post(
                name: .iosProcessingStatusUpdated,
                object: nil,
                userInfo: [
                    "recordingId": recordingId,
                    "status": statusName,
                    "uploadProgress": uploadProgress as Any,
                    "meetingId": meetingId as Any
                ]
            )
        }
    }
    #endif
}

// MARK: - Notifications

extension Notification.Name {
    /// Posted when the watch's authentication state changes (token received or cleared)
    static let watchAuthStateDidChange = Notification.Name("watchAuthStateDidChange")

    /// Posted when a recording transfer completes (watch side)
    static let recordingTransferDidComplete = Notification.Name("recordingTransferDidComplete")

    /// Posted when a recording is received from watch (iOS side)
    static let recordingDidReceiveFromWatch = Notification.Name("recordingDidReceiveFromWatch")

    /// Posted when iOS processing status is updated (watch side)
    static let iosProcessingStatusUpdated = Notification.Name("iosProcessingStatusUpdated")

    /// Posted when watch recording transfer is confirmed (watch side)
    static let watchRecordingTransferConfirmed = Notification.Name("watchRecordingTransferConfirmed")

    /// Posted when the iPhone requests the Watch to re-check its microphone permission (watch side)
    /// Observers (e.g. AudioPermissionManager) should call checkPermissionStatus() when this fires
    static let watchShouldRecheckMicrophonePermission = Notification.Name("watchShouldRecheckMicrophonePermission")

    /// Posted when iOS confirms the entire recording has been assembled and uploaded (watch side).
    /// For chunked recordings, the Watch should only delete local chunk files when this
    /// notification is received (not per-chunk). UserInfo contains "parentRecordingId" (UUID).
    static let fullRecordingConfirmed = Notification.Name("fullRecordingConfirmed")

    // MARK: - Transfer Coordination Notifications

    /// Posted on Watch when iPhone acknowledges it is ready to receive chunks
    static let iPhoneTransferAcknowledged = Notification.Name("iPhoneTransferAcknowledged")

    /// Posted on Watch when iPhone asks the user to open the iPhone app
    static let iPhoneRequestsOpenApp = Notification.Name("iPhoneRequestsOpenApp")

    /// Posted on Watch when iPhone requests retry of a transfer.
    /// UserInfo contains `WatchMessageKey.recordingId`.
    static let iPhoneRequestedTransferRetry = Notification.Name("iPhoneRequestedTransferRetry")

    /// Posted on iPhone when Watch is preparing to send chunks (metadata-only message)
    static let watchPreparingTransfer = Notification.Name("watchPreparingTransfer")

    /// Posted on iPhone when Watch requests cleanup of partial chunk data (complete fail)
    static let watchRequestedCleanup = Notification.Name("watchRequestedCleanup")

    /// Posted on Watch when iPhone requests fresh recording state (to verify stale activation context).
    /// WatchRecordingViewModel should observe this and re-send its current recording indicator.
    static let watchShouldResyncRecordingState = Notification.Name("watchShouldResyncRecordingState")
}

// MARK: - Message Keys for Watch Communication
/// Keys used for sendMessage-based communication (requires reachability)
enum WatchMessageKey {
    /// iPhone → Watch: Asks the Watch to re-check its microphone permission and sync back
    /// Sent when the iPhone app returns to foreground (e.g. user changed permission in Settings)
    static let requestMicrophonePermissionCheck = "requestMicrophonePermissionCheck"

    // MARK: - Transfer Coordination Keys

    /// Watch → iPhone: "action" key for message routing
    static let action = "action"

    /// Watch → iPhone: Sends recording metadata before chunk transfer begins.
    /// iPhone should respond with acknowledgment when ready to receive.
    static let actionPrepareForTransfer = "prepareForTransfer"

    /// Watch → iPhone: Tells iPhone to delete all partial chunks and metadata
    /// for a recording that hit the complete-fail state.
    static let actionCleanupPartials = "cleanupPartials"

    /// iPhone → Watch: Tells the Watch user to open the iPhone app
    /// (e.g., when background upload cannot proceed)
    static let actionOpenIPhoneApp = "openIPhoneApp"

    /// iPhone → Watch: Asks Watch to retry/resend a recording transfer.
    static let actionRetryTransferRequest = "retryTransferRequest"

    /// iPhone → Watch: Asks the Watch to re-send its current recording state via application context.
    /// Sent on session activation to verify whether cached `isRecordingOnWatch` is still accurate.
    static let requestRecordingStateCheck = "requestRecordingStateCheck"

    /// iPhone → Watch: Acknowledgment that iPhone is ready to receive chunks
    static let actionTransferAcknowledged = "transferAcknowledged"

    /// Key for recording ID in messages
    static let recordingId = "recordingId"

    /// Key for total chunk count in metadata messages
    static let totalChunks = "totalChunks"

    /// Key for total duration in metadata messages
    static let totalDuration = "totalDuration"
}

// MARK: - Microphone Permission Sync

extension WatchConnectivityManager {

    #if os(watchOS)
    /// Syncs the Watch's microphone permission status to the paired iPhone via application context
    /// Called whenever the microphone permission changes on the Watch (grant, deny, or initial check)
    /// - Parameter granted: Whether microphone permission is currently granted on the Watch
    func syncMicrophonePermissionStatus(granted: Bool) {
        // Must be called on main thread for getCachedApplicationContextSafely()
        if Thread.isMainThread {
            performSyncMicrophonePermission(granted: granted)
        } else {
            DispatchQueue.main.async { [weak self] in
                self?.performSyncMicrophonePermission(granted: granted)
            }
        }
    }

    /// Internal method to sync microphone permission (must be called on main thread)
    private func performSyncMicrophonePermission(granted: Bool) {
        dispatchPrecondition(condition: .onQueue(.main))

        // Merge into current application context to preserve other keys
        var context = getCachedApplicationContextSafely()
        context[WatchContextKey.microphonePermissionGranted] = granted

        updateApplicationContext(context) { [weak self] error in
            guard let self = self else { return }
            if let error = error {
                self.logger.error("[WatchConnectivity] Failed to sync microphone permission: \(error.localizedDescription)", error: error)
            } else {
                self.logger.info("[WatchConnectivity] Synced microphone permission to iPhone: \(granted ? "granted" : "not granted")")
            }
        }
    }
    #endif

    #if os(iOS)
    /// Handles microphone permission status received from the Watch via application context
    /// Updates the published `watchMicrophonePermissionGranted` property for UI gating
    /// - Parameter context: The application context dictionary received from the Watch
    private func handleWatchMicrophonePermissionContext(_ context: [String: Any]) {
        if let granted = context[WatchContextKey.microphonePermissionGranted] as? Bool {
            watchMicrophonePermissionGranted = granted
            logger.debug("[WatchConnectivity] Watch microphone permission: \(granted ? "granted" : "not granted")")
        }
    }

    /// Asks the Watch to re-check its microphone permission and sync the result back
    /// Call this when the iPhone app returns to foreground after the user visited Settings
    /// Uses sendMessage (requires Watch to be reachable) with application context fallback
    func requestWatchMicrophonePermissionCheck() {
        guard let session = session, activationState == .activated else {
            logger.debug("[WatchConnectivity] Cannot request mic re-check: session not active")
            return
        }

        guard session.isReachable else {
            logger.debug("[WatchConnectivity] Watch not reachable for mic re-check — will sync when Watch becomes active")
            return
        }

        let message: [String: Any] = [WatchMessageKey.requestMicrophonePermissionCheck: true]

        sendMessage(message) { [weak self] error in
            if let error = error {
                self?.logger.debug("[WatchConnectivity] Mic re-check request failed: \(error.localizedDescription)")
            } else {
                self?.logger.info("[WatchConnectivity] Sent mic permission re-check request to Watch")
            }
        }
    }

    /// Asks the Watch to re-send its current recording state via application context.
    /// Called on session activation when the cached context says recording is active,
    /// so we can confirm (or correct) the potentially stale value.
    func requestWatchRecordingStateCheck() {
        guard let session = session, activationState == .activated else {
            logger.debug("[WatchConnectivity] Cannot request recording state check: session not active")
            return
        }

        guard session.isReachable else {
            logger.debug("[WatchConnectivity] Watch not reachable for recording state check — will correct when fresh context arrives")
            return
        }

        let message: [String: Any] = [WatchMessageKey.requestRecordingStateCheck: true]

        sendMessage(message) { [weak self] error in
            if let error = error {
                self?.logger.debug("[WatchConnectivity] Recording state check request failed: \(error.localizedDescription)")
            } else {
                self?.logger.info("[WatchConnectivity] Sent recording state check request to Watch")
            }
        }
    }

    /// Requests the Watch to retry/resend a specific transfer.
    /// Watch-side queueing determines whether it starts immediately or is kept pending.
    func requestWatchTransferRetry(recordingId: UUID, completion: ((Error?) -> Void)? = nil) {
        let message: [String: Any] = [
            WatchMessageKey.action: WatchMessageKey.actionRetryTransferRequest,
            WatchMessageKey.recordingId: recordingId.uuidString
        ]
        sendMessage(message, completion: completion)
    }
    #endif
}

// MARK: - Recording File Transfer

extension WatchConnectivityManager {

    #if os(watchOS)
    /// Transfers a recording file from the watch to the iOS app.
    /// Uses WCSession.transferFile for reliable background delivery.
    /// - Parameters:
    ///   - fileURL: The URL of the recording file to transfer
    ///   - metadata: Recording metadata (id, filename, duration, createdAt)
    ///   - completion: Optional completion handler called when transfer is queued
    func transferRecording(
        fileURL: URL,
        metadata: RecordingTransferMetadata,
        completion: ((Result<Void, Error>) -> Void)? = nil
    ) {
        // Status checking is now handled by repository.canSendRecording() in ViewModel
        // before this method is called, so we don't need to check here

        guard let session = session else {
            logger.warning("[WatchConnectivity] Cannot transfer - session not available")
            completion?(.failure(WatchConnectivityError.notSupported))
            return
        }

        guard activationState == .activated else {
            logger.warning("[WatchConnectivity] Cannot transfer - session not activated")
            completion?(.failure(WatchConnectivityError.notActivated))
            return
        }

        // Verify file exists before attempting transfer
        guard FileManager.default.fileExists(atPath: fileURL.path) else {
            logger.error("[WatchConnectivity] Cannot transfer - file does not exist: \(fileURL.path)", error: nil)
            completion?(.failure(RecordingTransferError.fileNotFound))
            return
        }

        // Verify file is not empty (check file size)
        do {
            let fileAttributes = try FileManager.default.attributesOfItem(atPath: fileURL.path)
            if let fileSize = fileAttributes[.size] as? Int64, fileSize == 0 {
                logger.warning("[WatchConnectivity] Cannot transfer - file is empty (0 bytes): \(fileURL.path)")
                completion?(.failure(RecordingTransferError.fileNotFound))
                return
            }
        } catch {
            logger.error("[WatchConnectivity] ⚠️ Warning: Could not verify file size: \(error.localizedDescription)", error: error)
            // Continue anyway - file exists, size check is just validation
        }

        let isChunked = metadata.chunkInfo != nil

        // Reset idempotency cache for this recording lifecycle.
        // If this ID is retried/re-sent, we must allow a fresh confirmation.
        DispatchQueue.main.async {
            let idPrefix = "\(metadata.id.uuidString)|"
            self.processedConfirmationKeys = Set(
                self.processedConfirmationKeys.filter { !$0.hasPrefix(idPrefix) }
            )
        }

        // Initialize progress tracking immediately so UI shows progress right away
        DispatchQueue.main.async {
            // For chunked transfers, only set to 0 if not already tracking
            // (avoids resetting aggregate progress when later chunks are queued)
            if !isChunked || self.recordingTransferProgress[metadata.id] == nil {
                self.recordingTransferProgress[metadata.id] = 0.0
            }
            self.updateCachedAggregateStates()

            // Announce transfer start to iOS with initial progress and metadata
            self.sendProgressUpdateToiOS(recordingId: metadata.id, progress: 0.0, metadata: metadata)
        }

        // Prepare metadata dictionary for transfer
        let metadataDict = metadata.toDictionary()

        logger.info("[WatchConnectivity] Starting file transfer for recording: \(metadata.id), isChunked: \(isChunked)")
        logger.debug("[WatchConnectivity] File: \(fileURL.lastPathComponent), Size: \(fileURL.fileSizeString)")

        watchConnectivityQueue.async { [weak self] in
            guard let self = self else { return }

            // Use transferFile for reliable background delivery
            let fileTransfer = session.transferFile(fileURL, metadata: metadataDict)
            let transferObjId = ObjectIdentifier(fileTransfer)

            // Track this transfer in thread-safe manner
            self.transferStateQueue.async {
                if let chunkInfo = metadata.chunkInfo {
                    // Multi-chunk: track per-chunk transfer
                    self.chunkTransfers[transferObjId] = (recordingId: metadata.id, chunkIndex: chunkInfo.chunkIndex)

                    // Update total chunk count (definitive when isLastChunk is seen)
                    if chunkInfo.isLastChunk {
                        self.recordingChunkCounts[metadata.id] = chunkInfo.chunkIndex + 1
                    } else if self.recordingChunkCounts[metadata.id] == nil {
                        self.recordingChunkCounts[metadata.id] = chunkInfo.chunkIndex + 1
                    }

                    // Initialize tracking containers
                    if self.recordingCompletedChunks[metadata.id] == nil {
                        self.recordingCompletedChunks[metadata.id] = Set()
                    }
                    if self.chunkProgressValues[metadata.id] == nil {
                        self.chunkProgressValues[metadata.id] = [:]
                    }

                    self.logger.debug("[WatchConnectivity] Chunk \(chunkInfo.chunkIndex) queued for recording: \(metadata.id) (isLast: \(chunkInfo.isLastChunk))")

                    // Observe chunk-specific progress
                    DispatchQueue.main.async {
                        self.observeChunkTransferProgress(fileTransfer, transferObjId: transferObjId, recordingId: metadata.id, chunkIndex: chunkInfo.chunkIndex)
                        completion?(.success(()))
                    }
                } else {
                    // Single-file: use existing pendingTransfers mechanism
                    self.pendingTransfers[metadata.id] = fileTransfer
                    let count = self.pendingTransfers.count
                    self.logger.debug("[WatchConnectivity] File transfer queued. Pending transfers: \(count)")

                    // Start progress observation
                    DispatchQueue.main.async {
                        self.observeTransferProgress(fileTransfer, recordingId: metadata.id)
                        completion?(.success(()))
                    }
                }
            }
        }
    }

    /// Cancels a pending recording transfer (handles both single-file and multi-chunk)
    /// - Parameter recordingId: The ID of the recording to cancel transfer for
    func cancelTransfer(recordingId: UUID) {
        transferStateQueue.async { [weak self] in
            guard let self = self else { return }

            // Cancel single-file transfer if present
            if let transfer = self.pendingTransfers[recordingId] {
                transfer.cancel()
                self.pendingTransfers.removeValue(forKey: recordingId)
                self.progressObservers[recordingId]?.invalidate()
                self.progressObservers.removeValue(forKey: recordingId)
            }

            // Cancel all chunk transfers for this recording.
            // We must cancel the actual WCSessionFileTransfer objects in the OS queue,
            // not just clean up our in-memory tracking — otherwise the OS continues
            // delivering the old file and a retry creates a parallel duplicate.
            var cancelledChunks = 0
            for (objId, info) in self.chunkTransfers where info.recordingId == recordingId {
                self.chunkProgressObservers.removeValue(forKey: objId)?.invalidate()
                self.chunkTransfers.removeValue(forKey: objId)
                cancelledChunks += 1
            }

            // Also cancel any outstanding OS-level transfers for this recording
            if let session = self.session {
                for transfer in session.outstandingFileTransfers {
                    guard let metaDict = transfer.file.metadata,
                          let meta = RecordingTransferMetadata.fromDictionary(metaDict),
                          meta.id == recordingId else { continue }
                    transfer.cancel()
                    cancelledChunks += 1
                }
            }

            self.recordingChunkCounts.removeValue(forKey: recordingId)
            self.recordingCompletedChunks.removeValue(forKey: recordingId)
            self.chunkProgressValues.removeValue(forKey: recordingId)

            // Remove progress tracking on main thread
            DispatchQueue.main.async {
                self.recordingTransferProgress.removeValue(forKey: recordingId)
                self.updateCachedAggregateStates()
            }

            self.logger.info("[WatchConnectivity] Cancelled transfer for recording: \(recordingId) (chunks cancelled: \(cancelledChunks))")
        }
    }

    /// Returns the number of pending recording transfers (thread-safe)
    /// Counts both single-file and multi-chunk transfers as one per recording
    var pendingTransferCount: Int {
        return transferStateQueue.sync {
            let singleFileCount = pendingTransfers.count
            let chunkRecordingIds = Set(chunkTransfers.values.map { $0.recordingId })
            return singleFileCount + chunkRecordingIds.count
        }
    }

    /// Gets the transfer progress for a specific recording ID.
    /// For multi-chunk transfers, returns aggregate progress across all chunks.
    /// - Parameter recordingId: The UUID of the recording to check
    /// - Returns: Optional progress (0.0-1.0) if transferring, or nil if not being transferred
    /// - Note: Reads directly from the @Published `recordingTransferProgress` dictionary,
    ///   which is only populated during active transfers and cleaned up on confirmation/failure.
    ///   This avoids a race condition where `isRecordingTransferring()` might return false
    ///   because chunk tracking data on `transferStateQueue` hasn't been populated yet.
    func getTransferProgress(for recordingId: UUID) -> Double? {
        return recordingTransferProgress[recordingId]
    }

    /// Checks if a recording is currently being transferred (thread-safe)
    /// - Parameter recordingId: The UUID of the recording to check
    /// - Returns: True if the recording is being transferred
    func isRecordingTransferring(_ recordingId: UUID) -> Bool {
        let inMemory = transferStateQueue.sync { () -> Bool in
            // Single-file transfer
            if pendingTransfers[recordingId] != nil { return true }
            // Multi-chunk: check if any chunks are still in-flight
            if let total = recordingChunkCounts[recordingId],
               let completed = recordingCompletedChunks[recordingId],
               completed.count < total {
                return true
            }
            return false
        }

        if inMemory { return true }

        // Fallback: check the OS-level outstanding transfers.
        // In-memory dicts can lose state after stall detection cleanup or
        // app restart, but WCSession may still be delivering the file.
        guard let session = session else { return false }
        return session.outstandingFileTransfers.contains { transfer in
            guard let metadataDict = transfer.file.metadata,
                  let metadata = RecordingTransferMetadata.fromDictionary(metadataDict) else {
                return false
            }
            return metadata.id == recordingId
        }
    }

    /// Observes transfer progress using KVO on Progress object.
    /// More efficient and reliable than timer-based polling, especially in background.
    /// - Parameters:
    ///   - transfer: The WCSessionFileTransfer to observe
    ///   - recordingId: The UUID of the recording being transferred
    private func observeTransferProgress(_ transfer: WCSessionFileTransfer, recordingId: UUID) {
        // Initialize progress to 0.0 on main thread (where @Published property lives)
        DispatchQueue.main.async { [weak self] in
            guard let self = self else { return }
            self.recordingTransferProgress[recordingId] = 0.0
            self.updateCachedAggregateStates()
        }

        // Track last reported progress to smooth out jumps
        // Thread-safe wrapper to prevent race conditions from concurrent KVO callbacks
        class ThreadSafeProgress {
            private let lock = NSLock()
            private var _value: Double = 0.0

            var value: Double {
                get {
                    lock.lock()
                    defer { lock.unlock() }
                    return _value
                }
                set {
                    lock.lock()
                    defer { lock.unlock() }
                    _value = newValue
                }
            }
        }
        let lastReportedProgress = ThreadSafeProgress()

        // Track last sent progress percentage to avoid duplicate sends
        // Thread-safe wrapper to prevent race conditions
        class ThreadSafeLastSent {
            private let lock = NSLock()
            private var _value: Double = -1.0

            var value: Double {
                get {
                    lock.lock()
                    defer { lock.unlock() }
                    return _value
                }
                set {
                    lock.lock()
                    defer { lock.unlock() }
                    _value = newValue
                }
            }
        }
        let lastSentProgress = ThreadSafeLastSent()

        // Guard for invalid progress state
        guard transfer.progress.totalUnitCount > 0 else {
            logger.warning("[WatchConnectivity] ⚠️ Invalid progress: totalUnitCount is 0")
            return
        }

        // Use KVO to observe progress changes
        // CRITICAL: Use weak self to prevent retain cycles
        let observer = transfer.progress.observe(\.fractionCompleted, options: [.new, .initial]) { [weak self] progress, _ in
            guard let self = self else {
                // Manager was deallocated - observer should have been cleaned up
                return
            }

            // Thread-safe check if transfer is still pending
            // Safe: async outer + sync inner on same queue (no deadlock risk)
            let isStillPending = self.transferStateQueue.sync {
                return self.pendingTransfers[recordingId] != nil
            }

            guard isStillPending else {
                // Transfer was removed, stop observing
                // Clean up observer asynchronously to avoid deadlock
                self.transferStateQueue.async { [weak self] in
                    guard let self = self else { return }
                    self.progressObservers.removeValue(forKey: recordingId)?.invalidate()
                }
                return
            }

            let rawProgress = progress.fractionCompleted

            // Guard against invalid progress values
            guard rawProgress >= 0.0 && rawProgress <= 1.0 else {
                logger.warning("[WatchConnectivity] ⚠️ Invalid progress value: \(rawProgress)")
                return
            }

            // Smooth progress updates: ensure it only moves forward
            // Limit maximum increment to prevent jarring jumps
            let currentLastReported = lastReportedProgress.value
            let targetProgress = min(rawProgress, currentLastReported + Self.maxProgressIncrement)

            // Throttle: Send progress updates every 5% (0%, 5%, 10%, ..., 50%, ..., 95%, 100%)
            // This provides real-time feel while still reducing context update frequency
            let lastSent = lastSentProgress.value
            let progressPercent = Int(targetProgress * 100)
            let lastSentPercent = Int(lastSent * 100)

            // Send if we've crossed a 5% threshold or reached completion
            let shouldSend: Bool
            if targetProgress >= 1.0 {
                // Always send at completion (100%)
                shouldSend = lastSent < 1.0
            } else if progressPercent % 5 == 0 && progressPercent != lastSentPercent {
                // Send at 5% intervals (0%, 5%, 10%, 15%, ..., 95%)
                shouldSend = true
            } else {
                shouldSend = false
            }

            // Update local tracking even if we don't send to iOS
            if abs(targetProgress - currentLastReported) >= 0.01 || targetProgress >= 1.0 {
                lastReportedProgress.value = targetProgress

                // Update on main thread for @Published property
                DispatchQueue.main.async { [weak self] in
                    guard let self = self else { return }
                    self.recordingTransferProgress[recordingId] = targetProgress
                    self.updateCachedAggregateStates()

                    // Send progress update at 5% intervals for real-time feel
                    if shouldSend {
                        self.sendProgressUpdateToiOS(recordingId: recordingId, progress: targetProgress, metadata: nil)
                        lastSentProgress.value = targetProgress
                    }
                }
            }

            // Handle completion or cancellation
            if rawProgress >= 1.0 {
                // Ensure final update to 100%
                if lastReportedProgress.value < 1.0 {
                    lastReportedProgress.value = 1.0
                    DispatchQueue.main.async { [weak self] in
                        guard let self = self else { return }
                        self.recordingTransferProgress[recordingId] = 1.0
                        self.updateCachedAggregateStates()

                        // Send final progress update to iOS
                        self.sendProgressUpdateToiOS(recordingId: recordingId, progress: 1.0, metadata: nil)
                    }
                }

                // Stop observing when complete (async to avoid deadlock)
                self.transferStateQueue.async { [weak self] in
                    guard let self = self else { return }
                    self.progressObservers.removeValue(forKey: recordingId)?.invalidate()
                }
            } else if progress.isCancelled {
                // Stop observing if cancelled
                self.transferStateQueue.async { [weak self] in
                    guard let self = self else { return }
                    self.progressObservers.removeValue(forKey: recordingId)?.invalidate()
                }
            }
        }

        // Store observer for cleanup (thread-safe)
        transferStateQueue.async { [weak self] in
            guard let self = self else {
                // Manager deallocated - invalidate observer immediately
                observer.invalidate()
                return
            }

            // Remove existing observer if present (shouldn't happen, but be safe)
            self.progressObservers[recordingId]?.invalidate()

            // Store new observer
            self.progressObservers[recordingId] = observer
        }
    }

    /// Observes progress for a single chunk transfer and aggregates across all chunks
    /// of the same recording to update `recordingTransferProgress`.
    /// Sends aggregate progress to iOS at 5% intervals for real-time UI updates on the phone.
    /// - Parameters:
    ///   - transfer: The WCSessionFileTransfer for this chunk
    ///   - transferObjId: ObjectIdentifier of the transfer (for cleanup)
    ///   - recordingId: Parent recording UUID
    ///   - chunkIndex: Index of this chunk within the recording
    private func observeChunkTransferProgress(
        _ transfer: WCSessionFileTransfer,
        transferObjId: ObjectIdentifier,
        recordingId: UUID,
        chunkIndex: Int
    ) {
        // Track the last progress percentage sent to iOS to throttle at 5% intervals.
        // Uses a reference-type wrapper so the KVO closure captures a mutable reference.
        class MutableValue<T> { var value: T; init(_ v: T) { self.value = v } }
        let lastSentAggregatePercent = MutableValue<Int>(0)

        // Observe fractionCompleted with .initial so we get the current value immediately.
        // Even if totalUnitCount is 0 at setup time, the observer will fire again once
        // WCSession sets the real byte count and the transfer progresses.
        let observer = transfer.progress.observe(\.fractionCompleted, options: [.new, .initial]) { [weak self] progress, _ in
            guard let self = self else { return }

            // Skip invalid values (totalUnitCount may be 0 briefly at the start)
            guard progress.totalUnitCount > 0 else { return }
            let rawProgress = progress.fractionCompleted
            guard rawProgress >= 0.0 && rawProgress <= 1.0 else { return }

            self.transferStateQueue.async { [weak self] in
                guard let self = self else { return }

                if self.chunkProgressValues[recordingId] == nil {
                    self.chunkProgressValues[recordingId] = [:]
                }
                self.chunkProgressValues[recordingId]?[chunkIndex] = rawProgress

                let totalChunks = self.recordingChunkCounts[recordingId] ?? 1
                let allChunkProgress = self.chunkProgressValues[recordingId]?.values.reduce(0.0, +) ?? 0.0
                let aggregateProgress = min(allChunkProgress / Double(totalChunks), 1.0)

                // Determine if we should send this update to iOS (every 5%)
                let aggregatePercent = Int(aggregateProgress * 100)
                let shouldSendToiOS: Bool
                if aggregateProgress >= 1.0 {
                    shouldSendToiOS = lastSentAggregatePercent.value < 100
                } else if aggregatePercent >= lastSentAggregatePercent.value + 5 {
                    shouldSendToiOS = true
                } else {
                    shouldSendToiOS = false
                }

                DispatchQueue.main.async {
                    self.recordingTransferProgress[recordingId] = aggregateProgress
                    self.updateCachedAggregateStates()

                    if shouldSendToiOS {
                        self.sendProgressUpdateToiOS(recordingId: recordingId, progress: aggregateProgress, metadata: nil)
                        lastSentAggregatePercent.value = aggregatePercent
                    }
                }
            }

            // Clean up observer when done or cancelled
            if rawProgress >= 1.0 || progress.isCancelled {
                self.transferStateQueue.async { [weak self] in
                    self?.chunkProgressObservers.removeValue(forKey: transferObjId)?.invalidate()
                }
            }
        }

        // Store observer (thread-safe)
        transferStateQueue.async { [weak self] in
            guard let self = self else {
                observer.invalidate()
                return
            }
            self.chunkProgressObservers[transferObjId]?.invalidate()
            self.chunkProgressObservers[transferObjId] = observer
        }
    }

    /// Sends transfer progress update to iOS via application context
    /// Throttles updates to avoid flooding (sends every ~1% progress or on completion)
    /// - Parameters:
    ///   - recordingId: The UUID of the recording being transferred
    ///   - progress: The current progress (0.0 to 1.0)
    ///   - metadata: Optional metadata to send (typically on first update)
    private func sendProgressUpdateToiOS(recordingId: UUID, progress: Double, metadata: RecordingTransferMetadata? = nil) {
        dispatchPrecondition(condition: .onQueue(.main))
        guard let session = session else { return }

        // Get current context from cached copy (must be on main thread)
        var context = getCachedApplicationContextSafely()

        // Get existing progress updates or create new dictionary
        var progressUpdates: [String: Double]
        if let existing = context[WatchContextKey.transferProgressUpdates] as? [String: Double] {
            progressUpdates = existing
        } else {
            progressUpdates = [:]
        }

        // Only include transfers that are still active (not completed)
        // Check both single-file (pendingTransfers) and multi-chunk (chunkTransfers) tracking
        let isStillActive = transferStateQueue.sync {
            if pendingTransfers[recordingId] != nil { return true }
            if chunkTransfers.values.contains(where: { $0.recordingId == recordingId }) { return true }
            if let total = recordingChunkCounts[recordingId],
               let completed = recordingCompletedChunks[recordingId],
               completed.count < total { return true }
            return false
        }

        if isStillActive {
            // Update progress for this recording
            progressUpdates[recordingId.uuidString] = progress
            context[WatchContextKey.transferProgressUpdates] = progressUpdates

            // Send metadata if provided (typically on transfer start)
            if let metadata = metadata {
                var metadataDict: [String: [String: Any]]
                if let existing = context[WatchContextKey.transferMetadata] as? [String: [String: Any]] {
                    metadataDict = existing
                } else {
                    metadataDict = [:]
                }

                // Store metadata for this recording
                metadataDict[recordingId.uuidString] = metadata.toDictionary()
                context[WatchContextKey.transferMetadata] = metadataDict
            }
        } else {
            // Transfer is no longer active, clean it up from context
            progressUpdates.removeValue(forKey: recordingId.uuidString)
            if progressUpdates.isEmpty {
                context.removeValue(forKey: WatchContextKey.transferProgressUpdates)
            } else {
                context[WatchContextKey.transferProgressUpdates] = progressUpdates
            }

            // Remove metadata for completed transfers
            if var metadataDict = context[WatchContextKey.transferMetadata] as? [String: [String: Any]] {
                metadataDict.removeValue(forKey: recordingId.uuidString)
                if metadataDict.isEmpty {
                    context.removeValue(forKey: WatchContextKey.transferMetadata)
                } else {
                    context[WatchContextKey.transferMetadata] = metadataDict
                }
            }

            // Don't send update if no changes needed
            return
        }

        // Send via application context (reliable, even if iOS is in background)
        updateApplicationContext(context) { [weak self] error in
            guard let self = self else { return }
            if let error = error {
                self.logger.error("[WatchConnectivity] Failed to send progress update: \(error.localizedDescription)", error: error)
            } else {
                self.logger.debug("[WatchConnectivity] Sent progress update: \(recordingId) = \(Int(progress * 100))%")
            }
        }
    }

    /// Clears progress update and metadata for a completed transfer
    /// - Parameter recordingId: The UUID of the recording to clear progress for
    private func clearProgressUpdateForiOS(recordingId: UUID) {
        dispatchPrecondition(condition: .onQueue(.main))
        guard let session = session else { return }

        // Get current context from cached copy (must be on main thread)
        var context = getCachedApplicationContextSafely()

        // Aggressively prune completed transfer from context immediately
        if var progressUpdates = context[WatchContextKey.transferProgressUpdates] as? [String: Double] {
            progressUpdates.removeValue(forKey: recordingId.uuidString)
            // Also clean up any other completed transfers (defensive cleanup)
            // Keep only transfers that are still in pendingTransfers
            let activeIds = transferStateQueue.sync { Set(pendingTransfers.keys.map { $0.uuidString }) }
            progressUpdates = progressUpdates.filter { activeIds.contains($0.key) }

            if progressUpdates.isEmpty {
                context.removeValue(forKey: WatchContextKey.transferProgressUpdates)
            } else {
                context[WatchContextKey.transferProgressUpdates] = progressUpdates
            }
        }

        // Remove metadata immediately for completed transfer
        if var metadataDict = context[WatchContextKey.transferMetadata] as? [String: [String: Any]] {
            metadataDict.removeValue(forKey: recordingId.uuidString)
            // Clean up metadata for other completed transfers too
            let activeIds = transferStateQueue.sync { Set(pendingTransfers.keys.map { $0.uuidString }) }
            metadataDict = metadataDict.filter { activeIds.contains($0.key) }

            if metadataDict.isEmpty {
                context.removeValue(forKey: WatchContextKey.transferMetadata)
            } else {
                context[WatchContextKey.transferMetadata] = metadataDict
            }
        }

        // Update context (only if we actually changed something)
        updateApplicationContext(context) { [weak self] error in
            guard let self = self else { return }
            if let error = error {
                self.logger.error("[WatchConnectivity] Failed to clear progress update: \(error.localizedDescription)", error: error)
            }
        }
    }

    /// Notifies iPhone that recording has started or stopped on Watch. Call from main thread.
    /// Merges into current application context so auth and transfer keys are preserved.
    /// - Parameters:
    ///   - isRecording: True when recording (or paused), false when stopped
    ///   - startedAt: When recording started (for elapsed time on iPhone). Pass nil when isRecording is false.
    func sendRecordingOnWatchIndicator(isRecording: Bool, startedAt: Date?) {
        dispatchPrecondition(condition: .onQueue(.main))
        var context = getCachedApplicationContextSafely()
        context[WatchContextKey.isRecordingOnWatch] = isRecording
        if let started = startedAt {
            context[WatchContextKey.recordingStartedAt] = started.timeIntervalSince1970
        } else {
            context.removeValue(forKey: WatchContextKey.recordingStartedAt)
        }
        updateApplicationContext(context) { [weak self] error in
            guard let self = self else { return }
            if let error = error {
                self.logger.error("[WatchConnectivity] Failed to send recording indicator: \(error.localizedDescription)", error: error)
            } else {
                self.logger.debug("[WatchConnectivity] Sent recording on Watch: \(isRecording)")
            }
        }
    }

    /// Restores pending file transfers after app restart
    /// Checks session.outstandingFileTransfers and restores any transfers that aren't already confirmed
    private func restorePendingTransfers() {
        guard let session = session else { return }

        let outstanding = session.outstandingFileTransfers

        guard !outstanding.isEmpty else {
            logger.debug("[WatchConnectivity] No outstanding transfers to restore")
            return
        }

        logger.info("[WatchConnectivity] Restoring \(outstanding.count) pending transfer(s)")

        // Collect transfers to restore (thread-safe)
        var transfersToRestore: [(UUID, WCSessionFileTransfer, RecordingTransferMetadata)] = []

        for transfer in outstanding {
            guard let metadataDict = transfer.file.metadata,
                  let metadata = RecordingTransferMetadata.fromDictionary(metadataDict) else {
                continue
            }

            let recordingId = metadata.id

            // Check Core Data status before restoring — skip recordings already
            // confirmed/sent by iOS. Without this guard, already-completed transfers
            // are re-queued on every app restart, causing phantom progress in iPhone UI
            // and unnecessary duplicate resends.
            if let repo = repository {
                let (canSend, reason) = repo.canSendRecording(recordingId)
                if !canSend {
                    logger.info("[WatchConnectivity] ⏭️ Skipping restore for \(recordingId): \(reason ?? "not sendable")")
                    transfer.cancel()
                    continue
                }
            }

            transfersToRestore.append((recordingId, transfer, metadata))
        }

        // Restore all transfers in thread-safe manner
        transferStateQueue.async { [weak self] in
            guard let self = self else { return }

            for (recordingId, transfer, metadata) in transfersToRestore {
                let transferObjId = ObjectIdentifier(transfer)

                if let chunkInfo = metadata.chunkInfo {
                    // Restore as a chunk transfer
                    self.chunkTransfers[transferObjId] = (recordingId: recordingId, chunkIndex: chunkInfo.chunkIndex)

                    if chunkInfo.isLastChunk {
                        self.recordingChunkCounts[recordingId] = chunkInfo.chunkIndex + 1
                    } else if self.recordingChunkCounts[recordingId] == nil {
                        self.recordingChunkCounts[recordingId] = chunkInfo.chunkIndex + 1
                    }
                    if self.recordingCompletedChunks[recordingId] == nil {
                        self.recordingCompletedChunks[recordingId] = Set()
                    }
                    if self.chunkProgressValues[recordingId] == nil {
                        self.chunkProgressValues[recordingId] = [:]
                    }

                    let initialProgress = transfer.progress.fractionCompleted
                    self.chunkProgressValues[recordingId]?[chunkInfo.chunkIndex] = initialProgress

                    self.logger.info("[WatchConnectivity] ✅ Restored chunk \(chunkInfo.chunkIndex): \(metadata.filename)")

                    DispatchQueue.main.async {
                        // Compute aggregate for restored chunks
                        let totalChunks = self.recordingChunkCounts[recordingId] ?? 1
                        let allProgress = self.chunkProgressValues[recordingId]?.values.reduce(0.0, +) ?? 0.0
                        let aggregate = min(allProgress / Double(totalChunks), 1.0)
                        self.recordingTransferProgress[recordingId] = aggregate
                        self.updateCachedAggregateStates()

                        // Send restored progress to iOS so the phone reflects current state
                        self.sendProgressUpdateToiOS(recordingId: recordingId, progress: aggregate, metadata: metadata)

                        self.observeChunkTransferProgress(transfer, transferObjId: transferObjId, recordingId: recordingId, chunkIndex: chunkInfo.chunkIndex)
                    }
                } else {
                    // Restore as single-file transfer
                    self.pendingTransfers[recordingId] = transfer
                    self.logger.info("[WatchConnectivity] ✅ Restored: \(metadata.filename)")

                    let initialProgress = transfer.progress.fractionCompleted
                    DispatchQueue.main.async {
                        self.recordingTransferProgress[recordingId] = initialProgress
                        self.updateCachedAggregateStates()
                        self.sendProgressUpdateToiOS(recordingId: recordingId, progress: initialProgress, metadata: metadata)
                        self.observeTransferProgress(transfer, recordingId: recordingId)
                    }
                }
            }
        }
    }

    /// Handles confirmation that iOS received a recording (called when app context is received)
    func handleTransferConfirmation(_ context: [String: Any]) {
        // Check for transferred recording IDs that iOS has confirmed receiving
        // Use explicit type checking to ensure safety
        guard let transferredIdsValue = context[WatchContextKey.transferredRecordingIds] else {
            return
        }

        // Defensive parsing: handle both [String] and other array types
        var transferredIds: [String] = []

        if let stringArray = transferredIdsValue as? [String] {
            // Expected format: array of UUID strings
            transferredIds = stringArray
        } else if let uuidArray = transferredIdsValue as? [UUID] {
            // Fallback: array of UUID objects - convert to strings
            transferredIds = uuidArray.map { $0.uuidString }
            logger.warning("[WatchConnectivity] ⚠️ Received UUID objects instead of strings, converting...")
        } else if let anyArray = transferredIdsValue as? [Any] {
            // Fallback: array of mixed types - attempt to extract UUID strings
            transferredIds = anyArray.compactMap { value in
                if let uuidString = value as? String {
                    // Validate it's a valid UUID string
                    return UUID(uuidString: uuidString) != nil ? uuidString : nil
                } else if let uuid = value as? UUID {
                    return uuid.uuidString
                }
                // Try to parse as UUID string from description
                let description = String(describing: value)
                if UUID(uuidString: description) != nil {
                    return description
                }
                return nil
            }
            if transferredIds.isEmpty {
                logger.warning("[WatchConnectivity] ⚠️ Could not parse transferredRecordingIds from: \(type(of: transferredIdsValue))")
                return
            } else {
                logger.debug("[WatchConnectivity] ⚠️ Parsed \(transferredIds.count) UUIDs from mixed array type")
            }
        } else {
            logger.warning("[WatchConnectivity] ⚠️ Unexpected type for transferredRecordingIds: \(type(of: transferredIdsValue))")
            return
        }

        let phaseRaw = context[WatchContextKey.transferredRecordingAckPhase] as? String
        let confirmationPhase = RecordingTransferConfirmationPhase(rawValue: phaseRaw ?? "") ?? .received

        // Collect confirmations for thread-safe processing
        var confirmationsToProcess: [UUID] = []

        for idString in transferredIds {
            guard let recordingId = UUID(uuidString: idString) else {
                logger.warning("[WatchConnectivity] ⚠️ Invalid UUID string in transferredRecordingIds: \(idString)")
                continue
            }

            let confirmationKey = "\(recordingId.uuidString)|\(confirmationPhase.rawValue)"

            // Skip already processed confirmations (idempotency check)
            guard !processedConfirmationKeys.contains(confirmationKey) else {
                logger.debug("[WatchConnectivity] ⏭️ Ignoring duplicate \(confirmationPhase.rawValue) confirmation for: \(recordingId)")
                continue
            }

            // Mark as processed BEFORE doing any work (prevents race conditions)
            processedConfirmationKeys.insert(confirmationKey)

            // Add to confirmed IDs for processing
            logger.info("[WatchConnectivity] ✅ iOS sent \(confirmationPhase.rawValue) confirmation for recording: \(recordingId)")
            confirmationsToProcess.append(recordingId)
        }

        // Process confirmations in thread-safe manner
        transferStateQueue.async { [weak self] in
            guard let self = self else { return }

            for recordingId in confirmationsToProcess {
                logger.debug("[WatchConnectivity] Processing \(confirmationPhase.rawValue) confirmation for: \(recordingId)")

                do {
                    guard let repo = repository else {
                        logger.error("[WatchConnectivity] ❌ Repository not available - cannot update status", error: nil)
                        logger.warning("[WatchConnectivity] Continuing with in-memory cleanup and callbacks")
                        continue
                    }

                    switch confirmationPhase {
                    case .received:
                        // Mark transfer delivery confirmed on watch.
                        try repo.updateStatus(
                            recordingId,
                            status: .sent,
                            error: nil
                        )
                        logger.info("[WatchConnectivity] ✅ Core Data status updated to .sent")
                    case .processed:
                        // Mark full iPhone pipeline completion on watch.
                        try repo.updateStatus(
                            recordingId,
                            status: .confirmed,
                            error: nil
                        )
                        logger.info("[WatchConnectivity] ✅ Core Data status updated to .confirmed")
                    }
                } catch {
                    logger.error("[WatchConnectivity] ❌ Failed to update Core Data status for \(confirmationPhase.rawValue) confirmation", error: error)
                }

                // ========================================
                // Now safe to remove from pending transfers
                // ========================================

                // Remove from single-file pending transfers
                self.pendingTransfers.removeValue(forKey: recordingId)
                self.progressObservers[recordingId]?.invalidate()
                self.progressObservers.removeValue(forKey: recordingId)

                // Also clean up multi-chunk tracking (no-op if not a chunked transfer)
                self.cleanupAllChunkTracking(for: recordingId)

                // Update UI on main thread
                DispatchQueue.main.async {
                    // Remove from progress tracking
                    self.recordingTransferProgress.removeValue(forKey: recordingId)
                    self.updateCachedAggregateStates()
                    self.lastTransferredRecordingId = recordingId

                    // Notify completion callback only for transfer-received phase.
                    if confirmationPhase == .received {
                        self.onTransferComplete?(recordingId, true)
                    }

                    #if os(watchOS)
                    if confirmationPhase == .processed {
                        // For chunked recordings: full lifecycle is complete on iPhone.
                        // Post this only on processed confirmation to match semantics.
                        NotificationCenter.default.post(
                            name: .fullRecordingConfirmed,
                            object: nil,
                            userInfo: ["parentRecordingId": recordingId]
                        )
                    }
                    #endif

                    // Post transfer completion notification
                    NotificationCenter.default.post(
                        name: .recordingTransferDidComplete,
                        object: nil,
                        userInfo: ["recordingId": recordingId, "success": true]
                    )

                    // Post confirmation notification for Core Data status update
                    NotificationCenter.default.post(
                        name: .watchRecordingTransferConfirmed,
                        object: nil,
                        userInfo: ["recordingId": recordingId]
                    )

                    self.logger.info("[WatchConnectivity] 🎉 Transfer \(confirmationPhase.rawValue) confirmation handled: \(recordingId)")

                    // Scrub confirmed recording from applicationContext so stale
                    // progress entries are not re-delivered to iPhone on future
                    // context updates (applicationContext is persisted across restarts).
                    self.removeConfirmedRecordingFromContext(recordingId: recordingId)
                }
            }
        }
    }

    /// Removes a confirmed recording's progress and metadata entries from
    /// the application context. Without this cleanup, `transferProgressUpdates`
    /// persists across app restarts and every future context update re-injects
    /// stale progress into iPhone's `incomingTransferProgress`, causing phantom
    /// transfer entries in the UI.
    private func removeConfirmedRecordingFromContext(recordingId: UUID) {
        dispatchPrecondition(condition: .onQueue(.main))
        guard let session = session else { return }

        var context = getCachedApplicationContextSafely()
        var didChange = false

        if var progressUpdates = context[WatchContextKey.transferProgressUpdates] as? [String: Double] {
            if progressUpdates.removeValue(forKey: recordingId.uuidString) != nil {
                if progressUpdates.isEmpty {
                    context.removeValue(forKey: WatchContextKey.transferProgressUpdates)
                } else {
                    context[WatchContextKey.transferProgressUpdates] = progressUpdates
                }
                didChange = true
            }
        }

        if var metadataDict = context[WatchContextKey.transferMetadata] as? [String: [String: Any]] {
            if metadataDict.removeValue(forKey: recordingId.uuidString) != nil {
                if metadataDict.isEmpty {
                    context.removeValue(forKey: WatchContextKey.transferMetadata)
                } else {
                    context[WatchContextKey.transferMetadata] = metadataDict
                }
                didChange = true
            }
        }

        guard didChange else { return }

        updateApplicationContext(context) { [weak self] error in
            if let error = error {
                self?.logger.error("[WatchConnectivity] Failed to clean context for confirmed recording: \(error.localizedDescription)", error: error)
            } else {
                self?.logger.debug("[WatchConnectivity] 🧹 Cleaned context for confirmed recording: \(recordingId)")
            }
        }
    }

    /// Check if a recording has already been confirmed by iOS
    /// - Deprecated: This method is deprecated and should not be used.
    ///   Use `repository.canSendRecording()` instead for Core Data-based status tracking.
    /// - Parameter recordingId: The recording ID to check
    /// - Returns: Always returns false (deprecated method)
    /// - Warning: This method will be removed in a future version. Use repository status instead.
    @available(*, deprecated, message: "Use repository.canSendRecording() instead for Core Data-based status tracking")
    func isRecordingConfirmed(_ recordingId: UUID) -> Bool {
        logger.warning("[WatchConnectivity] ⚠️ isRecordingConfirmed called - this method is deprecated. Use repository.canSendRecording() instead")
        // Return false as this method is deprecated and should not be relied upon
        // The actual status check should be done via repository.canSendRecording()
        return false
    }

    /// Clear confirmed recordings (call on logout or when starting fresh)
    /// Note: With Core Data, this should reset recording statuses in repository
    func clearConfirmedRecordings() {
        logger.info("[WatchConnectivity] clearConfirmedRecordings called - Core Data cleanup should be used instead")
        // No-op - Core Data status is the source of truth now
    }

    /// Clear a specific recording from the confirmed list (allows re-transfer)
    /// - Parameter recordingId: The recording ID to clear
    /// Note: With Core Data, this should reset the recording status in repository
    func clearConfirmedRecording(_ recordingId: UUID) {
        logger.info("[WatchConnectivity] clearConfirmedRecording called for \(recordingId) - use repository.updateStatus instead")
        // No-op - Core Data status is the source of truth now
    }
    #endif

    #if os(iOS)
    /// Sends confirmation to the watch that recordings have been received
    /// - Parameter recordingIds: Array of recording IDs that have been successfully saved
    /// Maintains a persistent set of confirmed IDs and sends all confirmed IDs (with size limit)
    /// to prevent the watch from retrying already-confirmed transfers
    /// Sends confirmation to Watch that recordings were received.
    /// - Parameter phase: Confirmation phase (`received` or `processed`)
    /// - Returns: `true` if the confirmation was queued, `false` if session was not active.
    @discardableResult
    func confirmRecordingsReceived(
        _ recordingIds: [UUID],
        phase: RecordingTransferConfirmationPhase = .received
    ) -> Bool {
        guard !recordingIds.isEmpty else { return true }

        // Dispatch to main thread if not already there to avoid deadlock risk
        if Thread.isMainThread {
            return performConfirmRecordingsReceived(recordingIds: recordingIds, phase: phase)
        } else {
            DispatchQueue.main.async { [weak self] in
                self?.performConfirmRecordingsReceived(recordingIds: recordingIds, phase: phase)
            }
            // Async path can't report back; assume queued (callers on main thread should use sync path)
            return true
        }
    }

    /// Internal method to confirm recordings received (must be called on main thread).
    /// Uses `transferUserInfo` instead of `applicationContext` for guaranteed queued delivery.
    /// Unlike applicationContext (which is last-write-wins and can be overwritten by auth
    /// token syncs or status updates), transferUserInfo is queued -- every call is
    /// guaranteed to be delivered even if multiple calls happen in rapid succession.
    @discardableResult
    private func performConfirmRecordingsReceived(
        recordingIds: [UUID],
        phase: RecordingTransferConfirmationPhase
    ) -> Bool {
        dispatchPrecondition(condition: .onQueue(.main))

        guard let session = session, activationState == .activated else {
            logger.warning("[WatchConnectivity] Cannot send confirmation - session not active. Will retry later.")
            return false
        }

        let idStrings = recordingIds.map { $0.uuidString }

        // Use transferUserInfo for queued, guaranteed delivery of confirmations.
        // This prevents confirmations from being overwritten by other applicationContext
        // updates (e.g., auth token syncs, progress updates, status changes).
        let userInfo: [String: Any] = [
            WatchContextKey.transferredRecordingIds: idStrings,
            WatchContextKey.transferredRecordingAckPhase: phase.rawValue
        ]

        session.transferUserInfo(userInfo)
        logger.info("[WatchConnectivity] Sent \(phase.rawValue) confirmation via transferUserInfo for \(recordingIds.count) recording(s)")
        return true
    }

    /// Clear confirmed recordings (call on logout)
    /// Note: With Core Data, this should be handled by clearing RecordingMetadata in repository
    func clearConfirmedRecordings() {
        logger.info("[WatchConnectivity] clearConfirmedRecordings called - Core Data cleanup should be used instead")
        // No-op - Core Data is the source of truth now
    }

    /// Marks an incoming transfer as failed and removes it from tracking.
    /// Used by WatchRecordingService when a transfer stalls for too long (e.g. 5 minutes with no progress).
    /// Must be called on the main thread.
    /// - Parameters:
    ///   - recordingId: The UUID of the stuck recording
    ///   - error: Human-readable reason for the failure
    func markIncomingTransferTimedOut(recordingId: UUID, error: String) {
        dispatchPrecondition(condition: .onQueue(.main))

        guard incomingTransferProgress[recordingId] != nil else {
            logger.debug("[WatchConnectivity] Cannot mark timed-out — transfer not found: \(recordingId)")
            return
        }

        incomingTransferProgress[recordingId] = .failed(error)
        suppressedStaleIncomingProgressIds.insert(recordingId)
        updateCachedAggregateStates()
        logger.warning("[WatchConnectivity] Marked transfer as timed-out: \(recordingId) — \(error)")

        // Keep failed state visible for retry/dismiss actions in UI.
    }

    /// Marks an incoming chunked transfer as completed after all chunks have been
    /// assembled and merged. Without this, the observer in WatchRecordingService would
    /// overwrite the local .completed state back to .receiving because WCM never
    /// transitions chunked transfers to .completed on its own.
    /// Must be called on the main thread.
    /// - Parameter recordingId: The UUID of the assembled recording
    func markIncomingTransferCompleted(recordingId: UUID) {
        dispatchPrecondition(condition: .onQueue(.main))

        suppressedStaleIncomingProgressIds.remove(recordingId)
        incomingTransferProgress[recordingId] = .completed
        updateCachedAggregateStates()
        logger.info("[WatchConnectivity] Marked chunked transfer as completed: \(recordingId)")
    }

    /// Removes an incoming transfer from progress tracking.
    /// Called after the transfer is fully processed and the entry should no longer appear in the UI.
    /// Must be called on the main thread.
    /// - Parameter recordingId: The UUID of the recording to remove
    func removeIncomingTransfer(recordingId: UUID) {
        dispatchPrecondition(condition: .onQueue(.main))

        incomingTransferProgress.removeValue(forKey: recordingId)
        incomingProgressLastChangeAt.removeValue(forKey: recordingId)
        incomingProgressLastValue.removeValue(forKey: recordingId)
        suppressedStaleIncomingProgressIds.remove(recordingId)
        updateCachedAggregateStates()
        logger.info("[WatchConnectivity] Removed incoming transfer from tracking: \(recordingId)")
    }

    /// Clears stale-progress suppression before a manual retry request.
    /// Keeps state deterministic when the same recording ID is re-sent by Watch.
    func prepareIncomingTransferRetry(recordingId: UUID) {
        dispatchPrecondition(condition: .onQueue(.main))
        suppressedStaleIncomingProgressIds.remove(recordingId)
        incomingProgressLastChangeAt.removeValue(forKey: recordingId)
        incomingProgressLastValue.removeValue(forKey: recordingId)
        if case .failed = incomingTransferProgress[recordingId] {
            incomingTransferProgress.removeValue(forKey: recordingId)
        }
        updateCachedAggregateStates()
        logger.info("[WatchConnectivity] Prepared incoming transfer retry for: \(recordingId)")
    }

    /// Gets metadata for a recording from the application context (if available)
    /// This allows iOS to show transfer details before the file arrives
    /// - Parameter recordingId: The UUID of the recording
    /// - Returns: The recording metadata if available in context, nil otherwise
    func getTransferMetadata(for recordingId: UUID) -> RecordingTransferMetadata? {
        dispatchPrecondition(condition: .onQueue(.main))

        // Get context from cached copy (must be on main thread)
        let context = getCachedApplicationContextSafely()
        guard let metadataDict = context[WatchContextKey.transferMetadata] as? [String: [String: Any]],
              let recordingMetadata = metadataDict[recordingId.uuidString],
              let metadata = RecordingTransferMetadata.fromDictionary(recordingMetadata) else {
            return nil
        }

        return metadata
    }

    /// Maximum age of `recordingStartedAt` before we consider cached activation context stale.
    /// Recordings older than this threshold are assumed to have ended while the iPhone app was not running.
    private static let maxRecordingAgeForActivationContext: TimeInterval = 4 * 60 * 60 // 4 hours

    /// Handles recording-on-Watch indicator from application context.
    /// Updates isRecordingOnWatch and recordingStartedAt for Live Activity and Profile banner.
    /// - Parameters:
    ///   - context: The application context dictionary received from watch
    ///   - isFromActivation: When `true`, the context came from `session.receivedApplicationContext`
    ///     on session activation (potentially stale). A staleness guard is applied and
    ///     `isRecordingStateFromActivation` is set so downstream observers can defer side-effects
    ///     (e.g. notifications) until fresh context confirms the state.
    private func handleRecordingOnWatchContext(_ context: [String: Any], isFromActivation: Bool = false) {
        var recording = context[WatchContextKey.isRecordingOnWatch] as? Bool ?? false
        let startedAt: Date?
        if let ts = context[WatchContextKey.recordingStartedAt] as? TimeInterval {
            startedAt = Date(timeIntervalSince1970: ts)
        } else {
            startedAt = nil
        }

        // Staleness guard: if context comes from activation and the recording started too long ago,
        // it is almost certainly stale (the Watch sent `isRecording=false` while the iPhone was not running).
        if isFromActivation && recording {
            if let startedAt = startedAt {
                let age = Date().timeIntervalSince(startedAt)
                if age > Self.maxRecordingAgeForActivationContext {
                    logger.info("[WatchConnectivity] Ignoring stale recording-on-Watch from activation context (started \(Int(age / 60))m ago)")
                    recording = false
                }
            } else {
                // No startedAt means we can't verify freshness -- treat as stale
                logger.info("[WatchConnectivity] Ignoring recording-on-Watch from activation context (no startedAt)")
                recording = false
            }
        }

        // Mark whether this state came from (potentially stale) activation context.
        // Must be set BEFORE updating isRecordingOnWatch so that Combine observers
        // see the correct flag when the sink fires.
        isRecordingStateFromActivation = isFromActivation && recording

        isRecordingOnWatch = recording
        recordingStartedAt = recording ? startedAt : nil
        logger.debug("[WatchConnectivity] Recording on Watch: \(recording), startedAt: \(String(describing: startedAt)), fromActivation: \(isFromActivation)")
    }

    /// Handles transfer progress updates received from watch via application context
    /// Updates incomingTransferProgress with real-time progress from watch
    /// Cleans up stale entries (completed transfers should not be in context)
    /// - Parameter context: The application context dictionary received from watch
    private func handleReceivedProgressUpdates(_ context: [String: Any]) {
        // Extract metadata if available
        var metadataCache: [UUID: RecordingTransferMetadata] = [:]
        if let metadataDict = context[WatchContextKey.transferMetadata] as? [String: [String: Any]] {
            for (idString, metadataData) in metadataDict {
                if let recordingId = UUID(uuidString: idString),
                   let metadata = RecordingTransferMetadata.fromDictionary(metadataData) {
                    metadataCache[recordingId] = metadata
                }
            }
        }

        guard let progressUpdatesValue = context[WatchContextKey.transferProgressUpdates] else {
            return
        }

        guard let progressUpdates = progressUpdatesValue as? [String: Double] else {
            logger.warning("[WatchConnectivity] ⚠️ Unexpected type for transferProgressUpdates: \(type(of: progressUpdatesValue))")
            return
        }

        // CRITICAL: Remove placeholder immediately if progress updates exist
        // This prevents showing generic "Pending" when we have actual transfer IDs
        if !progressUpdates.isEmpty && incomingTransferProgress[Self.pendingPlaceholderID] != nil {
            incomingTransferProgress.removeValue(forKey: Self.pendingPlaceholderID)
            updateCachedAggregateStates()
            logger.debug("[WatchConnectivity] 🧹 Removed placeholder - got real transfer IDs")
        }

        // Clean up any stale entries: remove completed/failed transfers from local tracking
        // if they appear in context (they shouldn't, but be defensive)
        let contextIds = Set(progressUpdates.keys.compactMap { UUID(uuidString: $0) })
        let staleIds = incomingTransferProgress.keys.filter { id in
            if id == Self.pendingPlaceholderID { return false } // Keep placeholder (handled separately)
            if contextIds.contains(id) { return false } // Keep active transfers in context
            // Remove completed/failed transfers not in context (they should have been auto-removed)
            if case .completed = incomingTransferProgress[id] { return true }
            if case .failed = incomingTransferProgress[id] { return true }
            return false
        }

        if !staleIds.isEmpty {
            for id in staleIds {
                incomingTransferProgress.removeValue(forKey: id)
                logger.debug("[WatchConnectivity] Cleaned up stale transfer: \(id)")
            }
            updateCachedAggregateStates()
        }

        // CRITICAL: Aggressively remove placeholder if we have ANY real transfers
        // This prevents showing "Pending: 1" when actual transfers are already visible
        let hasRealTransfers = incomingTransferProgress.keys.contains { $0 != Self.pendingPlaceholderID }
        if hasRealTransfers && incomingTransferProgress[Self.pendingPlaceholderID] != nil {
            incomingTransferProgress.removeValue(forKey: Self.pendingPlaceholderID)
            updateCachedAggregateStates()
            logger.debug("[WatchConnectivity] 🧹 Removed placeholder - real transfers exist")
        }

        // Update progress for each recording in context
        // Also clean up any completed transfers when new progress updates arrive
        let newTransferIds = Set(progressUpdates.keys.compactMap { UUID(uuidString: $0) })
        let hasNewTransfers = !newTransferIds.isEmpty

        // If we have new active transfers, immediately remove all completed and 100% transfers
        // This ensures completed/finished transfers don't stay in UI when new transfers start
        if hasNewTransfers {
            let transfersToRemove = incomingTransferProgress.keys.filter { id in
                if id == Self.pendingPlaceholderID { return false }
                if newTransferIds.contains(id) { return false } // Don't remove active transfers

                // Remove completed transfers
                if case .completed = incomingTransferProgress[id] { return true }

                return false
            }

            if !transfersToRemove.isEmpty {
                for id in transfersToRemove {
                    incomingTransferProgress.removeValue(forKey: id)
                    logger.debug("[WatchConnectivity] Cleaned up completed transfer when new progress arrived: \(id)")
                }
                updateCachedAggregateStates()
            }
        }

        for (idString, progress) in progressUpdates {
            guard let recordingId = UUID(uuidString: idString) else {
                logger.warning("[WatchConnectivity] ⚠️ Invalid UUID string in transferProgressUpdates: \(idString)")
                continue
            }

            // If this recording was timed out as stale, ignore repeated identical progress
            // re-delivery from cached applicationContext. Only unsuppress when progress
            // meaningfully changes (new transfer cycle or real progress advance).
            if suppressedStaleIncomingProgressIds.contains(recordingId) {
                let previous = incomingProgressLastValue[recordingId]
                let progressed = previous.map { progress > ($0 + 0.01) } ?? false
                let restarted = previous.map { progress < ($0 - 0.05) } ?? true

                if progressed || restarted {
                    suppressedStaleIncomingProgressIds.remove(recordingId)
                    incomingProgressLastChangeAt[recordingId] = Date()
                    incomingProgressLastValue[recordingId] = progress
                    logger.info("[WatchConnectivity] Unsuppressed stale progress for \(recordingId) due to progress change (\(Int((previous ?? 0) * 100))% -> \(Int(progress * 100))%)")
                } else {
                    logger.debug("[WatchConnectivity] ⏭️ Ignoring stale re-delivered progress for timed-out transfer: \(recordingId) (\(Int(progress * 100))%)")
                    continue
                }
            }

            // Skip recordings already processed on iPhone (saved, uploaded, or meeting created).
            // Application context is persisted and can deliver stale progress entries on every
            // context update, creating phantom "receiving" entries in the UI long after the
            // recording was fully processed.
            if let repo = metadataRepository,
               let existingMetadata = try? repo.fetchById(recordingId),
               existingMetadata.meetingId != nil || existingMetadata.statusEnum.isProcessedOrBeyond {
                logger.debug("[WatchConnectivity] ⏭️ Ignoring stale progress for already-processed recording: \(recordingId)")
                continue
            }

            let currentState = incomingTransferProgress[recordingId]

            if case .completed = currentState {
                logger.debug("[WatchConnectivity] ⚠️ Ignoring stale progress update for completed transfer: \(recordingId)")
                continue
            }
            if case .failed = currentState {
                logger.debug("[WatchConnectivity] ⚠️ Ignoring stale progress update for failed transfer: \(recordingId)")
                continue
            }

            if currentState == nil || currentState == .pending {
                incomingTransferProgress[recordingId] = .receiving(progress: progress)
                incomingProgressLastChangeAt[recordingId] = Date()
                incomingProgressLastValue[recordingId] = progress
                updateCachedAggregateStates()
                logger.debug("[WatchConnectivity] 📊 Received progress update for \(recordingId): \(Int(progress * 100))%")
            } else if case .receiving(let oldProgress) = currentState {
                if oldProgress != progress {
                    incomingTransferProgress[recordingId] = .receiving(progress: progress)
                    incomingProgressLastChangeAt[recordingId] = Date()
                    incomingProgressLastValue[recordingId] = progress
                    updateCachedAggregateStates()
                    logger.debug("[WatchConnectivity] 📊 Updated progress for \(recordingId): \(Int(progress * 100))%")
                } else {
                    let lastChange = incomingProgressLastChangeAt[recordingId] ?? Date()
                    let staleFor = Date().timeIntervalSince(lastChange)
                    let timeout = incomingProgressTimeoutSeconds(for: recordingId)
                    if staleFor >= timeout {
                        let errorMessage = "Transfer stalled at \(Int(progress * 100))% on iPhone."
                        incomingTransferProgress[recordingId] = .failed(errorMessage)
                        suppressedStaleIncomingProgressIds.insert(recordingId)
                        updateCachedAggregateStates()
                        logger.warning("[WatchConnectivity] Marked incoming progress as stale for \(recordingId) after \(Int(staleFor))s without change")

                        // Keep stale failed row visible so user can retry/dismiss manually.
                    }
                }
            }
        }
    }

    private func incomingProgressTimeoutSeconds(for recordingId: UUID) -> TimeInterval {
        let transferMetadata = getTransferMetadata(for: recordingId)
        let metadataDuration = transferMetadata?.chunkInfo?.totalDurationSoFar
            ?? transferMetadata?.duration
        if let metadataDuration {
            return transferTimeoutPolicy.timeout(forRecordingDuration: metadataDuration)
        }
        // RecordingMetadata does not persist duration. If transfer metadata is missing
        // (e.g. stale/evicted applicationContext), fall back to policy minimum timeout.
        return transferTimeoutPolicy.timeout(forRecordingDuration: nil)
    }
    #endif
}

// MARK: - File Transfer Delegate Methods

extension WatchConnectivityManager {

    #if os(watchOS)
    /// Called when a file transfer finishes (on the sending side - watchOS)
    func session(_ session: WCSession, didFinish fileTransfer: WCSessionFileTransfer, error: Error?) {
        let transferObjId = ObjectIdentifier(fileTransfer)

        // Check if this is a multi-chunk transfer first
        let chunkInfo: (recordingId: UUID, chunkIndex: Int)? = transferStateQueue.sync {
            return chunkTransfers[transferObjId]
        }

        if let chunkInfo = chunkInfo {
            handleChunkTransferFinished(transferObjId: transferObjId, info: chunkInfo, error: error)
            return
        }

        // Fall through to single-file transfer handling
        let recordingId = transferStateQueue.sync { () -> UUID? in
            for (id, transfer) in pendingTransfers where transfer === fileTransfer {
                return id
            }
            return nil
        }

        guard let recordingId = recordingId else {
            return
        }

        // Handle transfer completion
        transferStateQueue.async { [weak self] in
            guard let self = self else { return }

        if let error = error {
                // Transfer failed - remove immediately
                self.pendingTransfers.removeValue(forKey: recordingId)
                self.progressObservers[recordingId]?.invalidate()
                self.progressObservers.removeValue(forKey: recordingId)

            DispatchQueue.main.async {
                    self.recordingTransferProgress.removeValue(forKey: recordingId)
                    self.updateCachedAggregateStates()
                self.onTransferComplete?(recordingId, false)

                NotificationCenter.default.post(
                    name: .recordingTransferDidComplete,
                    object: nil,
                    userInfo: ["recordingId": recordingId, "success": false, "error": error]
                )
            }
        } else {
                // Transfer succeeded - DO NOT remove yet
                // Keep in pendingTransfers until iOS confirms receipt
                // Stop progress observation (transfer is done)
                self.progressObservers[recordingId]?.invalidate()
                self.progressObservers.removeValue(forKey: recordingId)

            DispatchQueue.main.async {
                    // Update progress to 100% but keep tracking
                    self.recordingTransferProgress[recordingId] = 1.0
                    self.updateCachedAggregateStates()
                self.lastTransferredRecordingId = recordingId

                    // Clear progress update from context now that transfer is complete
                    self.clearProgressUpdateForiOS(recordingId: recordingId)

                self.logger.info("[WatchConnectivity] File transfer completed for recording: \(recordingId), waiting for iOS confirmation")
                    // Note: Transfer remains in pendingTransfers until handleTransferConfirmation() is called
                }
            }
        }
    }

    /// Handles completion of an individual chunk transfer within a multi-chunk recording.
    /// Marks the chunk as completed and updates aggregate progress. Only fires
    /// `onTransferComplete` once ALL chunks have been successfully delivered.
    private func handleChunkTransferFinished(
        transferObjId: ObjectIdentifier,
        info: (recordingId: UUID, chunkIndex: Int),
        error: Error?
    ) {
        let recordingId = info.recordingId
        let chunkIndex = info.chunkIndex

        transferStateQueue.async { [weak self] in
            guard let self = self else { return }

            // Clean up this chunk's observer
            self.chunkProgressObservers.removeValue(forKey: transferObjId)?.invalidate()
            self.chunkTransfers.removeValue(forKey: transferObjId)

            if let error = error {
                self.logger.error("[WatchConnectivity] ❌ Chunk \(chunkIndex) failed for recording \(recordingId): \(error.localizedDescription)", error: error)

                // On any chunk failure, fail the entire recording transfer
                self.cleanupAllChunkTracking(for: recordingId)

                DispatchQueue.main.async {
                    self.recordingTransferProgress.removeValue(forKey: recordingId)
                    self.updateCachedAggregateStates()
                    self.onTransferComplete?(recordingId, false)

                    NotificationCenter.default.post(
                        name: .recordingTransferDidComplete,
                        object: nil,
                        userInfo: ["recordingId": recordingId, "success": false, "error": error]
                    )
                }
            } else {
                // Mark chunk as completed
                self.recordingCompletedChunks[recordingId]?.insert(chunkIndex)
                self.chunkProgressValues[recordingId]?[chunkIndex] = 1.0

                let completedCount = self.recordingCompletedChunks[recordingId]?.count ?? 0
                let totalChunks = self.recordingChunkCounts[recordingId] ?? 1
                let allDone = completedCount >= totalChunks

                self.logger.info("[WatchConnectivity] ✅ Chunk \(chunkIndex) delivered for recording \(recordingId) (\(completedCount)/\(totalChunks))")

                if allDone {
                    self.logger.info("[WatchConnectivity] 🎉 All \(totalChunks) chunks delivered for recording \(recordingId), waiting for iOS confirmation")

                    DispatchQueue.main.async {
                        self.recordingTransferProgress[recordingId] = 1.0
                        self.updateCachedAggregateStates()
                        self.lastTransferredRecordingId = recordingId
                        self.clearProgressUpdateForiOS(recordingId: recordingId)
                    }
                } else {
                    // Update aggregate progress
                    let allChunkProgress = self.chunkProgressValues[recordingId]?.values.reduce(0.0, +) ?? 0.0
                    let aggregateProgress = min(allChunkProgress / Double(totalChunks), 0.99)

                    DispatchQueue.main.async {
                        self.recordingTransferProgress[recordingId] = aggregateProgress
                        self.updateCachedAggregateStates()
                        self.sendProgressUpdateToiOS(recordingId: recordingId, progress: aggregateProgress, metadata: nil)
                    }
                }
            }
        }
    }

    /// Removes all chunk-level tracking data for a recording
    private func cleanupAllChunkTracking(for recordingId: UUID) {
        // Must be called on transferStateQueue
        var idsToRemove: [ObjectIdentifier] = []
        for (objId, info) in chunkTransfers where info.recordingId == recordingId {
            idsToRemove.append(objId)
        }
        for objId in idsToRemove {
            chunkTransfers.removeValue(forKey: objId)
            chunkProgressObservers.removeValue(forKey: objId)?.invalidate()
        }
        recordingChunkCounts.removeValue(forKey: recordingId)
        recordingCompletedChunks.removeValue(forKey: recordingId)
        chunkProgressValues.removeValue(forKey: recordingId)
    }
    #endif

    #if os(iOS)
    /// Called when a file is received (on the receiving side - iOS)
    /// IMPORTANT: The file at file.fileURL is deleted immediately after this method returns!
    /// We must copy it synchronously before returning.
    func session(_ session: WCSession, didReceive file: WCSessionFile) {
        // CRITICAL: Copy file IMMEDIATELY before this method returns
        // WatchConnectivity deletes the temp file right after the delegate callback

        // Validate metadata exists
        guard let metadataDict = file.metadata else {
            logger.fatal("[WatchConnectivity] ❌ CRITICAL DATA LOSS: Received file without metadata - file will be deleted!")
            logger.error("[WatchConnectivity] File URL: \(file.fileURL.path)", error: nil)
            // Log file info if possible before it's deleted
            if let attrs = try? FileManager.default.attributesOfItem(atPath: file.fileURL.path),
               let size = attrs[.size] as? Int64 {
                logger.error("[WatchConnectivity] File size was: \(ByteCountFormatter.string(fromByteCount: size, countStyle: .file))", error: nil)
            }
            return
        }

        guard let metadata = RecordingTransferMetadata.fromDictionary(metadataDict) else {
            logger.fatal("[WatchConnectivity] ❌ CRITICAL DATA LOSS: Invalid metadata for received file - file will be deleted!")
            logger.error("[WatchConnectivity] File URL: \(file.fileURL.path)", error: nil)
            logger.error("[WatchConnectivity] Metadata dict: \(metadataDict)", error: nil)
            // Log file info if possible before it's deleted
            if let attrs = try? FileManager.default.attributesOfItem(atPath: file.fileURL.path),
               let size = attrs[.size] as? Int64 {
                logger.error("[WatchConnectivity] File size was: \(ByteCountFormatter.string(fromByteCount: size, countStyle: .file))", error: nil)
            }
            return
        }

        let recordingId = metadata.id
        let isChunkedTransfer = metadata.isChunked

        logger.info("[WatchConnectivity] FILE RECEIVED FROM WATCH — Recording ID: \(recordingId), Filename: \(metadata.filename), isChunked: \(isChunkedTransfer)")
        if let chunkInfo = metadata.chunkInfo {
            logger.info("[WatchConnectivity] Chunk details — index: \(chunkInfo.chunkIndex), isLast: \(chunkInfo.isLastChunk), parentId: \(chunkInfo.parentRecordingId), chunkDuration: \(chunkInfo.chunkDuration)s, totalSoFar: \(chunkInfo.totalDurationSoFar)s")
        }

        // ========================================
        // DUPLICATE DETECTION - Simplified Logic
        // ========================================
        // For chunked transfers, skip duplicate detection (chunks are always accepted;
        // ChunkAssemblyManager handles deduplication at the chunk level).
        // For single-file transfers, block if already completed or actively processing.
        // ========================================

        if isChunkedTransfer {
            logger.info("[WatchConnectivity] Chunked transfer — skipping duplicate detection (handled by ChunkAssemblyManager)")
        } else {
        logger.debug("[WatchConnectivity] Checking for duplicates...")

        // metadataRepository uses viewContext (main-queue NSManagedObjectContext) but
        // session(_:didReceive file:) runs on WCSession's background queue.
        // Access Core Data on the main thread to avoid threading violations.
        enum DuplicateCheckResult {
            case alreadyProcessed
            case currentlyProcessing
            case allowRetry
            case noExistingRecord
        }

        let checkResult: DuplicateCheckResult = DispatchQueue.main.sync {
            do {
                guard let existing = try metadataRepository?.fetchById(recordingId) else {
                    return .noExistingRecord
                }
                let status = existing.statusEnum
                if status == .created || existing.meetingId != nil {
                    return .alreadyProcessed
                }
                if status == .uploading || status == .creatingMeeting {
                    return .currentlyProcessing
                }
                if status.isFailed {
                    return .allowRetry
                }
                return .noExistingRecord
            } catch {
                logger.error("[WatchConnectivity] Error checking for duplicate: \(error)")
                return .noExistingRecord
            }
        }

        switch checkResult {
        case .alreadyProcessed:
            logger.info("[WatchConnectivity] Recording already processed: \(recordingId)")
            DispatchQueue.main.async {
                self.incomingTransferProgress[recordingId] = .completed
                self.updateCachedAggregateStates()
                self.confirmRecordingsReceived([recordingId])
            }
            return

        case .currentlyProcessing:
            logger.info("[WatchConnectivity] Recording currently processing: \(recordingId)")
            DispatchQueue.main.async {
                self.incomingTransferProgress[recordingId] = .receiving(progress: 1.0)
                self.updateCachedAggregateStates()
                _ = self.confirmRecordingsReceived([recordingId])
            }
            return

        case .allowRetry:
            logger.info("[WatchConnectivity] Retrying failed recording: \(recordingId)")

        case .noExistingRecord:
            logger.debug("🔵 [WatchConnectivity] ✅ New or retryable recording - proceeding")
        }

        // ========================================
        // DUPLICATE DETECTION - END
        // ========================================
        } // end if !isChunkedTransfer

        // Update transfer state to "receiving" when file arrives (before we process it)
        // For chunks, use parentRecordingId so all chunks show under one entry
        // Remove any placeholder pending states since we now have the actual recording
        let progressTrackingId = metadata.chunkInfo?.parentRecordingId ?? recordingId

        DispatchQueue.main.async {
            // Get current progress from watch if available (from progress updates)
            var initialProgress: Double? = nil
            if let currentState = self.incomingTransferProgress[progressTrackingId],
               case .receiving(let progress) = currentState {
                initialProgress = progress
            }

            // Always remove placeholder when a real transfer arrives
            if self.incomingTransferProgress[Self.pendingPlaceholderID] != nil {
                self.incomingTransferProgress.removeValue(forKey: Self.pendingPlaceholderID)
                self.logger.debug("[WatchConnectivity] Removed placeholder - real transfer arrived: \(progressTrackingId)")
            }

            // Clean up any old completed or 100% transfers when a new transfer arrives
            // This prevents accumulation of completed/finished transfers in the UI
            let transfersToRemove = self.incomingTransferProgress.keys.filter { id in
                if id == Self.pendingPlaceholderID { return false }
                if id == progressTrackingId { return false } // Don't remove the new one

                // Remove completed transfers
                if case .completed = self.incomingTransferProgress[id] { return true }

                // Also remove transfers that are at 100% progress (waiting for file)
                // These show "Receiving 100%" but file hasn't been received yet
                return false
            }

            if !transfersToRemove.isEmpty {
                for id in transfersToRemove {
                    self.incomingTransferProgress.removeValue(forKey: id)
                    self.logger.debug("[WatchConnectivity] Cleaned up old completed transfer: \(id)")
                }
                self.logger.debug("[WatchConnectivity] Cleaned up \(transfersToRemove.count) old transfer(s)")
                // Explicitly update state after cleanup to ensure UI updates
                self.updateCachedAggregateStates()
            }

            // Set state to receiving for this actual recording (preserve progress if we have it)
            self.suppressedStaleIncomingProgressIds.remove(progressTrackingId)
            self.suppressedStaleIncomingProgressIds.remove(recordingId)
            self.incomingProgressLastChangeAt[progressTrackingId] = Date()
            if let initialProgress {
                self.incomingProgressLastValue[progressTrackingId] = initialProgress
            }
            self.incomingTransferProgress[progressTrackingId] = .receiving(progress: initialProgress)
            self.updateCachedAggregateStates()
        }

        let originalURL = file.fileURL

        // ========================================
        // LOW-STORAGE PROTECTION
        // Check available disk space BEFORE copying to prevent data loss.
        // If the copy fails due to insufficient storage, watchOS deletes
        // the original temp file and the recording is permanently lost.
        // By checking first, we can skip the copy and let the Watch
        // keep its local copy for a later retry.
        // ========================================
        do {
            let incomingFileSize: Int64
            if let attrs = try? FileManager.default.attributesOfItem(atPath: originalURL.path),
               let size = attrs[.size] as? Int64 {
                incomingFileSize = size
            } else {
                incomingFileSize = 0
            }

            let tempDir = FileManager.default.temporaryDirectory
            let fsAttributes = try FileManager.default.attributesOfFileSystem(forPath: tempDir.path)
            let freeSpace = fsAttributes[.systemFreeSize] as? Int64 ?? 0

            // Require at least 2x the file size to be safe (copy + processing headroom)
            let requiredSpace = incomingFileSize * 2

            if freeSpace < requiredSpace && incomingFileSize > 0 {
                let freeSpaceMB = freeSpace / (1024 * 1024)
                let requiredMB = requiredSpace / (1024 * 1024)
                logger.error("[WatchConnectivity] INSUFFICIENT STORAGE: \(freeSpaceMB) MB free, need \(requiredMB) MB", error: nil)
                logger.error("[WatchConnectivity] Skipping file copy to protect Watch recording. Watch will retain its copy.", error: nil)

                // Update transfer state to failed -- do NOT send confirmation to Watch
                // so the Watch keeps its local copy for a later retry
                DispatchQueue.main.async {
                    self.incomingTransferProgress[recordingId] = .failed("Insufficient storage on iPhone. Free up space and try again.")
                    self.updateCachedAggregateStates()
                    self.onRecordingReceived?(.failure(RecordingTransferError.insufficientStorage))
                }
                return
            }

            logger.debug("[WatchConnectivity] Storage check passed: \(freeSpace / (1024 * 1024)) MB free, file size: \(incomingFileSize / 1024) KB")
        } catch {
            // If we can't check storage, log warning but proceed (better to try than to skip)
            logger.warning("[WatchConnectivity] Could not check available storage: \(error.localizedDescription). Proceeding with copy.")
        }
        // ========================================
        // LOW-STORAGE PROTECTION -- END
        // ========================================

        // Create a safe copy in our own temp directory SYNCHRONOUSLY.
        // For chunk-based transfers, use an organized directory structure:
        //   tmp/WatchRecordings/chunks/{parentRecordingId}/chunk_{index}.m4a
        // For single-file transfers, use the flat structure:
        //   tmp/WatchRecordings/{uuid}-{filename}
        let safeTempDir: URL
        let safeURL: URL

        if let chunkInfo = metadata.chunkInfo {
            // Chunk-based: organized by parentRecordingId
            safeTempDir = FileManager.default.temporaryDirectory
                .appendingPathComponent("WatchRecordings", isDirectory: true)
                .appendingPathComponent("chunks", isDirectory: true)
                .appendingPathComponent(chunkInfo.parentRecordingId.uuidString, isDirectory: true)
            safeURL = safeTempDir.appendingPathComponent("chunk_\(chunkInfo.chunkIndex).m4a")
        } else {
            // Single-file: flat structure
            safeTempDir = FileManager.default.temporaryDirectory
                .appendingPathComponent("WatchRecordings", isDirectory: true)
            safeURL = safeTempDir.appendingPathComponent("\(metadata.id.uuidString)-\(metadata.filename)")
        }

        do {
            // Create directory if needed
            try FileManager.default.createDirectory(at: safeTempDir, withIntermediateDirectories: true)

            // Remove existing file if present
            if FileManager.default.fileExists(atPath: safeURL.path) {
                try FileManager.default.removeItem(at: safeURL)
            }

            // Verify source file exists before copying (defensive programming)
            guard FileManager.default.fileExists(atPath: originalURL.path) else {
                throw RecordingTransferError.fileNotFound
            }

            // Copy the file IMMEDIATELY (synchronously)
            logger.info("[WatchConnectivity] Copying received file to safe location...")
            try FileManager.default.copyItem(at: originalURL, to: safeURL)

            // Verify the copy — reject empty/corrupt files to prevent data loss.
            // If we accept a 0-byte file, it would be saved, uploaded, confirmed to Watch
            // (which deletes its good copy), creating a meeting with no audio.
            let attrs = try FileManager.default.attributesOfItem(atPath: safeURL.path)
            let size = attrs[.size] as? Int64 ?? 0

            guard size > 0 else {
                logger.error("[WatchConnectivity] ❌ Received empty file (0 bytes) — rejecting transfer. Watch will retain its copy for retry.")
                try? FileManager.default.removeItem(at: safeURL)
                DispatchQueue.main.async {
                    self.incomingTransferProgress[recordingId] = .failed("Received empty file")
                    self.updateCachedAggregateStates()
                }
                return
            }

            logger.info("[WatchConnectivity] File copied successfully — size: \(size) bytes, path: \(safeURL.lastPathComponent)")

            // Now we can safely dispatch to main queue with the SAFE copy URL
            DispatchQueue.main.async {
                if isChunkedTransfer {
                    // For chunks: do NOT mark as completed yet. Keep receiving state.
                    // ChunkAssemblyManager will mark as completed when all chunks merge.
                    // Do NOT send per-chunk confirmation to Watch.
                    self.incomingTransferProgress[progressTrackingId] = .receiving(progress: nil)
                    self.updateCachedAggregateStates()
                    self.logger.info("[WatchConnectivity] Chunk file ready — dispatching to ChunkAssemblyManager (parentId: \(progressTrackingId))")
                } else {
                    // For single-file: mark as completed as before
                    self.incomingTransferProgress[recordingId] = .completed
                    self.updateCachedAggregateStates()
                    self.logger.info("[WatchConnectivity] Single-file transfer completed — recording: \(recordingId)")
                }

                self.onRecordingReceived?(.success((safeURL, metadata)))
                self.logger.info("[WatchConnectivity] onRecordingReceived callback invoked for recording: \(metadata.id)")

                NotificationCenter.default.post(
                    name: .recordingDidReceiveFromWatch,
                    object: nil,
                    userInfo: [
                        "fileURL": safeURL,
                        "metadata": metadata
                    ]
                )

                // Auto-remove completed transfers after a delay.
                // Skip auto-removal for chunked transfers -- they are managed by ChunkAssemblyManager.
                guard !isChunkedTransfer else { return }

                // This ensures the UI doesn't show completed transfers indefinitely
                // Also proactively clean up any other old completed transfers at the same time
                DispatchQueue.main.asyncAfter(deadline: .now() + Self.completedTransferAutoRemoveDelay) { [weak self] in
                    guard let self = self else { return }
                    var removedAny = false

                    // Remove this specific completed transfer
                    if case .completed = self.incomingTransferProgress[recordingId] {
                        self.incomingTransferProgress.removeValue(forKey: recordingId)
                        removedAny = true
                        logger.debug("[WatchConnectivity] ✅ Auto-removed completed transfer from UI: \(recordingId)")
                    }

                    // Also proactively clean up any other old completed transfers
                    // This prevents accumulation when multiple transfers complete
                    let allCompletedIds = self.incomingTransferProgress.keys.filter { id in
                        if id == Self.pendingPlaceholderID { return false }
                        if id == recordingId { return false } // Already handled above
                        if case .completed = self.incomingTransferProgress[id] { return true }
                        return false
                    }

                    if !allCompletedIds.isEmpty {
                        for id in allCompletedIds {
                            self.incomingTransferProgress.removeValue(forKey: id)
                            removedAny = true
                            logger.debug("[WatchConnectivity] ✅ Cleaned up additional completed transfer: \(id)")
                        }
                    }

                    // Update states if we removed anything
                    if removedAny {
                        self.updateCachedAggregateStates()
                    }
                }
            }

        } catch {
            logger.error("[WatchConnectivity] ❌ Failed to copy received file: \(error.localizedDescription)", error: error)

            // Cleanup: Remove copied file if it was created but processing failed
            // Note: safeURL is defined in the do block scope, so we recreate the path for cleanup
            let safeTempDir = FileManager.default.temporaryDirectory
                .appendingPathComponent("WatchRecordings", isDirectory: true)
            let safeURL = safeTempDir.appendingPathComponent("\(metadata.id.uuidString)-\(metadata.filename)")

            if FileManager.default.fileExists(atPath: safeURL.path) {
                try? FileManager.default.removeItem(at: safeURL)
                logger.debug("[WatchConnectivity] Cleaned up orphaned file: \(safeURL.path)")
            }

            // Update transfer state to failed
            DispatchQueue.main.async {
                self.incomingTransferProgress[recordingId] = .failed(error.localizedDescription)
                self.updateCachedAggregateStates()
                self.onRecordingReceived?(.failure(error))

                // Keep failed row visible so user can retry/dismiss manually.
            }
        }
    }
    #endif
}

// MARK: - Recording Transfer Error

/// Errors specific to recording transfer operations
enum RecordingTransferError: LocalizedError {
    case fileNotFound
    case transferFailed
    case metadataInvalid
    case insufficientStorage

    var errorDescription: String? {
        switch self {
        case .fileNotFound:
            return AppSharedText.errorFileNotFound
        case .transferFailed:
            return AppSharedText.errorTransferFailed
        case .metadataInvalid:
            return AppSharedText.errorMetadataInvalid
        case .insufficientStorage:
            return AppSharedText.errorInsufficientStorage
        }
    }
}

// MARK: - URL Extension for File Size

private extension URL {
    /// Returns a human-readable string of the file size
    var fileSizeString: String {
        guard let attrs = try? FileManager.default.attributesOfItem(atPath: path),
              let size = attrs[.size] as? Int64 else {
            return AppSharedText.errorUnknown
        }
        return ByteCountFormatter.string(fromByteCount: size, countStyle: .file)
    }
}

