    func trackChunk(index: Int, url: URL)
    func chunkURL(for index: Int) -> URL?
    func allChunkFiles() -> [Int: URL]
    func deleteAllTrackedChunks() -> ChunkDeletionReport
}

final class DefaultChunkFileStore: ChunkFileStoreProtocol {
    private let fileManager: FileManager
    private let baseDirectory: URL
    private var trackedChunkFiles: [Int: URL] = [:]

    /// Persistent inventory file so chunk tracking survives Watch app kills.
    /// Without this, chunks created during recording (via EXTEND) are orphaned
    /// in the temp directory if the app is killed before stopRecording() copies
    /// them to the persistent Recordings directory.
    private var inventoryFileURL: URL {
        baseDirectory.appendingPathComponent("chunk_file_store_inventory.json")
    }

    init(
        fileManager: FileManager = .default,
        baseDirectory: URL = FileManager.default.temporaryDirectory
    ) {
        self.fileManager = fileManager
        self.baseDirectory = baseDirectory
        restoreFromDisk()
    }

    func reset() {
        trackedChunkFiles.removeAll()
        removeInventoryFile()
    }

    func makeChunkURL(recordingId: UUID, chunkIndex: Int) -> URL {
        let chunkFilename = "\(recordingId.uuidString)_chunk\(chunkIndex).m4a"
        return baseDirectory.appendingPathComponent(chunkFilename)
    }

    func trackChunk(index: Int, url: URL) {
        trackedChunkFiles[index] = url
        persistToDisk()
    }

    func chunkURL(for index: Int) -> URL? {
        trackedChunkFiles[index]
    }

    func allChunkFiles() -> [Int: URL] {
        trackedChunkFiles
    }

    func deleteAllTrackedChunks() -> ChunkDeletionReport {
        var deleted: [Int: URL] = [:]
        var failures: [Int: Error] = [:]

        for (index, url) in trackedChunkFiles {
            do {
                try fileManager.removeItem(at: url)
                deleted[index] = url
            } catch {
                failures[index] = error
            }
        }

        trackedChunkFiles.removeAll()
        removeInventoryFile()
        return ChunkDeletionReport(deleted: deleted, failures: failures)
    }

    // MARK: - Disk Persistence

    private func persistToDisk() {
        // Serialize as [String: String] (index -> URL path) for simple JSON
        let serializable = trackedChunkFiles.reduce(into: [String: String]()) { dict, entry in
            dict[String(entry.key)] = entry.value.path
        }
        guard let data = try? JSONSerialization.data(withJSONObject: serializable) else { return }
        try? data.write(to: inventoryFileURL, options: .atomic)
    }

    private func restoreFromDisk() {
        guard let data = try? Data(contentsOf: inventoryFileURL),
              let dict = try? JSONSerialization.jsonObject(with: data) as? [String: String] else {
            return
        }

        var restored: [Int: URL] = [:]
        for (indexStr, path) in dict {
            guard let index = Int(indexStr) else { continue }
            let url = URL(fileURLWithPath: path)
            // Only restore entries whose files still exist on disk
            if fileManager.fileExists(atPath: url.path) {
                restored[index] = url
            }
        }
        trackedChunkFiles = restored
    }

    private func removeInventoryFile() {
        try? fileManager.removeItem(at: inventoryFileURL)
    }
}

