    // MARK: - Keep-Alive Session Management

    /// Starts an ExtendedRuntimeSession to keep the app alive during recording.
    /// Provides ~1 hour of background execution. User interaction (EXTEND/alerts)
    /// keeps the app in the foreground, extending effective recording duration.
    private func startExtendedRuntimeSessionFallback() {
        let sessionStarted = extendedRuntimeSessionManager.startSession(
            onStateChange: { sessionState in
                RecordingLogger.log("Extended runtime session state changed: \(sessionState)")
            },
            onExpiration: { [weak self] in
                Task { @MainActor [weak self] in
                    self?.handleExtendedRuntimeSessionExpiration()
                }
            },
            onInvalidation: { [weak self] reason, error in
                Task { @MainActor [weak self] in
                    self?.handleExtendedRuntimeSessionInvalidation(reason: reason, error: error)
                }
            }
        )

        if sessionStarted {
            RecordingLogger.success("ExtendedRuntimeSession fallback started (~1 hour limit)")
        } else {
            RecordingLogger.log("⚠️ ExtendedRuntimeSession fallback could not start")
        }
    }

    /// Stops the keep-alive extended runtime session.
    private func stopKeepAliveSession() {
        extendedRuntimeSessionManager.stopSession()
        RecordingLogger.log("Extended runtime session stopped")
    }

    // MARK: - Extended Runtime Session Handling

    /// Sets up callbacks for extended runtime session state changes and expiration
    private func setupExtendedRuntimeSessionCallbacks() {
        RecordingLogger.log("Setting up extended runtime session callbacks...")

        // Note: Callbacks are set when starting the session in startRecording()
        // This method is here for future extensibility if needed
        RecordingLogger.success("Extended runtime session callback setup ready")
    }

    // MARK: - Graceful Recording Shutdown

    /// Performs a graceful shutdown of an active recording: saves chunks, initiates transfer,
    /// logs the reason to Sentry (with user context), and shows a user-friendly message.
    ///
    /// Every error path that interrupts a recording must funnel through this method so that
    /// no recorded audio is lost.
    ///
    /// - Parameters:
    ///   - reason: Human-readable reason shown in the UI (e.g. "Session time limit was reached.")
    ///   - sentryMessage: Technical message sent to Sentry for debugging / alerting
    ///   - error: Optional underlying error object attached to the Sentry event
    private func gracefulRecordingShutdown(
        reason: String,
        sentryMessage: String,
        error: Error? = nil
    ) {
        guard state == .recording || state == .paused else { return }

        DispatchQueue.main.async { [weak self] in
            guard let self = self, self.state == .recording || self.state == .paused else { return }

            let recordedDuration = self.elapsed

            // Save the recording and initiate transfer to iPhone
            self.stopRecording()

            // Log to Sentry so we can track which users hit this and why
            RecordingLogger.error(
                "\(sentryMessage) — recording gracefully stopped after \(Int(recordedDuration))s",
                error: error
            )

            self.state = .error("Meeting saved. \(reason)")
            WKInterfaceDevice.current().play(.notification)
        }
    }

    /// Handles extended runtime session expiration
    /// Called when the session is about to expire (typically after ~4 hours).
    private func handleExtendedRuntimeSessionExpiration() {
        RecordingLogger.log("⚠️ Extended runtime session is expiring")

        gracefulRecordingShutdown(
            reason: "Session time limit was reached.",
            sentryMessage: "Session time limit reached (expiration callback)"
        )
    }

    /// Handles extended runtime session invalidation
    /// Called when the session is invalidated for various reasons
    /// - Parameters:
    ///   - reason: The reason for invalidation
    ///   - error: Optional error if invalidation was due to an error
    private func handleExtendedRuntimeSessionInvalidation(
        reason: WKExtendedRuntimeSessionInvalidationReason,
        error: Error?
    ) {
        RecordingLogger.log("Extended runtime session invalidated - Reason: \(reason)")

        switch reason {
        case .none:
            // Manual invalidation (expected when stopping recording) — no action needed
            RecordingLogger.log("Session invalidated manually (expected)")

        case .sessionInProgress:
            RecordingLogger.log("Session invalidated - another session already in progress")
            gracefulRecordingShutdown(
                reason: "A session conflict occurred.",
                sentryMessage: "Session invalidated — sessionInProgress"
            )

        case .expired:
            RecordingLogger.log("Session expired - time limit reached (invalidation handler)")
            gracefulRecordingShutdown(
                reason: "Session time limit was reached.",
                sentryMessage: "Session invalidated — expired"
            )

        case .resignedFrontmost:
            RecordingLogger.log("Session invalidated - app resigned frontmost status (will not pause during ringing)")
            // Do not pause on frontmost resignation (e.g., incoming call UI). Keep state as-is and attempt to keep the recorder running.
            if state == .recording {
                // Best-effort to keep/resume the engine in case the OS briefly halted it.
                chunkedRecordingManager.resumeRecording()
            }

        case .suppressedBySystem:
            RecordingLogger.log("Session invalidated - suppressed by system")
            gracefulRecordingShutdown(
                reason: "A system limitation occurred.",
                sentryMessage: "Session invalidated — suppressedBySystem"
            )

        case .error:
            RecordingLogger.log("Session invalidated due to error")
            gracefulRecordingShutdown(
                reason: "An unexpected error occurred.",
                sentryMessage: "Session invalidated — error",
                error: error
            )

        @unknown default:
            RecordingLogger.log("Session invalidated for unknown reason: \(reason.rawValue)")
            gracefulRecordingShutdown(
                reason: "The session ended unexpectedly.",
                sentryMessage: "Session invalidated — unknown reason (\(reason.rawValue))"
            )
        }
    }

    // MARK: - Recording State Resync

    /// Observes iPhone's request to re-send our current recording state.
    /// When the iPhone app launches, it reads cached `session.receivedApplicationContext` which may
    /// contain a stale `isRecordingOnWatch = true`. The iPhone sends a message asking us to confirm,
    /// and we respond with our actual current state via application context.
    private func setupRecordingStateResyncObserver() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handleRecordingStateResyncRequest),
            name: .watchShouldResyncRecordingState,
            object: nil
        )
        RecordingLogger.log("Recording state resync observer configured")
    }

    /// Observes iPhone's request to retry/resend a specific recording transfer.
    private func setupTransferRetryRequestObserver() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handleTransferRetryRequestFromiPhone(_:)),
            name: .iPhoneRequestedTransferRetry,
            object: nil
        )
        RecordingLogger.log("iPhone transfer retry observer configured")
    }

    @objc private func handleRecordingStateResyncRequest() {
        RecordingLogger.log("Received recording state resync request from iPhone")
        DispatchQueue.main.async { [weak self] in
            guard let self = self else { return }
            let isCurrentlyRecording = (self.state == .recording || self.state == .paused)
            let currentStartDate = isCurrentlyRecording ? self.startDate : nil

            RecordingLogger.log("Re-sending recording state: isRecording=\(isCurrentlyRecording), startedAt=\(String(describing: currentStartDate))")
            WatchConnectivityManager.shared.sendRecordingOnWatchIndicator(
                isRecording: isCurrentlyRecording,
                startedAt: currentStartDate
            )
        }
    }

    @objc private func handleTransferRetryRequestFromiPhone(_ notification: Notification) {
        guard let userInfo = notification.userInfo,
              let recordingIdString = userInfo[WatchMessageKey.recordingId] as? String,
              let recordingId = UUID(uuidString: recordingIdString) else {
            RecordingLogger.log("Received invalid retry request payload from iPhone")
            return
        }

        RecordingLogger.log("Received retry request from iPhone for recording: \(recordingId)")
        DispatchQueue.main.async { [weak self] in
            self?.handleRetryRequestFromiPhone(recordingId: recordingId)
        }
    }

    /// Handles iPhone-initiated retry while respecting one-recording-at-a-time queueing.
    private func handleRetryRequestFromiPhone(recordingId: UUID) {
        guard let localRepo = repository as? LocalRecordingRepository else {
            RecordingLogger.error("Cannot handle iPhone retry request - repository is not LocalRecordingRepository")
            return
        }

        guard let recording = try? repository.fetchAllRecordings().first(where: { $0.id == recordingId }) else {
            RecordingLogger.log("Retry request ignored - recording not found locally: \(recordingId)")
            return
        }

        if currentTransferRecordingId == recordingId || activeTransfers.contains(recordingId) ||
            connectivityManager.isRecordingTransferring(recordingId) {
            RecordingLogger.log("Retry request ignored because recording is already transferring: \(recordingId)")
            return
        }

        // If currently busy with a different recording, queue this one as pending.
        if let activeId = currentTransferRecordingId, activeId != recordingId {
            do {
                try localRepo.updateStatus(recordingId, status: .pending, error: "Queued from iPhone retry request")
                RecordingLogger.log("Queued retry request while transfer slot busy (\(activeId)) for recording: \(recordingId)")
            } catch {
                RecordingLogger.error("Failed to mark recording as queued from iPhone retry request", error: error)
            }
            return
        }

        if activeTransfers.contains(where: { $0 != recordingId }) {
            do {
                try localRepo.updateStatus(recordingId, status: .pending, error: "Queued from iPhone retry request")
                RecordingLogger.log("Queued retry request while another active transfer exists for recording: \(recordingId)")
            } catch {
                RecordingLogger.error("Failed to mark recording as queued from iPhone retry request", error: error)
            }
            return
        }

        // Ensure request retries are sendable through normal pipeline.
        do {
            try localRepo.updateStatus(recordingId, status: .pending, error: "Retry requested by iPhone")
        } catch {
            RecordingLogger.error("Failed to reset status before iPhone-requested retry", error: error)
        }

        transferToiOS(recording: recording)
    }

    // MARK: - Audio Interruption Handling

    /// Sets up notification observers for audio session interruptions (e.g., phone calls)
    private func setupAudioInterruptionHandling() {
        RecordingLogger.log("Setting up audio interruption handling...")

        audioInterruptionObserver = NotificationCenter.default.addObserver(
            forName: AVAudioSession.interruptionNotification,
            object: nil,
            queue: .main
        ) { [weak self] notification in
            self?.handleAudioInterruption(notification: notification)
        }

        RecordingLogger.success("Audio interruption handling configured")
    }

    deinit {
        chunkManagerCancellables.removeAll()
        cancellables.removeAll()

        // Clean up notification observers
        if let observer = audioInterruptionObserver {
            NotificationCenter.default.removeObserver(observer)
        }
        NotificationCenter.default.removeObserver(self, name: .watchShouldResyncRecordingState, object: nil)
        NotificationCenter.default.removeObserver(self, name: .iPhoneRequestedTransferRetry, object: nil)

        // Cancel any pending deferred pause when deinitializing
        pendingInterruptionPauseWorkItem?.cancel()
        pendingInterruptionPauseWorkItem = nil
    }

    /// Handles audio session interruption notifications (phone calls, etc.)
    private func handleAudioInterruption(notification: Notification) {
        guard let userInfo = notification.userInfo,
              let typeValue = userInfo[AVAudioSessionInterruptionTypeKey] as? UInt,
              let type = AVAudioSession.InterruptionType(rawValue: typeValue) else {
            return
        }

        switch type {
        case .began:
            RecordingLogger.log("Audio interruption began (e.g., phone call) — deferring pause by \(interruptionDeferralSeconds)s to avoid ring-only pauses")

            // Cancel any existing pending pause
            pendingInterruptionPauseWorkItem?.cancel()

            // Only consider pausing if we're actively recording; defer to see if the interruption clears quickly
            guard self.state == .recording else { return }

            let workItem = DispatchWorkItem { [weak self] in
                guard let self = self else { return }
                // If still recording after the deferral window, treat as a real/connected interruption and pause
                if self.state == .recording {
                    self.pauseRecording(reason: .audioInterruption)
                }
            }
            self.pendingInterruptionPauseWorkItem = workItem

            // If options indicate "shouldResume" or no options provided, treat as potentially transient (ring-only) and keep deferring.
            if let optionsValue = userInfo[AVAudioSessionInterruptionOptionKey] as? UInt {
                let options = AVAudioSession.InterruptionOptions(rawValue: optionsValue)
                if options.contains(.shouldResume) {
                    // Likely ring-only or transient; proceed with deferral without immediate pause.
                }
            }

            DispatchQueue.main.asyncAfter(deadline: .now() + interruptionDeferralSeconds, execute: workItem)

        case .ended:
            RecordingLogger.log("Audio interruption ended — cancelling any deferred pause and attempting resume if needed")

            // Cancel the deferred pause (ring-only interruptions end quickly and should not pause)
            pendingInterruptionPauseWorkItem?.cancel()
            pendingInterruptionPauseWorkItem = nil

            // If we never transitioned to paused but the underlying recorder might have been halted by the OS,
            // attempt a best-effort resume of the recording engine.
            if self.state == .recording {
                self.chunkedRecordingManager.resumeRecording()
            }

            // Respect existing auto-resume behavior when we did pause due to an interruption
            if let optionsValue = userInfo[AVAudioSessionInterruptionOptionKey] as? UInt {
                let options = AVAudioSession.InterruptionOptions(rawValue: optionsValue)
                if options.contains(.shouldResume) {
                    handleAutoResume()
                }
            } else {
                // If no options provided, try to auto-resume if it was an interruption pause
                handleAutoResume()
            }
        @unknown default:
            RecordingLogger.log("Unknown interruption type: \(typeValue)")
        }
    }

    /// Checks if recording should auto-resume and resumes if appropriate
    /// Only auto-resumes if the pause was due to an audio interruption (not manual)
    func handleAutoResume() {
        guard state == .paused else {
            return
        }
        // Never stop due to interruptions; only resume if it was an interruption pause.

        // Only auto-resume if it was paused due to audio interruption
        if pauseReason == .audioInterruption {
            RecordingLogger.log("Auto-resuming recording after audio interruption ended")
            resumeRecording()
        } else {
            RecordingLogger.log("Not auto-resuming - pause was manual or unknown reason")
        }
    }

    // MARK: - Recording Controls

    func startRecording() {
        RecordingLogger.log("=== START RECORDING ===")

        // Start extended runtime session to keep the app alive in the background.
        // The session provides ~1 hour of background execution. Since the user
        // periodically interacts (EXTEND button, dismiss alerts), the app stays
        // foreground-active, mitigating this limit for longer recordings.
        startExtendedRuntimeSessionFallback()

        // Continue with recording setup immediately

        // Update state immediately for instant UI feedback
        // This prevents the UI from freezing while audio session setup occurs
        state = .recording

        // Setup audio session (this can block, but state is already updated)
        guard setupAudioSession() else {
            RecordingLogger.error("Cannot start recording - audio session setup failed")
            // Clean up keep-alive session if audio setup fails
            stopKeepAliveSession()
            state = .error("Audio session setup failed")
            WKInterfaceDevice.current().play(.failure)
            return
        }

        // Start recording via ChunkedRecordingManager.
        // The manager handles AVAudioRecorder lifecycle, countdown timer, and chunk creation.
        // Chunks are created when user presses EXTEND; completed chunks are stored locally.
        // ALL chunks are transferred to iPhone only after recording stops (in stopRecording).
        let recordingId = chunkedRecordingManager.startRecording(
            onChunkCompleted: { chunkURL, chunkMetadata in
                let chunkIndex = chunkMetadata.chunkInfo?.chunkIndex ?? -1
                let isLast = chunkMetadata.chunkInfo?.isLastChunk ?? false
                RecordingLogger.log("Chunk \(chunkIndex) saved locally (isLast: \(isLast)), will transfer after stop")
            },
            onRecordingFinished: {
                RecordingLogger.log("All chunks finalized — ready for transfer")
            }
        )

        guard let recordingId = recordingId else {
            RecordingLogger.error("ChunkedRecordingManager failed to start recording")
            stopKeepAliveSession()
            state = .error("Failed to start recording")
            WKInterfaceDevice.current().play(.failure)
            return
        }

        currentRecordingId = recordingId

        // No separate currentRecordingURL needed -- ChunkedRecordingManager manages chunk files
        // currentRecordingURL is set to nil; stopRecording will use the manager's output
        currentRecordingURL = nil

        RecordingLogger.log("Recording ID: \(recordingId)")
        RecordingLogger.log("Recording started via ChunkedRecordingManager (dynamic chunk allocation)")

        // Recording started successfully via ChunkedRecordingManager
        let now = Date()
        recordingStartTime = now  // Capture the original start time (not affected by pause/resume)
        elapsed = 0
        pauseReason = nil  // Clear any previous pause reason
        state = .recording
        startTimer()

        RecordingLogger.success("Recording started successfully!")
        RecordingLogger.log("  Recording ID: \(recordingId)")
        RecordingLogger.log("  Start Time: \(now)")

        WKInterfaceDevice.current().play(.start)

        // Notify iPhone so it can show Live Activity and notification (Guideline 2.5.14)
        WatchConnectivityManager.shared.sendRecordingOnWatchIndicator(isRecording: true, startedAt: recordingStartTime)
    }

    func pauseRecording(reason: PauseReason = .manual) {
        RecordingLogger.log("=== PAUSE RECORDING (reason: \(reason)) ===")

        guard state == .recording else {
            RecordingLogger.log("Cannot pause - not in recording state (current: \(state))")
            return
        }

        // Pause via ChunkedRecordingManager (pauses the underlying AVAudioRecorder)
        chunkedRecordingManager.pauseRecording()
        RecordingLogger.log("Audio recorder paused")

        stopTimer()
        if let s = startDate {
            accumulated += Date().timeIntervalSince(s)
        }
        startDate = nil
        pauseReason = reason
        state = .paused

        RecordingLogger.success("Recording paused. Accumulated time: \(accumulated)s, Reason: \(reason)")
        WKInterfaceDevice.current().play(.stop)
    }

    func resumeRecording() {
        RecordingLogger.log("=== RESUME RECORDING ===")

        guard state == .paused else {
            RecordingLogger.log("Cannot resume - not in paused state (current: \(state))")
            return
        }

        // Resume via ChunkedRecordingManager (resumes the underlying AVAudioRecorder)
        chunkedRecordingManager.resumeRecording()
        RecordingLogger.log("Audio recorder resumed")

        startDate = Date()
        pauseReason = nil  // Clear pause reason when resuming
        state = .recording
        startTimer()

        RecordingLogger.success("Recording resumed")
        WKInterfaceDevice.current().play(.start)
    }

    // MARK: - Extend Recording

    /// Extends the recording by 45 minutes.
    /// Creates a chunk boundary (finalizes current chunk, starts new one),
    /// adds time to the countdown, and starts a fresh ExtendedRuntimeSession
    /// so the OS grants another ~1 hour of background execution.
    func extendRecording() {
        RecordingLogger.log("=== EXTEND RECORDING ===")

        guard state == .recording else {
            RecordingLogger.log("Cannot extend - not in recording state (current: \(state))")
            return
        }

        let success = chunkedRecordingManager.extendRecording()

        if success {
            RecordingLogger.success("Recording extended by \(chunkedRecordingManager.configuredExtendAmountSeconds / 60) minutes")

            // Reset alert tracking so alerts fire again for the new countdown window
            shownAlerts.removeAll()
            activeAlert = nil

            // Start a fresh ExtendedRuntimeSession to get another ~1 hour of background time.
            // startSession() internally parks the old session and invalidates it safely.
            RecordingLogger.log("Renewing ExtendedRuntimeSession for extended recording...")
            startExtendedRuntimeSessionFallback()

            WKInterfaceDevice.current().play(.success)
        } else {
            RecordingLogger.error("Failed to extend recording")
            WKInterfaceDevice.current().play(.failure)
        }
    }

    /// Dismisses the currently active time-remaining alert
    func dismissAlert() {
        activeAlert = nil
    }

    // MARK: - Alert Threshold Checking

    /// Checks if the remaining time has crossed any alert thresholds
    /// and triggers the appropriate alert with haptic feedback.
    /// Called every time remainingTime is updated.
    /// - Parameter remaining: Current remaining time in seconds
    private func checkAlertThresholds(remaining: TimeInterval) {
        guard state == .recording else { return }

        for threshold in alertThresholds {
            // Fire when remaining dips at or below the threshold, but only once per threshold
            if remaining <= threshold && remaining > 0 && !shownAlerts.contains(threshold) {
                shownAlerts.insert(threshold)

                // Determine which alert to show
                let alert: RecordingAlert
                switch threshold {
                case let t where t == 5 * 60:
                    alert = .fiveMinutes
                case let t where t == 2 * 60:
                    alert = .twoMinutes
                case let t where t == 30:
                    alert = .thirtySeconds
                default:
                    continue
                }

                RecordingLogger.log("Alert triggered: \(alert) (remaining: \(remaining)s)")

                // Show the alert and play haptic
                activeAlert = alert
                WKInterfaceDevice.current().play(.notification)

                // Auto-dismiss after 5 seconds
                DispatchQueue.main.asyncAfter(deadline: .now() + 5.0) { [weak self] in
                    if self?.activeAlert == alert {
                        self?.activeAlert = nil
                    }
                }

                // Only show one alert at a time (the most urgent)
                break
            }
        }
    }

    // MARK: - Stall Detection & Retry

    /// Starts monitoring transfer progress for stalls (works for both chunked and single-file).
    /// Call after transfers begin.
    func startStallDetection() {
        RecordingLogger.log("Starting stall detection timer")
        stallCheckTimer?.invalidate()

        // Seed single-file progress tracking for every active transfer
        let now = Date()
        for recordingId in activeTransfers {
            if recordingLastProgressUpdate[recordingId] == nil {
                recordingLastProgressUpdate[recordingId] = now
                recordingLastProgressValue[recordingId] = 0.0
            }
        }

        stallCheckTimer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { [weak self] _ in
            Task { @MainActor in
                self?.checkForStalledTransfers()
            }
        }
    }

    /// Stops the stall detection timer and clears all progress tracking state
    private func stopStallDetection() {
        stallCheckTimer?.invalidate()
        stallCheckTimer = nil
        chunkLastProgressUpdate.removeAll()
        chunkTransferProgress.removeAll()
        recordingLastProgressUpdate.removeAll()
        recordingLastProgressValue.removeAll()
        retryStartTime = nil
    }

    /// Updates progress for a specific chunk (called from transfer progress callbacks)
    /// - Parameters:
    ///   - chunkId: The UUID of the chunk being transferred
    ///   - progress: Current progress (0.0 to 1.0)
    func updateChunkProgress(chunkId: UUID, progress: Double) {
        chunkTransferProgress[chunkId] = progress
        chunkLastProgressUpdate[chunkId] = Date()
    }

    /// Checks all in-flight transfers (chunked and single-file) for stalls.
    /// A transfer is stalled if progress hasn't changed past the timeout policy.
    private func checkForStalledTransfers() {
        guard transferState == .transferring || transferState == .retrying else { return }

        let now = Date()

        // Check retry timeout (15-minute window for retries)
        if transferState == .retrying, let retryStart = retryStartTime {
            if now.timeIntervalSince(retryStart) >= Self.retryTimeoutSeconds {
                RecordingLogger.error("Retry timeout reached (15 min) - triggering COMPLETE FAIL")
                handleCompleteFail()
                return
            }
        }

        // --- Check chunk-based transfers ---
        for (chunkId, lastUpdate) in chunkLastProgressUpdate {
            let progress = chunkTransferProgress[chunkId] ?? 0
            let timeSinceUpdate = now.timeIntervalSince(lastUpdate)
            let activeRecordingId = currentTransferRecordingId
            let timeout = transferTimeoutSeconds(for: activeRecordingId)

            if progress < 1.0 && timeSinceUpdate >= timeout {
                RecordingLogger.error("Chunk \(chunkId) stalled at \(Int(progress * 100))% for \(Int(timeSinceUpdate))s")
                handleTransferStalled(
                    recordingId: activeRecordingId,
                    stalledProgress: progress,
                    stalledDuration: timeSinceUpdate
                )
                return
            }
        }

        // --- Check single-file transfers ---
        // For non-chunked transfers, chunkLastProgressUpdate is empty so the loop
        // above is a no-op. Poll WatchConnectivityManager's per-recording progress.
        guard chunkLastProgressUpdate.isEmpty else { return }

        for recordingId in activeTransfers {
            let currentProgress = connectivityManager.recordingTransferProgress[recordingId] ?? 0
            let previousProgress = recordingLastProgressValue[recordingId] ?? -1
            let timeout = transferTimeoutSeconds(for: recordingId)

            if currentProgress != previousProgress {
                recordingLastProgressUpdate[recordingId] = now
                recordingLastProgressValue[recordingId] = currentProgress
            } else if let lastUpdate = recordingLastProgressUpdate[recordingId] {
                let timeSinceUpdate = now.timeIntervalSince(lastUpdate)
                if currentProgress < 1.0 && timeSinceUpdate >= timeout {
                    RecordingLogger.error("Single-file transfer \(recordingId) stalled at \(Int(currentProgress * 100))% for \(Int(timeSinceUpdate))s")
                    handleTransferStalled(
                        recordingId: recordingId,
                        stalledProgress: currentProgress,
                        stalledDuration: timeSinceUpdate
                    )
                    return
                }
            }
        }
    }

    /// Handles a stalled transfer by cancelling the in-flight WCSession transfer
    /// and moving to failed state. The user must press RETRY to continue.
    private func handleTransferStalled(
        recordingId: UUID?,
        stalledProgress: Double,
        stalledDuration: TimeInterval
    ) {
        RecordingLogger.log("Transfer stalled — cancelling in-flight transfers before marking failed")

        // Cancel the existing WCSession transfer so the OS stops trying to deliver
        // the old payload. Without this, a retry would create a second parallel transfer.
        if let recordingId = recordingId ?? currentRecordingId {
            connectivityManager.cancelTransfer(recordingId: recordingId)
            RecordingLogger.log("Cancelled WCSession transfer for recording: \(recordingId)")
            timedOutTransferIds.insert(recordingId)

            Task { @MainActor [weak self] in
                await self?.transferFailureNotificationService.notifyTransferFailed(recordingId: recordingId)
            }
        }

        let failedMessage = "Transfer stalled at \(Int(stalledProgress * 100))% for \(Int(stalledDuration))s. Retry will resend from scratch."
        DispatchQueue.main.async {
            self.transferState = .failed(failedMessage)
        }

        WKInterfaceDevice.current().play(.failure)
    }

    /// Called when user presses RETRY from the failed state.
    /// Cancels any lingering WCSession transfers, then resends and starts a 15-minute timeout.
    func retryTransfer() {
        RecordingLogger.log("=== RETRY TRANSFER ===")

        guard case .failed = transferState else {
            RecordingLogger.log("Cannot retry - not in failed state (current: \(transferState))")
            return
        }

        // Cancel any lingering WCSession transfers to prevent duplicates
        if let recordingId = currentRecordingId {
            connectivityManager.cancelTransfer(recordingId: recordingId)
            RecordingLogger.log("Cancelled existing WCSession transfer before retry: \(recordingId)")
            if timedOutTransferIds.contains(recordingId) {
                // Timed-out transfers must retry from scratch to avoid partial-state divergence.
                requestCleanupPartialsOniPhone(recordingId: recordingId)
            }
        }

        transferState = .retrying
        retryStartTime = Date()

        // Retry pending transfers via the standard mechanism
        retryPendingTransfers()
        if let recordingId = currentRecordingId {
            timedOutTransferIds.remove(recordingId)
        }

        RecordingLogger.log("Retry started with 15-minute timeout")
        WKInterfaceDevice.current().play(.start)
    }

    private func transferTimeoutSeconds(for recordingId: UUID?) -> TimeInterval {
        guard let recordingId = recordingId,
              let recording = try? repository.fetchAllRecordings().first(where: { $0.id == recordingId }) else {
            return transferTimeoutPolicy.timeout(forRecordingDuration: nil)
        }
        return transferTimeoutPolicy.timeout(forRecordingDuration: recording.duration)
    }

    private func requestCleanupPartialsOniPhone(recordingId: UUID) {
        connectivityManager.sendMessage(
            ["action": "cleanupPartials", "recordingId": recordingId.uuidString]
        ) { error in
            if let error = error {
                RecordingLogger.error("Failed to send cleanup message to iPhone before retry", error: error)
            }
        }
    }

    /// Handles complete failure: retry timed out after 15 minutes.
    /// Cancels all in-flight transfers, deletes partial data, then resends from scratch.
    private func handleCompleteFail() {
        RecordingLogger.error("=== COMPLETE FAIL - Deleting all partials and resending ===")

        transferState = .completeFail

        // Cancel ALL in-flight WCSession transfers for this recording first
        if let recordingId = currentRecordingId {
            connectivityManager.cancelTransfer(recordingId: recordingId)
            RecordingLogger.log("Cancelled all WCSession transfers for complete fail: \(recordingId)")
        }

        // Clear all chunk progress tracking
        chunkTransferProgress.removeAll()
        chunkLastProgressUpdate.removeAll()
        retryStartTime = nil

        // Notify iPhone to delete partial data via connectivity manager
        connectivityManager.sendMessage(
            ["action": "cleanupPartials", "recordingId": currentRecordingId?.uuidString ?? ""]
        ) { error in
            if let error = error {
                RecordingLogger.error("Failed to send cleanup message to iPhone", error: error)
            }
        }

        // Re-send all chunks from the beginning
        let chunkFiles = chunkedRecordingManager.getLocalChunkFiles()
        RecordingLogger.log("Resending \(chunkFiles.count) chunks from scratch")

        // Small delay to let cleanup propagate, then start fresh transfer
        DispatchQueue.main.asyncAfter(deadline: .now() + 2.0) { [weak self] in
            guard let self = self else { return }
            self.transferState = .transferring
            self.retryStartTime = nil

            // Re-transfer all chunks
            self.retryPendingTransfers()
        }

        WKInterfaceDevice.current().play(.failure)
    }

    func stopRecording() {
        RecordingLogger.log("=== STOP RECORDING ===")

        guard state == .recording || state == .paused else {
            RecordingLogger.log("Cannot stop - not in recording/paused state (current: \(state))")
            return
        }

        // ✅ Get the recording ID we created at start
        guard let recordingId = currentRecordingId else {
            RecordingLogger.error("No recording ID found - this should not happen!")
            state = .error("Internal error: no recording ID")
            WKInterfaceDevice.current().play(.failure)
            return
        }

        state = .saving
        stopTimer()

        // Notify iPhone that recording stopped so it can end Live Activity
        WatchConnectivityManager.shared.sendRecordingOnWatchIndicator(isRecording: false, startedAt: nil)

        // Stop recording via ChunkedRecordingManager.
        // This finalizes the last chunk (marks isLastChunk = true).
        // No transfer happens yet — we send everything below after saving.
        let totalDuration = chunkedRecordingManager.stopRecording()

        RecordingLogger.log("Recording stopped. ID: \(recordingId), Total duration: \(totalDuration)s")

        // Save recording to local repository so it appears in Watch history.
        // Copy ALL chunks to the Recordings directory so that retries via transferToiOS
        // can find and re-send every chunk (not just the first).
        let chunkFiles = chunkedRecordingManager.getLocalChunkFiles()
        let sortedChunks = chunkFiles.sorted(by: { $0.key < $1.key })

        if let localRepo = repository as? LocalRecordingRepository {
            // Copy every chunk to the persistent Recordings directory
            for (chunkIndex, chunkURL) in sortedChunks {
                let destURL = localRepo.recordingsDirectoryURL
                    .appendingPathComponent(chunkURL.lastPathComponent)
                do {
                    if FileManager.default.fileExists(atPath: destURL.path) {
                        try FileManager.default.removeItem(at: destURL)
                    }
                    try FileManager.default.copyItem(at: chunkURL, to: destURL)
                    RecordingLogger.log("  Persisted chunk \(chunkIndex) → \(destURL.lastPathComponent)")
                } catch {
                    RecordingLogger.error("Failed to persist chunk \(chunkIndex): \(error.localizedDescription)", error: error)
                }
            }
        }

        // Save first chunk as the representative file for the Core Data entry
        var savedRecordingForTransfer: Recording?
        if let firstChunkEntry = sortedChunks.first {
            do {
                let savedRecording = try repository.saveRecording(
                    id: recordingId,
                    fileURL: firstChunkEntry.1,
                    duration: totalDuration,
                    startTime: recordingStartTime
                )
                RecordingLogger.success("Saved recording to local repository: \(savedRecording.id), duration: \(totalDuration)s, totalChunks: \(sortedChunks.count)")
                lastRecording = savedRecording
                savedRecordingForTransfer = savedRecording
            } catch {
                RecordingLogger.error("Failed to save recording to local repository", error: error)
            }
        } else {
            RecordingLogger.error("No chunk files available to save recording to local repository")
        }

        // Queue-aware transfer start:
        // only one recording is sent at a time; pending recordings remain queued.
        if let recordingToTransfer = savedRecordingForTransfer {
            transferToiOS(recording: recordingToTransfer)
        } else {
            RecordingLogger.error("Skipping transfer start because recording could not be saved")
        }

        state = .idle
        accumulated = 0
        elapsed = 0
        remainingTime = 0
        isExtendEnabled = false
        activeAlert = nil
        shownAlerts.removeAll()
        WKInterfaceDevice.current().play(.success)

        // Stop keep-alive session - allow app to suspend normally now
        stopKeepAliveSession()

        // Cleanup recording state (keep currentRecordingId for stall detection reference)
        // Keep recordingStartTime alive until transfer is confirmed — retries need it
        // for rebuilding RecordingTransferMetadata with the correct startTime.
        currentRecordingURL = nil
        pauseReason = nil
        deactivateAudioSession()

        RecordingLogger.log("=== STOP RECORDING COMPLETE ===")
    }

    // MARK: - iOS Transfer

    /// Transfers a recording to the iOS app via WatchConnectivity.
    /// Chunk-aware: scans the Recordings directory for all chunk files belonging to
    /// this recording and sends them with proper `chunkInfo` metadata so the iPhone
    /// can assemble them. Falls back to a single-file transfer when only one file exists.
    /// - Parameter recording: The recording to transfer
    func transferToiOS(recording: Recording) {
        RecordingLogger.log("=== TRANSFER TO iOS ===")
        RecordingLogger.log("Recording ID: \(recording.id)")
        RecordingLogger.log("File URL: \(recording.fileURL.path)")
        RecordingLogger.log("Filename: \(recording.filename)")
        RecordingLogger.log("Duration: \(recording.duration)s")

        // Enforce one-recording-at-a-time transfer policy.
        if let activeId = currentTransferRecordingId, activeId != recording.id {
            RecordingLogger.log("⏳ Transfer slot busy with \(activeId). Keeping \(recording.id) queued.")
            return
        }
        if let activeId = activeTransfers.first, activeId != recording.id {
            currentTransferRecordingId = activeId
            RecordingLogger.log("⏳ Transfer already active for \(activeId). Keeping \(recording.id) queued.")
            return
        }

        // Check if this recording is already being transferred
        if connectivityManager.isRecordingTransferring(recording.id) {
            RecordingLogger.log("⚠️ Recording \(recording.id) is already being transferred - skipping duplicate transfer")
            return
        }

        // Check if recording can be sent using Core Data status
        if let localRepo = repository as? LocalRecordingRepository {
            let (canSend, reason) = localRepo.canSendRecording(recording.id)
            if !canSend {
                RecordingLogger.log("⚠️ Cannot send recording: \(reason ?? "unknown")")
                return
            }
        }

        // Check if companion app is installed
        guard connectivityManager.isWatchConnected else {
            RecordingLogger.log("iOS app not connected - recording will stay local until sync")
            return
        }

        // Discover all chunk files for this recording in the Recordings directory.
        // Files follow the naming convention: {recordingID}_chunk{index}.m4a
        let chunkFiles = discoverChunkFiles(for: recording)

        guard !chunkFiles.isEmpty else {
            RecordingLogger.error("Cannot transfer - no chunk files found for recording: \(recording.id)")
            return
        }

        // Update status to transferring in Core Data
        if let localRepo = repository as? LocalRecordingRepository {
            do {
                try localRepo.updateStatus(recording.id, status: .transferring)
                RecordingLogger.log("✅ Updated status to transferring")
            } catch {
                RecordingLogger.error("Failed to update status", error: error)
            }
        }

        // Update transfer state
        currentTransferRecordingId = recording.id
        transferState = .transferring
        isTransferringToiOS = true
        activeTransfers.insert(recording.id)

        let isMultiChunk = chunkFiles.count > 1
        RecordingLogger.log("Found \(chunkFiles.count) chunk(s) — sending as \(isMultiChunk ? "chunked" : "single-file") transfer")

        if isMultiChunk {
            // Multi-chunk: send each chunk with chunkInfo so iPhone assembles them
            for (chunkIndex, chunkURL) in chunkFiles {
                let isLastChunk = (chunkIndex == chunkFiles.last?.0)

                let chunkInfo = ChunkTransferMetadata(
                    parentRecordingId: recording.id,
                    chunkId: UUID(),
                    chunkIndex: chunkIndex,
                    isLastChunk: isLastChunk,
                    chunkDuration: 0,
                    totalDurationSoFar: recording.duration,
                    recordingStartTime: recording.startTime
                )

                let metadata = RecordingTransferMetadata(
                    id: recording.id,
                    filename: chunkURL.lastPathComponent,
                    duration: recording.duration,
                    createdAt: recording.createdAt,
                    startTime: recording.startTime,
                    chunkInfo: chunkInfo
                )

                RecordingLogger.log("  Sending chunk \(chunkIndex)/\(chunkFiles.count - 1) (isLast: \(isLastChunk)): \(chunkURL.lastPathComponent)")
                connectivityManager.transferRecording(fileURL: chunkURL, metadata: metadata)
            }
        } else {
            // Single chunk: send as a single-file transfer (no chunkInfo)
            let chunkURL = chunkFiles[0].1
            let metadata = RecordingTransferMetadata(
                id: recording.id,
                filename: recording.filename,
                duration: recording.duration,
                createdAt: recording.createdAt,
                startTime: recording.startTime
            )

            RecordingLogger.log("  Sending single file: \(recording.filename)")
            connectivityManager.transferRecording(fileURL: chunkURL, metadata: metadata)
        }

        // Start stall detection
        startStallDetection()

        RecordingLogger.log("=== TRANSFER INITIATED (\(chunkFiles.count) file(s)) ===")
    }

    /// Starts the next eligible pending/failed recording transfer when idle.
    /// This is the dequeue engine for one-recording-at-a-time delivery.
    private func startNextQueuedTransferIfIdle() {
        guard connectivityManager.isWatchConnected else {
            RecordingLogger.log("Cannot dequeue next transfer - iOS app not connected")
            return
        }

        guard currentTransferRecordingId == nil, activeTransfers.isEmpty else {
            return
        }

        do {
            let recordings = try repository.fetchAllRecordings()
                .sorted(by: { $0.createdAt < $1.createdAt })

            // Priority 1: recordings that were previously in `.transferring` when app was closed.
            // If WCSession is not currently transferring them anymore, immediately re-queue first.
            if let localRepo = repository as? LocalRecordingRepository {
                for recording in recordings {
                    // If OS transfer is still alive, let WCSession continue naturally.
                    if connectivityManager.isRecordingTransferring(recording.id) {
                        continue
                    }

                    guard let entity = try? localRepo.fetchEntityById(recording.id) else {
                        continue
                    }

                    let status = WatchRecordingStatus(rawValue: entity.status) ?? .pending
                    guard status == .transferring else {
                        continue
                    }

                    RecordingLogger.log("Prioritizing interrupted transfer on app relaunch: \(recording.id)")

                    // Reset to pending so transferToiOS can re-queue immediately instead of waiting
                    // for stale timeout logic.
                    do {
                        try localRepo.updateStatus(recording.id, status: .pending)
                    } catch {
                        RecordingLogger.error("Failed to reset interrupted transfer to pending: \(recording.id)", error: error)
                        continue
                    }

                    transferToiOS(recording: recording)
                    return
                }
            }

            for recording in recordings {
                // Skip if already being transferred via WCSession.
                if connectivityManager.isRecordingTransferring(recording.id) {
                    continue
                }

                if let localRepo = repository as? LocalRecordingRepository {
                    let (canSend, _) = localRepo.canSendRecording(recording.id)
                    if !canSend {
                        continue
                    }
                }

                RecordingLogger.log("Dequeued next recording for transfer: \(recording.id)")
                transferToiOS(recording: recording)
                return
            }
        } catch {
            RecordingLogger.error("Failed to dequeue pending transfer", error: error)
        }
    }

    // MARK: - Chunk File Discovery

    /// Discovers all chunk files for a recording in the Recordings directory.
    /// Chunk files follow the naming convention: `{recordingID}_chunk{index}.m4a`.
    /// Falls back to the recording's own fileURL if no chunk-patterned files are found.
    /// - Parameter recording: The recording whose chunks to find
    /// - Returns: Sorted array of (chunkIndex, fileURL) pairs
    private func discoverChunkFiles(for recording: Recording) -> [(Int, URL)] {
        guard let localRepo = repository as? LocalRecordingRepository else {
            // Fallback: use the recording's own file if it exists
            if FileManager.default.fileExists(atPath: recording.fileURL.path) {
                return [(0, recording.fileURL)]
            }
            return []
        }

        let recordingsDir = localRepo.recordingsDirectoryURL
        let idString = recording.id.uuidString
        let chunkPrefix = "\(idString)_chunk"

        do {
            let allFiles = try FileManager.default.contentsOfDirectory(
                at: recordingsDir,
                includingPropertiesForKeys: nil,
                options: [.skipsHiddenFiles]
            )

            // Find all files matching {recordingID}_chunk{N}.m4a
            var chunks: [(Int, URL)] = []
            for fileURL in allFiles {
                let name = fileURL.deletingPathExtension().lastPathComponent
                if name.hasPrefix(chunkPrefix),
                   let indexStr = name.components(separatedBy: "chunk").last,
                   let index = Int(indexStr) {
                    chunks.append((index, fileURL))
                }
            }

            // Sort by chunk index
            chunks.sort(by: { $0.0 < $1.0 })

            if !chunks.isEmpty {
                RecordingLogger.log("Discovered \(chunks.count) chunk file(s) for recording \(recording.id)")
                return chunks
            }
        } catch {
            RecordingLogger.error("Failed to scan recordings directory: \(error.localizedDescription)", error: error)
        }

        // Fallback: single file
        if FileManager.default.fileExists(atPath: recording.fileURL.path) {
            return [(0, recording.fileURL)]
        }

        return []
    }

    /// Checks if a recording has already been sent to iOS
    /// - Parameter recordingId: The recording ID to check
    /// - Returns: True if the recording was already confirmed by iOS
    func isRecordingAlreadySent(_ recordingId: UUID) -> Bool {
        guard let localRepo = repository as? LocalRecordingRepository,
              let entity = try? localRepo.fetchEntityById(recordingId) else {
            return false
        }

        // Consider it sent if status is sent (2), confirmed (3), or has iOS processing status
        return entity.status >= 2 || entity.iosProcessingStatus != nil
    }

    /// Forces a transfer of a recording that was already sent.
    /// Uses `forceResetForRetransfer` which bypasses terminal state protection
    /// and clears all iOS processing metadata (iosProcessingStatus, meetingId, etc.)
    /// so that `canSendRecording()` allows the transfer to proceed.
    /// - Parameter recording: The recording to force transfer
    func forceTransferToiOS(recording: Recording) {
        RecordingLogger.log("=== FORCE TRANSFER TO iOS ===")
        RecordingLogger.log("Recording ID: \(recording.id)")
        RecordingLogger.log("Force transferring already-sent recording")

        // Check if this recording is already being transferred
        if connectivityManager.isRecordingTransferring(recording.id) {
            RecordingLogger.log("⚠️ Recording \(recording.id) is already being transferred - skipping duplicate force transfer")
            return
        }

        // Force-reset status, bypassing terminal state guard and clearing iOS metadata
        if let localRepo = repository as? LocalRecordingRepository {
            do {
                let didReset = try localRepo.forceResetForRetransfer(recording.id)
                if didReset {
                    RecordingLogger.log("✅ Force-reset status to pending for re-transfer (cleared iOS metadata)")
                } else {
                    RecordingLogger.error("⚠️ Force reset returned false - recording may not exist")
                    return
                }
            } catch {
                RecordingLogger.error("Failed to force-reset status for re-transfer", error: error)
                return
            }
        }

        // Now perform the transfer (canSendRecording will succeed since status is .pending)
        transferToiOS(recording: recording)
    }

    /// Checks if a recording is currently being transferred
    /// - Parameter recordingId: The UUID of the recording to check
    /// - Returns: True if the recording is being transferred
    func isRecordingTransferring(_ recordingId: UUID) -> Bool {
        return connectivityManager.isRecordingTransferring(recordingId)
    }

    // MARK: - RecordingHealthCheckDelegate

    /// Called by health check service when a recording should be retried.
    /// Cancels any lingering WCSession transfer before re-queuing to prevent
    /// duplicate parallel transfers for the same recording.
    func shouldRetryRecording(_ recording: Recording) {
        RecordingLogger.log("Health check requested retry for \(recording.id) — cancelling existing transfer first")
        connectivityManager.cancelTransfer(recordingId: recording.id)
        currentTransferRecordingId = nil
        activeTransfers.remove(recording.id)
        transferToiOS(recording: recording)
    }

    // MARK: - Status Information

    /// Information about a recording's current status for UI display
    struct RecordingStatusInfo {
        let icon: String
        let color: Color
        let displayText: String
        let uploadProgress: Double?  // 0.0 to 1.0, only set when uploading on iOS
        let showSendAgainButton: Bool  // Show "Send Again" button (e.g., when status is "Received")
    }

    /// Gets the current status information for a recording
    /// - Parameter recordingId: The recording ID to check
    /// - Returns: Status information for UI display, or nil if recording not found
    func getRecordingStatusInfo(_ recordingId: UUID) -> RecordingStatusInfo? {
        guard let localRepo = repository as? LocalRecordingRepository,
              let entity = try? localRepo.fetchEntityById(recordingId) else {
            return nil
        }

        // Check iOS processing status first (takes priority over local status)
        if let iosStatus = entity.iosProcessingStatus {
            switch iosStatus {
            case "Received":
                return RecordingStatusInfo(
                    icon: "checkmark.circle",
                    color: .green,
                    displayText: "Received by iPhone",
                    uploadProgress: nil,
                    showSendAgainButton: true
                )
            case "Uploading":
                // Include upload progress if available
                let progress = entity.iosUploadProgress > 0 ? entity.iosUploadProgress : nil
                return RecordingStatusInfo(
                    icon: "arrow.up.circle",
                    color: .blue,
                    displayText: "iPhone uploading",
                    uploadProgress: progress,
                    showSendAgainButton: false
                )
            case "Uploaded":
                return RecordingStatusInfo(
                    icon: "cloud.fill",
                    color: .blue,
                    displayText: "Uploaded",
                    uploadProgress: nil,
                    showSendAgainButton: false
                )
            case "Creating Meeting":
                return RecordingStatusInfo(
                    icon: "gear",
                    color: .orange,
                    displayText: "Creating meeting",
                    uploadProgress: nil,
                    showSendAgainButton: false
                )
            case "Created":
                return RecordingStatusInfo(
                    icon: "checkmark.circle.fill",
                    color: .green,
                    displayText: "Meeting created",
                    uploadProgress: nil,
                    showSendAgainButton: false
                )
            default:
                break
            }
        }

        // Fall back to local status
        let status = WatchRecordingStatus(rawValue: entity.status) ?? .pending
        let displayText = (status == .pending) ? "Queued" : status.displayName

        return RecordingStatusInfo(
            icon: status.icon,
            color: colorForStatus(status),
            displayText: displayText,
            uploadProgress: nil,
            showSendAgainButton: false
        )
    }

    /// Gets the appropriate color for a watch recording status
    private func colorForStatus(_ status: WatchRecordingStatus) -> Color {
        switch status {
        case .pending: return .gray
        case .transferring: return .blue
        case .sent: return .orange
        case .confirmed: return .green
        case .failed: return .red
        }
    }

    /// Checks if a recording can be sent (used for button state)
    func canSendRecording(_ recordingId: UUID) -> (canSend: Bool, reason: String?) {
        guard let localRepo = repository as? LocalRecordingRepository else {
            return (false, "Repository not available")
        }

        return localRepo.canSendRecording(recordingId)
    }

    /// Retries transferring local recordings that are genuinely pending or failed.
    /// Pre-filters by Core Data status and in-flight state to avoid duplicate transfers.
    func retryPendingTransfers() {
        RecordingLogger.log("=== RETRY PENDING TRANSFERS ===")

        guard connectivityManager.isWatchConnected else {
            RecordingLogger.log("iOS app not connected - cannot retry transfers")
            return
        }

        startNextQueuedTransferIfIdle()
        RecordingLogger.log("Retry trigger complete - queue scheduler invoked")
    }

    // MARK: - App Lifecycle

    /// Call this when the watch app appears/becomes active.
    /// This checks for any local recordings that haven't been transferred yet
    /// (e.g., if the app was killed before transfer completed or confirmation was received)
    /// and attempts to transfer them to iOS.
    func onAppAppear() {
        RecordingLogger.log("=== APP APPEAR - CHECKING FOR UNTRANSFERRED RECORDINGS ===")

        // Check for any local recordings that need to be synced
        do {
            let localRecordings = try repository.fetchAllRecordings()

            // Update pending sync count
            DispatchQueue.main.async {
                self.pendingSyncCount = localRecordings.count
            }

            if localRecordings.isEmpty {
                RecordingLogger.log("No local recordings to sync")
                return
            }

            RecordingLogger.log("Found \(localRecordings.count) local recording(s) that may need syncing")

            // If iOS is connected, attempt to transfer any unsynced recordings
            if connectivityManager.isWatchConnected {
                RecordingLogger.log("iOS app is connected - attempting to sync pending recordings")

                // Small delay to ensure connectivity manager is fully ready
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) { [weak self] in
                    self?.retryPendingTransfers()
                }
            } else {
                RecordingLogger.log("iOS app not connected - will sync when connection is available")

                // Set up a one-time observer to sync when iOS becomes available
                self.setupConnectionObserverForPendingSync()
            }

        } catch {
            RecordingLogger.error("Failed to check for local recordings on app appear", error: error)
        }
    }

    /// Sets up an observer to sync recordings when iOS connection becomes available
    private func setupConnectionObserverForPendingSync() {
        // Listen for connection changes
        connectivityManager.$isWatchConnected
            .receive(on: DispatchQueue.main)
            .filter { $0 == true } // Only when connected
            .first() // One-time only
            .sink { [weak self] _ in
                RecordingLogger.log("iOS connection established - syncing pending recordings")
                self?.retryPendingTransfers()
            }
            .store(in: &cancellables)
    }

    /// Call this when the watch app goes to background/disappears.
    /// Currently just logs, but can be extended for cleanup if needed.
    func onAppDisappear() {
        RecordingLogger.log("App going to background")
        // Any cleanup or state saving can go here
    }

    /// Manually deletes a recording from local storage
    /// Use this if automatic deletion after transfer fails
    func deleteLocalRecording(id: UUID) {
        RecordingLogger.log("Manually deleting local recording: \(id)")

        do {
            try repository.deleteRecording(id: id)
            RecordingLogger.success("Manually deleted recording: \(id)")

            DispatchQueue.main.async {
                if self.lastRecording?.id == id {
                    self.lastRecording = nil
                }
            }
        } catch {
            RecordingLogger.error("Failed to manually delete recording", error: error)
        }
    }

    // MARK: - Timer Management

    /// Timer is now managed primarily by ChunkedRecordingManager.
    /// The ViewModel subscribes to its published properties (remainingTime, elapsed, etc.)
    /// This local timer is kept only for lightweight UI updates that need faster refresh.

    private func startTimer() {
        // No-op by design. Manager bindings are configured once in init
        // to avoid duplicate subscriptions across start/resume cycles.
    }

    func updateTimerInterval(active: Bool) {
        // Timer interval is now managed by ChunkedRecordingManager
        // No-op here since we use Combine subscriptions instead
        RecordingLogger.log("Scene phase changed: active=\(active)")
    }

    private func stopTimer() {
        timerCancellable?.cancel()
        timerCancellable = nil
    }

    // MARK: - Chunk Manager Binding

    /// Binds manager publishers once to avoid repeated subscriptions during lifecycle events.
    private func bindChunkedRecordingManager() {
        chunkedRecordingManager.totalElapsedTimePublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] totalTime in
                self?.elapsed = totalTime
            }
            .store(in: &chunkManagerCancellables)

        chunkedRecordingManager.remainingTimePublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] remaining in
                guard let self = self else { return }
                self.remainingTime = remaining
                self.checkAlertThresholds(remaining: remaining)
            }
            .store(in: &chunkManagerCancellables)

        chunkedRecordingManager.isExtendEnabledPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isEnabled in
                self?.isExtendEnabled = isEnabled
            }
            .store(in: &chunkManagerCancellables)
    }

    /// Configures manager callbacks that need ViewModel handling.
    private func configureChunkedRecordingCallbacks() {
        chunkedRecordingManager.onAutoStop = { [weak self] in
            guard let self = self else { return }

            RecordingLogger.log("Auto-stop triggered by countdown reaching zero")
            self.gracefulRecordingShutdown(
                reason: "Recording time limit was reached.",
                sentryMessage: "Recording countdown reached zero — auto-stop"
            )
        }
    }

    // MARK: - Debug Helpers

    /// Logs the current state of the recordings directory
    func debugLogRecordingsDirectory() {
        RecordingLogger.log("=== DEBUG: Recordings Directory ===")

        do {
            let docs = try FileManager.default.url(for: .documentDirectory, in: .userDomainMask, appropriateFor: nil, create: false)
            let recordingsDir = docs.appendingPathComponent("Recordings", isDirectory: true)

            RecordingLogger.log("Documents directory: \(docs.path)")
            RecordingLogger.log("Recordings directory: \(recordingsDir.path)")

            if FileManager.default.fileExists(atPath: recordingsDir.path) {
                let contents = try FileManager.default.contentsOfDirectory(at: recordingsDir, includingPropertiesForKeys: [.fileSizeKey, .creationDateKey])
                RecordingLogger.log("Found \(contents.count) files:")

                for file in contents {
                    let attrs = try FileManager.default.attributesOfItem(atPath: file.path)
                    let size = attrs[.size] as? Int64 ?? 0
                    let created = attrs[.creationDate] as? Date ?? Date()
                    RecordingLogger.log("  - \(file.lastPathComponent): \(size) bytes, created: \(created)")
                }
            } else {
                RecordingLogger.log("Recordings directory does not exist")
            }
        } catch {
            RecordingLogger.error("Failed to read recordings directory", error: error)
        }

        RecordingLogger.log("=== END DEBUG ===")
    }
}

import Foundation
import Combine
import SwiftUI
import AVFoundation

// MARK: - Logger for Recording

/// Logger wrapper for recording operations with Sentry integration
/// Provides convenience methods that match the existing RecordingLogger API
private enum RecordingLogger {
    /// Shared logger instance
    private static let logger = LoggerFactory.makeLogger()

    /// Logs a debug/info message
    /// - Parameters:
    ///   - message: The message to log
    ///   - function: The function name (automatically captured via #function)
    static func log(_ message: String, function: String = #function) {
        logger.info("[RecordingLogger] [\(function)] \(message)")
    }

    /// Logs an error message
    /// - Parameters:
    ///   - message: The error message to log
    ///   - error: Optional error object
    ///   - function: The function name (automatically captured via #function)
    static func error(_ message: String, error: Error? = nil, function: String = #function) {
        logger.error("[RecordingLogger] [\(function)] \(message)", error: error)
    }

    /// Logs a success message
    /// - Parameters:
    ///   - message: The success message to log
    ///   - function: The function name (automatically captured via #function)
    static func success(_ message: String, function: String = #function) {
        logger.info("[RecordingLogger] ✅ [\(function)] \(message)")
    }
}

// MARK: - WatchRecordingViewModel

@MainActor
final class WatchRecordingViewModel: ObservableObject, RecordingHealthCheckDelegate {
    // MARK: - Recording Limits

    /// Maximum recording duration is now managed dynamically by ChunkedRecordingManager
    /// via the countdown allocation system. No fixed cap here.

    enum State: Equatable {
        case idle
        case recording
        case paused
        case saving
        case playing
        case error(String)
    }

    /// Transfer state for UI display — includes stall detection and retry states
    enum TransferState: Equatable {
        case idle
        case preparingMetadata   // Sending metadata to iPhone before chunks
        case waitingForAck       // Waiting for iPhone acknowledgment
        case transferring        // Actively transferring chunks
        case completed           // All chunks transferred successfully
        case stalled             // Progress stuck past timeout policy (0-99%)
        case failed(String)      // User must press RETRY
        case retrying            // Retry in progress (15-min timeout)
        case completeFail        // Retry timed out — delete all, resend from scratch
    }

    /// Reason why recording was paused
    enum PauseReason {
        case manual          // User manually paused via UI
        case audioInterruption  // Paused due to audio session interruption (e.g., phone call)
    }

    @Published var state: State = .idle
    @Published var elapsed: TimeInterval = 0
    @Published var lastRecording: Recording? = nil

    // Transfer state tracking
    @Published var transferState: TransferState = .idle
    @Published var isTransferringToiOS: Bool = false  // Deprecated - use activeTransfers

    /// Set of recording IDs currently being transferred
    @Published private(set) var activeTransfers: Set<UUID> = []

    /// Single active recording-level transfer gate.
    /// Only one recording is allowed to start transfer at a time.
    private var currentTransferRecordingId: UUID?

    /// Computed property: true if any transfers are active
    var hasActiveTransfers: Bool {
        return !activeTransfers.isEmpty
    }

    /// Computed property: number of active transfers
    var activeTransferCount: Int {
        return activeTransfers.count
    }

    /// Number of local recordings pending sync to iOS
    @Published var pendingSyncCount: Int = 0

    /// Remaining recording time from the chunked recording manager's countdown.
    /// Drives the countdown UI display.
    @Published var remainingTime: TimeInterval = 0

    /// Whether the EXTEND button should be enabled (delegated from ChunkedRecordingManager)
    @Published var isExtendEnabled: Bool = false

    /// Active alert to show as a full-screen overlay on the Watch (5 min / 2 min / 30 sec warnings)
    @Published var activeAlert: RecordingAlert? = nil

    /// Alert types for time-remaining warnings
    enum RecordingAlert: Equatable {
        case fiveMinutes
        case twoMinutes
        case thirtySeconds
    }

    /// Tracks which alert thresholds have already been shown (to avoid re-triggering)
    private var shownAlerts: Set<TimeInterval> = []

    /// Alert thresholds in seconds
    private let alertThresholds: [TimeInterval] = [5 * 60, 2 * 60, 30]

    // MARK: - Stall Detection Properties

    /// Shared timeout policy (3 minutes per 30 minutes of recording duration).
    private let transferTimeoutPolicy = TransferTimeoutPolicy.default

    /// Duration after which a retry attempt is considered a complete failure (15 minutes)
    private static let retryTimeoutSeconds: TimeInterval = 15 * 60

    /// Tracks the last progress update time per chunk (for stall detection)
    private var chunkLastProgressUpdate: [UUID: Date] = [:]

    /// Tracks progress per chunk (0.0 to 1.0)
    @Published var chunkTransferProgress: [UUID: Double] = [:]

    /// Tracks the last progress update time per recording for single-file stall detection.
    /// Keyed by recording UUID (vs chunk UUID in chunkLastProgressUpdate).
    private var recordingLastProgressUpdate: [UUID: Date] = [:]

    /// Last known progress per recording for single-file stall detection (0.0 to 1.0)
    private var recordingLastProgressValue: [UUID: Double] = [:]

    /// Timer for periodic stall checks
    private var stallCheckTimer: Timer?

    /// When the current retry attempt started (nil if not retrying)
    private var retryStartTime: Date?

    /// Recordings that timed out and must be retried from scratch.
    private var timedOutTransferIds: Set<UUID> = []

    // Timer for UI updates (elapsed time is driven by ChunkedRecordingManager publisher)
    private var timerCancellable: AnyCancellable?

    /// Tracks the original recording start time (not affected by pause/resume)
    /// Used for sending to backend via RecordingTransferMetadata
    private var recordingStartTime: Date?

    // Audio recording
    private var currentRecordingURL: URL?
    /// Tracks the recording ID generated at start - ensures consistency throughout lifecycle
    private var currentRecordingId: UUID?

    /// Tracks why the recording was paused (nil if not paused or if paused for unknown reason)
    private var pauseReason: PauseReason?

    // Audio session
    private let audioSession = AVAudioSession.sharedInstance()

    private let repository: RecordingRepository

    // Watch connectivity manager for transferring recordings
    private let connectivityManager = WatchConnectivityManager.shared

    /// Cross-device transfer timeout notifier (local Watch notification).
    private let transferFailureNotificationService = TransferFailureNotificationService.shared

    // Extended runtime session manager for background execution keep-alive
    private let extendedRuntimeSessionManager = ExtendedRuntimeSessionManager()

    // Chunked recording manager for dynamic chunk allocation and countdown
    private let chunkedRecordingManager: ChunkedRecordingManaging

    // Cancellables for Combine subscriptions
    private var cancellables = Set<AnyCancellable>()
    private var chunkManagerCancellables = Set<AnyCancellable>()

    // Notification observer token for audio interruptions
    private var audioInterruptionObserver: NSObjectProtocol?

    // Defers pausing for brief ring-only interruptions (avoid pausing unless call actually connects)
    private var pendingInterruptionPauseWorkItem: DispatchWorkItem?
    private let interruptionDeferralSeconds: TimeInterval = 3.0

    // Health check service for monitoring stale recordings
    private var healthCheckService: RecordingHealthCheckService?

    init(
        repository: RecordingRepository,
        chunkedRecordingManager: ChunkedRecordingManaging? = nil
    ) {
        self.repository = repository
        self.chunkedRecordingManager = chunkedRecordingManager ?? ChunkedRecordingManager()
        RecordingLogger.log("ViewModel initialized with repository: \(type(of: repository))")

        bindChunkedRecordingManager()
        configureChunkedRecordingCallbacks()

        // Setup transfer completion callback
        setupTransferCallbacks()

        // Setup audio interruption handling
        setupAudioInterruptionHandling()

        // Setup extended runtime session callbacks
        setupExtendedRuntimeSessionCallbacks()

        // Setup iOS status update observer
        observeiOSStatusUpdates()

        // Listen for iPhone asking us to re-send our current recording state.
        // This fires when the iPhone reads stale activation context and needs fresh confirmation.
        setupRecordingStateResyncObserver()
        setupTransferRetryRequestObserver()

        // Initialize and start health check service
        // Cast repository to LocalRecordingRepository for type safety
        if let localRepo = repository as? LocalRecordingRepository {
            healthCheckService = RecordingHealthCheckService(repository: localRepo, delegate: self)
            healthCheckService?.startMonitoring()
        } else {
            RecordingLogger.error("Cannot initialize health check service - repository is not LocalRecordingRepository")
        }
    }

    // MARK: - Transfer Callback Setup

    /// Sets up callbacks for when recordings are successfully transferred to iOS
    private func setupTransferCallbacks() {
        RecordingLogger.log("Setting up transfer callbacks...")

        // Listen for transfer completion via callback
        connectivityManager.onTransferComplete = { [weak self] recordingId, success in
            Task { @MainActor [weak self] in
                guard let self = self else { return }

                RecordingLogger.log("Transfer completion callback received for: \(recordingId), success: \(success)")

                if success {
                    self.handleTransferCompleted(recordingId: recordingId)
                } else {
                    self.handleTransferFailed(recordingId: recordingId)
                }
            }
        }

        // Note: Transfer progress is now per-recording, observed individually in transferToiOS
        // The global transferState has been removed to support concurrent transfers
    }

    /// Sets up observer for iOS processing status updates
    private func observeiOSStatusUpdates() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handleiOSStatusUpdate(_:)),
            name: .iosProcessingStatusUpdated,
            object: nil
        )

        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handleTransferConfirmed(_:)),
            name: .watchRecordingTransferConfirmed,
            object: nil
        )
    }

    /// Handles iOS status update notifications
    /// This method is idempotent - it checks terminal state before processing
    @objc private func handleiOSStatusUpdate(_ notification: Notification) {
        guard let recordingId = notification.userInfo?["recordingId"] as? UUID,
              let status = notification.userInfo?["status"] as? String else {
            return
        }

        let meetingId = notification.userInfo?["meetingId"] as? String
        let uploadProgress = notification.userInfo?["uploadProgress"] as? Double

        guard let localRepo = repository as? LocalRecordingRepository else {
            return
        }

        // CRITICAL: Check if recording still exists and is not finalized
        // This prevents crashes from late/out-of-order callbacks
        guard let entity = try? localRepo.fetchEntityById(recordingId) else {
            RecordingLogger.log("⏭️ Ignoring iOS status update - recording not found: \(recordingId)")
            return
        }

        let currentStatus = WatchRecordingStatus(rawValue: entity.status) ?? .pending

        // Allow "Created" status even for terminal recordings (final confirmation)
        // But ignore all other late status updates for finalized recordings
        if currentStatus.isTerminal && status != "Created" {
            RecordingLogger.log("⏭️ Ignoring iOS status update '\(status)' for finalized recording: \(recordingId)")
            return
        }

        do {
            try localRepo.updateiOSProcessingStatus(
                recordingId,
                status: status,
                progress: uploadProgress,
                meetingId: meetingId
            )

            let progressStr = uploadProgress.map { " (\(Int($0 * 100))%)" } ?? ""
            RecordingLogger.log("Updated iOS status for \(recordingId): \(status)\(progressStr)")

            // UI will auto-update via Core Data observers
        } catch {
            RecordingLogger.error("Failed to update iOS status | Error: \(error.localizedDescription)", error: error)
        }
    }

    /// Handles transfer confirmation notifications
    /// This method is idempotent - it checks terminal state before processing
    @objc private func handleTransferConfirmed(_ notification: Notification) {
        guard let recordingId = notification.userInfo?["recordingId"] as? UUID else {
            return
        }

        guard let localRepo = repository as? LocalRecordingRepository else {
            return
        }

        // CRITICAL: Check if recording still exists and is not already confirmed
        // This prevents duplicate processing of the same confirmation
        guard let entity = try? localRepo.fetchEntityById(recordingId) else {
            RecordingLogger.log("⏭️ Ignoring confirmation - recording not found: \(recordingId)")
            return
        }

        let currentStatus = WatchRecordingStatus(rawValue: entity.status) ?? .pending
        if currentStatus.isTerminal {
            RecordingLogger.log("⏭️ Ignoring duplicate confirmation for finalized recording: \(recordingId)")
            return
        }

        do {
            try localRepo.updateStatus(recordingId, status: .sent)
            RecordingLogger.log("Recording confirmed by iOS: \(recordingId)")

            // UI will auto-update via Core Data observers
        } catch {
            RecordingLogger.error("Failed to update confirmed status | Error: \(error.localizedDescription)", error: error)
        }
    }

    /// Handles iOS confirmation that a recording was received.
    /// Local recording is NOT deleted here — deletion only happens when iOS confirms
    /// full processing (status = "Created"), handled by the health check / cleanup service.
    private func handleTransferCompleted(recordingId: UUID) {
        RecordingLogger.log("=== TRANSFER CONFIRMED BY iOS: \(recordingId) ===")

        DispatchQueue.main.async {
            // Remove from active transfers
            self.activeTransfers.remove(recordingId)
            self.timedOutTransferIds.remove(recordingId)
            if self.currentTransferRecordingId == recordingId {
                self.currentTransferRecordingId = nil
            }

            // Update transfer state
            self.transferState = .completed
            self.isTransferringToiOS = !self.activeTransfers.isEmpty

            // Decrement pending sync count
            if self.pendingSyncCount > 0 {
                self.pendingSyncCount -= 1
            }

            // Stop stall detection when all transfers are done
            if self.activeTransfers.isEmpty {
                self.stopStallDetection()
                // Safe to clear recordingStartTime now that transfer is confirmed
                self.recordingStartTime = nil
            }

            // Reset transfer state after a brief delay (only if no active transfers)
            DispatchQueue.main.asyncAfter(deadline: .now() + 2.0) {
                if self.transferState == .completed && self.activeTransfers.isEmpty {
                    self.transferState = .idle
                }
            }

            // Start next queued transfer (if any) now that the active slot is free.
            self.startNextQueuedTransferIfIdle()
        }

        // DO NOT delete the local recording here.
        // The recording stays in Core Data (status = .sent) until iOS confirms full processing
        // (iosProcessingStatus = "Created"). The WatchRecordingCleanupService will handle
        // safe deletion once the meeting has been created on the backend.
        RecordingLogger.log("Recording \(recordingId) stays local until iOS confirms processing")

        // Haptic feedback for successful sync
        WKInterfaceDevice.current().play(.success)
    }

    /// Handles failed transfer - keeps local copy
    private func handleTransferFailed(recordingId: UUID) {
        RecordingLogger.error("Transfer failed for recording: \(recordingId)")

        DispatchQueue.main.async {
            // Remove from active transfers
            self.activeTransfers.remove(recordingId)
            if self.currentTransferRecordingId == recordingId {
                self.currentTransferRecordingId = nil
            }

            // Update legacy state
            self.transferState = .failed("Transfer failed")
            self.isTransferringToiOS = !self.activeTransfers.isEmpty

            // Reset transfer state after showing error briefly (only if no active transfers)
            DispatchQueue.main.asyncAfter(deadline: .now() + 3.0) {
                if case .failed(_) = self.transferState, self.activeTransfers.isEmpty {
                    self.transferState = .idle
                }
            }

            // Continue queue drain by attempting the next pending recording.
            self.startNextQueuedTransferIfIdle()
        }

        // Recording stays local - will be retried later
        WKInterfaceDevice.current().play(.failure)
    }

    func fetchAllRecordings() throws -> [Recording] {
        RecordingLogger.log("Fetching all recordings...")
        let recordings = try repository.fetchAllRecordings()
        RecordingLogger.success("Fetched \(recordings.count) recordings")

        // Log each recording for debugging
        for (index, recording) in recordings.enumerated() {
            let fileExists = FileManager.default.fileExists(atPath: recording.fileURL.path)
            let fileSize = (try? FileManager.default.attributesOfItem(atPath: recording.fileURL.path)[.size] as? Int64) ?? 0
            RecordingLogger.log("  [\(index + 1)] \(recording.filename) - Duration: \(recording.duration)s, Exists: \(fileExists), Size: \(fileSize) bytes")
        }

        return recordings
    }

    // MARK: - Audio Session Setup

    /// Configures the audio session for recording
    private func setupAudioSession() -> Bool {
     //   RecordingLogger.log("Setting up audio session...")

        do {
            // Configure audio session for recording (watchOS doesn't support defaultToSpeaker)
            // Use .mixWithOthers to avoid interrupting other audio sources
            try audioSession.setCategory(.playAndRecord, mode: .default, options: [.mixWithOthers])
            try audioSession.setActive(true)

            return true
        } catch {
            RecordingLogger.error("Failed to setup audio session", error: error)
            return false
        }
    }

    /// Deactivates the audio session
    private func deactivateAudioSession() {
        RecordingLogger.log("Deactivating audio session...")

        do {
            try audioSession.setActive(false, options: .notifyOthersOnDeactivation)
            RecordingLogger.success("Audio session deactivated")
        } catch {
            RecordingLogger.error("Failed to deactivate audio session", error: error)
        }
    }

    /// Pre-warms the audio session to reduce delay when starting recording
    /// Call this when the view appears to prepare the audio session in advance
    func prepareAudioSession() {
        Task { @MainActor in
            // Pre-warm audio session so it's ready when user starts recording
            // This reduces the delay when the user taps the record button
            _ = setupAudioSession()
        }
    }

    // MARK: - Keep-Alive Session Management

    /// Starts an ExtendedRuntimeSession to keep the app alive during recording.
    /// Provides ~1 hour of background execution. User interaction (EXTEND/alerts)
    /// keeps the app in the foreground, extending effective recording duration.
    private func startExtendedRuntimeSessionFallback() {
        let sessionStarted = extendedRuntimeSessionManager.startSession(
            onStateChange: { sessionState in
                RecordingLogger.log("Extended runtime session state changed: \(sessionState)")
            },
            onExpiration: { [weak self] in
                Task { @MainActor [weak self] in
                    self?.handleExtendedRuntimeSessionExpiration()
                }
            },
            onInvalidation: { [weak self] reason, error in
                Task { @MainActor [weak self] in
                    self?.handleExtendedRuntimeSessionInvalidation(reason: reason, error: error)
                }
            }
        )

        if sessionStarted {
            RecordingLogger.success("ExtendedRuntimeSession fallback started (~1 hour limit)")
        } else {
            RecordingLogger.log("⚠️ ExtendedRuntimeSession fallback could not start")
        }
    }

    /// Stops the keep-alive extended runtime session.
    private func stopKeepAliveSession() {
        extendedRuntimeSessionManager.stopSession()
        RecordingLogger.log("Extended runtime session stopped")
    }

    // MARK: - Extended Runtime Session Handling

    /// Sets up callbacks for extended runtime session state changes and expiration
    private func setupExtendedRuntimeSessionCallbacks() {
        RecordingLogger.log("Setting up extended runtime session callbacks...")

        // Note: Callbacks are set when starting the session in startRecording()
        // This method is here for future extensibility if needed
        RecordingLogger.success("Extended runtime session callback setup ready")
    }

    // MARK: - Graceful Recording Shutdown

    /// Performs a graceful shutdown of an active recording: saves chunks, initiates transfer,
    /// logs the reason to Sentry (with user context), and shows a user-friendly message.
    ///
    /// Every error path that interrupts a recording must funnel through this method so that
    /// no recorded audio is lost.
    ///
    /// - Parameters:
    ///   - reason: Human-readable reason shown in the UI (e.g. "Session time limit was reached.")
    ///   - sentryMessage: Technical message sent to Sentry for debugging / alerting
    ///   - error: Optional underlying error object attached to the Sentry event
    private func gracefulRecordingShutdown(
        reason: String,
        sentryMessage: String,
        error: Error? = nil
    ) {
        guard state == .recording || state == .paused else { return }

        DispatchQueue.main.async { [weak self] in
            guard let self = self, self.state == .recording || self.state == .paused else { return }

            let recordedDuration = self.elapsed

            // Save the recording and initiate transfer to iPhone
            self.stopRecording()

            // Log to Sentry so we can track which users hit this and why
            RecordingLogger.error(
                "\(sentryMessage) — recording gracefully stopped after \(Int(recordedDuration))s",
                error: error
            )

            self.state = .error("Meeting saved. \(reason)")
            WKInterfaceDevice.current().play(.notification)
        }
    }

    /// Handles extended runtime session expiration
    /// Called when the session is about to expire (typically after ~4 hours).
    private func handleExtendedRuntimeSessionExpiration() {
        RecordingLogger.log("⚠️ Extended runtime session is expiring")

        gracefulRecordingShutdown(
            reason: "Session time limit was reached.",
            sentryMessage: "Session time limit reached (expiration callback)"
        )
    }

    /// Handles extended runtime session invalidation
    /// Called when the session is invalidated for various reasons
    /// - Parameters:
    ///   - reason: The reason for invalidation
    ///   - error: Optional error if invalidation was due to an error
    private func handleExtendedRuntimeSessionInvalidation(
        reason: WKExtendedRuntimeSessionInvalidationReason,
        error: Error?
    ) {
        RecordingLogger.log("Extended runtime session invalidated - Reason: \(reason)")

        switch reason {
        case .none:
            // Manual invalidation (expected when stopping recording) — no action needed
            RecordingLogger.log("Session invalidated manually (expected)")

        case .sessionInProgress:
            RecordingLogger.log("Session invalidated - another session already in progress")
            gracefulRecordingShutdown(
                reason: "A session conflict occurred.",
                sentryMessage: "Session invalidated — sessionInProgress"
            )

        case .expired:
            RecordingLogger.log("Session expired - time limit reached (invalidation handler)")
            gracefulRecordingShutdown(
                reason: "Session time limit was reached.",
                sentryMessage: "Session invalidated — expired"
            )

        case .resignedFrontmost:
            RecordingLogger.log("Session invalidated - app resigned frontmost status (will not pause during ringing)")
            // Do not pause on frontmost resignation (e.g., incoming call UI). Keep state as-is and attempt to keep the recorder running.
            if state == .recording {
                // Best-effort to keep/resume the engine in case the OS briefly halted it.
                chunkedRecordingManager.resumeRecording()
            }

        case .suppressedBySystem:
            RecordingLogger.log("Session invalidated - suppressed by system")
            gracefulRecordingShutdown(
                reason: "A system limitation occurred.",
                sentryMessage: "Session invalidated — suppressedBySystem"
            )

        case .error:
            RecordingLogger.log("Session invalidated due to error")
            gracefulRecordingShutdown(
                reason: "An unexpected error occurred.",
                sentryMessage: "Session invalidated — error",
                error: error
            )

        @unknown default:
            RecordingLogger.log("Session invalidated for unknown reason: \(reason.rawValue)")
            gracefulRecordingShutdown(
                reason: "The session ended unexpectedly.",
                sentryMessage: "Session invalidated — unknown reason (\(reason.rawValue))"
            )
        }
    }

    // MARK: - Recording State Resync

    /// Observes iPhone's request to re-send our current recording state.
    /// When the iPhone app launches, it reads cached `session.receivedApplicationContext` which may
    /// contain a stale `isRecordingOnWatch = true`. The iPhone sends a message asking us to confirm,
    /// and we respond with our actual current state via application context.
    private func setupRecordingStateResyncObserver() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handleRecordingStateResyncRequest),
            name: .watchShouldResyncRecordingState,
            object: nil
        )
        RecordingLogger.log("Recording state resync observer configured")
    }

    /// Observes iPhone's request to retry/resend a specific recording transfer.
    private func setupTransferRetryRequestObserver() {
        NotificationCenter.default.addObserver(
            self,
            selector: #selector(handleTransferRetryRequestFromiPhone(_:)),
            name: .iPhoneRequestedTransferRetry,
            object: nil
        )
        RecordingLogger.log("iPhone transfer retry observer configured")
    }

    @objc private func handleRecordingStateResyncRequest() {
        RecordingLogger.log("Received recording state resync request from iPhone")
        DispatchQueue.main.async { [weak self] in
            guard let self = self else { return }
            let isCurrentlyRecording = (self.state == .recording || self.state == .paused)
            let currentStartDate = isCurrentlyRecording ? self.startDate : nil

            RecordingLogger.log("Re-sending recording state: isRecording=\(isCurrentlyRecording), startedAt=\(String(describing: currentStartDate))")
            WatchConnectivityManager.shared.sendRecordingOnWatchIndicator(
                isRecording: isCurrentlyRecording,
                startedAt: currentStartDate
            )
        }
    }

    @objc private func handleTransferRetryRequestFromiPhone(_ notification: Notification) {
        guard let userInfo = notification.userInfo,
              let recordingIdString = userInfo[WatchMessageKey.recordingId] as? String,
              let recordingId = UUID(uuidString: recordingIdString) else {
            RecordingLogger.log("Received invalid retry request payload from iPhone")
            return
        }

        RecordingLogger.log("Received retry request from iPhone for recording: \(recordingId)")
        DispatchQueue.main.async { [weak self] in
            self?.handleRetryRequestFromiPhone(recordingId: recordingId)
        }
    }

    /// Handles iPhone-initiated retry while respecting one-recording-at-a-time queueing.
    private func handleRetryRequestFromiPhone(recordingId: UUID) {
        guard let localRepo = repository as? LocalRecordingRepository else {
            RecordingLogger.error("Cannot handle iPhone retry request - repository is not LocalRecordingRepository")
            return
        }

        guard let recording = try? repository.fetchAllRecordings().first(where: { $0.id == recordingId }) else {
            RecordingLogger.log("Retry request ignored - recording not found locally: \(recordingId)")
            return
        }

        if currentTransferRecordingId == recordingId || activeTransfers.contains(recordingId) ||
            connectivityManager.isRecordingTransferring(recordingId) {
            RecordingLogger.log("Retry request ignored because recording is already transferring: \(recordingId)")
            return
        }

        // If currently busy with a different recording, queue this one as pending.
        if let activeId = currentTransferRecordingId, activeId != recordingId {
            do {
                try localRepo.updateStatus(recordingId, status: .pending, error: "Queued from iPhone retry request")
                RecordingLogger.log("Queued retry request while transfer slot busy (\(activeId)) for recording: \(recordingId)")
            } catch {
                RecordingLogger.error("Failed to mark recording as queued from iPhone retry request", error: error)
            }
            return
        }

        if activeTransfers.contains(where: { $0 != recordingId }) {
            do {
                try localRepo.updateStatus(recordingId, status: .pending, error: "Queued from iPhone retry request")
                RecordingLogger.log("Queued retry request while another active transfer exists for recording: \(recordingId)")
            } catch {
                RecordingLogger.error("Failed to mark recording as queued from iPhone retry request", error: error)
            }
            return
        }

        // Ensure request retries are sendable through normal pipeline.
        do {
            try localRepo.updateStatus(recordingId, status: .pending, error: "Retry requested by iPhone")
        } catch {
            RecordingLogger.error("Failed to reset status before iPhone-requested retry", error: error)
        }

        transferToiOS(recording: recording)
    }

    // MARK: - Audio Interruption Handling

    /// Sets up notification observers for audio session interruptions (e.g., phone calls)
    private func setupAudioInterruptionHandling() {
        RecordingLogger.log("Setting up audio interruption handling...")

        audioInterruptionObserver = NotificationCenter.default.addObserver(
            forName: AVAudioSession.interruptionNotification,
            object: nil,
            queue: .main
        ) { [weak self] notification in
            self?.handleAudioInterruption(notification: notification)
        }

        RecordingLogger.success("Audio interruption handling configured")
    }

    deinit {
        chunkManagerCancellables.removeAll()
        cancellables.removeAll()

        // Clean up notification observers
        if let observer = audioInterruptionObserver {
            NotificationCenter.default.removeObserver(observer)
        }
        NotificationCenter.default.removeObserver(self, name: .watchShouldResyncRecordingState, object: nil)
        NotificationCenter.default.removeObserver(self, name: .iPhoneRequestedTransferRetry, object: nil)

        // Cancel any pending deferred pause when deinitializing
        pendingInterruptionPauseWorkItem?.cancel()
        pendingInterruptionPauseWorkItem = nil
    }

    /// Handles audio session interruption notifications (phone calls, etc.)
    private func handleAudioInterruption(notification: Notification) {
        guard let userInfo = notification.userInfo,
              let typeValue = userInfo[AVAudioSessionInterruptionTypeKey] as? UInt,
              let type = AVAudioSession.InterruptionType(rawValue: typeValue) else {
            return
        }

        switch type {
        case .began:
            RecordingLogger.log("Audio interruption began (e.g., phone call) — deferring pause by \(interruptionDeferralSeconds)s to avoid ring-only pauses")

            // Cancel any existing pending pause
            pendingInterruptionPauseWorkItem?.cancel()

            // Only consider pausing if we're actively recording; defer to see if the interruption clears quickly
            guard self.state == .recording else { return }

            let workItem = DispatchWorkItem { [weak self] in
                guard let self = self else { return }
                // If still recording after the deferral window, treat as a real/connected interruption and pause
                if self.state == .recording {
                    self.pauseRecording(reason: .audioInterruption)
                }
            }
            self.pendingInterruptionPauseWorkItem = workItem

            // If options indicate "shouldResume" or no options provided, treat as potentially transient (ring-only) and keep deferring.
            if let optionsValue = userInfo[AVAudioSessionInterruptionOptionKey] as? UInt {
                let options = AVAudioSession.InterruptionOptions(rawValue: optionsValue)
                if options.contains(.shouldResume) {
                    // Likely ring-only or transient; proceed with deferral without immediate pause.
                }
            }

            DispatchQueue.main.asyncAfter(deadline: .now() + interruptionDeferralSeconds, execute: workItem)

        case .ended:
            RecordingLogger.log("Audio interruption ended — cancelling any deferred pause and attempting resume if needed")

            // Cancel the deferred pause (ring-only interruptions end quickly and should not pause)
            pendingInterruptionPauseWorkItem?.cancel()
            pendingInterruptionPauseWorkItem = nil

            // If we never transitioned to paused but the underlying recorder might have been halted by the OS,
            // attempt a best-effort resume of the recording engine.
            if self.state == .recording {
                self.chunkedRecordingManager.resumeRecording()
            }

            // Respect existing auto-resume behavior when we did pause due to an interruption
            if let optionsValue = userInfo[AVAudioSessionInterruptionOptionKey] as? UInt {
                let options = AVAudioSession.InterruptionOptions(rawValue: optionsValue)
                if options.contains(.shouldResume) {
                    handleAutoResume()
                }
            } else {
                // If no options provided, try to auto-resume if it was an interruption pause
                handleAutoResume()
            }
        @unknown default:
            RecordingLogger.log("Unknown interruption type: \(typeValue)")
        }
    }

    /// Checks if recording should auto-resume and resumes if appropriate
    /// Only auto-resumes if the pause was due to an audio interruption (not manual)
    func handleAutoResume() {
        guard state == .paused else {
            return
        }
        // Never stop due to interruptions; only resume if it was an interruption pause.

        // Only auto-resume if it was paused due to audio interruption
        if pauseReason == .audioInterruption {
            RecordingLogger.log("Auto-resuming recording after audio interruption ended")
            resumeRecording()
        } else {
            RecordingLogger.log("Not auto-resuming - pause was manual or unknown reason")
        }
    }

    // MARK: - Recording Controls

    func startRecording() {
        RecordingLogger.log("=== START RECORDING ===")

        // Start extended runtime session to keep the app alive in the background.
        // The session provides ~1 hour of background execution. Since the user
        // periodically interacts (EXTEND button, dismiss alerts), the app stays
        // foreground-active, mitigating this limit for longer recordings.
        startExtendedRuntimeSessionFallback()

        // Continue with recording setup immediately

        // Update state immediately for instant UI feedback
        // This prevents the UI from freezing while audio session setup occurs
        state = .recording

        // Setup audio session (this can block, but state is already updated)
        guard setupAudioSession() else {
            RecordingLogger.error("Cannot start recording - audio session setup failed")
            // Clean up keep-alive session if audio setup fails
            stopKeepAliveSession()
            state = .error("Audio session setup failed")
            WKInterfaceDevice.current().play(.failure)
            return
        }

        // Start recording via ChunkedRecordingManager.
        // The manager handles AVAudioRecorder lifecycle, countdown timer, and chunk creation.
        // Chunks are created when user presses EXTEND; completed chunks are stored locally.
        // ALL chunks are transferred to iPhone only after recording stops (in stopRecording).
        let recordingId = chunkedRecordingManager.startRecording(
            onChunkCompleted: { chunkURL, chunkMetadata in
                let chunkIndex = chunkMetadata.chunkInfo?.chunkIndex ?? -1
                let isLast = chunkMetadata.chunkInfo?.isLastChunk ?? false
                RecordingLogger.log("Chunk \(chunkIndex) saved locally (isLast: \(isLast)), will transfer after stop")
            },
            onRecordingFinished: {
                RecordingLogger.log("All chunks finalized — ready for transfer")
            }
        )

        guard let recordingId = recordingId else {
            RecordingLogger.error("ChunkedRecordingManager failed to start recording")
            stopKeepAliveSession()
            state = .error("Failed to start recording")
            WKInterfaceDevice.current().play(.failure)
            return
        }

        currentRecordingId = recordingId

        // No separate currentRecordingURL needed -- ChunkedRecordingManager manages chunk files
        // currentRecordingURL is set to nil; stopRecording will use the manager's output
        currentRecordingURL = nil

        RecordingLogger.log("Recording ID: \(recordingId)")
        RecordingLogger.log("Recording started via ChunkedRecordingManager (dynamic chunk allocation)")

        // Recording started successfully via ChunkedRecordingManager
        let now = Date()
        recordingStartTime = now  // Capture the original start time (not affected by pause/resume)
        elapsed = 0
        pauseReason = nil  // Clear any previous pause reason
        state = .recording
        startTimer()

        RecordingLogger.success("Recording started successfully!")
        RecordingLogger.log("  Recording ID: \(recordingId)")
        RecordingLogger.log("  Start Time: \(now)")

        WKInterfaceDevice.current().play(.start)

        // Notify iPhone so it can show Live Activity and notification (Guideline 2.5.14)
        WatchConnectivityManager.shared.sendRecordingOnWatchIndicator(isRecording: true, startedAt: recordingStartTime)
    }

    func pauseRecording(reason: PauseReason = .manual) {
        RecordingLogger.log("=== PAUSE RECORDING (reason: \(reason)) ===")

        guard state == .recording else {
            RecordingLogger.log("Cannot pause - not in recording state (current: \(state))")
            return
        }

        // Pause via ChunkedRecordingManager (pauses the underlying AVAudioRecorder)
        chunkedRecordingManager.pauseRecording()
        RecordingLogger.log("Audio recorder paused")

        stopTimer()
        pauseReason = reason
        state = .paused

        RecordingLogger.success("Recording paused. Elapsed: \(elapsed)s, Reason: \(reason)")
        WKInterfaceDevice.current().play(.stop)
    }

    func resumeRecording() {
        RecordingLogger.log("=== RESUME RECORDING ===")

        guard state == .paused else {
            RecordingLogger.log("Cannot resume - not in paused state (current: \(state))")
            return
        }

        // Resume via ChunkedRecordingManager (resumes the underlying AVAudioRecorder)
        chunkedRecordingManager.resumeRecording()
        RecordingLogger.log("Audio recorder resumed")

        startDate = Date()
        pauseReason = nil  // Clear pause reason when resuming
        state = .recording
        startTimer()

        RecordingLogger.success("Recording resumed")
        WKInterfaceDevice.current().play(.start)
    }

    // MARK: - Extend Recording

    /// Extends the recording by 45 minutes.
    /// Creates a chunk boundary (finalizes current chunk, starts new one),
    /// adds time to the countdown, and starts a fresh ExtendedRuntimeSession
    /// so the OS grants another ~1 hour of background execution.
    func extendRecording() {
        RecordingLogger.log("=== EXTEND RECORDING ===")

        guard state == .recording else {
            RecordingLogger.log("Cannot extend - not in recording state (current: \(state))")
            return
        }

        let success = chunkedRecordingManager.extendRecording()

        if success {
            RecordingLogger.success("Recording extended by \(chunkedRecordingManager.configuredExtendAmountSeconds / 60) minutes")

            // Reset alert tracking so alerts fire again for the new countdown window
            shownAlerts.removeAll()
            activeAlert = nil

            // Start a fresh ExtendedRuntimeSession to get another ~1 hour of background time.
            // startSession() internally parks the old session and invalidates it safely.
            RecordingLogger.log("Renewing ExtendedRuntimeSession for extended recording...")
            startExtendedRuntimeSessionFallback()

            WKInterfaceDevice.current().play(.success)
        } else {
            RecordingLogger.error("Failed to extend recording")
            WKInterfaceDevice.current().play(.failure)
        }
    }

    /// Dismisses the currently active time-remaining alert
    func dismissAlert() {
        activeAlert = nil
    }

    // MARK: - Alert Threshold Checking

    /// Checks if the remaining time has crossed any alert thresholds
    /// and triggers the appropriate alert with haptic feedback.
    /// Called every time remainingTime is updated.
    /// - Parameter remaining: Current remaining time in seconds
    private func checkAlertThresholds(remaining: TimeInterval) {
        guard state == .recording else { return }

        for threshold in alertThresholds {
            // Fire when remaining dips at or below the threshold, but only once per threshold
            if remaining <= threshold && remaining > 0 && !shownAlerts.contains(threshold) {
                shownAlerts.insert(threshold)

                // Determine which alert to show
                let alert: RecordingAlert
                switch threshold {
                case let t where t == 5 * 60:
                    alert = .fiveMinutes
                case let t where t == 2 * 60:
                    alert = .twoMinutes
                case let t where t == 30:
                    alert = .thirtySeconds
                default:
                    continue
                }

                RecordingLogger.log("Alert triggered: \(alert) (remaining: \(remaining)s)")

                // Show the alert and play haptic
                activeAlert = alert
                WKInterfaceDevice.current().play(.notification)

                // Auto-dismiss after 5 seconds
                DispatchQueue.main.asyncAfter(deadline: .now() + 5.0) { [weak self] in
                    if self?.activeAlert == alert {
                        self?.activeAlert = nil
                    }
                }

                // Only show one alert at a time (the most urgent)
                break
            }
        }
    }

    // MARK: - Stall Detection & Retry

    /// Starts monitoring transfer progress for stalls (works for both chunked and single-file).
    /// Call after transfers begin.
    func startStallDetection() {
        RecordingLogger.log("Starting stall detection timer")
        stallCheckTimer?.invalidate()

        // Seed single-file progress tracking for every active transfer
        let now = Date()
        for recordingId in activeTransfers {
            if recordingLastProgressUpdate[recordingId] == nil {
                recordingLastProgressUpdate[recordingId] = now
                recordingLastProgressValue[recordingId] = 0.0
            }
        }

        stallCheckTimer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { [weak self] _ in
            Task { @MainActor in
                self?.checkForStalledTransfers()
            }
        }
    }

    /// Stops the stall detection timer and clears all progress tracking state
    private func stopStallDetection() {
        stallCheckTimer?.invalidate()
        stallCheckTimer = nil
        chunkLastProgressUpdate.removeAll()
        chunkTransferProgress.removeAll()
        recordingLastProgressUpdate.removeAll()
        recordingLastProgressValue.removeAll()
        retryStartTime = nil
    }

    /// Updates progress for a specific chunk (called from transfer progress callbacks)
    /// - Parameters:
    ///   - chunkId: The UUID of the chunk being transferred
    ///   - progress: Current progress (0.0 to 1.0)
    func updateChunkProgress(chunkId: UUID, progress: Double) {
        chunkTransferProgress[chunkId] = progress
        chunkLastProgressUpdate[chunkId] = Date()
    }

    /// Checks all in-flight transfers (chunked and single-file) for stalls.
    /// A transfer is stalled if progress hasn't changed past the timeout policy.
    private func checkForStalledTransfers() {
        guard transferState == .transferring || transferState == .retrying else { return }

        let now = Date()

        // Check retry timeout (15-minute window for retries)
        if transferState == .retrying, let retryStart = retryStartTime {
            if now.timeIntervalSince(retryStart) >= Self.retryTimeoutSeconds {
                RecordingLogger.error("Retry timeout reached (15 min) - triggering COMPLETE FAIL")
                handleCompleteFail()
                return
            }
        }

        // --- Check chunk-based transfers ---
        for (chunkId, lastUpdate) in chunkLastProgressUpdate {
            let progress = chunkTransferProgress[chunkId] ?? 0
            let timeSinceUpdate = now.timeIntervalSince(lastUpdate)
            let activeRecordingId = currentTransferRecordingId
            let timeout = transferTimeoutSeconds(for: activeRecordingId)

            if progress < 1.0 && timeSinceUpdate >= timeout {
                RecordingLogger.error("Chunk \(chunkId) stalled at \(Int(progress * 100))% for \(Int(timeSinceUpdate))s")
                handleTransferStalled(
                    recordingId: activeRecordingId,
                    stalledProgress: progress,
                    stalledDuration: timeSinceUpdate
                )
                return
            }
        }

        // --- Check single-file transfers ---
        // For non-chunked transfers, chunkLastProgressUpdate is empty so the loop
        // above is a no-op. Poll WatchConnectivityManager's per-recording progress.
        guard chunkLastProgressUpdate.isEmpty else { return }

        for recordingId in activeTransfers {
            let currentProgress = connectivityManager.recordingTransferProgress[recordingId] ?? 0
            let previousProgress = recordingLastProgressValue[recordingId] ?? -1
            let timeout = transferTimeoutSeconds(for: recordingId)

            if currentProgress != previousProgress {
                recordingLastProgressUpdate[recordingId] = now
                recordingLastProgressValue[recordingId] = currentProgress
            } else if let lastUpdate = recordingLastProgressUpdate[recordingId] {
                let timeSinceUpdate = now.timeIntervalSince(lastUpdate)
                if currentProgress < 1.0 && timeSinceUpdate >= timeout {
                    RecordingLogger.error("Single-file transfer \(recordingId) stalled at \(Int(currentProgress * 100))% for \(Int(timeSinceUpdate))s")
                    handleTransferStalled(
                        recordingId: recordingId,
                        stalledProgress: currentProgress,
                        stalledDuration: timeSinceUpdate
                    )
                    return
                }
            }
        }
    }

    /// Handles a stalled transfer by cancelling the in-flight WCSession transfer
    /// and moving to failed state. The user must press RETRY to continue.
    private func handleTransferStalled(
        recordingId: UUID?,
        stalledProgress: Double,
        stalledDuration: TimeInterval
    ) {
        RecordingLogger.log("Transfer stalled — cancelling in-flight transfers before marking failed")

        // Cancel the existing WCSession transfer so the OS stops trying to deliver
        // the old payload. Without this, a retry would create a second parallel transfer.
        if let recordingId = recordingId ?? currentRecordingId {
            connectivityManager.cancelTransfer(recordingId: recordingId)
            RecordingLogger.log("Cancelled WCSession transfer for recording: \(recordingId)")
            timedOutTransferIds.insert(recordingId)

            Task { @MainActor [weak self] in
                await self?.transferFailureNotificationService.notifyTransferFailed(recordingId: recordingId)
            }
        }

        let failedMessage = "Transfer stalled at \(Int(stalledProgress * 100))% for \(Int(stalledDuration))s. Retry will resend from scratch."
        DispatchQueue.main.async {
            self.transferState = .failed(failedMessage)
        }

        WKInterfaceDevice.current().play(.failure)
    }

    /// Called when user presses RETRY from the failed state.
    /// Cancels any lingering WCSession transfers, then resends and starts a 15-minute timeout.
    func retryTransfer() {
        RecordingLogger.log("=== RETRY TRANSFER ===")

        guard case .failed = transferState else {
            RecordingLogger.log("Cannot retry - not in failed state (current: \(transferState))")
            return
        }

        // Cancel any lingering WCSession transfers to prevent duplicates
        if let recordingId = currentRecordingId {
            connectivityManager.cancelTransfer(recordingId: recordingId)
            RecordingLogger.log("Cancelled existing WCSession transfer before retry: \(recordingId)")
            if timedOutTransferIds.contains(recordingId) {
                // Timed-out transfers must retry from scratch to avoid partial-state divergence.
                requestCleanupPartialsOniPhone(recordingId: recordingId)
            }
        }

        transferState = .retrying
        retryStartTime = Date()

        // Retry pending transfers via the standard mechanism
        retryPendingTransfers()
        if let recordingId = currentRecordingId {
            timedOutTransferIds.remove(recordingId)
        }

        RecordingLogger.log("Retry started with 15-minute timeout")
        WKInterfaceDevice.current().play(.start)
    }

    private func transferTimeoutSeconds(for recordingId: UUID?) -> TimeInterval {
        guard let recordingId = recordingId,
              let recording = try? repository.fetchAllRecordings().first(where: { $0.id == recordingId }) else {
            return transferTimeoutPolicy.timeout(forRecordingDuration: nil)
        }
        return transferTimeoutPolicy.timeout(forRecordingDuration: recording.duration)
    }

    private func requestCleanupPartialsOniPhone(recordingId: UUID) {
        connectivityManager.sendMessage(
            ["action": "cleanupPartials", "recordingId": recordingId.uuidString]
        ) { error in
            if let error = error {
                RecordingLogger.error("Failed to send cleanup message to iPhone before retry", error: error)
            }
        }
    }

    /// Handles complete failure: retry timed out after 15 minutes.
    /// Cancels all in-flight transfers, deletes partial data, then resends from scratch.
    private func handleCompleteFail() {
        RecordingLogger.error("=== COMPLETE FAIL - Deleting all partials and resending ===")

        transferState = .completeFail

        // Cancel ALL in-flight WCSession transfers for this recording first
        if let recordingId = currentRecordingId {
            connectivityManager.cancelTransfer(recordingId: recordingId)
            RecordingLogger.log("Cancelled all WCSession transfers for complete fail: \(recordingId)")
        }

        // Clear all chunk progress tracking
        chunkTransferProgress.removeAll()
        chunkLastProgressUpdate.removeAll()
        retryStartTime = nil

        // Notify iPhone to delete partial data via connectivity manager
        connectivityManager.sendMessage(
            ["action": "cleanupPartials", "recordingId": currentRecordingId?.uuidString ?? ""]
        ) { error in
            if let error = error {
                RecordingLogger.error("Failed to send cleanup message to iPhone", error: error)
            }
        }

        // Re-send all chunks from the beginning
        let chunkFiles = chunkedRecordingManager.getLocalChunkFiles()
        RecordingLogger.log("Resending \(chunkFiles.count) chunks from scratch")

        // Small delay to let cleanup propagate, then start fresh transfer
        DispatchQueue.main.asyncAfter(deadline: .now() + 2.0) { [weak self] in
            guard let self = self else { return }
            self.transferState = .transferring
            self.retryStartTime = nil

            // Re-transfer all chunks
            self.retryPendingTransfers()
        }

        WKInterfaceDevice.current().play(.failure)
    }

    func stopRecording() {
        RecordingLogger.log("=== STOP RECORDING ===")

        guard state == .recording || state == .paused else {
            RecordingLogger.log("Cannot stop - not in recording/paused state (current: \(state))")
            return
        }

        // ✅ Get the recording ID we created at start
        guard let recordingId = currentRecordingId else {
            RecordingLogger.error("No recording ID found - this should not happen!")
            state = .error("Internal error: no recording ID")
            WKInterfaceDevice.current().play(.failure)
            return
        }

        state = .saving
        stopTimer()

        // Notify iPhone that recording stopped so it can end Live Activity
        WatchConnectivityManager.shared.sendRecordingOnWatchIndicator(isRecording: false, startedAt: nil)

        // Stop recording via ChunkedRecordingManager.
        // This finalizes the last chunk (marks isLastChunk = true).
        // No transfer happens yet — we send everything below after saving.
        let totalDuration = chunkedRecordingManager.stopRecording()

        RecordingLogger.log("Recording stopped. ID: \(recordingId), Total duration: \(totalDuration)s")

        // Save recording to local repository so it appears in Watch history.
        // Copy ALL chunks to the Recordings directory so that retries via transferToiOS
        // can find and re-send every chunk (not just the first).
        let chunkFiles = chunkedRecordingManager.getLocalChunkFiles()
        let sortedChunks = chunkFiles.sorted(by: { $0.key < $1.key })

        if let localRepo = repository as? LocalRecordingRepository {
            // Copy every chunk to the persistent Recordings directory
            for (chunkIndex, chunkURL) in sortedChunks {
                let destURL = localRepo.recordingsDirectoryURL
                    .appendingPathComponent(chunkURL.lastPathComponent)
                do {
                    if FileManager.default.fileExists(atPath: destURL.path) {
                        try FileManager.default.removeItem(at: destURL)
                    }
                    try FileManager.default.copyItem(at: chunkURL, to: destURL)
                    RecordingLogger.log("  Persisted chunk \(chunkIndex) → \(destURL.lastPathComponent)")
                } catch {
                    RecordingLogger.error("Failed to persist chunk \(chunkIndex): \(error.localizedDescription)", error: error)
                }
            }
        }

        // Save first chunk as the representative file for the Core Data entry
        var savedRecordingForTransfer: Recording?
        if let firstChunkEntry = sortedChunks.first {
            do {
                let savedRecording = try repository.saveRecording(
                    id: recordingId,
                    fileURL: firstChunkEntry.1,
                    duration: totalDuration,
                    startTime: recordingStartTime
                )
                RecordingLogger.success("Saved recording to local repository: \(savedRecording.id), duration: \(totalDuration)s, totalChunks: \(sortedChunks.count)")
                lastRecording = savedRecording
                savedRecordingForTransfer = savedRecording
            } catch {
                RecordingLogger.error("Failed to save recording to local repository", error: error)
            }
        } else {
            RecordingLogger.error("No chunk files available to save recording to local repository")
        }

        // Queue-aware transfer start:
        // only one recording is sent at a time; pending recordings remain queued.
        if let recordingToTransfer = savedRecordingForTransfer {
            transferToiOS(recording: recordingToTransfer)
        } else {
            RecordingLogger.error("Skipping transfer start because recording could not be saved")
        }

        state = .idle
        accumulated = 0
        elapsed = 0
        remainingTime = 0
        isExtendEnabled = false
        activeAlert = nil
        shownAlerts.removeAll()
        WKInterfaceDevice.current().play(.success)

        // Stop keep-alive session - allow app to suspend normally now
        stopKeepAliveSession()

        // Cleanup recording state (keep currentRecordingId for stall detection reference)
        // Keep recordingStartTime alive until transfer is confirmed — retries need it
        // for rebuilding RecordingTransferMetadata with the correct startTime.
        currentRecordingURL = nil
        pauseReason = nil
        deactivateAudioSession()

        RecordingLogger.log("=== STOP RECORDING COMPLETE ===")
    }

    // MARK: - iOS Transfer

    /// Transfers a recording to the iOS app via WatchConnectivity.
    /// Chunk-aware: scans the Recordings directory for all chunk files belonging to
    /// this recording and sends them with proper `chunkInfo` metadata so the iPhone
    /// can assemble them. Falls back to a single-file transfer when only one file exists.
    /// - Parameter recording: The recording to transfer
    func transferToiOS(recording: Recording) {
        RecordingLogger.log("=== TRANSFER TO iOS ===")
        RecordingLogger.log("Recording ID: \(recording.id)")
        RecordingLogger.log("File URL: \(recording.fileURL.path)")
        RecordingLogger.log("Filename: \(recording.filename)")
        RecordingLogger.log("Duration: \(recording.duration)s")

        // Enforce one-recording-at-a-time transfer policy.
        if let activeId = currentTransferRecordingId, activeId != recording.id {
            RecordingLogger.log("⏳ Transfer slot busy with \(activeId). Keeping \(recording.id) queued.")
            return
        }
        if let activeId = activeTransfers.first, activeId != recording.id {
            currentTransferRecordingId = activeId
            RecordingLogger.log("⏳ Transfer already active for \(activeId). Keeping \(recording.id) queued.")
            return
        }

        // Check if this recording is already being transferred
        if connectivityManager.isRecordingTransferring(recording.id) {
            RecordingLogger.log("⚠️ Recording \(recording.id) is already being transferred - skipping duplicate transfer")
            return
        }

        // Check if recording can be sent using Core Data status
        if let localRepo = repository as? LocalRecordingRepository {
            let (canSend, reason) = localRepo.canSendRecording(recording.id)
            if !canSend {
                RecordingLogger.log("⚠️ Cannot send recording: \(reason ?? "unknown")")
                return
            }
        }

        // Check if companion app is installed
        guard connectivityManager.isWatchConnected else {
            RecordingLogger.log("iOS app not connected - recording will stay local until sync")
            return
        }

        // Discover all chunk files for this recording in the Recordings directory.
        // Files follow the naming convention: {recordingID}_chunk{index}.m4a
        let chunkFiles = discoverChunkFiles(for: recording)

        guard !chunkFiles.isEmpty else {
            RecordingLogger.error("Cannot transfer - no chunk files found for recording: \(recording.id)")
            return
        }

        // Update status to transferring in Core Data
        if let localRepo = repository as? LocalRecordingRepository {
            do {
                try localRepo.updateStatus(recording.id, status: .transferring)
                RecordingLogger.log("✅ Updated status to transferring")
            } catch {
                RecordingLogger.error("Failed to update status", error: error)
            }
        }

        // Update transfer state
        currentTransferRecordingId = recording.id
        transferState = .transferring
        isTransferringToiOS = true
        activeTransfers.insert(recording.id)

        let isMultiChunk = chunkFiles.count > 1
        RecordingLogger.log("Found \(chunkFiles.count) chunk(s) — sending as \(isMultiChunk ? "chunked" : "single-file") transfer")

        if isMultiChunk {
            // Multi-chunk: send each chunk with chunkInfo so iPhone assembles them
            for (chunkIndex, chunkURL) in chunkFiles {
                let isLastChunk = (chunkIndex == chunkFiles.last?.0)

                let chunkInfo = ChunkTransferMetadata(
                    parentRecordingId: recording.id,
                    chunkId: UUID(),
                    chunkIndex: chunkIndex,
                    isLastChunk: isLastChunk,
                    chunkDuration: 0,
                    totalDurationSoFar: recording.duration,
                    recordingStartTime: recording.startTime
                )

                let metadata = RecordingTransferMetadata(
                    id: recording.id,
                    filename: chunkURL.lastPathComponent,
                    duration: recording.duration,
                    createdAt: recording.createdAt,
                    startTime: recording.startTime,
                    chunkInfo: chunkInfo
                )

                RecordingLogger.log("  Sending chunk \(chunkIndex)/\(chunkFiles.count - 1) (isLast: \(isLastChunk)): \(chunkURL.lastPathComponent)")
                connectivityManager.transferRecording(fileURL: chunkURL, metadata: metadata)
            }
        } else {
            // Single chunk: send as a single-file transfer (no chunkInfo)
            let chunkURL = chunkFiles[0].1
            let metadata = RecordingTransferMetadata(
                id: recording.id,
                filename: recording.filename,
                duration: recording.duration,
                createdAt: recording.createdAt,
                startTime: recording.startTime
            )

            RecordingLogger.log("  Sending single file: \(recording.filename)")
            connectivityManager.transferRecording(fileURL: chunkURL, metadata: metadata)
        }

        // Start stall detection
        startStallDetection()

        RecordingLogger.log("=== TRANSFER INITIATED (\(chunkFiles.count) file(s)) ===")
    }

    /// Starts the next eligible pending/failed recording transfer when idle.
    /// This is the dequeue engine for one-recording-at-a-time delivery.
    private func startNextQueuedTransferIfIdle() {
        guard connectivityManager.isWatchConnected else {
            RecordingLogger.log("Cannot dequeue next transfer - iOS app not connected")
            return
        }

        guard currentTransferRecordingId == nil, activeTransfers.isEmpty else {
            return
        }

        do {
            let recordings = try repository.fetchAllRecordings()
                .sorted(by: { $0.createdAt < $1.createdAt })

            // Priority 1: recordings that were previously in `.transferring` when app was closed.
            // If WCSession is not currently transferring them anymore, immediately re-queue first.
            if let localRepo = repository as? LocalRecordingRepository {
                for recording in recordings {
                    // If OS transfer is still alive, let WCSession continue naturally.
                    if connectivityManager.isRecordingTransferring(recording.id) {
                        continue
                    }

                    guard let entity = try? localRepo.fetchEntityById(recording.id) else {
                        continue
                    }

                    let status = WatchRecordingStatus(rawValue: entity.status) ?? .pending
                    guard status == .transferring else {
                        continue
                    }

                    RecordingLogger.log("Prioritizing interrupted transfer on app relaunch: \(recording.id)")

                    // Reset to pending so transferToiOS can re-queue immediately instead of waiting
                    // for stale timeout logic.
                    do {
                        try localRepo.updateStatus(recording.id, status: .pending)
                    } catch {
                        RecordingLogger.error("Failed to reset interrupted transfer to pending: \(recording.id)", error: error)
                        continue
                    }

                    transferToiOS(recording: recording)
                    return
                }
            }

            for recording in recordings {
                // Skip if already being transferred via WCSession.
                if connectivityManager.isRecordingTransferring(recording.id) {
                    continue
                }

                if let localRepo = repository as? LocalRecordingRepository {
                    let (canSend, _) = localRepo.canSendRecording(recording.id)
                    if !canSend {
                        continue
                    }
                }

                RecordingLogger.log("Dequeued next recording for transfer: \(recording.id)")
                transferToiOS(recording: recording)
                return
            }
        } catch {
            RecordingLogger.error("Failed to dequeue pending transfer", error: error)
        }
    }

    // MARK: - Chunk File Discovery

    /// Discovers all chunk files for a recording in the Recordings directory.
    /// Chunk files follow the naming convention: `{recordingID}_chunk{index}.m4a`.
    /// Falls back to the recording's own fileURL if no chunk-patterned files are found.
    /// - Parameter recording: The recording whose chunks to find
    /// - Returns: Sorted array of (chunkIndex, fileURL) pairs
    private func discoverChunkFiles(for recording: Recording) -> [(Int, URL)] {
        guard let localRepo = repository as? LocalRecordingRepository else {
            // Fallback: use the recording's own file if it exists
            if FileManager.default.fileExists(atPath: recording.fileURL.path) {
                return [(0, recording.fileURL)]
            }
            return []
        }

        let recordingsDir = localRepo.recordingsDirectoryURL
        let idString = recording.id.uuidString
        let chunkPrefix = "\(idString)_chunk"

        do {
            let allFiles = try FileManager.default.contentsOfDirectory(
                at: recordingsDir,
                includingPropertiesForKeys: nil,
                options: [.skipsHiddenFiles]
            )

            // Find all files matching {recordingID}_chunk{N}.m4a
            var chunks: [(Int, URL)] = []
            for fileURL in allFiles {
                let name = fileURL.deletingPathExtension().lastPathComponent
                if name.hasPrefix(chunkPrefix),
                   let indexStr = name.components(separatedBy: "chunk").last,
                   let index = Int(indexStr) {
                    chunks.append((index, fileURL))
                }
            }

            // Sort by chunk index
            chunks.sort(by: { $0.0 < $1.0 })

            if !chunks.isEmpty {
                RecordingLogger.log("Discovered \(chunks.count) chunk file(s) for recording \(recording.id)")
                return chunks
            }
        } catch {
            RecordingLogger.error("Failed to scan recordings directory: \(error.localizedDescription)", error: error)
        }

        // Fallback: single file
        if FileManager.default.fileExists(atPath: recording.fileURL.path) {
            return [(0, recording.fileURL)]
        }

        return []
    }

    /// Checks if a recording has already been sent to iOS
    /// - Parameter recordingId: The recording ID to check
    /// - Returns: True if the recording was already confirmed by iOS
    func isRecordingAlreadySent(_ recordingId: UUID) -> Bool {
        guard let localRepo = repository as? LocalRecordingRepository,
              let entity = try? localRepo.fetchEntityById(recordingId) else {
            return false
        }

        // Consider it sent if status is sent (2), confirmed (3), or has iOS processing status
        return entity.status >= 2 || entity.iosProcessingStatus != nil
    }

    /// Forces a transfer of a recording that was already sent.
    /// Uses `forceResetForRetransfer` which bypasses terminal state protection
    /// and clears all iOS processing metadata (iosProcessingStatus, meetingId, etc.)
    /// so that `canSendRecording()` allows the transfer to proceed.
    /// - Parameter recording: The recording to force transfer
    func forceTransferToiOS(recording: Recording) {
        RecordingLogger.log("=== FORCE TRANSFER TO iOS ===")
        RecordingLogger.log("Recording ID: \(recording.id)")
        RecordingLogger.log("Force transferring already-sent recording")

        // Check if this recording is already being transferred
        if connectivityManager.isRecordingTransferring(recording.id) {
            RecordingLogger.log("⚠️ Recording \(recording.id) is already being transferred - skipping duplicate force transfer")
            return
        }

        // Force-reset status, bypassing terminal state guard and clearing iOS metadata
        if let localRepo = repository as? LocalRecordingRepository {
            do {
                let didReset = try localRepo.forceResetForRetransfer(recording.id)
                if didReset {
                    RecordingLogger.log("✅ Force-reset status to pending for re-transfer (cleared iOS metadata)")
                } else {
                    RecordingLogger.error("⚠️ Force reset returned false - recording may not exist")
                    return
                }
            } catch {
                RecordingLogger.error("Failed to force-reset status for re-transfer", error: error)
                return
            }
        }

        // Now perform the transfer (canSendRecording will succeed since status is .pending)
        transferToiOS(recording: recording)
    }

    /// Checks if a recording is currently being transferred
    /// - Parameter recordingId: The UUID of the recording to check
    /// - Returns: True if the recording is being transferred
    func isRecordingTransferring(_ recordingId: UUID) -> Bool {
        return connectivityManager.isRecordingTransferring(recordingId)
    }

    // MARK: - RecordingHealthCheckDelegate

    /// Called by health check service when a recording should be retried.
    /// Cancels any lingering WCSession transfer before re-queuing to prevent
    /// duplicate parallel transfers for the same recording.
    func shouldRetryRecording(_ recording: Recording) {
        RecordingLogger.log("Health check requested retry for \(recording.id) — cancelling existing transfer first")
        connectivityManager.cancelTransfer(recordingId: recording.id)
        currentTransferRecordingId = nil
        activeTransfers.remove(recording.id)
        transferToiOS(recording: recording)
    }

    // MARK: - Status Information

    /// Information about a recording's current status for UI display
    struct RecordingStatusInfo {
        let icon: String
        let color: Color
        let displayText: String
        let uploadProgress: Double?  // 0.0 to 1.0, only set when uploading on iOS
        let showSendAgainButton: Bool  // Show "Send Again" button (e.g., when status is "Received")
    }

    /// Gets the current status information for a recording
    /// - Parameter recordingId: The recording ID to check
    /// - Returns: Status information for UI display, or nil if recording not found
    func getRecordingStatusInfo(_ recordingId: UUID) -> RecordingStatusInfo? {
        guard let localRepo = repository as? LocalRecordingRepository,
              let entity = try? localRepo.fetchEntityById(recordingId) else {
            return nil
        }

        // Check iOS processing status first (takes priority over local status)
        if let iosStatus = entity.iosProcessingStatus {
            switch iosStatus {
            case "Received":
                return RecordingStatusInfo(
                    icon: "checkmark.circle",
                    color: .green,
                    displayText: "Received by iPhone",
                    uploadProgress: nil,
                    showSendAgainButton: true
                )
            case "Uploading":
                // Include upload progress if available
                let progress = entity.iosUploadProgress > 0 ? entity.iosUploadProgress : nil
                return RecordingStatusInfo(
                    icon: "arrow.up.circle",
                    color: .blue,
                    displayText: "iPhone uploading",
                    uploadProgress: progress,
                    showSendAgainButton: false
                )
            case "Uploaded":
                return RecordingStatusInfo(
                    icon: "cloud.fill",
                    color: .blue,
                    displayText: "Uploaded",
                    uploadProgress: nil,
                    showSendAgainButton: false
                )
            case "Creating Meeting":
                return RecordingStatusInfo(
                    icon: "gear",
                    color: .orange,
                    displayText: "Creating meeting",
                    uploadProgress: nil,
                    showSendAgainButton: false
                )
            case "Created":
                return RecordingStatusInfo(
                    icon: "checkmark.circle.fill",
                    color: .green,
                    displayText: "Meeting created",
                    uploadProgress: nil,
                    showSendAgainButton: false
                )
            default:
                break
            }
        }

        // Fall back to local status
        let status = WatchRecordingStatus(rawValue: entity.status) ?? .pending
        let displayText = (status == .pending) ? "Queued" : status.displayName

        return RecordingStatusInfo(
            icon: status.icon,
            color: colorForStatus(status),
            displayText: displayText,
            uploadProgress: nil,
            showSendAgainButton: false
        )
    }

    /// Gets the appropriate color for a watch recording status
    private func colorForStatus(_ status: WatchRecordingStatus) -> Color {
        switch status {
        case .pending: return .gray
        case .transferring: return .blue
        case .sent: return .orange
        case .confirmed: return .green
        case .failed: return .red
        }
    }

    /// Checks if a recording can be sent (used for button state)
    func canSendRecording(_ recordingId: UUID) -> (canSend: Bool, reason: String?) {
        guard let localRepo = repository as? LocalRecordingRepository else {
            return (false, "Repository not available")
        }

        return localRepo.canSendRecording(recordingId)
    }

    /// Retries transferring local recordings that are genuinely pending or failed.
    /// Pre-filters by Core Data status and in-flight state to avoid duplicate transfers.
    func retryPendingTransfers() {
        RecordingLogger.log("=== RETRY PENDING TRANSFERS ===")

        guard connectivityManager.isWatchConnected else {
            RecordingLogger.log("iOS app not connected - cannot retry transfers")
            return
        }

        startNextQueuedTransferIfIdle()
        RecordingLogger.log("Retry trigger complete - queue scheduler invoked")
    }

    // MARK: - App Lifecycle

    /// Call this when the watch app appears/becomes active.
    /// This checks for any local recordings that haven't been transferred yet
    /// (e.g., if the app was killed before transfer completed or confirmation was received)
    /// and attempts to transfer them to iOS.
    func onAppAppear() {
        RecordingLogger.log("=== APP APPEAR - CHECKING FOR UNTRANSFERRED RECORDINGS ===")

        // Check for any local recordings that need to be synced
        do {
            let localRecordings = try repository.fetchAllRecordings()

            // Update pending sync count
            DispatchQueue.main.async {
                self.pendingSyncCount = localRecordings.count
            }

            if localRecordings.isEmpty {
                RecordingLogger.log("No local recordings to sync")
                return
            }

            RecordingLogger.log("Found \(localRecordings.count) local recording(s) that may need syncing")

            // If iOS is connected, attempt to transfer any unsynced recordings
            if connectivityManager.isWatchConnected {
                RecordingLogger.log("iOS app is connected - attempting to sync pending recordings")

                // Small delay to ensure connectivity manager is fully ready
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) { [weak self] in
                    self?.retryPendingTransfers()
                }
            } else {
                RecordingLogger.log("iOS app not connected - will sync when connection is available")

                // Set up a one-time observer to sync when iOS becomes available
                self.setupConnectionObserverForPendingSync()
            }

        } catch {
            RecordingLogger.error("Failed to check for local recordings on app appear", error: error)
        }
    }

    /// Sets up an observer to sync recordings when iOS connection becomes available
    private func setupConnectionObserverForPendingSync() {
        // Listen for connection changes
        connectivityManager.$isWatchConnected
            .receive(on: DispatchQueue.main)
            .filter { $0 == true } // Only when connected
            .first() // One-time only
            .sink { [weak self] _ in
                RecordingLogger.log("iOS connection established - syncing pending recordings")
                self?.retryPendingTransfers()
            }
            .store(in: &cancellables)
    }

    /// Call this when the watch app goes to background/disappears.
    /// Currently just logs, but can be extended for cleanup if needed.
    func onAppDisappear() {
        RecordingLogger.log("App going to background")
        // Any cleanup or state saving can go here
    }

    /// Manually deletes a recording from local storage
    /// Use this if automatic deletion after transfer fails
    func deleteLocalRecording(id: UUID) {
        RecordingLogger.log("Manually deleting local recording: \(id)")

        do {
            try repository.deleteRecording(id: id)
            RecordingLogger.success("Manually deleted recording: \(id)")

            DispatchQueue.main.async {
                if self.lastRecording?.id == id {
                    self.lastRecording = nil
                }
            }
        } catch {
            RecordingLogger.error("Failed to manually delete recording", error: error)
        }
    }

    // MARK: - Timer Management

    /// Timer is now managed primarily by ChunkedRecordingManager.
    /// The ViewModel subscribes to its published properties (remainingTime, elapsed, etc.)
    /// This local timer is kept only for lightweight UI updates that need faster refresh.

    private func startTimer() {
        // No-op by design. Manager bindings are configured once in init
        // to avoid duplicate subscriptions across start/resume cycles.
    }

    func updateTimerInterval(active: Bool) {
        // Timer interval is now managed by ChunkedRecordingManager
        // No-op here since we use Combine subscriptions instead
        RecordingLogger.log("Scene phase changed: active=\(active)")
    }

    private func stopTimer() {
        timerCancellable?.cancel()
        timerCancellable = nil
    }

    // MARK: - Chunk Manager Binding

    /// Binds manager publishers once to avoid repeated subscriptions during lifecycle events.
    private func bindChunkedRecordingManager() {
        chunkedRecordingManager.totalElapsedTimePublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] totalTime in
                self?.elapsed = totalTime
            }
            .store(in: &chunkManagerCancellables)

        chunkedRecordingManager.remainingTimePublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] remaining in
                guard let self = self else { return }
                self.remainingTime = remaining
                self.checkAlertThresholds(remaining: remaining)
            }
            .store(in: &chunkManagerCancellables)

        chunkedRecordingManager.isExtendEnabledPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isEnabled in
                self?.isExtendEnabled = isEnabled
            }
            .store(in: &chunkManagerCancellables)
    }

    /// Configures manager callbacks that need ViewModel handling.
    private func configureChunkedRecordingCallbacks() {
        chunkedRecordingManager.onAutoStop = { [weak self] in
            guard let self = self else { return }

            RecordingLogger.log("Auto-stop triggered by countdown reaching zero")
            self.gracefulRecordingShutdown(
                reason: "Recording time limit was reached.",
                sentryMessage: "Recording countdown reached zero — auto-stop"
            )
        }
    }

    // MARK: - Debug Helpers

    /// Logs the current state of the recordings directory
    func debugLogRecordingsDirectory() {
        RecordingLogger.log("=== DEBUG: Recordings Directory ===")

        do {
            let docs = try FileManager.default.url(for: .documentDirectory, in: .userDomainMask, appropriateFor: nil, create: false)
            let recordingsDir = docs.appendingPathComponent("Recordings", isDirectory: true)

            RecordingLogger.log("Documents directory: \(docs.path)")
            RecordingLogger.log("Recordings directory: \(recordingsDir.path)")

            if FileManager.default.fileExists(atPath: recordingsDir.path) {
                let contents = try FileManager.default.contentsOfDirectory(at: recordingsDir, includingPropertiesForKeys: [.fileSizeKey, .creationDateKey])
                RecordingLogger.log("Found \(contents.count) files:")

                for file in contents {
                    let attrs = try FileManager.default.attributesOfItem(atPath: file.path)
                    let size = attrs[.size] as? Int64 ?? 0
                    let created = attrs[.creationDate] as? Date ?? Date()
                    RecordingLogger.log("  - \(file.lastPathComponent): \(size) bytes, created: \(created)")
                }
            } else {
                RecordingLogger.log("Recordings directory does not exist")
            }
        } catch {
            RecordingLogger.error("Failed to read recordings directory", error: error)
        }

        RecordingLogger.log("=== END DEBUG ===")
    }
}

