//
//  WatchStatusSync.swift
//  Memorable
//
//  Helper for syncing recording status from iOS to Watch
//

import Foundation

/// Helper for syncing recording status from iOS to Watch
final class WatchStatusSync {
    private let connectivity = WatchConnectivityManager.shared
    private let logger = LoggerFactory.makeLogger()

    /// Sends processing status update to watch with optional upload progress
    /// - Parameters:
    ///   - recordingId: Recording identifier
    ///   - status: Current RecordingStatus
    ///   - uploadProgress: Upload progress (0.0 to 1.0) - only for .uploading status
    ///   - meetingId: Meeting ID when meeting is created
    /// - Note: This method must be called from the main thread as it accesses @Published properties
    func sendStatusToWatch(recordingId: UUID, status: RecordingStatus, uploadProgress: Double? = nil, meetingId: UUID? = nil) {
        // applicationContext requires main thread access (enforced by dispatchPrecondition)
        var context = connectivity.applicationContext

        // Get existing status dictionary or create new
        var processingStatuses = context["recordingProcessingStatuses"] as? [String: [String: Any]] ?? [:]

        // Create status payload
        var statusPayload: [String: Any] = [
            "status": status.displayName,
            "statusRaw": status.rawValue,
            "timestamp": Date().timeIntervalSince1970
        ]

        // Include upload progress for uploading status
        if let progress = uploadProgress, status == .uploading {
            statusPayload["uploadProgress"] = progress
        }

        if let meetingId = meetingId {
            statusPayload["meetingId"] = meetingId.uuidString
        }

        processingStatuses[recordingId.uuidString] = statusPayload
        context["recordingProcessingStatuses"] = processingStatuses

        connectivity.updateApplicationContext(context) { [weak self] error in
            if let error = error {
                self?.logger.error("Failed to sync status to watch: \(error)")
            } else {
                let progressStr = uploadProgress.map { " (\(Int($0 * 100))%)" } ?? ""
                self?.logger.info("Synced status to watch: \(recordingId) -> \(status.displayName)\(progressStr)")
            }
        }
    }

    /// Clears status for a completed recording
    /// - Note: This method must be called from the main thread as it accesses @Published properties
    func clearStatusFromWatch(recordingId: UUID) {
        // applicationContext requires main thread access (enforced by dispatchPrecondition)
        var context = connectivity.applicationContext

        guard var processingStatuses = context["recordingProcessingStatuses"] as? [String: [String: Any]] else {
            return
        }

        processingStatuses.removeValue(forKey: recordingId.uuidString)

        if processingStatuses.isEmpty {
            context.removeValue(forKey: "recordingProcessingStatuses")
        } else {
            context["recordingProcessingStatuses"] = processingStatuses
        }

        connectivity.updateApplicationContext(context, completion: nil)
    }
}

//
//  WatchRecordingService.swift
//  Memorable
//
//  Handles reception and storage of recordings transferred from Apple Watch.
//  This service sets up the WatchConnectivityManager callbacks to receive
//  recording files, save them to local storage, and automatically submit
//  them for transcription.
//

import Foundation
import Combine
import WatchConnectivity
#if os(iOS)
import UIKit
#endif

/// Service responsible for handling recordings received from Apple Watch.
/// Automatically submits received recordings to the transcription service.
/// Should be initialized early in the app lifecycle to ensure recordings are captured.
///
/// Flow:
/// 1. Watch records audio → transfers to iOS
/// 2. WatchRecordingService receives file via WatchConnectivityManager
/// 3. File is saved to local storage
/// 4. Recording is automatically submitted for transcription
/// 5. Confirmation sent back to watch to delete local copy
@MainActor
final class WatchRecordingService: ObservableObject {

    // MARK: - Singleton

    static let shared = WatchRecordingService()

    // MARK: - Published Properties

    /// Number of recordings received from watch in current session
    @Published private(set) var recordingsReceivedCount: Int = 0

    /// Last received recording (if any)
    @Published private(set) var lastReceivedRecording: Recording? = nil

    /// Indicates if the service is currently processing a received file
    @Published private(set) var isProcessingTransfer: Bool = false

    /// Indicates if there are pending files from when app was terminated
    @Published private(set) var hasPendingFiles: Bool = false

    /// Information about incoming transfers from watch (per-recording)
    @Published private(set) var incomingTransfers: [UUID: IncomingTransferInfo] = [:]

    // MARK: - Incoming Transfer Info

    /// Information about an incoming transfer from watch
    struct IncomingTransferInfo: Identifiable {
        let id: UUID
        let metadata: RecordingTransferMetadata?
        var state: WatchConnectivityManager.IncomingTransferState
        var progress: Double?  // Optional - can be nil for indeterminate progress
        var uploadId: UUID?  // Track associated upload
        var uploadProgress: Double?  // Upload progress (0.0 to 1.0)

        // MARK: - Chunk-Aware Fields

        /// Number of chunks received so far (nil for single-file transfers)
        var chunksReceived: Int?

        /// Total expected chunks (nil if last chunk not yet received, or single-file)
        var totalExpectedChunks: Int?

        /// True if the recording is currently being merged from chunks
        var isMerging: Bool = false

        /// Last time progress was updated (for stalled transfer detection)
        var lastProgressUpdateTime: Date?

        // MARK: - Computed Properties

        var isUploading: Bool {
            return uploadId != nil && uploadProgress != nil && uploadProgress! < 1.0
        }

        /// True if this transfer appears stalled (no progress update in 2+ minutes).
        /// Shown as a visual warning in the UI before the 5-minute hard timeout kicks in.
        var isStalled: Bool {
            guard let lastUpdate = lastProgressUpdateTime else { return false }
            return Date().timeIntervalSince(lastUpdate) > 120
        }

        /// Human-readable chunk progress (e.g., "2 of 3 parts received")
        var chunkProgressText: String? {
            guard let received = chunksReceived else { return nil }
            if let total = totalExpectedChunks {
                return "\(received) of \(total) parts received"
            } else {
                return "\(received) part(s) received"
            }
        }

        /// Total recording duration from chunk metadata (shows accumulated duration, not per-chunk)
        var totalRecordingDuration: TimeInterval? {
            return metadata?.chunkInfo?.totalDurationSoFar ?? metadata?.duration
        }

        init(id: UUID, metadata: RecordingTransferMetadata? = nil, state: WatchConnectivityManager.IncomingTransferState, uploadId: UUID? = nil, uploadProgress: Double? = nil, lastProgressUpdateTime: Date = Date()) {
            self.id = id
            self.metadata = metadata
            self.state = state
            self.uploadId = uploadId
            self.uploadProgress = uploadProgress
            self.lastProgressUpdateTime = lastProgressUpdateTime
            // Extract progress from state
            switch state {
            case .pending:
                self.progress = nil // Indeterminate
            case .receiving(let progress):
                self.progress = progress // Use progress from watch if available
            case .completed:
                self.progress = 1.0 // 100%
            case .failed:
                self.progress = nil // No progress on failure
            }
        }
    }

    // MARK: - Private Properties

    private let connectivityManager = WatchConnectivityManager.shared
    private var repository: LocalRecordingRepository?
    private var locationManager: LocationManager?
    private var createMeetingFromAudioUseCase: CreateMeetingFromAudioUseCase?
    private var metadataRepository: RecordingMetadataRepository?
    private let notificationService = NotificationService.shared
    private let liveActivityManager = TransferLiveActivityManager.shared
    private let recordingLiveActivityManager = RecordingLiveActivityManager.shared
    private var cancellables = Set<AnyCancellable>()

    /// True when we already showed "recording started" for the current session (avoid duplicate notifications).
    private var didNotifyRecordingStartedThisSession = false

    /// Queue of recording IDs that have been successfully saved (pending confirmation to watch)
    private var pendingConfirmations: [UUID] = []

    /// Flag to track if we've already checked for pending files on this launch
    private var hasCheckedPendingFiles: Bool = false

    /// Whether automatic upload and meeting creation is enabled
    private var autoUploadEnabled: Bool = true

    /// Tracks which recordings already triggered a completion notification to avoid duplicates
    private var notifiedRecordingIds: Set<UUID> = []

    /// Mapping from upload ID to recording ID for tracking upload progress
    private var uploadIdToRecordingId: [UUID: UUID] = [:]

    /// Cancellable for observing upload progress
    private var uploadProgressCancellable: AnyCancellable?

    /// Dispatch queue for thread-safe notification idempotency checks
    private let notificationQueue = DispatchQueue(label: "com.memorable.watchRecordingService.notificationIds")

    /// Core Data repository tracking the full incoming-transfer lifecycle.
    /// Replaces the old in-memory `processedChunkKeys` set with persisted dedup
    /// and gives `ChunkAssemblyManager` a durable chunk inventory.
    private var watchTransferRepository: WatchTransferRepository?

    /// Lightweight in-memory dedup for the window between init and configure(),
    /// when watchTransferRepository is still nil. WCM fires both a callback and a
    /// notification for each file, so without this the same file could be processed
    /// twice before Core Data dedup is available.
    private var preConfigureDeliveryKeys: Set<String> = []

    /// Tracks last sent upload progress percentage per recording to avoid missing intermediate values
    private var lastSentUploadProgress: [UUID: Int] = [:]

    /// Timer that periodically checks for transfers stuck without progress updates
    private var stallCheckTimer: Timer?

    /// Shared timeout policy (3 minutes per 30 minutes of recording duration).
    private let transferTimeoutPolicy = TransferTimeoutPolicy.default

    /// Local notification sender for timeout failures.
    private let transferFailureNotificationService = TransferFailureNotificationService.shared

    // NOTE: UIBackgroundTask management was removed in favor of BackgroundUploadManager
    // which uses a background URLSession that survives app termination.
    // If an upload is interrupted, RecordingRetryService picks it up on next launch.

    // MARK: - Logging

    private let logPrefix = "📱🎙️ [WatchRecordingService]"
    private let logger = LoggerFactory.makeLogger()

    // MARK: - Initialization

    private init() {
        setupRepository()
        setupRecordingReceptionCallback()
        setupActivationStateObserver()
        setupIncomingTransferObserver()
        setupUploadProgressObserver()
        setupRecordingOnWatchObserver()
        setupTransferCoordinationObservers()
        setupStallDetectionTimer()
        // Log Live Activities diagnostics
        liveActivityManager.printDiagnostics()

    }

    /// Sets up observer for upload progress updates.
    /// Throttled to avoid flooding ActivityKit with updates (it rate-limits at ~1/sec).
    private func setupUploadProgressObserver() {
        uploadProgressCancellable = UploadManager.shared.$activeUploads
            .throttle(for: .seconds(1.0), scheduler: DispatchQueue.main, latest: true)
            .receive(on: DispatchQueue.main)
            .sink { [weak self] uploads in
                guard let self = self else { return }


                for (uploadId, uploadProgress) in uploads {
                    log("   Upload \(uploadId): \(Int(uploadProgress.progress * 100))% - \(uploadProgress.status)")

                    guard let recordingId = self.uploadIdToRecordingId[uploadId] else {
                        log("   ⚠️ No recording mapped to upload ID: \(uploadId)")
                        continue
                    }

                    log("   ✅ Linked to recording: \(recordingId)")

                    if var transfer = self.incomingTransfers[recordingId] {
                        transfer.uploadId = uploadId
                        transfer.uploadProgress = uploadProgress.progress
                        self.incomingTransfers[recordingId] = transfer
                        log("   ✅ Updated transfer info with progress: \(Int(uploadProgress.progress * 100))%")

                        self.updateLiveActivityForTransfer(
                            recordingId: recordingId,
                            transferInfo: transfer
                        )
                    } else {
                        // Transfer was dropped (e.g., incoming transfer observer rebuilt the dict
                        // before upload progress was set). Re-create so cloud upload stays visible.
                        log("   ⚠️ Re-creating transfer for recording: \(recordingId)")
                        let metadata = self.connectivityManager.getTransferMetadata(for: recordingId)
                        let recreated = IncomingTransferInfo(
                            id: recordingId,
                            metadata: metadata,
                            state: .completed,
                            uploadId: uploadId,
                            uploadProgress: uploadProgress.progress
                        )
                        self.incomingTransfers[recordingId] = recreated

                        self.updateLiveActivityForTransfer(
                            recordingId: recordingId,
                            transferInfo: recreated
                        )
                        log("   ✅ Re-created transfer with upload progress: \(Int(uploadProgress.progress * 100))%")
                    }

                    // Sync upload progress to watch (throttle to every 10%)
                    let progress = uploadProgress.progress
                    let progressPercent = Int(progress * 100)
                    let lastSent = self.lastSentUploadProgress[recordingId] ?? -1

                    if progressPercent >= lastSent + 10 || progress >= 1.0 {
                        WatchStatusSync().sendStatusToWatch(
                            recordingId: recordingId,
                            status: .uploading,
                            uploadProgress: progress
                        )
                        self.lastSentUploadProgress[recordingId] = progressPercent
                        log("   📤 Sent progress update to watch: \(progressPercent)%")

                        if progress >= 1.0 {
                            log("   ✅ Upload reached 100% for recording: \(recordingId)")
                        }
                    }
                }
            }
    }

    // MARK: - Configuration

    /// Configures dependencies for automatic upload and meeting creation.
    /// Call this after AppContainer is set up.
    /// - Parameters:
    ///   - locationManager: The LocationManager for getting location data
    ///   - createMeetingFromAudioUseCase: The use case for creating meetings from audio files
    ///   - metadataRepository: The repository for recording metadata persistence
    func configure(
        locationManager: LocationManager,
        createMeetingFromAudioUseCase: CreateMeetingFromAudioUseCase,
        metadataRepository: RecordingMetadataRepository,
        watchTransferRepository: WatchTransferRepository
    ) {

        self.locationManager = locationManager
        self.createMeetingFromAudioUseCase = createMeetingFromAudioUseCase
        self.metadataRepository = metadataRepository
        self.watchTransferRepository = watchTransferRepository

        // Clear pre-configure fallback dedup cache once durable Core Data dedup is ready.
        // Keeping these keys beyond startup can incorrectly block legitimate retries.
        preConfigureDeliveryKeys.removeAll()

        // Share the repository with the chunk assembly manager
        ChunkAssemblyManager.shared.setWatchTransferRepository(watchTransferRepository)

        // Configure chunk assembly manager to route merged recordings into the upload pipeline.
        // IMPORTANT: callback must be set BEFORE processRestoredAssemblies() to avoid
        // merged files being produced but never handed off to the upload pipeline.
        setupChunkAssemblyCallback()

        // Now that the callback is wired, process any assemblies that were complete before app kill
        ChunkAssemblyManager.shared.processRestoredAssemblies()

        // Clean up completed transfers older than 24 hours
        try? watchTransferRepository.deleteCompleted(olderThan: Date().addingTimeInterval(-86400))
    }

    // MARK: - Chunk Assembly Integration

    /// Sets up the callback for when ChunkAssemblyManager finishes merging a recording.
    /// The merged file is treated like a single-file recording from this point forward:
    /// saved to permanent storage, metadata updated, and uploaded.
    private func setupChunkAssemblyCallback() {
        ChunkAssemblyManager.shared.onRecordingAssembled = { [weak self] parentRecordingId, mergedFileURL, totalDuration, recordingStartTime in
            guard let self = self else { return }

            self.logger.info("[WatchRecordingService] Assembled recording ready: \(parentRecordingId)")
            self.logger.info("[WatchRecordingService] Merged file: \(mergedFileURL.path), duration: \(totalDuration)s")

            // Build metadata for the assembled recording
            let assembledMetadata = RecordingTransferMetadata(
                id: parentRecordingId,
                filename: mergedFileURL.lastPathComponent,
                duration: totalDuration,
                createdAt: Date(),
                startTime: recordingStartTime ?? Date()
            )

            // Process like a single-file recording (save, upload, confirm)
            self.handleAssembledRecording(fileURL: mergedFileURL, metadata: assembledMetadata)
        }

        logger.info("[WatchRecordingService] ChunkAssemblyManager callback configured")
    }

    /// Handles a fully assembled (merged) recording from the chunk pipeline.
    /// This mirrors the single-file flow: save to permanent storage, upload, confirm.
    /// - Parameters:
    ///   - fileURL: The merged file URL
    ///   - metadata: Metadata for the assembled recording
    private func handleAssembledRecording(fileURL: URL, metadata: RecordingTransferMetadata) {
        log("═══════════════════════════════════════════════════")
        log("📥 ASSEMBLED RECORDING READY FOR UPLOAD")
        log("═══════════════════════════════════════════════════")
        log("Recording ID: \(metadata.id)")
        log("Duration: \(String(format: "%.2f", metadata.duration))s")

        guard let repository = repository else {
            logError("❌ Repository not initialized for assembled recording!", error: nil)
            return
        }

        do {
            // Save to permanent storage (same as single-file flow)
            let savedRecording = try repository.saveRecordingFromWatch(
                sourceURL: fileURL,
                id: metadata.id,
                filename: metadata.filename,
                duration: metadata.duration,
                createdAt: metadata.createdAt,
                startTime: metadata.startTime
            )

            // Create/update metadata
            if let metadataRepo = metadataRepository {
                do {
                    if try metadataRepo.fetchById(metadata.id) == nil {
                        _ = try metadataRepo.create(recordingId: metadata.id, filePath: savedRecording.fileURL.path)
                    }
                    try metadataRepo.updateFilePath(metadata.id, filePath: savedRecording.fileURL.path)
                    try metadataRepo.updateStatus(metadata.id, status: .received, error: nil)
                    try? repository.updateStatus(metadata.id, status: .received, error: nil)
                } catch {
                    logError("⚠️ Failed to update metadata for assembled recording", error: error)
                }
            }

            recordingsReceivedCount += 1
            lastReceivedRecording = savedRecording

            // Mark the chunked transfer as completed in the connectivity manager.
            // Without this, the observer in setupIncomingTransferObserver() would overwrite
            // our local .completed state back to .receiving (since WCM never transitions
            // chunked transfers to .completed on its own).
            connectivityManager.markIncomingTransferCompleted(recordingId: metadata.id)

            // Update transfer info to completed.
            // Set uploadProgress to 0.0 so the incoming-transfer observer's merge logic
            // keeps this entry alive while the cloud upload is pending.
            let completedTransfer = IncomingTransferInfo(
                id: metadata.id,
                metadata: metadata,
                state: .completed,
                uploadId: nil,
                uploadProgress: 0.0
            )
            incomingTransfers[metadata.id] = completedTransfer

            // Mark WatchTransfer as completed in Core Data
            if let repo = watchTransferRepository {
                try? repo.markCompleted(metadata.id)
            }

            // Send confirmation to watch (for the ENTIRE recording, not per-chunk)
            // The Watch will only delete its local chunks after this full-recording confirmation
            pendingConfirmations.append(metadata.id)
            sendConfirmationToWatch()

            // Upload and create meeting
            uploadAndCreateMeeting(recording: savedRecording)

            log("✅ ASSEMBLED RECORDING PROCESSED SUCCESSFULLY")

            // Clean up chunk assembly data (chunks files on disk)
            ChunkAssemblyManager.shared.cleanupAssembly(for: metadata.id)

            // Auto-remove the transfer card from UI after a brief display period.
            // The transfer itself is complete (confirmed to Watch). The ongoing upload
            // status is tracked via RecordingMetadata in the recordings list.
            let assembledId = metadata.id
            DispatchQueue.main.asyncAfter(deadline: .now() + 3.0) { [weak self] in
                guard let self = self else { return }
                if let transfer = self.incomingTransfers[assembledId],
                   case .completed = transfer.state {
                    self.incomingTransfers.removeValue(forKey: assembledId)
                    self.connectivityManager.removeIncomingTransfer(recordingId: assembledId)
                    self.log("🧹 Auto-removed assembled transfer from UI: \(assembledId)")
                }
            }

        } catch {
            logError("❌ Failed to save assembled recording", error: error)
        }
    }

    /// Enables or disables automatic upload and meeting creation of received recordings
    /// - Parameter enabled: Whether to automatically upload recordings
    func setAutoUpload(enabled: Bool) {
        autoUploadEnabled = enabled
        log("Auto-upload \(enabled ? "enabled" : "disabled")")
    }

    // MARK: - Transcription Observers

    // MARK: - Logging Helper

    /// Logs a message with timestamp and prefix
    private func log(_ message: String, level: LogLevel = .info) {
        let fullMessage = "\(logPrefix) \(message)"
        switch level {
        case .debug:
            logger.debug(fullMessage)
        case .info:
            logger.info(fullMessage)
        case .warning:
            logger.warning(fullMessage)
        case .error:
            logger.error(fullMessage, error: nil)
        case .fatal:
            logger.fatal(fullMessage, error: nil)
        }
    }

    /// Logs an error with context
    private func logError(_ message: String, error: Error?) {
        logger.error("\(logPrefix) \(message)", error: error)
    }

    // MARK: - Pending Files Handling

    /// Sets up observer for WCSession activation state to check for pending files
    private func setupActivationStateObserver() {
        log("Setting up activation state observer...")

        // Listen for activation state changes to check for pending files
        connectivityManager.$activationState
            .receive(on: DispatchQueue.main)
            .sink { [weak self] state in
                guard let self = self else { return }

                self.log("WCSession activation state changed: \(state.rawValue)")

                if state == .activated && !self.hasCheckedPendingFiles {
                    self.hasCheckedPendingFiles = true
                    self.log("Session activated - checking for pending files in 1 second...")
                    // Give a brief delay for any pending delegate calls to come through
                    DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) {
                        self.checkForPendingReceivedFiles()
                    }
                }
            }
            .store(in: &cancellables)
    }

    /// Checks for any files that were received while the app was terminated.
    /// WCSession delivers pending files through the delegate after activation,
    /// but we also check the hasContentPending flag for awareness.
    /// Call this on app launch after WCSession is activated.
    func checkForPendingReceivedFiles() {
        log("═══════════════════════════════════════════════════")
        log("CHECKING FOR PENDING RECEIVED FILES")
        log("═══════════════════════════════════════════════════")

        guard WCSession.isSupported() else {
            log("⚠️ WCSession not supported on this device")
            return
        }

        let session = WCSession.default

        guard session.activationState == .activated else {
            log("⏳ WCSession not activated yet - will check later")
            return
        }

        // Check if there's pending content (files received while app was terminated)
        // Note: hasContentPending is true if there are transfers/messages waiting
        #if os(iOS)
        let hasContentPending = session.hasContentPending
        log("Has content pending: \(hasContentPending)")

        self.hasPendingFiles = hasContentPending

        if hasContentPending {
            log("📥 Pending content detected - delegate methods will deliver files")
            log("Waiting for WCSession delegate callbacks...")
        } else {
            log("✓ No pending files to process")
        }
        #endif

        log("═══════════════════════════════════════════════════")
    }

    /// Forces a re-check for pending files. Call this if you suspect files were missed.
    func forceCheckPendingFiles() {
        log("Force re-checking for pending files...")
        hasCheckedPendingFiles = false
        checkForPendingReceivedFiles()
        hasCheckedPendingFiles = true
    }

    // MARK: - Setup

    /// Initializes the local recording repository for storing received files
    private func setupRepository() {
        log("Setting up local recording repository...")
        do {
            let coreDataStack = AppContainer.shared.makeCoreDataStack()
            let repository = try LocalRecordingRepository(context: coreDataStack.viewContext)
            self.repository = repository

            log("✅ Repository initialized successfully")
            log("Storage directory: \(repository.directoryURL.path)")
        } catch {
            logError("❌ Failed to initialize repository: \(error.localizedDescription)", error: error)
        }
    }

    /// Sets up the callback on WatchConnectivityManager for receiving recording files
    private func setupRecordingReceptionCallback() {
        logger.debug("🔵 [WatchRecordingService] Setting up recording reception callback...")
        log("Setting up recording reception callback...")

        // Set up the callback for when files are received
        connectivityManager.onRecordingReceived = { [weak self] result in
            Task { @MainActor in
                switch result {
                case .success((let fileURL, let metadata)):
                    self?.logger.info("[WatchRecordingService] onRecordingReceived — file: \(fileURL.lastPathComponent), recordingId: \(metadata.id), isChunked: \(metadata.isChunked)")
                    self?.handleReceivedRecording(fileURL: fileURL, metadata: metadata)
                case .failure(let error):
                    self?.logger.error("[WatchRecordingService] onRecordingReceived failed: \(error.localizedDescription)", error: error)
                    self?.isProcessingTransfer = false
                }
            }
        }

        logger.info("[WatchRecordingService] Recording reception callback registered")

        // Also listen for the notification-based approach
        NotificationCenter.default.publisher(for: .recordingDidReceiveFromWatch)
            .receive(on: DispatchQueue.main)
            .sink { [weak self] notification in
                guard let fileURL = notification.userInfo?["fileURL"] as? URL,
                      let metadata = notification.userInfo?["metadata"] as? RecordingTransferMetadata else {
                    self?.logger.warning("[WatchRecordingService] recordingDidReceiveFromWatch notification missing fileURL or metadata")
                    return
                }
                self?.logger.info("[WatchRecordingService] Received recordingDidReceiveFromWatch notification — recordingId: \(metadata.id)")
                self?.handleReceivedRecording(fileURL: fileURL, metadata: metadata)
            }
            .store(in: &cancellables)

        log("✅ Recording reception callback configured")
    }

    /// Sets up observer for incoming transfer progress from WatchConnectivityManager
    private func setupIncomingTransferObserver() {
        log("Setting up incoming transfer progress observer...")

        // Observe incoming transfer progress changes
        connectivityManager.$incomingTransferProgress
            .receive(on: DispatchQueue.main)
            .sink { [weak self] progressDict in
                guard let self = self else { return }

                // Update our incoming transfers based on connectivity manager state
                var updatedTransfers: [UUID: IncomingTransferInfo] = [:]

                // Filter out placeholder ID (should never appear in UI)
                let placeholderId = WatchConnectivityManager.pendingPlaceholderID

                for (recordingId, state) in progressDict {
                    // Skip placeholder - it should be filtered out
                    if recordingId == placeholderId {
                        continue
                    }

                    // Get existing transfer info if available
                    var transferInfo = self.incomingTransfers[recordingId]

                    // If we don't have metadata yet, try to get it from context
                    var metadata = transferInfo?.metadata
                    if metadata == nil {
                        // Try to get metadata from context (sent by watch when transfer starts)
                        metadata = self.connectivityManager.getTransferMetadata(for: recordingId)
                    }

                    if transferInfo == nil {
                        // NEW TRANSFER DETECTED - Track in-memory only (no DB entry yet)
                        // RecordingMetadata will be created when the actual file is received
                        transferInfo = IncomingTransferInfo(id: recordingId, metadata: metadata, state: state)

                        // Start Live Activity for new transfer
                        if self.liveActivityManager.startActivity(for: recordingId, metadata: metadata) {
                            self.log("✅ Started Live Activity for recording: \(recordingId)")
                        }
                    } else {
                        // Only reset lastProgressUpdateTime if the state actually changed.
                        // This is critical for accurate stall detection — if the publisher
                        // re-emits the same state, we must keep the original timestamp.
                        let stateChanged = transferInfo!.state != state
                        let preservedTimestamp = stateChanged
                            ? Date()
                            : (transferInfo!.lastProgressUpdateTime ?? Date())

                        transferInfo = IncomingTransferInfo(
                            id: recordingId,
                            metadata: metadata ?? transferInfo!.metadata,
                            state: state,
                            uploadId: transferInfo!.uploadId,
                            uploadProgress: transferInfo!.uploadProgress,
                            lastProgressUpdateTime: preservedTimestamp
                        )
                    }

                    updatedTransfers[recordingId] = transferInfo

                    // Update Live Activity with current transfer progress
                    // transferInfo is guaranteed to be non-nil after the if-else block above
                    if let transferInfo = transferInfo {
                        self.updateLiveActivityForTransfer(
                            recordingId: recordingId,
                            transferInfo: transferInfo
                        )
                    }
                }

                // Always update to match the connectivity manager state (removes deleted transfers)
                // But preserve any upload tracking info for transfers not in the update
                let previousCount = self.incomingTransfers.count

                // Preserve transfers that are no longer in the connectivity manager's progress dict
                // but are still relevant (uploading to cloud or waiting for upload to start).
                for (recordingId, existingTransfer) in self.incomingTransfers {
                    guard updatedTransfers[recordingId] == nil else { continue }

                    let shouldPreserve: Bool
                    if case .completed = existingTransfer.state {
                        // Keep completed transfers unless upload is fully done (progress >= 1.0).
                        // This covers: upload pending (nil), upload starting (0.0), upload in-flight (0.x).
                        if let progress = existingTransfer.uploadProgress, progress >= 1.0 {
                            shouldPreserve = false
                        } else {
                            shouldPreserve = true
                        }
                    } else if let uploadProgress = existingTransfer.uploadProgress, uploadProgress < 1.0 {
                        shouldPreserve = true
                    } else {
                        shouldPreserve = false
                    }

                    if shouldPreserve {
                        updatedTransfers[recordingId] = existingTransfer
                    }
                }

                self.incomingTransfers = updatedTransfers
                let newCount = updatedTransfers.count

                if previousCount != newCount {
                    log("📊 Transfer count changed: \(previousCount) -> \(newCount)")
                }

                // Log state changes
                if !updatedTransfers.isEmpty {
                    let transfers = Array(updatedTransfers.values)
                    let pendingCount = transfers.filter { if case .pending = $0.state { return true }; return false }.count
                    let receivingCount = transfers.filter { if case .receiving = $0.state { return true }; return false }.count
                    let completedCount = transfers.filter { if case .completed = $0.state { return true }; return false }.count
                    let failedCount = transfers.filter { if case .failed = $0.state { return true }; return false }.count

                    if pendingCount > 0 || receivingCount > 0 {
                        log("📊 Incoming transfers - Pending: \(pendingCount), Receiving: \(receivingCount), Completed: \(completedCount), Failed: \(failedCount)")
                    }
                } else if previousCount > 0 {
                    log("📊 All transfers cleared from UI")
                }
            }
            .store(in: &cancellables)

        log("✅ Incoming transfer progress observer configured")
    }

    /// Sets up observer for recording-on-Watch indicator (Guideline 2.5.14).
    /// Starts Recording Live Activity and sends local notification when Watch starts recording;
    /// ends Live Activity when Watch stops recording.
    ///
    /// Includes `isRecordingStateFromActivation` in the combine pipeline so that notifications
    /// are only sent when the recording state has been confirmed by fresh context from the Watch
    /// (not from potentially stale cached context read during session activation).
    private func setupRecordingOnWatchObserver() {
        connectivityManager.$isRecordingOnWatch
            .combineLatest(
                connectivityManager.$recordingStartedAt,
                connectivityManager.$isRecordingStateFromActivation
            )
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isRecording, startedAt, isFromActivation in
                guard let self = self else { return }
                log("📡 isRecordingOnWatch=\(isRecording), startedAt=\(String(describing: startedAt)), fromActivation=\(isFromActivation)")
                if isRecording {
                    let started = startedAt ?? Date()
                    if recordingLiveActivityManager.startRecordingActivity(startedAt: started) {
                        log("✅ Started Recording Live Activity (recording on Watch)")
                    } else {
                        log("⚠️ Recording Live Activity did not start — check Settings > Memorable > Live Activities is ON, and iOS 18+")
                    }
                    // Only send notification when the state is confirmed by fresh context.
                    // Activation context may be stale (Watch sent isRecording=false while iPhone was not running),
                    // so we wait for the Watch to re-confirm via a fresh application context update.
                    if isFromActivation {
                        log("⏳ Recording state from activation context — deferring notification until confirmed by Watch")
                    } else if !didNotifyRecordingStartedThisSession {
                        didNotifyRecordingStartedThisSession = true
                        Task {
                            let sent = await self.notificationService.notifyRecordingStartedOnWatch()
                            if !sent {
                                await MainActor.run { self.didNotifyRecordingStartedThisSession = false }
                            }
                        }
                    }
                } else {
                    recordingLiveActivityManager.endRecordingActivity()
                    didNotifyRecordingStartedThisSession = false
                    log("✅ Ended Recording Live Activity (recording stopped on Watch)")
                }
            }
            .store(in: &cancellables)
        log("✅ Recording-on-Watch observer configured")
    }

    // MARK: - Transfer Coordination

    /// Sets up observers for Watch transfer coordination messages:
    /// - Metadata readiness check (Watch sends metadata, iPhone acknowledges)
    /// - Cleanup request (Watch hit complete-fail, iPhone deletes partial data)
    private func setupTransferCoordinationObservers() {
        log("Setting up transfer coordination observers...")

        // Watch is preparing to send chunks — acknowledge readiness
        NotificationCenter.default.publisher(for: .watchPreparingTransfer)
            .receive(on: DispatchQueue.main)
            .sink { [weak self] notification in
                guard let self = self else { return }
                self.handleTransferPreparation(notification: notification)
            }
            .store(in: &cancellables)

        // Watch hit complete-fail — clean up partial chunk data
        NotificationCenter.default.publisher(for: .watchRequestedCleanup)
            .receive(on: DispatchQueue.main)
            .sink { [weak self] notification in
                guard let self = self else { return }
                self.handleCleanupRequest(notification: notification)
            }
            .store(in: &cancellables)

        log("Transfer coordination observers configured")
    }

    /// Handles the Watch's "prepare for transfer" message.
    /// Sends an acknowledgment back so the Watch knows it can start sending chunks.
    /// - Parameter notification: Contains recording metadata (recordingId, totalChunks, etc.)
    private func handleTransferPreparation(notification: Notification) {
        guard let userInfo = notification.userInfo,
              let recordingIdString = userInfo[WatchMessageKey.recordingId] as? String else {
            log("Received prepareForTransfer without recordingId")
            return
        }

        log("Received transfer preparation request for recording: \(recordingIdString)")

        // Send acknowledgment to Watch that we're ready to receive
        let ackMessage: [String: Any] = [
            WatchMessageKey.action: WatchMessageKey.actionTransferAcknowledged,
            WatchMessageKey.recordingId: recordingIdString
        ]

        connectivityManager.sendMessage(ackMessage) { [weak self] error in
            if let error = error {
                self?.logError("Failed to send transfer acknowledgment", error: error)
            } else {
                self?.log("Transfer acknowledgment sent to Watch")
            }
        }
    }

    /// Handles the Watch's "cleanup partials" request.
    /// Deletes all partial chunk data and metadata for a recording that hit complete-fail.
    /// - Parameter notification: Contains the recordingId to clean up
    private func handleCleanupRequest(notification: Notification) {
        guard let userInfo = notification.userInfo,
              let recordingIdString = userInfo[WatchMessageKey.recordingId] as? String,
              let recordingId = UUID(uuidString: recordingIdString) else {
            log("Received cleanup request without valid recordingId")
            return
        }

        log("Cleaning up partial data for recording: \(recordingId)")

        // Clean up chunk assembly data
        ChunkAssemblyManager.shared.cleanupAssembly(for: recordingId)

        // Clean up metadata if it exists
        if let metadataRepo = metadataRepository {
            do {
                if let metadata = try metadataRepo.fetchById(recordingId) {
                    try metadataRepo.delete(recordingId)
                    log("Deleted metadata for recording: \(recordingId)")
                }
            } catch {
                logError("Failed to cleanup metadata for recording: \(recordingId)", error: error)
            }
        }

        // Remove from incoming transfers UI
        incomingTransfers.removeValue(forKey: recordingId)

        log("Cleanup complete for recording: \(recordingId) — Watch will resend all chunks")
    }

    // MARK: - Stall Detection (iPhone-Side)

    /// Starts a repeating timer that checks for transfers stuck without progress updates.
    /// Fires every 60 seconds. Timeout budget is duration-aware via `TransferTimeoutPolicy`
    /// (3 min per 30 min bucket). The Watch has its own parallel stall detection;
    /// this acts as a safety net on the iPhone side.
    private func setupStallDetectionTimer() {
        stallCheckTimer?.invalidate()
        stallCheckTimer = Timer.scheduledTimer(withTimeInterval: 60, repeats: true) { [weak self] _ in
            Task { @MainActor in
                self?.checkForStalledIncomingTransfers()
            }
        }
        log("✅ Stall detection timer started (60s interval, duration-aware timeout)")
    }

    /// Iterates all incoming transfers and fails any that have been stuck for too long.
    /// Also checks Core Data for:
    /// - Orphaned transfers (progress 100% in DB but file never arrived — no RecordingMetadata)
    /// - Chunk assemblies stuck in `.receiving` for > 1 hour.
    private func checkForStalledIncomingTransfers() {
        let now = Date()

        for (recordingId, transfer) in incomingTransfers {
            // Only check active transfers (pending / receiving); skip completed or already-failed
            switch transfer.state {
            case .pending, .receiving:
                break
            case .completed, .failed:
                continue
            }

            guard let lastUpdate = transfer.lastProgressUpdateTime else { continue }

            let elapsed = now.timeIntervalSince(lastUpdate)
            let timeout = transferTimeoutPolicy.timeout(forRecordingDuration: transfer.totalRecordingDuration)
            guard elapsed >= timeout else { continue }

            let elapsedMinutes = Int(elapsed / 60)
            log("⏰ Transfer \(recordingId) stalled — no progress for \(elapsedMinutes) min. Marking as failed.")
            handleStalledIncomingTransfer(recordingId: recordingId)
        }

        // Orphaned transfer check: DB shows receiving with old updatedAt but no RecordingMetadata.
        // File was never saved (e.g. progress reached 100% via context but didReceive file never fired).
        if let repo = watchTransferRepository, let metadataRepo = metadataRepository {
            if let active = try? repo.fetchActive() {
                for transfer in active {
                    guard let recordingId = transfer.id else { continue }
                    guard transfer.statusEnum == .receiving else { continue }
                    let timeout = transferTimeoutPolicy.timeout(forRecordingDuration: transfer.duration)
                    let staleCutoff = now.addingTimeInterval(-timeout)
                    guard (transfer.updatedAt ?? transfer.createdAt ?? now) < staleCutoff else { continue }
                    // No RecordingMetadata means file was never received and saved.
                    guard (try? metadataRepo.fetchById(recordingId)) == nil else { continue }
                    let orphanError = "Transfer stalled at 100% — file never arrived. Tap Retry to resend."
                    log("⏰ Orphaned transfer detected: \(recordingId) — \(orphanError)")
                    handleStalledIncomingTransfer(recordingId: recordingId, customError: orphanError)
                }
            }
        }

        // Stale assembly timeout: chunk assemblies stuck in `.receiving` for > 1 hour.
        if let repo = watchTransferRepository {
            let oneHourAgo = now.addingTimeInterval(-3600)
            if let staleAssemblies = try? repo.fetchStaleAssemblies(olderThan: oneHourAgo) {
                for transfer in staleAssemblies {
                    guard let recordingId = transfer.id else { continue }
                    log("⏰ Stale chunk assembly detected: \(recordingId) — no chunk for > 1 hour. Timing out.")
                    try? repo.markTimedOut(recordingId)
                    handleStalledIncomingTransfer(recordingId: recordingId)
                }
            }
        }
    }

    /// Handles a single stalled incoming transfer:
    /// 1. Marks it as failed in both WatchRecordingService and WatchConnectivityManager
    /// 2. Cleans up partial chunk assembly data
    /// 3. Ends the associated Live Activity
    /// 4. Keeps failed row visible for manual retry/dismiss
    /// - Parameters:
    ///   - recordingId: The UUID of the stalled recording
    ///   - customError: Optional custom error message (e.g. for orphaned "100% but file never arrived" case)
    private func handleStalledIncomingTransfer(recordingId: UUID, customError: String? = nil) {
        let timeoutSeconds = transferTimeoutSeconds(for: recordingId)
        let timeoutMinutes = Int(timeoutSeconds / 60)
        let errorMessage = customError ?? "Transfer timed out — no progress for \(timeoutMinutes) minutes. Retry will start from scratch."

        // 0. Persist failure in Core Data
        if let repo = watchTransferRepository {
            try? repo.markFailed(recordingId, error: errorMessage)
        }

        // 1. Mark as failed in WatchConnectivityManager so the observer doesn't overwrite us
        connectivityManager.markIncomingTransferTimedOut(
            recordingId: recordingId,
            error: errorMessage
        )

        // 2. Update our local transfer info
        let existing = incomingTransfers[recordingId]
        let failedTransfer = IncomingTransferInfo(
            id: recordingId,
            metadata: existing?.metadata,
            state: .failed(errorMessage),
            uploadId: existing?.uploadId,
            uploadProgress: existing?.uploadProgress
        )
        incomingTransfers[recordingId] = failedTransfer

        // 3. Timeouts must retry from scratch, so remove all partial assembly state.
        ChunkAssemblyManager.shared.cleanupAssembly(for: recordingId)

        // 4. End Live Activity with failure
        liveActivityManager.endActivity(
            recordingId: recordingId,
            success: false,
            errorMessage: errorMessage
        )

        Task { @MainActor [weak self] in
            await self?.transferFailureNotificationService.notifyTransferFailed(recordingId: recordingId)
        }

        logError("❌ Transfer timed out for recording: \(recordingId)", error: nil)

        // 5. Keep failed row visible so user can inspect details and retry.
    }

    private func transferTimeoutSeconds(for recordingId: UUID) -> TimeInterval {
        if let transfer = incomingTransfers[recordingId] {
            return transferTimeoutPolicy.timeout(forRecordingDuration: transfer.totalRecordingDuration)
        }
        if let repo = watchTransferRepository,
           let transfer = try? repo.fetchById(recordingId) {
            return transferTimeoutPolicy.timeout(forRecordingDuration: transfer.duration)
        }
        return transferTimeoutPolicy.timeout(forRecordingDuration: nil)
    }

    /// Prepares local iPhone state so manual retry from Watch starts from scratch.
    /// Clears partial chunk assembly and resets incoming transfer progress guards.
    func prepareManualRetryFromScratch(recordingId: UUID) {
        ChunkAssemblyManager.shared.cleanupAssembly(for: recordingId)
        connectivityManager.prepareIncomingTransferRetry(recordingId: recordingId)
        log("Prepared manual retry from scratch for recording: \(recordingId)")
    }

    // MARK: - Recording Reception

    /// Handles a recording file received from the Apple Watch.
    ///
    /// If the transfer contains chunk info, the file is routed to `ChunkAssemblyManager`
    /// for progressive assembly. Otherwise, it follows the existing single-file flow.
    ///
    /// Flow (single-file): Receive → Save → Upload → Confirm
    /// Flow (chunked):     Receive → AssemblyManager → (all chunks) → Merge → Upload → Confirm
    ///
    /// - Parameters:
    ///   - fileURL: The temporary URL where the transferred file is located
    ///   - metadata: The recording metadata from the watch
    private func handleReceivedRecording(fileURL: URL, metadata: RecordingTransferMetadata) {
        logger.info("[WatchRecordingService] Receiving recording from Watch — id: \(metadata.id), filename: \(metadata.filename), duration: \(String(format: "%.2f", metadata.duration))s, isChunked: \(metadata.isChunked)")

        // ========================================
        // DUPLICATE DELIVERY GUARD
        // WatchConnectivityManager fires both `onRecordingReceived` callback AND
        // `.recordingDidReceiveFromWatch` notification for the same incoming file.
        // Primary: Core Data-based dedup (survives app restarts).
        // Fallback: in-memory Set for the window before configure() is called.
        // ========================================
        let deliveryKey: String = metadata.chunkInfo.map {
            "\($0.parentRecordingId)-chunk\($0.chunkIndex)"
        } ?? metadata.id.uuidString

        if let chunkInfo = metadata.chunkInfo {
            if let repo = watchTransferRepository,
               (try? repo.hasReceivedChunk(recordingId: chunkInfo.parentRecordingId, chunkIndex: chunkInfo.chunkIndex)) == true {
                logger.info("[WatchRecordingService] ⏭️ Skipping duplicate chunk delivery: \(deliveryKey)")
                return
            }
        } else {
            if let repo = watchTransferRepository,
               let existing = try? repo.fetchById(metadata.id),
               existing.statusEnum == .completed || existing.statusEnum == .assembled {
                logger.info("[WatchRecordingService] ⏭️ Skipping duplicate single-file delivery: \(metadata.id)")
                return
            }
        }

        // In-memory fallback dedup is ONLY for the pre-configure window (repo is nil).
        // Once watchTransferRepository is available, durable Core Data dedup is used instead.
        if watchTransferRepository == nil {
            guard preConfigureDeliveryKeys.insert(deliveryKey).inserted else {
                logger.info("[WatchRecordingService] ⏭️ Skipping duplicate delivery (in-memory guard): \(deliveryKey)")
                return
            }
        }

        // ========================================
        // ALREADY-PROCESSED GUARD
        // Prevent re-processing recordings that already have a meeting created.
        // This can happen when the Watch retries after an app kill, but the iPhone
        // had already processed and uploaded the recording before the kill.
        // ========================================
        let guardRecordingId = metadata.chunkInfo?.parentRecordingId ?? metadata.id
        if let metadataRepo = metadataRepository,
           let existingMetadata = try? metadataRepo.fetchById(guardRecordingId),
           existingMetadata.meetingId != nil {
            logger.info("[WatchRecordingService] ⏭️ Recording \(guardRecordingId) already has a meeting (id: \(existingMetadata.meetingId?.uuidString ?? "?")) — skipping re-processing")
            // Re-send confirmation to Watch so it can update its status
            if !pendingConfirmations.contains(guardRecordingId) {
                pendingConfirmations.append(guardRecordingId)
                sendConfirmationToWatch()
            }
            return
        }

        // ========================================
        // CHUNK ROUTING
        // If the transfer contains chunk info, route it to the assembly pipeline
        // instead of processing it as a single complete recording.
        // ========================================
        if let chunkInfo = metadata.chunkInfo {
            let parentId = chunkInfo.parentRecordingId
            logger.info("[WatchRecordingService] Routing chunk \(chunkInfo.chunkIndex) to ChunkAssemblyManager — parentId: \(parentId), isLast: \(chunkInfo.isLastChunk), chunkDuration: \(chunkInfo.chunkDuration)s")

            // Route to assembly manager first so its state is up-to-date
            ChunkAssemblyManager.shared.chunkReceived(fileURL: fileURL, metadata: metadata)

            // Persist chunk arrival in Core Data (creates transfer row on first chunk)
            if let repo = watchTransferRepository {
                do {
                    let _ = try repo.createOrUpdate(
                        recordingId: parentId,
                        isChunked: true,
                        filename: metadata.filename,
                        duration: chunkInfo.totalDurationSoFar,
                        startTime: metadata.startTime,
                        status: .receiving
                    )
                    try repo.addChunkIndex(
                        recordingId: parentId,
                        chunkIndex: chunkInfo.chunkIndex,
                        isLastChunk: chunkInfo.isLastChunk,
                        totalExpectedChunks: chunkInfo.isLastChunk ? (chunkInfo.chunkIndex + 1) : nil
                    )
                } catch {
                    logger.error("[WatchRecordingService] Failed to persist chunk arrival: \(error)")
                }
            }

            // Compute actual chunk progress from assembly state
            let assemblyState = ChunkAssemblyManager.shared.getAssemblyState(for: parentId)
            let (chunksReceived, totalExpected): (Int, Int?) = {
                if case .receiving(let count, let total) = assemblyState {
                    return (count, total)
                }
                return (chunkInfo.chunkIndex + 1, nil)
            }()

            // Calculate real progress: chunksReceived / totalExpected (or estimate)
            let chunkProgress: Double? = {
                if let total = totalExpected, total > 0 {
                    return Double(chunksReceived) / Double(total)
                }
                return nil
            }()

            var transferInfo = IncomingTransferInfo(
                id: parentId,
                metadata: metadata,
                state: .receiving(progress: chunkProgress),
                uploadId: nil,
                uploadProgress: nil
            )
            transferInfo.chunksReceived = chunksReceived
            transferInfo.totalExpectedChunks = totalExpected
            incomingTransfers[parentId] = transferInfo

            // Start Live Activity if not already active
            if !liveActivityManager.hasActivity(for: parentId) {
                liveActivityManager.startActivity(for: parentId, metadata: metadata)
            }

            // Push chunk progress to Live Activity
            updateLiveActivityForTransfer(recordingId: parentId, transferInfo: transferInfo)

            // Persist progress in Core Data
            if let repo = watchTransferRepository, let p = chunkProgress {
                try? repo.updateProgress(parentId, progress: p)
            }

            logger.info("[WatchRecordingService] Chunk \(chunkInfo.chunkIndex) processed — progress: \(chunksReceived)/\(totalExpected.map { String($0) } ?? "?"), totalDurationSoFar: \(chunkInfo.totalDurationSoFar)s")

            return
        }
        // ========================================
        // CHUNK ROUTING -- END (single-file flow below)
        // ========================================

        log("═══════════════════════════════════════════════════")
        log("📥 RECEIVING RECORDING FROM WATCH")
        log("═══════════════════════════════════════════════════")
        log("Recording ID: \(metadata.id)")
        log("Filename: \(metadata.filename)")
        log("Duration: \(String(format: "%.2f", metadata.duration))s")
        log("Created: \(metadata.createdAt)")
        log("Temp File: \(fileURL.path)")

        isProcessingTransfer = true

        // Persist single-file transfer in Core Data
        if let repo = watchTransferRepository {
            do {
                let _ = try repo.createOrUpdate(
                    recordingId: metadata.id,
                    isChunked: false,
                    filename: metadata.filename,
                    duration: metadata.duration,
                    startTime: metadata.startTime,
                    status: .receiving
                )
                try repo.updateProgress(metadata.id, progress: 1.0)
            } catch {
                logger.error("[WatchRecordingService] Failed to persist single-file transfer: \(error)")
            }
        }

        // Verify the temporary file exists
        guard FileManager.default.fileExists(atPath: fileURL.path) else {
            logError("❌ ERROR: Temporary file does not existt! Path: \(fileURL.path)", error: nil)
            isProcessingTransfer = false
            return
        }

        // Log file size
        if let attrs = try? FileManager.default.attributesOfItem(atPath: fileURL.path),
           let size = attrs[.size] as? Int64 {
            log("📦 File size: \(ByteCountFormatter.string(fromByteCount: size, countStyle: .file))")
        }

        guard let repository = repository else {
            logError("❌ ERROR: Repository not initialized!", error: nil)
            log("⚠️ Transfer dropped because repository is nil. Check setupRepository() initialization.")
            isProcessingTransfer = false
            return
        }

        // Save the recording to permanent storage
        do {
            log("💾 Saving recording to permanent storage...")

            // Create RecordingMetadata if it doesn't exist
            // Metadata is only created when the actual file is received (not on progress updates)
            if let metadataRepo = metadataRepository {
                do {
                    if try metadataRepo.fetchById(metadata.id) == nil {
                        // Create new metadata - will be updated with actual file path after save
                        _ = try metadataRepo.create(recordingId: metadata.id, filePath: "receiving")
                        log("📊 Recording metadata created for new recording")
                    } else {
                        log("📊 Recording metadata already exists (retry scenario)")
                    }
                } catch {
                    logError("⚠️ Failed to create metadata", error: error)
                }
            }

            // Update transfer info with metadata (preserve upload tracking if present)
            if var transferInfo = incomingTransfers[metadata.id] {
                transferInfo = IncomingTransferInfo(
                    id: metadata.id,
                    metadata: metadata,
                    state: transferInfo.state,
                    uploadId: transferInfo.uploadId,
                    uploadProgress: transferInfo.uploadProgress
                )
                incomingTransfers[metadata.id] = transferInfo
            }

            let savedRecording = try repository.saveRecordingFromWatch(
                sourceURL: fileURL,
                id: metadata.id,
                filename: metadata.filename,
                duration: metadata.duration,
                createdAt: metadata.createdAt,
                startTime: metadata.startTime
            )

            log("✅ Recording saved successfully!")
            log("📍 Saved to: \(savedRecording.fileURL.path)")

            // Update metadata status to received and set actual file path
            if let metadataRepo = metadataRepository {
                do {
                    try metadataRepo.updateFilePath(metadata.id, filePath: savedRecording.fileURL.path)
                    try metadataRepo.updateStatus(metadata.id, status: .received, error: nil)
                    try? repository.updateStatus(metadata.id, status: .received, error: nil)
                    log("📊 Recording metadata updated to received status with file path")

                    // Sync status to watch
                    WatchStatusSync().sendStatusToWatch(recordingId: metadata.id, status: .received)
                } catch {
                    logError("⚠️ Failed to update metadata status", error: error)
                }
            }

            recordingsReceivedCount += 1
            lastReceivedRecording = savedRecording
            isProcessingTransfer = false

            // Update transfer info to completed (preserve upload tracking if present).
            // Set uploadProgress to 0.0 so the incoming-transfer observer's merge logic
            // keeps this entry alive while the cloud upload is pending.
            let existingTransfer = incomingTransfers[metadata.id]
            let completedTransfer = IncomingTransferInfo(
                id: metadata.id,
                metadata: metadata,
                state: .completed,
                uploadId: existingTransfer?.uploadId,
                uploadProgress: existingTransfer?.uploadProgress ?? 0.0
            )
            incomingTransfers[metadata.id] = completedTransfer

            // Update Live Activity - transfer complete, transition to upload stage
            updateLiveActivityForTransfer(
                recordingId: metadata.id,
                transferInfo: completedTransfer
            )

            // Mark WatchTransfer as completed in Core Data
            if let repo = watchTransferRepository {
                try? repo.markCompleted(metadata.id)
            }

            // Add to pending confirmations and send confirmation to watch
            pendingConfirmations.append(metadata.id)
            sendConfirmationToWatch()

            // Post notification that a new recording was received
            NotificationCenter.default.post(
                name: .newRecordingReceivedFromWatch,
                object: nil,
                userInfo: ["recording": savedRecording]
            )

            logger.debug("🔵 [WatchRecordingService] ✅ File saved successfully, calling uploadAndCreateMeeting...")
            logger.debug("🔵 [WatchRecordingService] Saved file path: \(savedRecording.fileURL.path)")

            // Upload and create meeting (if enabled)
            uploadAndCreateMeeting(recording: savedRecording)

            logger.debug("🔵 [WatchRecordingService] uploadAndCreateMeeting called, returning from handleReceivedRecording")

            // Auto-remove the transfer card from UI after a brief display period.
            // The transfer is complete (confirmed to Watch). Upload status is tracked
            // via RecordingMetadata in the recordings list.
            let singleFileId = metadata.id
            DispatchQueue.main.asyncAfter(deadline: .now() + 3.0) { [weak self] in
                guard let self = self else { return }
                if let transfer = self.incomingTransfers[singleFileId],
                   case .completed = transfer.state {
                    self.incomingTransfers.removeValue(forKey: singleFileId)
                    self.connectivityManager.removeIncomingTransfer(recordingId: singleFileId)
                    self.log("🧹 Auto-removed single-file transfer from UI: \(singleFileId)")
                }
            }

            log("═══════════════════════════════════════════════════")
            log("✅ RECORDING RECEPTION COMPLETE")
            log("═══════════════════════════════════════════════════")

        } catch {
            logError("❌ ERROR: Failed to save recording: \(error.localizedDescription)", error: error)
            isProcessingTransfer = false

            // Mark WatchTransfer as failed in Core Data
            if let repo = watchTransferRepository {
                try? repo.markFailed(metadata.id, error: error.localizedDescription)
            }

            // Update metadata status to failedReceiving
            if let metadataRepo = metadataRepository {
                do {
                    try metadataRepo.updateStatus(
                        metadata.id,
                        status: .failedReceiving,
                        error: error.localizedDescription
                    )
                    log("📊 Recording metadata updated to failedReceiving status")
                } catch {
                    logError("⚠️ Failed to update metadata status", error: error)
                }
            }

            // Update transfer info to failed state (preserve upload tracking if present)
            let existingTransfer = incomingTransfers[metadata.id]
            let failedTransfer = IncomingTransferInfo(
                id: metadata.id,
                metadata: metadata,
                state: .failed(error.localizedDescription),
                uploadId: existingTransfer?.uploadId,
                uploadProgress: existingTransfer?.uploadProgress
            )
            incomingTransfers[metadata.id] = failedTransfer

            // End Live Activity with failure
            liveActivityManager.endActivity(
                recordingId: metadata.id,
                success: false,
                errorMessage: error.localizedDescription
            )
        }
    }

    // MARK: - Live Activity Helpers

    /// Updates Live Activity for a transfer based on current state
    /// - Parameters:
    ///   - recordingId: The UUID of the recording
    ///   - transferInfo: Current transfer information
    private func updateLiveActivityForTransfer(
        recordingId: UUID,
        transferInfo: IncomingTransferInfo
    ) {
        // Determine stage based on transfer state and upload progress
        let stage: TransferStage
        let watchProgress: Double
        let uploadProgress: Double

        switch transferInfo.state {
        case .pending:
            stage = .transferringFromWatch
            watchProgress = 0.0
            uploadProgress = 0.0
        case .receiving(let progress):
            stage = .transferringFromWatch
            watchProgress = progress ?? 0.0
            uploadProgress = 0.0
        case .completed:
            // Transfer complete - check if uploading
            if let uploadProg = transferInfo.uploadProgress, uploadProg < 1.0 {
                stage = .uploadingToServer
                watchProgress = 1.0
                uploadProgress = uploadProg
            } else if transferInfo.uploadProgress == 1.0 {
                // Both complete
                stage = .completed
                watchProgress = 1.0
                uploadProgress = 1.0
            } else {
                // Transfer complete, upload not started yet
                stage = .uploadingToServer
                watchProgress = 1.0
                uploadProgress = 0.0
            }
        case .failed(let error):
            stage = .failed
            watchProgress = transferInfo.progress ?? 0.0
            uploadProgress = transferInfo.uploadProgress ?? 0.0

            // Update Live Activity with error
            liveActivityManager.updateActivity(
                recordingId: recordingId,
                stage: stage,
                watchProgress: watchProgress,
                uploadProgress: uploadProgress,
                errorMessage: error
            )
            return
        }

        // Update Live Activity
        liveActivityManager.updateActivity(
            recordingId: recordingId,
            stage: stage,
            watchProgress: watchProgress,
            uploadProgress: uploadProgress,
            errorMessage: nil
        )
    }

    // MARK: - Transcription Integration

    /// Sends a local notification when meeting creation completes (idempotent).
    /// Thread-safe: Uses dispatch queue to ensure atomic check-and-set operation.
    private func notifyMeetingCreation(recording: Recording, meetingTitle: String?) async {
        // Thread-safe check-and-set to prevent duplicate notifications
        let shouldNotify = notificationQueue.sync {
            guard !notifiedRecordingIds.contains(recording.id) else { return false }
            notifiedRecordingIds.insert(recording.id)
            return true
        }

        guard shouldNotify else { return }

        // await notificationService.notifyTranscriptionCompleted(
        //     recording: recording,
        //     meetingTitle: meetingTitle
        // )
    }

    /// Uploads recording and creates meeting
    /// - Parameter recording: The recording to upload
    private func uploadAndCreateMeeting(recording: Recording) {
        logger.debug("🟢 [WatchRecordingService] ==========================================")
        logger.debug("🟢 [WatchRecordingService] UPLOADING AND CREATING MEETING")
        logger.debug("🟢 [WatchRecordingService] ==========================================")
        logger.debug("🟢 [WatchRecordingService] Recording ID: \(recording.id)")
        logger.debug("🟢 [WatchRecordingService] File path: \(recording.fileURL.path)")

        log("───────────────────────────────────────────────────")
        log("🎯 UPLOADING AND CREATING MEETING")
        log("───────────────────────────────────────────────────")

        // Check if auto-upload is enabled
        guard autoUploadEnabled else {
            logger.debug("🟢 [WatchRecordingService] ❌ Auto-upload is disabled - skipping")
            log("⏸️ Auto-upload is disabled - skipping")
            // End Live Activity since we won't be uploading (transfer itself completed successfully)
            liveActivityManager.endActivity(recordingId: recording.id, success: true, errorMessage: nil)
            incomingTransfers.removeValue(forKey: recording.id)
            return
        }

        // Check if use case is configured
        guard let useCase = createMeetingFromAudioUseCase else {
            logger.debug("🟢 [WatchRecordingService] ❌ CreateMeetingFromAudioUseCase not configured!")
            log("⚠️ CreateMeetingFromAudioUseCase not configured!")
            log("💡 Call configure(createMeetingFromAudioUseCase:) to enable upload")
            // End Live Activity since upload can't proceed (transfer itself completed successfully)
            liveActivityManager.endActivity(recordingId: recording.id, success: true, errorMessage: nil)
            incomingTransfers.removeValue(forKey: recording.id)
            return
        }

        logger.debug("🟢 [WatchRecordingService] ✅ Auto-upload enabled and use case configured")

        // Verify the audio file exists
        guard FileManager.default.fileExists(atPath: recording.fileURL.path) else {
            log("❌ Audio file not found: \(recording.fileURL.path)")
            // End Live Activity with failure since file is missing
            liveActivityManager.endActivity(
                recordingId: recording.id,
                success: false,
                errorMessage: "Audio file not found"
            )
            incomingTransfers.removeValue(forKey: recording.id)
            return
        }

        // Log file info
        if let attrs = try? FileManager.default.attributesOfItem(atPath: recording.fileURL.path),
           let size = attrs[.size] as? Int64 {
            log("📦 Audio file: \(recording.filename)")
            log("📦 File size: \(ByteCountFormatter.string(fromByteCount: size, countStyle: .file))")
            log("⏱️ Duration: \(String(format: "%.2f", recording.duration))s")
        }

        // Background upload is handled by BackgroundUploadManager (background URLSession).
        // No UIBackgroundTask needed -- BackgroundUploadManager survives app termination.
        // If interrupted, RecordingRetryService retries on next app launch.

        logger.debug("🟢 [WatchRecordingService] Starting Task for upload and meeting creation...")

        // Execute upload and meeting creation
        Task { @MainActor [self] in
            logger.debug("🟢 [WatchRecordingService] Task started, checking cancellation...")

            guard !Task.isCancelled else {
                logger.debug("🟢 [WatchRecordingService] ❌ Task was cancelled")
                self.log("⚠️ Upload task cancelled")
                // End Live Activity since upload was cancelled
                self.liveActivityManager.endActivity(
                    recordingId: recording.id,
                    success: false,
                    errorMessage: "Upload cancelled"
                )
                self.incomingTransfers.removeValue(forKey: recording.id)
                return
            }

            logger.debug("🟢 [WatchRecordingService] ✅ Task not cancelled, proceeding with upload...")

            do {
                // Get location data (or generate random if not available)
                let locationData: CreateMeetingFromAudioUseCase.LocationData?

                if let locationMgr = locationManager, locationMgr.isLocationAvailable {
                    log("📍 Location permission available - fetching current location...")
                    do {
                        let currentLocation = try await locationMgr.getCurrentLocation()
                        locationData = CreateMeetingFromAudioUseCase.LocationData(
                            latitude: currentLocation.latitude,
                            longitude: currentLocation.longitude,
                            accuracy: currentLocation.accuracy,
                            placeName: nil
                        )
                        log("✅ Location retrieved: \(currentLocation.latitude), \(currentLocation.longitude)")
                    } catch {
                        logError("⚠️ Failed to get location - using random location", error: error)
                        locationData = nil
                    }
                } else {
                    log("📍 Location permission not available - will use random coordinates")
                    locationData = nil
                }

                // Update status to uploading
                if let metadataRepo = metadataRepository {
                    do {
                        try metadataRepo.updateStatus(recording.id, status: .uploading, error: nil)
                        try? self.repository?.updateStatus(recording.id, status: .uploading, error: nil)
                        log("📊 Recording metadata updated to uploading status")

                        // Sync status to watch
                        WatchStatusSync().sendStatusToWatch(recordingId: recording.id, status: .uploading)
                    } catch {
                        logError("⚠️ Failed to update metadata status", error: error)
                    }
                }

                // Update Live Activity - upload starting
                if var transfer = self.incomingTransfers[recording.id] {
                    transfer.uploadId = nil // Will be set when upload starts
                    transfer.uploadProgress = 0.0
                    self.incomingTransfers[recording.id] = transfer
                    self.updateLiveActivityForTransfer(
                        recordingId: recording.id,
                        transferInfo: transfer
                    )
                }

                // Create meeting parameters
                logger.debug("🟢 [WatchRecordingService] Creating meeting parameters...")
                let parameters = CreateMeetingFromAudioUseCase.Parameters(
                    audioFileURL: recording.fileURL,
                    recordingDuration: recording.duration,
                    locationData: locationData,
                    startTime: recording.startTime
                )

                logger.debug("🟢 [WatchRecordingService] Parameters created:")
                logger.debug("🟢 [WatchRecordingService]   - audioFileURL: \(recording.fileURL.path)")
                logger.debug("🟢 [WatchRecordingService]   - recordingDuration: \(recording.duration)")
                logger.debug("🟢 [WatchRecordingService]   - locationData: \(locationData != nil ? "provided" : "nil (random)")")
                logger.debug("🟢 [WatchRecordingService]   - startTime: \(recording.startTime)")

                // Execute use case
                logger.debug("🟢 [WatchRecordingService] 🚀 About to execute useCase.execute()...")
                log("🚀 Uploading and creating meeting...")
                let meeting = try await useCase.execute(parameters) { [weak self] uploadId in
                    self?.logger.debug("🟢 [WatchRecordingService] 📎 onUploadStarted callback - uploadId: \(uploadId)")
                    // Store mapping from upload ID to recording ID
                    self?.log("📎 Linking upload \(uploadId) to recording \(recording.id)")
                    self?.uploadIdToRecordingId[uploadId] = recording.id
                    self?.log("📎 Current upload mappings: \(self?.uploadIdToRecordingId.count ?? 0)")

                    // Update status to uploaded (upload just started, will update when complete)
                    // Note: This is called when upload starts, we'll update to uploaded later
                }

                // Upload and meeting creation succeeded
                logger.debug("🟢 [WatchRecordingService] ==========================================")
                logger.info("🟢 [WatchRecordingService] ✅ MEETING CREATED SUCCESSFULLY!")
                logger.debug("🟢 [WatchRecordingService] Meeting ID: \(meeting.id)")
                logger.debug("🟢 [WatchRecordingService] Title: \(meeting.title)")
                logger.debug("🟢 [WatchRecordingService] ==========================================")

                log("✅ Meeting created successfully!")
                log("   Meeting ID: \(meeting.id)")
                log("   Title: \(meeting.title)")
                log("   Duration: \(meeting.durationSeconds ?? 0)s")
                if let lat = meeting.latitude, let lon = meeting.longitude {
                    log("   Location: \(lat), \(lon)")
                }
                log("───────────────────────────────────────────────────")

                // Update status to created with meeting ID
                if let metadataRepo = metadataRepository {
                    do {
                        try metadataRepo.updateStatus(recording.id, status: .created, error: nil)
                        try metadataRepo.updateMeetingId(recording.id, meetingId: meeting.id)
                        try? self.repository?.updateStatus(recording.id, status: .created, error: nil)
                        try? self.repository?.updateMeetingId(recording.id, meetingId: meeting.id.uuidString)
                        log("📊 Recording metadata updated to created status with meeting ID")

                        // Sync status to watch with meeting ID
                        WatchStatusSync().sendStatusToWatch(
                            recordingId: recording.id,
                            status: .created,
                            meetingId: meeting.id
                        )
                        sendProcessedConfirmationToWatch(
                            recordingId: recording.id,
                            trigger: "meeting_created"
                        )
                    } catch {
                        logError("⚠️ Failed to update metadata status", error: error)
                    }
                }

                // End Live Activity with success
                self.liveActivityManager.endActivity(
                    recordingId: recording.id,
                    success: true,
                    errorMessage: nil
                )

                // Remove upload tracking
                if let transfer = self.incomingTransfers[recording.id], let uploadId = transfer.uploadId {
                    self.uploadIdToRecordingId.removeValue(forKey: uploadId)
                    // Clean up progress tracking
                    self.lastSentUploadProgress.removeValue(forKey: recording.id)
                }

                // Clear transfer from list since it's complete
                self.incomingTransfers.removeValue(forKey: recording.id)
                self.log("🧹 Removed completed transfer from UI: \(recording.id)")

                // Notify user that meeting is ready
                await self.notifyMeetingCreation(recording: recording, meetingTitle: meeting.title)

                // Schedule delayed cleanup as fallback (in case transfer wasn't removed above)
                // This ensures transfers are removed even if something goes wrong
                DispatchQueue.main.asyncAfter(deadline: .now() + 5.0) { [weak self] in
                    guard let self = self else { return }
                    if self.incomingTransfers[recording.id] != nil {
                        self.incomingTransfers.removeValue(forKey: recording.id)
                        self.log("🧹 Delayed cleanup: Removed transfer from UI: \(recording.id)")
                    }
                }

            } catch {
                logger.debug("🟢 [WatchRecordingService] ==========================================")
                logger.error("🟢 [WatchRecordingService] ❌ UPLOAD/MEETING CREATION FAILED!", error: error)
                logger.debug("🟢 [WatchRecordingService] Error: \(error)")
                logger.debug("🟢 [WatchRecordingService] Error type: \(type(of: error))")
                logger.debug("🟢 [WatchRecordingService] ==========================================")

                logError("❌ ERROR: Failed to upload and create meeting: \(error.localizedDescription)", error: error)
                log("───────────────────────────────────────────────────")

                // End Live Activity with failure
                self.liveActivityManager.endActivity(
                    recordingId: recording.id,
                    success: false,
                    errorMessage: error.localizedDescription
                )

                // Clean up upload tracking on failure
                if let transfer = self.incomingTransfers[recording.id],
                   let uploadId = transfer.uploadId {
                    self.uploadIdToRecordingId.removeValue(forKey: uploadId)
                    self.log("🧹 Cleaned up upload tracking for failed upload: \(uploadId)")
                }
                // Clean up progress tracking
                self.lastSentUploadProgress.removeValue(forKey: recording.id)

                // Update status to failed
                if let metadataRepo = metadataRepository {
                    do {
                        try metadataRepo.updateStatus(
                            recording.id,
                            status: .failedUploading,
                            error: error.localizedDescription
                        )
                        try? self.repository?.updateStatus(
                            recording.id,
                            status: .failedUploading,
                            error: error.localizedDescription
                        )
                        log("📊 Recording metadata updated to failedUploading status")

                        // Sync failure status to watch
                        WatchStatusSync().sendStatusToWatch(recordingId: recording.id, status: .failedUploading)
                    } catch {
                        logError("⚠️ Failed to update metadata status", error: error)
                    }
                }

                // If the app is in the background and the upload failed, ask the user
                // to open the iPhone app so the upload can proceed in the foreground.
                self.notifyWatchToOpenIPhoneAppIfNeeded(recordingId: recording.id)

                // Schedule delayed cleanup for failed transfers
                DispatchQueue.main.asyncAfter(deadline: .now() + 5.0) { [weak self] in
                    guard let self = self else { return }
                    if self.incomingTransfers[recording.id] != nil {
                        self.incomingTransfers.removeValue(forKey: recording.id)
                        self.log("🧹 Delayed cleanup: Removed failed transfer from UI: \(recording.id)")
                    }
                }
            }
        }
    }




    // MARK: - Open iPhone App Request

    /// Sends a message to the Watch asking the user to open the iPhone app.
    /// Called when the upload fails and the app may need foreground access to retry.
    /// - Parameter recordingId: The recording whose upload failed
    private func notifyWatchToOpenIPhoneAppIfNeeded(recordingId: UUID) {
        #if os(iOS)
        // Only send if the app is currently in the background
        let appState = UIApplication.shared.applicationState
        guard appState == .background else {
            log("App is in foreground — no need to ask Watch user to open iPhone app")
            return
        }

        log("App is in background and upload failed — asking Watch user to open iPhone app")

        let message: [String: Any] = [
            WatchMessageKey.action: WatchMessageKey.actionOpenIPhoneApp,
            WatchMessageKey.recordingId: recordingId.uuidString
        ]

        connectivityManager.sendMessage(message) { [weak self] error in
            if let error = error {
                self?.logError("Failed to send open-app request to Watch", error: error)
            } else {
                self?.log("Sent open-app request to Watch")
            }
        }
        #endif
    }

    // MARK: - Watch Confirmation

    /// Sends confirmation to the watch that recordings have been received
    /// The watch will delete its local copies upon receiving this confirmation
    private func sendConfirmationToWatch() {
        guard !pendingConfirmations.isEmpty else { return }

        log("📤 Sending confirmation to watch for \(pendingConfirmations.count) recording(s)")

        // Only clear pending confirmations if the session was active and the
        // confirmation was actually queued. Otherwise retain them for retry.
        let sent = connectivityManager.confirmRecordingsReceived(
            pendingConfirmations,
            phase: .received
        )

        if sent {
            log("✅ Confirmation sent - watch will delete local copies")
            pendingConfirmations.removeAll()
        } else {
            log("⚠️ Confirmation not sent (session not active) — will retry on next opportunity")
        }
    }

    /// Sends an explicit confirmation for a single recording when iPhone-side processing
    /// reaches a terminal state (e.g., meeting created). This is a safety net in case the
    /// initial receipt confirmation was missed while session connectivity was unstable.
    private func sendProcessedConfirmationToWatch(recordingId: UUID, trigger: String) {
        log("📤 Sending terminal confirmation to watch [trigger=\(trigger)] for recording: \(recordingId)")

        let sent = connectivityManager.confirmRecordingsReceived(
            [recordingId],
            phase: .processed
        )
        if sent {
            log("✅ Terminal confirmation queued for recording: \(recordingId)")
        } else {
            log("⚠️ Terminal confirmation not sent (session not active) for recording: \(recordingId)")
        }
    }

    // MARK: - Public Methods

    /// Fetches all recordings (including those received from watch)
    /// - Returns: Array of all stored recordings
    func fetchAllRecordings() -> [Recording] {
        log("Fetching all recordings...")
        do {
            let recordings = try repository?.fetchAllRecordings() ?? []
            log("Found \(recordings.count) recording(s)")
            return recordings
        } catch {
            logError("❌ Failed to fetch recordings: \(error.localizedDescription)", error: error)
            return []
        }
    }

    /// Deletes a recording by ID
    /// - Parameter id: The UUID of the recording to delete
    func deleteRecording(id: UUID) {
        log("Deleting recording: \(id)")
        do {
            try repository?.deleteRecording(id: id)
            log("✅ Deleted recording: \(id)")

            // Update last received if it matches
            if lastReceivedRecording?.id == id {
                lastReceivedRecording = nil
            }
        } catch {
            logError("❌ Failed to delete recording: \(error.localizedDescription)", error: error)
        }
    }

    // MARK: - Debug & Status

    /// Prints a comprehensive status summary for debugging
    func printStatusSummary() {
        log("═══════════════════════════════════════════════════")
        log("📊 WATCH RECORDING SERVICE STATUS")
        log("═══════════════════════════════════════════════════")
        log("Recordings received this session: \(recordingsReceivedCount)")
        log("Is processing transfer: \(isProcessingTransfer)")
        log("Has pending files: \(hasPendingFiles)")
        log("Auto-upload enabled: \(autoUploadEnabled)")
        log("Upload manager configured: \(createMeetingFromAudioUseCase != nil)")

        if let repo = repository {
            log("Storage directory: \(repo.directoryURL.path)")
        }

        let recordings = fetchAllRecordings()
        log("Total recordings in storage: \(recordings.count)")

        // Upload status
        let uploadManager = UploadManager.shared
        log("───────────────────────────────────────────────────")
        log("📤 UPLOAD STATUS:")
        log("Active uploads: \(uploadManager.activeUploadCount)")
        log("Total tracked uploads: \(uploadManager.activeUploads.count)")

        log("═══════════════════════════════════════════════════")
    }

    // MARK: - Deinitialization

    /// Cleans up resources when service is deallocated
    /// Note: Cannot call @MainActor methods from deinit, so logging is omitted
    deinit {
        stallCheckTimer?.invalidate()
        uploadProgressCancellable?.cancel()
        cancellables.removeAll()
    }
}

// MARK: - Notifications

extension Notification.Name {
    /// Posted when a new recording is received and saved from Apple Watch
    static let newRecordingReceivedFromWatch = Notification.Name("newRecordingReceivedFromWatch")
}

