 2→//  WatchRecordingCleanupService.swift
 3→//  MemorableWatch Watch App
 4→//
 5→//  Background service that automatically deletes confirmed recordings after a specified time period
 6→//
 7→
 8→import Foundation
 9→import Combine
10→
11→/// Background service that automatically deletes confirmed recordings after a specified time period
12→final class WatchRecordingCleanupService {
13→    private let repository: LocalRecordingRepository
14→    private let daysToKeep: Int
15→    private var timer: Timer?
16→    private let logger = LoggerFactory.makeLogger()
17→    
18→    init(repository: LocalRecordingRepository, daysToKeep: Int = 7) {
19→        self.repository = repository
20→        self.daysToKeep = daysToKeep
21→    }
22→    
23→    /// Starts automatic cleanup (runs daily)
24→    func startAutomaticCleanup() {
25→        logger.info("[Cleanup] Starting automatic cleanup service (retention: \(daysToKeep) days)")
26→        
27→        // Run immediately on startup
28→        performCleanup()
29→        
30→        // Then schedule to run every 24 hours
31→        DispatchQueue.main.async { [weak self] in
32→            guard let self = self else { return }
33→            self.timer = Timer.scheduledTimer(withTimeInterval: 86400, repeats: true) { [weak self] _ in
34→                self?.performCleanup()
35→            }
36→            self.logger.info("[Cleanup] Scheduled daily cleanup timer")
37→        }
38→    }
39→    
40→    func stopAutomaticCleanup() {
41→        DispatchQueue.main.async { [weak self] in
42→            self?.timer?.invalidate()
43→            self?.timer = nil
44→        }
45→        logger.info("[Cleanup] Stopped automatic cleanup")
46→    }
47→    
48→    /// Performs cleanup of old confirmed recordings
49→    func performCleanup() {
50→        logger.info("[Cleanup] Starting automatic cleanup (keeping last \(daysToKeep) days)")
51→        
52→        do {
53→            let recordingsToDelete = try repository.fetchRecordingsForCleanup(olderThanDays: daysToKeep)
54→            
55→            logger.info("[Cleanup] Found \(recordingsToDelete.count) recording(s) to delete")
56→            
57→            for recording in recordingsToDelete {
58→                do {
59→                    try repository.deleteRecording(id: recording.id)
60→                    logger.info("[Cleanup] ✅ Deleted old recording: \(recording.id)")
61→                } catch {
62→                    logger.error("[Cleanup] ❌ Failed to delete recording \(recording.id)", error: error)
63→                }
64→            }
65→            
66→            if recordingsToDelete.isEmpty {
67→                logger.info("[Cleanup] No old recordings to clean up")
68→            } else {
69→                logger.info("[Cleanup] ✅ Cleanup complete - deleted \(recordingsToDelete.count) recording(s)")
70→            }
71→        } catch {
72→            logger.error("[Cleanup] ❌ Cleanup failed", error: error)
73→        }
74→    }
75→    
76→    /// Manually trigger cleanup
77→    func cleanupNow() {
78→        logger.info("[Cleanup] Manual cleanup triggered")
79→        performCleanup()
80→    }
81→    
82→    deinit {
83→        stopAutomaticCleanup()
84→    }
85→}
