//
//  WatchRecordingStatus.swift
//  MemorableWatch Watch App
//
//  Status enum for watch-side recording transfer states
//

import Foundation

/// Status of a recording on the watch side
enum WatchRecordingStatus: Int16, Codable {
    case pending = 0        // Local recording, not sent yet
    case transferring = 1   // Transfer in progress
    case sent = 2           // Transfer completed, waiting for iOS confirmation
    case confirmed = 3      // iOS confirmed receipt and processing
    case failed = 4         // Transfer failed

    var displayName: String {
        switch self {
        case .pending: return "Not Sent"
        case .transferring: return "Sending"
        case .sent: return "Sent"
        case .confirmed: return "Confirmed"
        case .failed: return "Failed"
        }
    }

    var icon: String {
        switch self {
        case .pending: return "clock"
        case .transferring: return "arrow.up.circle"
        case .sent: return "checkmark.circle"
        case .confirmed: return "checkmark.circle.fill"
        case .failed: return "exclamationmark.triangle"
        }
    }

    var color: String {
        switch self {
        case .pending: return "gray"
        case .transferring: return "blue"
        case .sent: return "orange"
        case .confirmed: return "green"
        case .failed: return "red"
        }
    }

    // MARK: - Terminal State Management

    /// Whether this is a final state that should ignore further updates
    /// Once a recording reaches a terminal state, no more status updates should be processed
    /// This prevents crashes from late/out-of-order WatchConnectivity callbacks
    var isTerminal: Bool {
        return self == .confirmed
    }

    /// Checks if transition to new status is valid
    /// - Parameter newStatus: The status to transition to
    /// - Returns: True if the transition is allowed, false otherwise
    func canTransition(to newStatus: WatchRecordingStatus) -> Bool {
        // Terminal states never transition (prevents duplicate processing)
        if self.isTerminal {
            return false
        }

        // Define valid state transitions for safety
        switch self {
        case .pending:
            // From pending, can go to transferring or failed
            return newStatus == .transferring || newStatus == .failed
        case .transferring:
            // From transferring, can go to sent, failed, or back to pending (retry)
            return newStatus == .sent || newStatus == .failed || newStatus == .pending
        case .sent:
            // From sent, can go to confirmed, failed, or back to pending (retry)
            return newStatus == .confirmed || newStatus == .failed || newStatus == .pending
        case .confirmed:
            // Terminal state - no transitions allowed
            return false
        case .failed:
            // From failed, can retry (go back to pending or transferring)
            return newStatus == .pending || newStatus == .transferring
        }
    }
}

//
//  RecordingRow.swift
//  MemorableWatch Watch App
//
//  Row component displaying a single recording's metadata with transfer progress.
//

import SwiftUI

// MARK: - UI Status Types

/// Simplified UI status for recording display on Watch
/// Shows user-friendly transfer lifecycle: queued → transferring → transferred → open iPhone / failed
enum RecordingUIStatus {
    case queued              // Saved locally, waiting to transfer
    case transferring        // Actively sending to iPhone
    case transferred         // Successfully delivered to iPhone
    case failed              // Transfer failed — user should retry
    case openIPhone          // iPhone has the recording — user should open iPhone app

    /// Display text shown to the user (includes emoji for quick scanning)
    var displayText: String {
        switch self {
        case .queued:       return AppText.TransferStatus.queued
        case .transferring: return AppText.TransferStatus.transferring
        case .transferred:  return AppText.TransferStatus.transferred
        case .failed:       return AppText.TransferStatus.failed
        case .openIPhone:   return AppText.TransferStatus.openIPhone
        }
    }

    /// SF Symbol icon for the status
    var icon: String {
        switch self {
        case .queued:
            return "clock"
        case .transferring:
            return "arrow.right.circle"
        case .transferred:
            return "checkmark.circle"
        case .failed:
            return "exclamationmark.triangle"
        case .openIPhone:
            return "iphone"
        }
    }

    /// Color for the status indicator
    var color: Color {
        switch self {
        case .queued:
            return .gray
        case .transferring:
            return .blue
        case .transferred:
            return .green
        case .failed:
            return .red
        case .openIPhone:
            return .orange
        }
    }
}

/// Row component displaying a single recording's metadata
/// Shows recording title, date, duration, and transfer progress if applicable
struct RecordingRow: View {

    // MARK: - Properties

    /// The recording to display
    let recording: Recording

    /// Observed connectivity manager for transfer state
    @ObservedObject private var connectivity = WatchConnectivityManager.shared

    /// View model for status information
    @EnvironmentObject private var viewModel: WatchRecordingViewModel

    // MARK: - Computed Properties

    /// Maps internal status to simplified UI status (5 user-friendly states)
    private var uiStatus: RecordingUIStatus? {
        guard let statusInfo = viewModel.getRecordingStatusInfo(recording.id) else {
            // nil means pending (not sent yet) — show "Queued"
            return .queued
        }

        switch statusInfo.displayText {
            case AppText.TransferRawStatus.queued,
                 AppText.TransferRawStatus.notSent:
                return .queued

            case AppText.TransferRawStatus.sending:
                return .transferring

            case AppText.TransferRawStatus.sent,
                 AppText.TransferRawStatus.receivedByIPhone:
                return .transferred

            case AppText.TransferRawStatus.iPhoneUploading,
                 AppText.TransferRawStatus.uploaded,
                 AppText.TransferRawStatus.creatingMeeting,
                 AppText.TransferRawStatus.meetingCreated,
                 AppText.TransferRawStatus.confirmed:
                return .openIPhone

            case AppText.TransferRawStatus.failed:
                return .failed

            default:
                return nil

        }
    }

    // MARK: - Body

    var body: some View {
        VStack(alignment: .leading, spacing: 4) {
            // Recording title (using filename or "Recording")
            Text(AppText.txtRecording)
                .font(.headline)
                .lineLimit(1)

            HStack(spacing: 8) {
                // Creation date
                Text(formatDate(recording.createdAt))
                    .font(.caption2)
                    .foregroundColor(.secondary)

                // Duration (only show if greater than 0)
                if recording.duration > 0 {
                    Text("•")
                        .font(.caption2)
                        .foregroundColor(.secondary)
                    Text(formatDuration(recording.duration))
                        .font(.caption2)
                        .foregroundColor(.secondary)
                }
            }

            // Show transfer progress if this recording is being transferred to phone
            if let progress = connectivity.getTransferProgress(for: recording.id) {
                VStack(alignment: .leading, spacing: 4) {
                    ProgressView(value: progress, total: 1.0)
                        .progressViewStyle(LinearProgressViewStyle(tint: .blue))
                        .frame(height: 1)
                        .padding(.bottom, 2)
                        .accessibilityLabel("Recording is being transferred to phone")

                    Text("\(Int(progress * 100))% \(AppText.txtUploaded)")
                        .font(.caption2)
                        .foregroundColor(.secondary)
                }
                .padding(.top, 2)
            }

            // Show simplified status badge
            if let status = uiStatus {
                HStack(spacing: 4) {
                    Image(systemName: status.icon)
                        .foregroundColor(status.color)
                        .font(.caption2)

                    Text(status.displayText)
                        .font(.caption2)
                        .foregroundColor(.secondary)
                }
                .padding(.top, 2)
            }
        }
        .padding(.vertical, 4)
    }

    // MARK: - Helper Methods

    /// Formats a date to a compact format suitable for Watch with time
    /// - Parameter date: The date to format
    /// - Returns: Formatted date string (e.g., "Dec 24, 2025, 3:45 PM")
    private func formatDate(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }

    /// Formats duration in seconds to MM:SS or HH:MM:SS format
    /// - Parameter duration: Duration in seconds (TimeInterval)
    /// - Returns: Formatted duration string
    private func formatDuration(_ duration: TimeInterval) -> String {
        let totalSeconds = Int(duration)
        let hours = totalSeconds / 3600
        let minutes = (totalSeconds % 3600) / 60
        let seconds = totalSeconds % 60

        if hours > 0 {
            return String(format: "%d:%02d:%02d", hours, minutes, seconds)
        } else {
            return String(format: "%d:%02d", minutes, seconds)
        }
    }
}


/// Information about a recording's current status for UI display
struct RecordingStatusInfo {
    let icon: String
    let color: Color
    let displayText: String
    let uploadProgress: Double?  // 0.0 to 1.0, only set when uploading on iOS
    let showSendAgainButton: Bool  // Show "Send Again" button (e.g., when status is "Received")
}

/// Gets the current status information for a recording
/// - Parameter recordingId: The recording ID to check
/// - Returns: Status information for UI display, or nil if recording not found
func getRecordingStatusInfo(_ recordingId: UUID) -> RecordingStatusInfo? {
    guard let localRepo = repository as? LocalRecordingRepository,
          let entity = try? localRepo.fetchEntityById(recordingId) else {
        return nil
    }

    // Check iOS processing status first (takes priority over local status)
    if let iosStatus = entity.iosProcessingStatus {
        switch iosStatus {
        case "Received":
            return RecordingStatusInfo(
                icon: "checkmark.circle",
                color: .green,
                displayText: "Received by iPhone",
                uploadProgress: nil,
                showSendAgainButton: true
            )
        case "Uploading":
            // Include upload progress if available
            let progress = entity.iosUploadProgress > 0 ? entity.iosUploadProgress : nil
            return RecordingStatusInfo(
                icon: "arrow.up.circle",
                color: .blue,
                displayText: "iPhone uploading",
                uploadProgress: progress,
                showSendAgainButton: false
            )
        case "Uploaded":
            return RecordingStatusInfo(
                icon: "cloud.fill",
                color: .blue,
                displayText: "Uploaded",
                uploadProgress: nil,
                showSendAgainButton: false
            )
        case "Creating Meeting":
            return RecordingStatusInfo(
                icon: "gear",
                color: .orange,
                displayText: "Creating meeting",
                uploadProgress: nil,
                showSendAgainButton: false
            )
        case "Created":
            return RecordingStatusInfo(
                icon: "checkmark.circle.fill",
                color: .green,
                displayText: "Meeting created",
                uploadProgress: nil,
                showSendAgainButton: false
            )
        default:
            break
        }
    }

    // Fall back to local status
    let status = WatchRecordingStatus(rawValue: entity.status) ?? .pending
    let displayText = (status == .pending) ? "Queued" : status.displayName

    return RecordingStatusInfo(
        icon: status.icon,
        color: colorForStatus(status),
        displayText: displayText,
        uploadProgress: nil,
        showSendAgainButton: false
    )
}

/// Gets the appropriate color for a watch recording status
private func colorForStatus(_ status: WatchRecordingStatus) -> Color {
    switch status {
    case .pending: return .gray
    case .transferring: return .blue
    case .sent: return .orange
    case .confirmed: return .green
    case .failed: return .red
    }
}

/// Checks if a recording can be sent (used for button state)
func canSendRecording(_ recordingId: UUID) -> (canSend: Bool, reason: String?) {
    guard let localRepo = repository as? LocalRecordingRepository else {
        return (false, "Repository not available")
    }

    return localRepo.canSendRecording(recordingId)
}

/// Retries transferring local recordings that are genuinely pending or failed.
/// Pre-filters by Core Data status and in-flight state to avoid duplicate transfers.
func retryPendingTransfers() {
    RecordingLogger.log("=== RETRY PENDING TRANSFERS ===")

    guard connectivityManager.isWatchConnected else {
        RecordingLogger.log("iOS app not connected - cannot retry transfers")
        return
    }

    startNextQueuedTransferIfIdle()
    RecordingLogger.log("Retry trigger complete - queue scheduler invoked")
}

// MARK: - App Lifecycle

/// Call this when the watch app appears/becomes active.
/// This checks for any local recordings that haven't been transferred yet

